,OAAPN,MAAOM,EAAEX,CAACA,MAADA,CAAQY,QAAAA,CAAAA,CAAVD,CAArE,CAAA,GAAA,CAAAhB,OAAQC,OAAAA,CAAOC,oBAAf,EAAgCG,0BAAxBJ,CAAR,IAAA,GAAA;;AAERI;;;AAGAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA,UAAYL,OAAQC,OAAAA,CAAQI,+BAAD,GAAA,CAAgCA,CAACA,SAADA,CAAWa,SAAAA,CAAAA,CAA3C,CAAA,GAAoDb,4BAA3DJ;AACpBI;;AAEAA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA,UAAYL,OAAQC,OAAAA,CAAQI,+BAAD,GAAA,CAAgCA,CAACA,SAADA,CAAWa,SAAAA,CAAAA,CAA3C,CAAA,GAAoDb,uBAA3DJ;AACpBI;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA,YAAcL,OAAQC,OAAAA,CAAQI,+BAAD,GAAA,CAAgCA,CAACA,SAADA,CAAWa,SAAAA,CAAAA,CAA3C,CAAA,GAAoDb,mCAA3DJ;AACtBI;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;IAnFEA,CAAAA,IAAAA;IAsFAT,OAAAuB,uBAAAA,mBAAYb,MAAD,EA3vBbC,OA2vBEY;AAAAA,MAAAA;;;MA3vBF;;MA2vBsB,kCAAA,6BAAQX;MAC1BF,SAASK,KAAMC,eAAAA,CAAYN,MAAlB,EAA0BO,aAA1B,EAAoC,QAA9BD,CAAsCE,MAAAA,CAAM,IAAlD,EAAwDK,EAAZL,CAAeC,QAAAA,CAAQI,QAARJ;MAEpEI,OAAAzB,IAAAW,QAAAA,CAAOC,MAAMc,OAAAA,CAACZ,CAADY,CAAb,EAAkB,oBAAA,UAAQV,MAAR,EAAlBL,CAAiCe,OAAAA,CAACZ,CAADY;IAHnCD,CAAAA,IAAAA;EAxvBFvB,GAAM,IAANA,EAAAA,IAAAA;AAHAH;"}}, {:offset=>{:line=>1029, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./set.rb"], :sourcesContent=>["# Set has been moved to corelib\n"], :names=>["<top (required)>"], :mappings=>"AAAAA,sBAAAA,2BAAAA;"}}, {:offset=>{:line=>1031, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["ast/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule AST\n  # Node is an immutable class, instances of which represent abstract\n  # syntax tree nodes. It combines semantic information (i.e. anything\n  # that affects the algorithmic properties of a program) with\n  # meta-information (line numbers or compiler intermediates).\n  #\n  # Notes on inheritance\n  # ====================\n  #\n  # The distinction between semantics and metadata is important. Complete\n  # semantic information should be contained within just the {#type} and\n  # {#children} of a Node instance; in other words, if an AST was to be\n  # stripped of all meta-information, it should remain a valid AST which\n  # could be successfully processed to yield a result with the same\n  # algorithmic properties.\n  #\n  # Thus, Node should never be inherited in order to define methods which\n  # affect or return semantic information, such as getters for `class_name`,\n  # `superclass` and `body` in the case of a hypothetical `ClassNode`. The\n  # correct solution is to use a generic Node with a {#type} of `:class`\n  # and three children. See also {Processor} for tips on working with such\n  # ASTs.\n  #\n  # On the other hand, Node can and should be inherited to define\n  # application-specific metadata (see also {#initialize}) or customize the\n  # printing format. It is expected that an application would have one or two\n  # such classes and use them across the entire codebase.\n  #\n  # The rationale for this pattern is extensibility and maintainability.\n  # Unlike static ones, dynamic languages do not require the presence of a\n  # predefined, rigid structure, nor does it improve dispatch efficiency,\n  # and while such a structure can certainly be defined, it does not add\n  # any value but incurs a maintaining cost.\n  # For example, extending the AST even with a transformation-local\n  # temporary node type requires making globally visible changes to\n  # the codebase.\n  #\n  class Node\n    # Returns the type of this node.\n    # @return [Symbol]\n    attr_reader :type\n\n    # Returns the children of this node.\n    # The returned value is frozen.\n    # The to_a alias is useful for decomposing nodes concisely.\n    # For example:\n    #\n    #     node = s(:gasgn, :$foo, s(:integer, 1))\n    #     var_name, value = *node\n    #     p var_name # => :$foo\n    #     p value    # => (integer 1)\n    #\n    # @return [Array]\n    attr_reader :children\n    alias to_a children\n\n    # Returns the precomputed hash value for this node\n    # @return [Fixnum]\n    attr_reader :hash\n\n    # Constructs a new instance of Node.\n    #\n    # The arguments `type` and `children` are converted with `to_sym` and\n    # `to_a` respectively. Additionally, the result of converting `children`\n    # is frozen. While mutating the arguments is generally considered harmful,\n    # the most common case is to pass an array literal to the constructor. If\n    # your code does not expect the argument to be frozen, use `#dup`.\n    #\n    # The `properties` hash is passed to {#assign_properties}.\n    def initialize(type, children=[], properties={})\n      @type, @children = type.to_sym, children.to_a.freeze\n\n      assign_properties(properties)\n\n      @hash = [@type, @children, self.class].hash\n\n      freeze\n    end\n\n    # Test if other object is equal to\n    # @param [Object] other\n    # @return [Boolean]\n    def eql?(other)\n      self.class.eql?(other.class)   &&\n      @type.eql?(other.type)         &&\n      @children.eql?(other.children)\n    end\n\n    # By default, each entry in the `properties` hash is assigned to\n    # an instance variable in this instance of Node. A subclass should define\n    # attribute readers for such variables. The values passed in the hash\n    # are not frozen or whitelisted; such behavior can also be implemented\n    # by subclassing Node and overriding this method.\n    #\n    # @return [nil]\n    def assign_properties(properties)\n      properties.each do |name, value|\n        instance_variable_set :\"@\#{name}\", value\n      end\n\n      nil\n    end\n    protected :assign_properties\n\n    alias   :original_dup :dup\n    private :original_dup\n\n    # Nodes are already frozen, so there is no harm in returning the\n    # current node as opposed to initializing from scratch and freezing\n    # another one.\n    #\n    # @return self\n    def dup\n      self\n    end\n    alias :clone :dup\n\n    # Returns a new instance of Node where non-nil arguments replace the\n    # corresponding fields of `self`.\n    #\n    # For example, `Node.new(:foo, [ 1, 2 ]).updated(:bar)` would yield\n    # `(bar 1 2)`, and `Node.new(:foo, [ 1, 2 ]).updated(nil, [])` would\n    # yield `(foo)`.\n    #\n    # If the resulting node would be identical to `self`, does nothing.\n    #\n    # @param  [Symbol, nil] type\n    # @param  [Array, nil]  children\n    # @param  [Hash, nil]   properties\n    # @return [AST::Node]\n    def updated(type=nil, children=nil, properties=nil)\n      new_type       = type       || @type\n      new_children   = children   || @children\n      new_properties = properties || {}\n\n      if @type == new_type &&\n          @children == new_children &&\n          properties.nil?\n        self\n      else\n        copy = original_dup\n        copy.send :initialize, new_type, new_children, new_properties\n        copy\n      end\n    end\n\n    # Compares `self` to `other`, possibly converting with `to_ast`. Only\n    # `type` and `children` are compared; metadata is deliberately ignored.\n    #\n    # @return [Boolean]\n    def ==(other)\n      if equal?(other)\n        true\n      elsif other.respond_to? :to_ast\n        other = other.to_ast\n        other.type == self.type &&\n          other.children == self.children\n      else\n        false\n      end\n    end\n\n    # Concatenates `array` with `children` and returns the resulting node.\n    #\n    # @return [AST::Node]\n    def concat(array)\n      updated(nil, @children + array.to_a)\n    end\n\n    alias + concat\n\n    # Appends `element` to `children` and returns the resulting node.\n    #\n    # @return [AST::Node]\n    def append(element)\n      updated(nil, @children + [element])\n    end\n\n    alias << append\n\n    # Converts `self` to a pretty-printed s-expression.\n    #\n    # @param  [Integer] indent Base indentation level.\n    # @return [String]\n    def to_sexp(indent=0)\n      indented = \"  \" * indent\n      sexp = \"\#{indented}(\#{fancy_type}\"\n\n      children.each do |child|\n        if child.is_a?(Node)\n          sexp += \"\\n\#{child.to_sexp(indent + 1)}\"\n        else\n          sexp += \" \#{child.inspect}\"\n        end\n      end\n\n      sexp += \")\"\n\n      sexp\n    end\n\n    alias to_s to_sexp\n\n    # Converts `self` to a s-expression ruby string.\n    # The code return will recreate the node, using the sexp module s()\n    #\n    # @param  [Integer] indent Base indentation level.\n    # @return [String]\n    def inspect(indent=0)\n      indented = \"  \" * indent\n      sexp = \"\#{indented}s(:\#{@type}\"\n\n      children.each do |child|\n        if child.is_a?(Node)\n          sexp += \",\\n\#{child.inspect(indent + 1)}\"\n        else\n          sexp += \", \#{child.inspect}\"\n        end\n      end\n\n      sexp += \")\"\n\n      sexp\n    end\n\n    # @return [AST::Node] self\n    def to_ast\n      self\n    end\n\n    # Converts `self` to an Array where the first element is the type as a Symbol,\n    # and subsequent elements are the same representation of its children.\n    #\n    # @return [Array<Symbol, [...Array]>]\n    def to_sexp_array\n      children_sexp_arrs = children.map do |child|\n        if child.is_a?(Node)\n          child.to_sexp_array\n        else\n          child\n        end\n      end\n\n      [type, *children_sexp_arrs]\n    end\n\n    # Enables matching for Node, where type is the first element\n    # and the children are remaining items.\n    #\n    # @return [Array]\n    def deconstruct\n      [type, *children]\n    end\n\n    protected\n\n    # Returns `@type` with all underscores replaced by dashes. This allows\n    # to write symbol literals without quotes in Ruby sources and yet have\n    # nicely looking s-expressions.\n    #\n    # @return [String]\n    def fancy_type\n      @type.to_s.gsub('_', '-')\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:AST>", "<class:Node>", "self", "attr_reader", "initialize", "type", "children", "properties", "to_sym", "to_a", "freeze", "@type", "@children", "assign_properties", "@hash", "class", "hash", "eql?", "other", "$ret_or_1", "$ret_or_2", "each", "block in assign_properties", "name", "value", "block (2 levels) in assign_properties", "instance_variable_set", "protected", "private", "dup", "updated", "new_type", "new_children", "new_properties", "nil?", "copy", "original_dup", "send", "==", "equal?", "respond_to?", "to_ast", "concat", "array", "+", "append", "element", "to_sexp", "indent", "0", "indented", "*", "sexp", "fancy_type", "block in to_sexp", "child", "is_a?", "Node", "block (2 levels) in to_sexp", "1", "inspect", "block in inspect", "block (2 levels) in inspect", "to_sexp_array", "children_sexp_arrs", "map", "block in to_sexp_array", "block (2 levels) in to_sexp_array", "deconstruct", "to_s", "gsub"], :mappings=>"AAAAA,2BAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAqCEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MAGEC,IAAAC,aAAAA,CAAY,MAAZA;MAaAD,IAAAC,aAAAA,CAAY,UAAZA;MACA,aAAM,MAAN,EAAW,UAAX;MAIAD,IAAAC,aAAAA,CAAY,MAAZA;;AAWAC,MAAAA,0BAAAA,sBAAeC,IAAD,EAAOC,QAAP,EAAoBC,UAAlCH;AAAAA,QAAAA;;;QAAqB,iCAAS;QAAI,qCAAW,YAAA;QAC3C,KAAmB,CAAAC,IAAIG,QAAAA,CAAAA,CAAJ,EAAaF,QAAQG,MAAAA,CAAAA,CAAKC,QAAAA,CAAAA,CAA1B,CAAnB,EAAAC,CAAAA,YAAA,KAAAA,CAAA,EAAOC,CAAAA,gBAAP,KAAOA,CAAP;QAEAV,IAAAW,mBAAAA,CAAkBN,UAAlBM;QAEAC,YAAQ,CAACH,SAAD,EAAQC,aAAR,EAAmBV,IAAIa,OAAAA,CAAAA,CAAvB,CAA8BC,MAAAA,CAAAA;QAEtCZ,OAAAF,IAAAQ,QAAAA,CAAAA;MAPFN,CAAAA,IAAAA;;AAaAa,MAAAA,oBAAAA,0BAASC,KAATD;AAAAA,QAAAA;;QACE,IAAA,QAAAE,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAlB,IAAIa,OAAAA,CAAAA,CAAME,SAAAA,CAAMC,KAAKH,OAAAA,CAAAA,CAAXE,CAAVG,CAAA,CAAA,GAAA,CACAT,SAAKM,SAAAA,CAAMC,KAAKb,MAAAA,CAAAA,CAAXY,CADL,IAAA,CAAA,SAAA,CAAA,CAAAE,CAAA,CAAA;UAEAF,OAAAL,aAASK,SAAAA,CAAMC,KAAKZ,UAAAA,CAAAA,CAAXW;QAFT;UAAAA,OAAA;QAAA;MADFA,CAAAA;;AAaAJ,MAAAA,iCAAAA,6BAAsBN,UAAtBM;AAAAA,QAAAA;;;QACYQ,MAAVd,UAAUc,QAAAA,EAAAA,EAAAA,EAAVC,aAAoBC,IAAD,EAAOC,KAA1BF,EAAAG;;;UAAoB;UAAM;UACxBA,OAAAvB,IAAAwB,uBAAAA,CAAwBD,GAAF,GAAA,CAAKF,IAAL,CAAtB,EAAmCC,KAAnCE,EADFJ,CAAAA,GAAAA,SAAAA,CAAUD;QAIVR,OAAA;MALFA,CAAAA;MAOAX,IAAAyB,WAAAA,CAAU,mBAAVA;MAEA,aAAQ,cAAR,EAAsB,KAAtB;MACAzB,IAAA0B,SAAAA,CAAQ,cAARA;;AAOAC,MAAAA,mBAAAA,YAAAA;MAGA,aAAM,OAAN,EAAa,KAAb;;AAeAC,MAAAA,uBAAAA,mBAAYzB,IAAD,EAAWC,QAAX,EAAyBC,UAApCuB;AAAAA,QAAAA;;;QAAY,yBAAK;QAAK,iCAAS;QAAK,qCAAW;QAC7CC,WAAiB,CAAA,QAAAZ,CAAAA,YAAAd,IAAAc,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAcR,SAAd,CAAA;QACjBqB,eAAiB,CAAA,QAAAb,CAAAA,YAAAb,QAAAa,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAcP,aAAd,CAAA;QACjBqB,iBAAiB,CAAA,QAAAd,CAAAA,YAAAZ,UAAAY,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAc,YAAA,EAAd,CAAA;QAEjB,IAAG,CAAA,CAAA,MAAAR,SAAA,EAASoB,QAAT,CAAA,IAAA,CAAA,MACCnB,aADD,EACcoB,YADd,CAAA,CAAA,CAAA,IAAA,CAAA,QAECzB,UAAU2B,SAAAA,CAAAA,CAFX,CAAA,CAAA,CAAH;UAGEJ,OAAA5B;QAHF;;UAKEiC,OAAOjC,IAAAkC,cAAAA,CAAAA;UACPD,IAAIE,MAAAA,CAAM,YAAV,EAAuBN,QAAvB,EAAiCC,YAAjC,EAA+CC,cAA3CI;UACJP,OAAAK;QAPF;MALFL,CAAAA,IAAAA;;AAoBAQ,MAAAA,kBAAAA,wBAAOpB,KAAPoB;AAAAA,QAAAA;;QACE,IAAA,QAAGpC,IAAAqC,WAAAA,CAAOrB,KAAPqB,CAAH,CAAA;UACED,OAAA;QADF,OAEA,IAAA,QAAMpB,KAAKsB,gBAAAA,CAAa,QAAbA,CAAX,CAAA;;UACEtB,QAAQA,KAAKuB,QAAAA,CAAAA;UACb,IAAA,QAAAtB,CAAAA,YAAAD,KAAKb,MAAAA,CAAAA,CAAMiC,OAAAA,CAAGpC,IAAIG,MAAAA,CAAAA,CAAPiC,CAAXnB,CAAA,CAAA;YACEmB,OAAApB,KAAKZ,UAAAA,CAAAA,CAAUgC,OAAAA,CAAGpC,IAAII,UAAAA,CAAAA,CAAPgC;UADjB;YAAAA,OAAA;UAAA;QAFF;UAKEA,OAAA;QALF;MAHFA,CAAAA;;AAeAI,MAAAA,sBAAAA,kBAAWC,KAAXD;AAAAA,QAAAA;;QACEA,OAAAxC,IAAA4B,SAAAA,CAAQ,GAAR,EAAuBc,SAAVhC,aAAUgC,EAAED,KAAKlC,MAAAA,CAAAA,CAAPmC,CAAvBd;MADFY,CAAAA;MAIA,aAAM,GAAN,EAAQ,QAAR;;AAKAG,MAAAA,sBAAAA,kBAAWC,OAAXD;AAAAA,QAAAA;;QACEA,OAAA3C,IAAA4B,SAAAA,CAAQ,GAAR,EAAuBc,SAAVhC,aAAUgC,EAAE,CAACE,OAAD,CAAFF,CAAvBd;MADFe,CAAAA;MAIA,aAAM,IAAN,EAAS,QAAT;;AAMAE,MAAAA,uBAAAA,mBAAYC,MAAZD;AAAAA,QAAAA;;;QAAY,6BAAOE;QACjBC,WAAgBC,UAALJ,IAAKI,EAAEH,MAAFG;QAChBC,OAAO,EAAA,GAAA,CAAGF,QAAH,CAAA,GAAYH,GAAZ,GAAA,CAAe7C,IAAAmD,YAAAA,CAAAA,CAAf;QAEChC,MAARnB,IAAAI,UAAAA,CAAAA,CAAQe,QAAAA,EAAAA,EAAAA,EAARiC,aAAkBC,KAAlBD;;UAAkB;UAChB,IAAA,QAAGC,KAAKC,UAAAA,CAAOC,UAAPD,CAAR,CAAA;YACEE,OAAAN,CAAAA,OAAKR,SAALQ,IAAKR,EAAIc,IAAD,GAAA,CAAKH,KAAKR,SAAAA,CAAgBH,SAAPI,MAAOJ,EAAEe,CAAFf,CAAhBG,CAAV,CAAHH,CAALQ;UADF;YAGEM,OAAAN,CAAAA,OAAKR,SAALQ,IAAKR,EAAIc,GAAD,GAAA,CAAIH,KAAKK,SAAAA,CAAAA,CAAT,CAAHhB,CAALQ;UAHF,EADFE,CAAQjC;QAQR+B,OAAKR,SAALQ,IAAKR,EAAGG,GAAHH;QAELG,OAAAK;MAdFL,CAAAA,IAAAA;MAiBA,aAAM,MAAN,EAAW,SAAX;;AAOAa,MAAAA,uBAAAA,mBAAYZ,MAAZY;AAAAA,QAAAA;;;QAAY,6BAAOX;QACjBC,WAAgBC,UAALS,IAAKT,EAAEH,MAAFG;QAChBC,OAAO,EAAA,GAAA,CAAGF,QAAH,CAAA,GAAYU,KAAZ,GAAA,CAAiBjD,SAAjB;QAECU,MAARnB,IAAAI,UAAAA,CAAAA,CAAQe,QAAAA,EAAAA,EAAAA,EAARwC,aAAkBN,KAAlBM;;UAAkB;UAChB,IAAA,QAAGN,KAAKC,UAAAA,CAAOC,UAAPD,CAAR,CAAA;YACEM,OAAAV,CAAAA,OAAKR,SAALQ,IAAKR,EAAIkB,KAAD,GAAA,CAAMP,KAAKK,SAAAA,CAAgBhB,SAAPI,MAAOJ,EAAEe,CAAFf,CAAhBgB,CAAX,CAAHhB,CAALQ;UADF;YAGEU,OAAAV,CAAAA,OAAKR,SAALQ,IAAKR,EAAIkB,IAAD,GAAA,CAAKP,KAAKK,SAAAA,CAAAA,CAAV,CAAHhB,CAALQ;UAHF,EADFS,CAAQxC;QAQR+B,OAAKR,SAALQ,IAAKR,EAAGgB,GAAHhB;QAELgB,OAAAR;MAdFQ,CAAAA,IAAAA;;AAkBAnB,MAAAA,sBAAAA,YAAAA;;AAQAsB,MAAAA,6BAAAA,yBAAAA;AAAAA,QAAAA;;;QACEC,qBAA6BC,MAAR/D,IAAAI,UAAAA,CAAAA,CAAQ2D,OAAAA,EAAAA,EAAAA,EAARC,aAAiBX,KAAjBW;;UAAiB;UACpC,IAAA,QAAGX,KAAKC,UAAAA,CAAOC,UAAPD,CAAR,CAAA;YACEW,OAAAZ,KAAKQ,eAAAA,CAAAA;UADP;YAGEI,OAAAZ;UAHF,EADmBW,CAAQD;QAQ7BF,OAAA,CAAC7D,IAAAG,MAAAA,CAAAA,CAAD,CAAA,QAAO,MAAC2D,kBAAD,CAAP;MATFD,CAAAA;;AAgBAK,MAAAA,2BAAAA,uBAAAA;AAAAA,QAAAA;;QACEA,OAAA,CAAClE,IAAAG,MAAAA,CAAAA,CAAD,CAAA,QAAO,MAACH,IAAAI,UAAAA,CAAAA,CAAD,CAAP;MADF8D,CAAAA;MAIAlE,IAAAyB,WAAAA,CAAAA;MAOA1B,OAAAoD,0BAAAA,sBAAAA;AAAAA,QAAAA;;QACEA,OAAA1C,SAAK0D,MAAAA,CAAAA,CAAKC,MAAAA,CAAMjB,GAAhB,EAAqBA,GAAXiB;MADZjB,CAAAA;IAhOFpD,GAAAA,WAAAA,EAAAA,IAAAA;EArCFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>1215, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["ast/processor/mixin.rb"], :sourcesContent=>["module AST\n  class Processor\n    # The processor module is a module which helps transforming one\n    # AST into another.  In a nutshell, the {#process} method accepts\n    # a {Node} and dispatches it to a handler corresponding to its\n    # type, and returns a (possibly) updated variant of the node.\n    #\n    # The processor module has a set of associated design patterns.\n    # They are best explained with a concrete example. Let's define a\n    # simple arithmetic language and an AST format for it:\n    #\n    # Terminals (AST nodes which do not have other AST nodes inside):\n    #\n    #   * `(integer <int-literal>)`,\n    #\n    # Nonterminals (AST nodes with other nodes as children):\n    #\n    #   * `(add <node> <node>)`,\n    #   * `(multiply <node> <node>)`,\n    #   * `(divide <node> <node>)`,\n    #   * `(negate <node>)`,\n    #   * `(store <node> <string-literal>)`: stores value of `<node>`\n    #     into a variable named `<string-literal>`,\n    #   * `(load <string-literal>)`: loads value of a variable named\n    #     `<string-literal>`,\n    #   * `(each <node> ...)`: computes each of the `<node>`s and\n    #     prints the result.\n    #\n    # All AST nodes have the same Ruby class, and therefore they don't\n    # know how to traverse themselves. (A solution which dynamically\n    # checks the type of children is possible, but is slow and\n    # error-prone.) So, a class including the module which knows how\n    # to traverse the entire tree should be defined.  Such classes\n    # have a handler for each nonterminal node which recursively\n    # processes children nodes:\n    #\n    #     require 'ast'\n    #\n    #     class ArithmeticsProcessor\n    #       include AST::Processor::Mixin\n    #       # This method traverses any binary operators such as (add)\n    #       # or (multiply).\n    #       def process_binary_op(node)\n    #         # Children aren't decomposed automatically; it is\n    #         # suggested to use Ruby multiple assignment expansion,\n    #         # as it is very convenient here.\n    #         left_expr, right_expr = *node\n    #\n    #         # AST::Node#updated won't change node type if nil is\n    #         # passed as a first argument, which allows to reuse the\n    #         # same handler for multiple node types using `alias'\n    #         # (below).\n    #         node.updated(nil, [\n    #           process(left_expr),\n    #           process(right_expr)\n    #         ])\n    #       end\n    #       alias_method :on_add,      :process_binary_op\n    #       alias_method :on_multiply, :process_binary_op\n    #       alias_method :on_divide,   :process_binary_op\n    #\n    #       def on_negate(node)\n    #         # It is also possible to use #process_all for more\n    #         # compact code if every child is a Node.\n    #         node.updated(nil, process_all(node))\n    #       end\n    #\n    #       def on_store(node)\n    #         expr, variable_name = *node\n    #\n    #         # Note that variable_name is not a Node and thus isn't\n    #         # passed to #process.\n    #         node.updated(nil, [\n    #           process(expr),\n    #           variable_name\n    #         ])\n    #       end\n    #\n    #       # (load) is effectively a terminal node, and so it does\n    #       # not need an explicit handler, as the following is the\n    #       # default behavior.  Essentially, for any nodes that don't\n    #       # have a defined handler, the node remains unchanged.\n    #       def on_load(node)\n    #         nil\n    #       end\n    #\n    #       def on_each(node)\n    #         node.updated(nil, process_all(node))\n    #       end\n    #     end\n    #\n    # Let's test our ArithmeticsProcessor:\n    #\n    #     include AST::Sexp\n    #     expr = s(:add, s(:integer, 2), s(:integer, 2))\n    #\n    #     p ArithmeticsProcessor.new.process(expr) == expr # => true\n    #\n    # As expected, it does not change anything at all. This isn't\n    # actually very useful, so let's now define a Calculator, which\n    # will compute the expression values:\n    #\n    #     # This Processor folds nonterminal nodes and returns an\n    #     # (integer) terminal node.\n    #     class ArithmeticsCalculator < ArithmeticsProcessor\n    #       def compute_op(node)\n    #         # First, node children are processed and then unpacked\n    #         # to local variables.\n    #         nodes = process_all(node)\n    #\n    #         if nodes.all? { |node| node.type == :integer }\n    #           # If each of those nodes represents a literal, we can\n    #           # fold this node!\n    #           values = nodes.map { |node| node.children.first }\n    #           AST::Node.new(:integer, [\n    #             yield(values)\n    #           ])\n    #         else\n    #           # Otherwise, we can just leave the current node in the\n    #           # tree and only update it with processed children\n    #           # nodes, which can be partially folded.\n    #           node.updated(nil, nodes)\n    #         end\n    #       end\n    #\n    #       def on_add(node)\n    #         compute_op(node) { |left, right| left + right }\n    #       end\n    #\n    #       def on_multiply(node)\n    #         compute_op(node) { |left, right| left * right }\n    #       end\n    #     end\n    #\n    # Let's check:\n    #\n    #     p ArithmeticsCalculator.new.process(expr) # => (integer 4)\n    #\n    # Excellent, the calculator works! Now, a careful reader could\n    # notice that the ArithmeticsCalculator does not know how to\n    # divide numbers. What if we pass an expression with division to\n    # it?\n    #\n    #     expr_with_division = \\\n    #       s(:add,\n    #         s(:integer, 1),\n    #         s(:divide,\n    #           s(:add, s(:integer, 8), s(:integer, 4)),\n    #           s(:integer, 3))) # 1 + (8 + 4) / 3\n    #\n    #     folded_expr_with_division = ArithmeticsCalculator.new.process(expr_with_division)\n    #     p folded_expr_with_division\n    #     # => (add\n    #     #      (integer 1)\n    #     #      (divide\n    #     #        (integer 12)\n    #     #        (integer 3)))\n    #\n    # As you can see, the expression was folded _partially_: the inner\n    # `(add)` node which could be computed was folded to\n    # `(integer 12)`, the `(divide)` node is left as-is because there\n    # is no computing handler for it, and the root `(add)` node was\n    # also left as it is because some of its children were not\n    # literals.\n    #\n    # Note that this partial folding is only possible because the\n    # _data_ format, i.e. the format in which the computed values of\n    # the nodes are represented, is the same as the AST itself.\n    #\n    # Let's extend our ArithmeticsCalculator class further.\n    #\n    #     class ArithmeticsCalculator\n    #       def on_divide(node)\n    #         compute_op(node) { |left, right| left / right }\n    #       end\n    #\n    #       def on_negate(node)\n    #         # Note how #compute_op works regardless of the operator\n    #         # arity.\n    #         compute_op(node) { |value| -value }\n    #       end\n    #     end\n    #\n    # Now, let's apply our renewed ArithmeticsCalculator to a partial\n    # result of previous evaluation:\n    #\n    #     p ArithmeticsCalculator.new.process(expr_with_division) # => (integer 5)\n    #\n    # Five! Excellent. This is also pretty much how CRuby 1.8 executed\n    # its programs.\n    #\n    # Now, let's do some automated bug searching. Division by zero is\n    # an error, right? So if we could detect that someone has divided\n    # by zero before the program is even run, that could save some\n    # debugging time.\n    #\n    #     class DivisionByZeroVerifier < ArithmeticsProcessor\n    #       class VerificationFailure < Exception; end\n    #\n    #       def on_divide(node)\n    #         # You need to process the children to handle nested divisions\n    #         # such as:\n    #         # (divide\n    #         #   (integer 1)\n    #         #   (divide (integer 1) (integer 0))\n    #         left, right = process_all(node)\n    #\n    #         if right.type == :integer &&\n    #            right.children.first == 0\n    #           raise VerificationFailure, \"Ouch! This code divides by zero.\"\n    #         end\n    #       end\n    #\n    #       def divides_by_zero?(ast)\n    #         process(ast)\n    #         false\n    #       rescue VerificationFailure\n    #         true\n    #       end\n    #     end\n    #\n    #     nice_expr = \\\n    #       s(:divide,\n    #         s(:add, s(:integer, 10), s(:integer, 2)),\n    #         s(:integer, 4))\n    #\n    #     p DivisionByZeroVerifier.new.divides_by_zero?(nice_expr)\n    #     # => false. Good.\n    #\n    #     bad_expr = \\\n    #       s(:add, s(:integer, 10),\n    #         s(:divide, s(:integer, 1), s(:integer, 0)))\n    #\n    #     p DivisionByZeroVerifier.new.divides_by_zero?(bad_expr)\n    #     # => true. WHOOPS. DO NOT RUN THIS.\n    #\n    # Of course, this won't detect more complex cases... unless you\n    # use some partial evaluation before! The possibilites are\n    # endless. Have fun.\n    module Mixin\n      # Dispatches `node`. If a node has type `:foo`, then a handler\n      # named `on_foo` is invoked with one argument, the `node`; if\n      # there isn't such a handler, {#handler_missing} is invoked\n      # with the same argument.\n      #\n      # If the handler returns `nil`, `node` is returned; otherwise,\n      # the return value of the handler is passed along.\n      #\n      # @param  [AST::Node, nil] node\n      # @return [AST::Node, nil]\n      def process(node)\n        return if node.nil?\n\n        node = node.to_ast\n\n        # Invoke a specific handler\n        on_handler = :\"on_\#{node.type}\"\n        if respond_to? on_handler\n          new_node = send on_handler, node\n        else\n          new_node = handler_missing(node)\n        end\n\n        node = new_node if new_node\n\n        node\n      end\n\n      # {#process}es each node from `nodes` and returns an array of\n      # results.\n      #\n      # @param  [Array<AST::Node>] nodes\n      # @return [Array<AST::Node>]\n      def process_all(nodes)\n        nodes.to_a.map do |node|\n          process node\n        end\n      end\n\n      # Default handler. Does nothing.\n      #\n      # @param  [AST::Node] node\n      # @return [AST::Node, nil]\n      def handler_missing(node)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:AST>", "<class:Processor>", "<module:Mixin>", "process", "node", "nil?", "to_ast", "on_handler", "type", "self", "respond_to?", "new_node", "send", "handler_missing", "process_all", "nodes", "map", "to_a", "block in process_all", "block (2 levels) in process_all"], :mappings=>"AAAAA,sCAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MA8OEA,OAAAC;MAAAA;;;;;AAWEC,QAAAA,uBAAAA,mBAAYC,IAAZD;AAAAA,UAAAA;;;UACE,IAAA,QAAUC,IAAIC,SAAAA,CAAAA,CAAd,CAAA;YAAA,OAAA;UAAA;UAEAD,OAAOA,IAAIE,QAAAA,CAAAA;UAGXC,aAAeJ,KAAF,GAAA,CAAOC,IAAII,MAAAA,CAAAA,CAAX;UACb,IAAA,QAAGC,IAAAC,gBAAAA,CAAYH,UAAZG,CAAH,CAAA;YACEC,WAAWF,IAAAG,MAAAA,CAAKL,UAAL,EAAiBH,IAAjBQ;UADb;YAGED,WAAWF,IAAAI,iBAAAA,CAAgBT,IAAhBS;UAHb;UAMA,IAAA,QAAmBF,QAAnB,CAAA;YAAAP,OAAOO;UAAP;UAEAR,OAAAC;QAfFD,CAAAA;;AAuBAW,QAAAA,2BAAAA,uBAAgBC,KAAhBD;AAAAA,UAAAA;;UACEA,OAAUE,MAAVD,KAAKE,MAAAA,CAAAA,CAAKD,OAAAA,EAAAA,EAAAA,EAAVE,aAAmBd,IAAnBc,EAAAC;;;YAAmB;YACjBA,OAAAV,IAAAN,SAAAA,CAAQC,IAARD,EADFe,CAAAA,GAAAA,SAAAA,CAAUF;QADZF,CAAAA;QAUAZ,OAAAW,+BAAAA,YA3RN,GA2RMA,CAAAA;MA5CFX,GAAAA,WAAAA;IA9OFD,GAAAA,WAAAA,EAAAA,IAAAA;EADFD,GAAAA,WAAAA;AAAAD;"}}, {:offset=>{:line=>1269, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["ast/processor.rb"], :sourcesContent=>["module AST\n  # This class includes {AST::Processor::Mixin}; however, it is\n  # deprecated, since the module defines all of the behaviors that\n  # the processor includes.  Any new libraries should use\n  # {AST::Processor::Mixin} instead of subclassing this.\n  #\n  # @deprecated Use {AST::Processor::Mixin} instead.\n  class Processor\n    require 'ast/processor/mixin'\n    include Mixin\n  end\nend\n"], :names=>["<top (required)>", "<module:AST>", "<class:Processor>", "self", "require", "include", "Mixin"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;IAOEA,OAAAC;IAAAA;;MAAAA;;;MACEC,IAAAC,SAAAA,CAAQF,qBAARE;MACAF,OAAAC,IAAAE,SAAAA,CAAQC,WAARD;IAFFH,GAAAA,WAAAA,EAAAA,IAAAA;EAPFD,GAAAA,WAAAA;AAAAD;"}}, {:offset=>{:line=>1289, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["ast/sexp.rb"], :sourcesContent=>["module AST\n  # This simple module is very useful in the cases where one needs\n  # to define deeply nested ASTs from Ruby code, for example, in\n  # tests. It should be used like this:\n  #\n  #     describe YourLanguage::AST do\n  #       include Sexp\n  #\n  #       it \"should correctly parse expressions\" do\n  #         YourLanguage.parse(\"1 + 2 * 3\").should ==\n  #             s(:add,\n  #               s(:integer, 1),\n  #               s(:multiply,\n  #                 s(:integer, 2),\n  #                 s(:integer, 3)))\n  #       end\n  #     end\n  #\n  # This way the amount of boilerplate code is greatly reduced.\n  module Sexp\n    # Creates a {Node} with type `type` and children `children`.\n    # Note that the resulting node is of the type AST::Node and not a\n    # subclass.\n    # This would not pose a problem with comparisons, as {Node#==}\n    # ignores metadata.\n    def s(type, *children)\n      Node.new(type, children)\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:AST>", "<module:Sexp>", "s", "type", "Node", "new", "children"], :mappings=>"AAAAA,2BAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;IAmBEA,OAAAC;IAAAA;;MAAAA;;MAMEA,OAAAC,iBAAAA,aAAMC,IAAD,EAzBT,EAyBID;AAAAA,QAAAA;;;QAzBJ;QAyBgB;QACVA,OAAAE,UAAIC,KAAAA,CAAKF,IAAT,EAAeG,QAAXD;MADNH,CAAAA,IAAAA;IANFD,GAAAA,WAAAA;EAnBFD,GAAAA,WAAAA;AAAAD;"}}, {:offset=>{:line=>1314, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./ast.rb"], :sourcesContent=>["# {AST} is a library for manipulating abstract syntax trees.\n#\n# It embraces immutability; each AST node is inherently frozen at\n# creation, and updating a child node requires recreating that node\n# and its every parent, recursively.\n# This is a design choice. It does create some pressure on\n# garbage collector, but completely eliminates all concurrency\n# and aliasing problems.\n#\n# See also {AST::Node}, {AST::Processor::Mixin} and {AST::Sexp} for\n# additional recommendations and design patterns.\n#\nmodule AST\n  require 'ast/node'\n  require 'ast/processor'\n  require 'ast/sexp'\nend\n"], :names=>["<top (required)>", "<module:AST>", "self", "require"], :mappings=>"AAAAA,sBAAAA,gBAAAA;EAAAA;;EAYAA,OAAAC;EAAAA;;;;IACEC,IAAAC,SAAAA,CAAQF,UAARE;IACAD,IAAAC,SAAAA,CAAQF,eAARE;IACAF,OAAAC,IAAAC,SAAAA,CAAQF,UAARE;EAHFF,GAAAA,WAAAA;AAZAD;"}}, {:offset=>{:line=>1328, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/ast/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  module AST\n\n    ##\n    # {Parser::AST::Node} contains information about a single AST node and its\n    # child nodes. It extends the basic [AST::Node](https://www.rubydoc.info/gems/ast/AST/Node)\n    # class provided by gem [ast](https://www.rubydoc.info/gems/ast).\n    #\n    # @api public\n    #\n    # @!attribute [r] location\n    #  Source map for this Node.\n    #  @return [Parser::Source::Map]\n    #\n    class Node < ::AST::Node\n      attr_reader :location\n\n      alias loc location\n\n      ##\n      # Assigns various properties to this AST node. Currently only the\n      # location can be set.\n      #\n      # @param [Hash] properties\n      # @option properties [Parser::Source::Map] :location Location information\n      #  of the node.\n      #\n      def assign_properties(properties)\n        if (location = properties[:location])\n          location = location.dup if location.frozen?\n          location.node = self\n          @location = location\n        end\n      end\n    end\n\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<module:AST>", "<class:Node>", "self", "attr_reader", "assign_properties", "properties", "location", "[]", "frozen?", "dup", "node=", "@location", "AST::Node", "AST"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAaEA,OAAAC;MAAAA;;;;QACEC,IAAAC,aAAAA,CAAY,UAAZA;QAEA,aAAM,KAAN,EAAU,UAAV;QAUAF,OAAAG,iCAAAA,6BAAsBC,UAAtBD;AAAAA,UAAAA;;UACE,IAAA,QAAIE,CAAAA,WAAWD,UAAUE,OAAAA,CAAC,UAADA,CAArBD,CAAJ,CAAA;;YACE,IAAA,QAA2BA,QAAQE,YAAAA,CAAAA,CAAnC,CAAA;cAAAF,WAAWA,QAAQG,KAAAA,CAAAA;YAAnB;YACAH,QAAQI,UAAAA,CAAQR,IAARQ;YACRN,OAAAO,CAAAA,gBAAYL,QAAZK;UAHF;YA9BRP,OAAA;UA8BQ;QADFA,CAAAA;MAbFH,GAAAA,WAAAA,EAAaW,IAAAC,UAAAD,SAAbX;IAbFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>1367, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/ast/node.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'ast'\nrequire 'parser/ast/node'\n\nmodule Opal\n  module AST\n    class Node < ::Parser::AST::Node\n      attr_reader :meta\n\n      def assign_properties(properties)\n        if meta = properties[:meta]\n          meta = meta.dup if meta.frozen?\n          @meta.merge!(meta)\n        else\n          @meta ||= {}\n        end\n\n        super\n      end\n\n      def line\n        loc.line if loc\n      end\n\n      def column\n        loc.column if loc\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:AST>", "<class:Node>", "attr_reader", "assign_properties", "properties", "meta", "[]", "frozen?", "dup", "@meta", "merge!", "$ret_or_1", "line", "loc", "column", "Parser::AST::Node", "Parser::AST", "Parser"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,KAARE;EACAD,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEJ,IAAAK,aAAAA,CAAY,MAAZA;;AAEAC,QAAAA,iCAAAA,6BAAsBC,UAAtBD;AAAAA,UAAAA;;UAAAA;;UACE,IAAA,QAAGE,CAAAA,OAAOD,UAAUE,OAAAA,CAAC,MAADA,CAAjBD,CAAH,CAAA;;YACE,IAAA,QAAmBA,IAAIE,YAAAA,CAAAA,CAAvB,CAAA;cAAAF,OAAOA,IAAIG,KAAAA,CAAAA;YAAX;YACAC,SAAKC,WAAAA,CAAQL,IAARK;UAFP;YAIED,YAfV,CAAA,QAAAE,CAAAA,YAeUF,SAfVE,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAeoB,YAAA,EAfpB,CAAA;UAWQ;UAOAR,OAAA,OAAAN,IAAA,EAAA,wEAAA,qBAAA,EAAA,CAAAO,UAAA,CAAA,EAAA,MAAA;QARFD,CAAAA;;AAWAS,QAAAA,oBAAAA,gBAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAYf,IAAAgB,KAAAA,CAAAA,CAAZ,CAAA;YAAAD,OAAAf,IAAAgB,KAAAA,CAAAA,CAAGD,MAAAA,CAAAA;UAAH;YAtBRA,OAAA;UAsBQ;QADFA,CAAAA;QAIAX,OAAAa,sBAAAA,kBAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAcjB,IAAAgB,KAAAA,CAAAA,CAAd,CAAA;YAAAC,OAAAjB,IAAAgB,KAAAA,CAAAA,CAAGC,QAAAA,CAAAA;UAAH;YA1BRA,OAAA;UA0BQ;QADFA,CAAAA;MAlBFb,GAAAA,WAAAA,EAAac,IAAAC,IAAAC,aAAAD,QAAAD,SAAbd;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>1432, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["racc/parser.rb"], :sourcesContent=>["# Opal port of racc/parser.rb.\n#\n# Original license:\n#\n# frozen_string_literal: false\n#--\n# $originalId: parser.rb,v 1.8 2006/07/06 11:42:07 aamine Exp $\n#\n# Copyright (c) 1999-2006 Minero Aoki\n#\n# This program is free software.\n# You can distribute/modify this program under the same terms of ruby.\n#\n# As a special exception, when this code is copied by Racc\n# into a Racc output file, you may use that output file\n# without restriction.\n#++\n\nmodule Racc\n  class ParseError < StandardError; end\nend\nunless defined?(::ParseError)\n  ParseError = Racc::ParseError\nend\n\n# Racc is a LALR(1) parser generator.\n# It is written in Ruby itself, and generates Ruby programs.\n#\n# == Command-line Reference\n#\n#     racc [-o<var>filename</var>] [--output-file=<var>filename</var>]\n#          [-e<var>rubypath</var>] [--embedded=<var>rubypath</var>]\n#          [-v] [--verbose]\n#          [-O<var>filename</var>] [--log-file=<var>filename</var>]\n#          [-g] [--debug]\n#          [-E] [--embedded]\n#          [-l] [--no-line-convert]\n#          [-c] [--line-convert-all]\n#          [-a] [--no-omit-actions]\n#          [-C] [--check-only]\n#          [-S] [--output-status]\n#          [--version] [--copyright] [--help] <var>grammarfile</var>\n#\n# [+filename+]\n#   Racc grammar file. Any extension is permitted.\n# [-o+outfile+, --output-file=+outfile+]\n#   A filename for output. default is <+filename+>.tab.rb\n# [-O+filename+, --log-file=+filename+]\n#   Place logging output in file +filename+.\n#   Default log file name is <+filename+>.output.\n# [-e+rubypath+, --executable=+rubypath+]\n#   output executable file(mode 755). where +path+ is the Ruby interpreter.\n# [-v, --verbose]\n#   verbose mode. create +filename+.output file, like yacc's y.output file.\n# [-g, --debug]\n#   add debug code to parser class. To display debugging information,\n#   use this '-g' option and set @yydebug true in parser class.\n# [-E, --embedded]\n#   Output parser which doesn't need runtime files (racc/parser.rb).\n# [-C, --check-only]\n#   Check syntax of racc grammar file and quit.\n# [-S, --output-status]\n#   Print messages time to time while compiling.\n# [-l, --no-line-convert]\n#   turns off line number converting.\n# [-c, --line-convert-all]\n#   Convert line number of actions, inner, header and footer.\n# [-a, --no-omit-actions]\n#   Call all actions, even if an action is empty.\n# [--version]\n#   print Racc version and quit.\n# [--copyright]\n#   Print copyright and quit.\n# [--help]\n#   Print usage and quit.\n#\n# == Generating Parser Using Racc\n#\n# To compile Racc grammar file, simply type:\n#\n#   $ racc parse.y\n#\n# This creates Ruby script file \"parse.tab.y\". The -o option can change the output filename.\n#\n# == Writing A Racc Grammar File\n#\n# If you want your own parser, you have to write a grammar file.\n# A grammar file contains the name of your parser class, grammar for the parser,\n# user code, and anything else.\n# When writing a grammar file, yacc's knowledge is helpful.\n# If you have not used yacc before, Racc is not too difficult.\n#\n# Here's an example Racc grammar file.\n#\n#   class Calcparser\n#   rule\n#     target: exp { print val[0] }\n#\n#     exp: exp '+' exp\n#        | exp '*' exp\n#        | '(' exp ')'\n#        | NUMBER\n#   end\n#\n# Racc grammar files resemble yacc files.\n# But (of course), this is Ruby code.\n# yacc's $$ is the 'result', $0, $1... is\n# an array called 'val', and $-1, $-2... is an array called '_values'.\n#\n# See the {Grammar File Reference}[rdoc-ref:lib/racc/rdoc/grammar.en.rdoc] for\n# more information on grammar files.\n#\n# == Parser\n#\n# Then you must prepare the parse entry method. There are two types of\n# parse methods in Racc, Racc::Parser#do_parse and Racc::Parser#yyparse\n#\n# Racc::Parser#do_parse is simple.\n#\n# It's yyparse() of yacc, and Racc::Parser#next_token is yylex().\n# This method must returns an array like [TOKENSYMBOL, ITS_VALUE].\n# EOF is [false, false].\n# (TOKENSYMBOL is a Ruby symbol (taken from String#intern) by default.\n# If you want to change this, see the grammar reference.\n#\n# Racc::Parser#yyparse is little complicated, but useful.\n# It does not use Racc::Parser#next_token, instead it gets tokens from any iterator.\n#\n# For example, <code>yyparse(obj, :scan)</code> causes\n# calling +obj#scan+, and you can return tokens by yielding them from +obj#scan+.\n#\n# == Debugging\n#\n# When debugging, \"-v\" or/and the \"-g\" option is helpful.\n#\n# \"-v\" creates verbose log file (.output).\n# \"-g\" creates a \"Verbose Parser\".\n# Verbose Parser prints the internal status when parsing.\n# But it's _not_ automatic.\n# You must use -g option and set +@yydebug+ to +true+ in order to get output.\n# -g option only creates the verbose parser.\n#\n# === Racc reported syntax error.\n#\n# Isn't there too many \"end\"?\n# grammar of racc file is changed in v0.10.\n#\n# Racc does not use '%' mark, while yacc uses huge number of '%' marks..\n#\n# === Racc reported \"XXXX conflicts\".\n#\n# Try \"racc -v xxxx.y\".\n# It causes producing racc's internal log file, xxxx.output.\n#\n# === Generated parsers does not work correctly\n#\n# Try \"racc -g xxxx.y\".\n# This command let racc generate \"debugging parser\".\n# Then set @yydebug=true in your parser.\n# It produces a working log of your parser.\n#\n# == Re-distributing Racc runtime\n#\n# A parser, which is created by Racc, requires the Racc runtime module;\n# racc/parser.rb.\n#\n# Ruby 1.8.x comes with Racc runtime module,\n# you need NOT distribute Racc runtime files.\n#\n# If you want to include the Racc runtime module with your parser.\n# This can be done by using '-E' option:\n#\n#   $ racc -E -omyparser.rb myparser.y\n#\n# This command creates myparser.rb which `includes' Racc runtime.\n# Only you must do is to distribute your parser file (myparser.rb).\n#\n# Note: parser.rb is LGPL, but your parser is not.\n# Your own parser is completely yours.\nmodule Racc\n\n  unless defined?(Racc_No_Extensions)\n    Racc_No_Extensions = false # :nodoc:\n  end\n\n  class Parser\n\n    Racc_Runtime_Version = '1.4.6'\n    Racc_Runtime_Revision = %w$originalRevision: 1.8 $[1]\n\n    Racc_Runtime_Core_Version_R = '1.4.6'\n    Racc_Runtime_Core_Revision_R = %w$originalRevision: 1.8 $[1]\n    # DISABLED: opal has no racc/cparse\n    # begin\n    #   require 'racc/cparse'\n    # # Racc_Runtime_Core_Version_C  = (defined in extension)\n    #   Racc_Runtime_Core_Revision_C = Racc_Runtime_Core_Id_C.split[2]\n    #   unless new.respond_to?(:_racc_do_parse_c, true)\n    #     raise LoadError, 'old cparse.so'\n    #   end\n    #   if Racc_No_Extensions\n    #     raise LoadError, 'selecting ruby version of racc runtime core'\n    #   end\n    #\n    #   Racc_Main_Parsing_Routine    = :_racc_do_parse_c # :nodoc:\n    #   Racc_YY_Parse_Method         = :_racc_yyparse_c # :nodoc:\n    #   Racc_Runtime_Core_Version    = Racc_Runtime_Core_Version_C # :nodoc:\n    #   Racc_Runtime_Core_Revision   = Racc_Runtime_Core_Revision_C # :nodoc:\n    #   Racc_Runtime_Type            = 'c' # :nodoc:\n    # rescue LoadError\n      Racc_Main_Parsing_Routine    = :_racc_do_parse_rb\n      Racc_YY_Parse_Method         = :_racc_yyparse_rb\n      Racc_Runtime_Core_Version    = Racc_Runtime_Core_Version_R\n      Racc_Runtime_Core_Revision   = Racc_Runtime_Core_Revision_R\n      Racc_Runtime_Type            = 'ruby'\n    # end\n\n    def Parser.racc_runtime_type # :nodoc:\n      Racc_Runtime_Type\n    end\n\n    def _racc_setup\n      @yydebug = false unless self.class::Racc_debug_parser\n      @yydebug = false unless defined?(@yydebug)\n      if @yydebug\n        @racc_debug_out = $stderr unless defined?(@racc_debug_out)\n        @racc_debug_out ||= $stderr\n      end\n      arg = self.class::Racc_arg\n      arg[13] = true if arg.size < 14\n      arg\n    end\n\n    def _racc_init_sysvars\n      @racc_state  = [0]\n      @racc_tstack = []\n      @racc_vstack = []\n\n      @racc_t = nil\n      @racc_val = nil\n\n      @racc_read_next = true\n\n      @racc_user_yyerror = false\n      @racc_error_status = 0\n    end\n\n    # The entry point of the parser. This method is used with #next_token.\n    # If Racc wants to get token (and its value), calls next_token.\n    #\n    # Example:\n    #     def parse\n    #       @q = [[1,1],\n    #             [2,2],\n    #             [3,3],\n    #             [false, '$']]\n    #       do_parse\n    #     end\n    #\n    #     def next_token\n    #       @q.shift\n    #     end\n    def do_parse\n      __send__(Racc_Main_Parsing_Routine, _racc_setup(), false)\n    end\n\n    # The method to fetch next token.\n    # If you use #do_parse method, you must implement #next_token.\n    #\n    # The format of return value is [TOKEN_SYMBOL, VALUE].\n    # +token-symbol+ is represented by Ruby's symbol by default, e.g. :IDENT\n    # for 'IDENT'.  \";\" (String) for ';'.\n    #\n    # The final symbol (End of file) must be false.\n    def next_token\n      raise NotImplementedError, \"\#{self.class}\\#next_token is not defined\"\n    end\n\n    def _racc_do_parse_rb(arg, in_debug)\n      action_table, action_check, action_default, action_pointer,\n      _,            _,            _,              _,\n      _,            _,            token_table,    _,\n      _,            _,            * = arg\n\n      _racc_init_sysvars\n      tok = act = i = nil\n\n      catch(:racc_end_parse) {\n        while true\n          if i = action_pointer[@racc_state[-1]]\n            if @racc_read_next\n              if @racc_t != 0   # not EOF\n                tok, @racc_val = next_token()\n                unless tok      # EOF\n                  @racc_t = 0\n                else\n                  @racc_t = (token_table[tok] or 1)   # error token\n                end\n                racc_read_token(@racc_t, tok, @racc_val) if @yydebug\n                @racc_read_next = false\n              end\n            end\n            i += @racc_t\n            unless i >= 0 and\n                   act = action_table[i] and\n                   action_check[i] == @racc_state[-1]\n              act = action_default[@racc_state[-1]]\n            end\n          else\n            act = action_default[@racc_state[-1]]\n          end\n          while act = _racc_evalact(act, arg)\n            ;\n          end\n        end\n      }\n    end\n\n    # Another entry point for the parser.\n    # If you use this method, you must implement RECEIVER#METHOD_ID method.\n    #\n    # RECEIVER#METHOD_ID is a method to get next token.\n    # It must 'yield' the token, which format is [TOKEN-SYMBOL, VALUE].\n    def yyparse(recv, mid)\n      __send__(Racc_YY_Parse_Method, recv, mid, _racc_setup(), true)\n    end\n\n    def _racc_yyparse_rb(recv, mid, arg, c_debug)\n      action_table, action_check, action_default, action_pointer,\n      _,             _,            _,              _,\n      _,            _,            token_table,    _,\n      _,            _,            * = arg\n\n      _racc_init_sysvars\n      act = nil\n      i = nil\n\n      catch(:racc_end_parse) {\n        until i = action_pointer[@racc_state[-1]]\n          while act = _racc_evalact(action_default[@racc_state[-1]], arg)\n            ;\n          end\n        end\n        recv.__send__(mid) do |tok, val|\n          unless tok\n            @racc_t = 0\n          else\n            @racc_t = (token_table[tok] or 1)   # error token\n          end\n          @racc_val = val\n          @racc_read_next = false\n\n          i += @racc_t\n          unless i >= 0 and\n                 act = action_table[i] and\n                 action_check[i] == @racc_state[-1]\n            act = action_default[@racc_state[-1]]\n          end\n          while act = _racc_evalact(act, arg)\n            ;\n          end\n\n          while not(i = action_pointer[@racc_state[-1]]) or\n                not @racc_read_next or\n                @racc_t == 0   # $\n            unless i and i += @racc_t and\n                   i >= 0 and\n                   act = action_table[i] and\n                   action_check[i] == @racc_state[-1]\n              act = action_default[@racc_state[-1]]\n            end\n            while act = _racc_evalact(act, arg)\n              ;\n            end\n          end\n        end\n      }\n    end\n\n    ###\n    ### common\n    ###\n\n    def _racc_evalact(act, arg)\n      action_table, action_check, _, action_pointer,\n      _,   _, _, _,\n      _,   _, _, shift_n,  reduce_n,\n      _,   _, * = arg\n\n      if act > 0 and act < shift_n\n        #\n        # shift\n        #\n        if @racc_error_status > 0\n          @racc_error_status -= 1 unless @racc_t == 1   # error token\n        end\n        @racc_vstack.push @racc_val\n        @racc_state.push act\n        @racc_read_next = true\n        if @yydebug\n          @racc_tstack.push @racc_t\n          racc_shift @racc_t, @racc_tstack, @racc_vstack\n        end\n\n      elsif act < 0 and act > -reduce_n\n        #\n        # reduce\n        #\n        code = catch(:racc_jump) {\n          @racc_state.push _racc_do_reduce(arg, act)\n          false\n        }\n        if code\n          case code\n          when 1 # yyerror\n            @racc_user_yyerror = true   # user_yyerror\n            return -reduce_n\n          when 2 # yyaccept\n            return shift_n\n          else\n            raise '[Racc Bug] unknown jump code'\n          end\n        end\n\n      elsif act == shift_n\n        #\n        # accept\n        #\n        racc_accept if @yydebug\n        throw :racc_end_parse, @racc_vstack[0]\n\n      elsif act == -reduce_n\n        #\n        # error\n        #\n        case @racc_error_status\n        when 0\n          unless arg[21]    # user_yyerror\n            on_error @racc_t, @racc_val, @racc_vstack\n          end\n        when 3\n          if @racc_t == 0   # is $\n            throw :racc_end_parse, nil\n          end\n          @racc_read_next = true\n        end\n        @racc_user_yyerror = false\n        @racc_error_status = 3\n        while true\n          if i = action_pointer[@racc_state[-1]]\n            i += 1   # error token\n            if  i >= 0 and\n                (act = action_table[i]) and\n                action_check[i] == @racc_state[-1]\n              break\n            end\n          end\n          throw :racc_end_parse, nil if @racc_state.size <= 1\n          @racc_state.pop\n          @racc_vstack.pop\n          if @yydebug\n            @racc_tstack.pop\n            racc_e_pop @racc_state, @racc_tstack, @racc_vstack\n          end\n        end\n        return act\n\n      else\n        raise \"[Racc Bug] unknown action \#{act.inspect}\"\n      end\n\n      racc_next_state(@racc_state[-1], @racc_state) if @yydebug\n\n      nil\n    end\n\n    def _racc_do_reduce(arg, act)\n      _, _, _, _,\n      goto_table,   goto_check,   goto_default,   goto_pointer,\n      nt_base,      reduce_table, _,    _,\n      _,     use_result,   * = arg\n      state = @racc_state\n      vstack = @racc_vstack\n      tstack = @racc_tstack\n\n      i = act * -3\n      len       = reduce_table[i]\n      reduce_to = reduce_table[i+1]\n      method_id = reduce_table[i+2]\n      void_array = []\n\n      tmp_t = tstack[-len, len] if @yydebug\n      tmp_v = vstack[-len, len]\n      tstack[-len, len] = void_array if @yydebug\n      vstack[-len, len] = void_array\n      state[-len, len]  = void_array\n\n      # tstack must be updated AFTER method call\n      if use_result\n        vstack.push __send__(method_id, tmp_v, vstack, tmp_v[0])\n      else\n        vstack.push __send__(method_id, tmp_v, vstack)\n      end\n      tstack.push reduce_to\n\n      racc_reduce(tmp_t, reduce_to, tstack, vstack) if @yydebug\n\n      k1 = reduce_to - nt_base\n      if i = goto_pointer[k1]\n        i += state[-1]\n        if i >= 0 and (curstate = goto_table[i]) and goto_check[i] == k1\n          return curstate\n        end\n      end\n      goto_default[k1]\n    end\n\n    # This method is called when a parse error is found.\n    #\n    # ERROR_TOKEN_ID is an internal ID of token which caused error.\n    # You can get string representation of this ID by calling\n    # #token_to_str.\n    #\n    # ERROR_VALUE is a value of error token.\n    #\n    # value_stack is a stack of symbol values.\n    # DO NOT MODIFY this object.\n    #\n    # This method raises ParseError by default.\n    #\n    # If this method returns, parsers enter \"error recovering mode\".\n    def on_error(t, val, vstack)\n      raise ParseError, sprintf(\"\\nparse error on value %s (%s)\",\n                                val.inspect, token_to_str(t) || '?')\n    end\n\n    # Enter error recovering mode.\n    # This method does not call #on_error.\n    def yyerror\n      throw :racc_jump, 1\n    end\n\n    # Exit parser.\n    # Return value is Symbol_Value_Stack[0].\n    def yyaccept\n      throw :racc_jump, 2\n    end\n\n    # Leave error recovering mode.\n    def yyerrok\n      @racc_error_status = 0\n    end\n\n    # For debugging output\n    def racc_read_token(t, tok, val)\n      @racc_debug_out.print 'read    '\n      @racc_debug_out.print tok.inspect, '(', racc_token2str(t), ') '\n      @racc_debug_out.puts val.inspect\n      @racc_debug_out.puts\n    end\n\n    def racc_shift(tok, tstack, vstack)\n      @racc_debug_out.puts \"shift   \#{racc_token2str tok}\"\n      racc_print_stacks tstack, vstack\n      @racc_debug_out.puts\n    end\n\n    def racc_reduce(toks, sim, tstack, vstack)\n      out = @racc_debug_out\n      out.print 'reduce '\n      if toks.empty?\n        out.print ' <none>'\n      else\n        toks.each {|t| out.print ' ', racc_token2str(t) }\n      end\n      out.puts \" --> \#{racc_token2str(sim)}\"\n\n      racc_print_stacks tstack, vstack\n      @racc_debug_out.puts\n    end\n\n    def racc_accept\n      @racc_debug_out.puts 'accept'\n      @racc_debug_out.puts\n    end\n\n    def racc_e_pop(state, tstack, vstack)\n      @racc_debug_out.puts 'error recovering mode: pop token'\n      racc_print_states state\n      racc_print_stacks tstack, vstack\n      @racc_debug_out.puts\n    end\n\n    def racc_next_state(curstate, state)\n      @racc_debug_out.puts  \"goto    \#{curstate}\"\n      racc_print_states state\n      @racc_debug_out.puts\n    end\n\n    def racc_print_stacks(t, v)\n      out = @racc_debug_out\n      out.print '        ['\n      t.each_index do |i|\n        out.print ' (', racc_token2str(t[i]), ' ', v[i].inspect, ')'\n      end\n      out.puts ' ]'\n    end\n\n    def racc_print_states(s)\n      out = @racc_debug_out\n      out.print '        ['\n      s.each {|st| out.print ' ', st }\n      out.puts ' ]'\n    end\n\n    def racc_token2str(tok)\n      self.class::Racc_token_to_s_table[tok] or\n          raise \"[Racc Bug] can't convert token \#{tok} to string\"\n    end\n\n    # Convert internal ID of token symbol to the string.\n    def token_to_str(t)\n      self.class::Racc_token_to_s_table[t]\n    end\n\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Racc>", "<class:ParseError>", "StandardError", "Racc::ParseError", "Racc", "<class:Parser>", "[]", "1", "Racc_Runtime_Core_Version_R", "Racc_Runtime_Core_Revision_R", "racc_runtime_type", "Parser", "Racc_Runtime_Type", "_racc_setup", "class::Racc_debug_parser", "self", "class", "@yydebug", "@racc_debug_out", "$stderr", "$ret_or_1", "arg", "class::Racc_arg", "<", "size", "14", "[]=", "13", "_racc_init_sysvars", "@racc_state", "0", "@racc_tstack", "@racc_vstack", "@racc_t", "@racc_val", "@racc_read_next", "@racc_user_yyerror", "@racc_error_status", "do_parse", "__send__", "Racc_Main_Parsing_Routine", "next_token", "raise", "NotImplementedError", "_racc_do_parse_rb", "in_debug", "action_table", "action_check", "action_default", "action_pointer", "_", "token_table", "tok", "act", "i", "catch", "block in _racc_do_parse_rb", "block (2 levels) in _racc_do_parse_rb", "-1", "racc_read_token", "+", ">=", "_racc_evalact", "yyparse", "recv", "mid", "Racc_YY_Parse_Method", "_racc_yyparse_rb", "c_debug", "block in _racc_yyparse_rb", "block (2 levels) in _racc_yyparse_rb", "val", "block (3 levels) in _racc_yyparse_rb", "$ret_or_2", "!", "==", "shift_n", "reduce_n", ">", "-", "push", "racc_shift", "-@", "code", "block in _racc_evalact", "block (2 levels) in _racc_evalact", "_racc_do_reduce", "2", "racc_accept", "throw", "21", "on_error", "3", "<=", "pop", "racc_e_pop", "inspect", "racc_next_state", "goto_table", "goto_check", "goto_default", "goto_pointer", "nt_base", "reduce_table", "use_result", "state", "vstack", "tstack", "*", "-3", "len", "reduce_to", "method_id", "void_array", "tmp_t", "tmp_v", "racc_reduce", "k1", "curstate", "t", "ParseError", "sprintf", "token_to_str", "yyerror", "yyaccept", "yyerrok", "print", "racc_token2str", "puts", "racc_print_stacks", "toks", "sim", "out", "empty?", "each", "block in racc_reduce", "block (2 levels) in racc_reduce", "racc_print_states", "v