AA;;UACEA,OAAAE,WAAKC,KAAAA,CAAKnC,kBAAV,EACI,CAACC,cAAD,EAAauC,KAAK9C,WAAAA,CAAAA,CAAlB,CAA6B+C,KAAAA,CAAAA,CADjC,EAEI,CAACvC,YAAD,EAAasC,KAAK7C,SAAAA,CAAAA,CAAlB,CAA2B+C,KAAAA,CAAAA,CAF1BP;QADPH,CAAAA;;AAWAW,QAAAA,yBAAAA,qBAAcH,KAAdG;AAAAA,UAAAA;;UACE,IAAA,QAAOvD,IAAAwD,cAAAA,CAAUJ,KAAVI,CAAP,CAAA;YA5NRD,OAAA;UA4NQ;YACEA,OAAAT,WAAKC,KAAAA,CAAKnC,kBAAV,EACE,CAACC,cAAD,EAAauC,KAAK9C,WAAAA,CAAAA,CAAlB,CAA6BgD,KAAAA,CAAAA,CAD/B,EAEE,CAACxC,YAAD,EAAasC,KAAK7C,SAAAA,CAAAA,CAAlB,CAA2B8C,KAAAA,CAAAA,CAFxBN;UADP;QADFQ,CAAAA;;AAgBAC,QAAAA,yBAAAA,gCAAcJ,KAAdI;AAAAA,UAAAA;;UACE,IAAG,CAAA,QAAAxD,IAAAyD,WAAAA,CAAAA,CAAA,CAAA,IAAA,CAAA,QAAUL,KAAKK,WAAAA,CAAAA,CAAf,CAAA,CAAA,CAAH;YACED,OAAA3C,cAAW6C,OAAAA,CAAGN,KAAK9C,WAAAA,CAAAA,CAARoD;UADb,OAGE,IAAA,QAAAC,CAAAA,YAAWC,OAAX/C,cAAW+C,EAAGR,KAAK7C,SAAAA,CAAAA,CAARqD,CAAXD,CAAA,CAAA;YAAAH,OAAA;UAAA;YAA+BA,OAAgBI,OAAhBR,KAAK9C,WAAAA,CAAAA,CAAWsD,EAAG9C,YAAH8C;UAA/C;QAJJJ,CAAAA;;AAcAK,QAAAA,yBAAAA,gCAAcT,KAAdS;AAAAA,UAAAA;;UACEA,OAAC7D,IAAAwD,cAAAA,CAAUJ,KAAVI,CAADM,MAAAA,CAAAA;QADFD,CAAAA;;AAYAE,QAAAA,yBAAAA,gCAAcX,KAAdW;AAAAA,UAAAA;;UACEA,OAAgEH,OAA/BlB,SAAhCU,KAAK9C,WAAAA,CAAAA,CAAW0D,QAAAA,CAAInD,cAAJmD,CAAgBtB,EAAG5B,YAASkD,QAAAA,CAAIZ,KAAK7C,SAAAA,CAAAA,CAATyD,CAAZtB,CAA+BkB,EAAI,CAAA,QAAAR,KAAKK,WAAAA,CAAAA,CAAL,CAAA,GAAA,CAAeQ,CAAf,IAAA,CAAmBtB,CAAnB,CAAA,CAAJiB;QADlEG,CAAAA;;AAYAG,QAAAA,0BAAAA,iCAAed,KAAfc;AAAAA,UAAAA;;UACEA,OAAAd,KAAKW,cAAAA,CAAW/D,IAAX+D;QADPG,CAAAA;;AAYAC,QAAAA,yBAAAA,gCAAcf,KAAde;AAAAA,UAAAA;;;UACE,KAAA,QAAoBnE,IAAA6D,cAAAA,CAAUT,KAAVS,CAApB,CAAA;YAAA,OAAO;UAAP;UACAM,OAAiCC,UAAhCvD,cAAWmD,QAAAA,CAAIZ,KAAK9C,WAAAA,CAAAA,CAAT0D,CAAqBI,EAAGtD,YAASkD,QAAAA,CAAIZ,KAAK7C,SAAAA,CAAAA,CAATyD,CAAZI,CAA+BC,OAAAA,CAAG1B,CAAH0B;QAFlEF,CAAAA;;AAQAV,QAAAA,sBAAAA,6BAAAA;AAAAA,UAAAA;;UACEA,OAAA5C,cAAWwD,OAAAA,CAAGvD,YAAHuD;QADbZ,CAAAA;;AAOAO,QAAAA,mBAAAA,4BAAQZ,KAARY;AAAAA,UAAAA;;;UACE,KAAkB,CAAA,QAAAZ,KAAKkB,UAAAA,CAAOC,IAAAC,IAAAC,aAAAD,WAAAD,UAAPD,CAAL,CAAA,IAAA,CAAA,MAChB1D,kBADgB,EACEwC,KAAK/C,eAAAA,CAAAA,CADP,CAAA,CAAA,CAAlB;YAAA,OAAO;UAAP;UAEA,IAAA,QAAAsD,CAAAA,YAAC9C,cAAWmD,QAAAA,CAAIZ,KAAK9C,WAAAA,CAAAA,CAAT0D,CAAoBU,aAAAA,CAAAA,CAAhCf,CAAA,CAAA;YAAAK,OAAA;UAAA;;YACCA,OAAAlD,YAASkD,QAAAA,CAAIZ,KAAK7C,SAAAA,CAAAA,CAATyD;UADV;QAHFA,CAAAA;QAOAhE,IAAAuB,cAAAA,CAAa,MAAb,EAAoB,IAApBA;;AAKAoD,QAAAA,oBAAAA,gBAAAA;AAAAA,UAAAA;;UACEA,OAAA,CAAC/D,kBAAD,EAAiBC,cAAjB,EAA6BC,YAA7B,CAAsC6D,MAAAA,CAAAA;QADxCA,CAAAA;QAOA5E,OAAA+B,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAACA,0BAAD,GAAA,CAA2BlB,kBAAc6B,MAAAA,CAAAA,CAAzC,CAAA,GAA+CX,GAA/C,GAAA,CAAkDjB,cAAlD,CAAA,GAA6DiB,KAA7D,GAAA,CAAkEhB,YAAlE,CAAA,GAA2EgB;QAD7EA,CAAAA;MAtSF/B,GAAAA,WAAAA,EAAAA,IAAAA;IAtBFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>3298, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/source/comment.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  module Source\n\n    ##\n    # A comment in the source code.\n    #\n    # @!attribute [r] text\n    #  @return [String]\n    #\n    # @!attribute [r] location\n    #  @return [Parser::Source::Range]\n    #\n    # @api public\n    #\n    class Comment\n      attr_reader  :text\n\n      attr_reader  :location\n      alias_method :loc, :location\n\n      ##\n      # Associate `comments` with `ast` nodes by their corresponding node.\n      #\n      # @param [Parser::AST::Node] ast\n      # @param [Array<Comment>]    comments\n      # @return [Hash<Parser::AST::Node, Array<Comment>>]\n      # @see Parser::Source::Comment::Associator#associate\n      # @deprecated Use {associate_locations}.\n      #\n      def self.associate(ast, comments)\n        associator = Associator.new(ast, comments)\n        associator.associate\n      end\n\n      ##\n      # Associate `comments` with `ast` nodes by their location in the\n      # source.\n      #\n      # @param [Parser::AST::Node] ast\n      # @param [Array<Comment>]    comments\n      # @return [Hash<Parser::Source::Map, Array<Comment>>]\n      # @see Parser::Source::Comment::Associator#associate_locations\n      #\n      def self.associate_locations(ast, comments)\n        associator = Associator.new(ast, comments)\n        associator.associate_locations\n      end\n\n      ##\n      # Associate `comments` with `ast` nodes using identity.\n      #\n      # @param [Parser::AST::Node] ast\n      # @param [Array<Comment>]    comments\n      # @return [Hash<Parser::Source::Node, Array<Comment>>]\n      # @see Parser::Source::Comment::Associator#associate_by_identity\n      #\n      def self.associate_by_identity(ast, comments)\n        associator = Associator.new(ast, comments)\n        associator.associate_by_identity\n      end\n\n      ##\n      # @param [Parser::Source::Range] range\n      #\n      def initialize(range)\n        @location = Parser::Source::Map.new(range)\n        @text     = range.source.freeze\n\n        freeze\n      end\n\n      ##\n      # Type of this comment.\n      #\n      #   * Inline comments correspond to `:inline`:\n      #\n      #         # whatever\n      #\n      #   * Block comments correspond to `:document`:\n      #\n      #         =begin\n      #         hi i am a document\n      #         =end\n      #\n      # @return [Symbol]\n      #\n      def type\n        if text.start_with?(\"#\".freeze)\n          :inline\n        elsif text.start_with?(\"=begin\".freeze)\n          :document\n        end\n      end\n\n      ##\n      # @see #type\n      # @return [Boolean] true if this is an inline comment.\n      #\n      def inline?\n        type == :inline\n      end\n\n      ##\n      # @see #type\n      # @return [Boolean] true if this is a block comment.\n      #\n      def document?\n        type == :document\n      end\n\n      ##\n      # Compares comments. Two comments are equal if they\n      # correspond to the same source range.\n      #\n      # @param [Object] other\n      # @return [Boolean]\n      #\n      def ==(other)\n        other.is_a?(Source::Comment) &&\n          @location == other.location\n      end\n\n      ##\n      # @return [String] a human-readable representation of this comment\n      #\n      def inspect\n        \"#<Parser::Source::Comment \#{@location.expression.to_s} \#{text.inspect}>\"\n      end\n    end\n\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<module:Source>", "<class:Comment>", "self", "attr_reader", "alias_method", "associate", "ast", "comments", "associator", "Associator", "new", "associate_locations", "associate_by_identity", "initialize", "range", "@location", "Parser::Source::Map", "Parser::Source", "Parser", "@text", "source", "freeze", "type", "text", "start_with?", "inline?", "==", "document?", "other", "$ret_or_1", "is_a?", "Source::Comment", "Source", "location", "inspect", "expression", "to_s"], :mappings=>"AAAAA,wCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAaEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEC,IAAAC,aAAAA,CAAa,MAAbA;QAEAD,IAAAC,aAAAA,CAAa,UAAbA;QACAD,IAAAE,cAAAA,CAAa,KAAb,EAAmB,UAAnBA;QAWAC,MAAIH,IAAJG,gBAAAA,qBAAmBC,GAAD,EAAMC,QAAxBF;AAAAA,UAAAA;;;UACEG,aAAaC,gBAAUC,KAAAA,CAAKJ,GAAf,EAAoBC,QAAVG;UACvBL,OAAAG,UAAUH,WAAAA,CAAAA;QAFZA,CAAAA;QAcAM,MAAIT,IAAJS,0BAAAA,+BAA6BL,GAAD,EAAMC,QAAlCI;AAAAA,UAAAA;;;UACEH,aAAaC,gBAAUC,KAAAA,CAAKJ,GAAf,EAAoBC,QAAVG;UACvBC,OAAAH,UAAUG,qBAAAA,CAAAA;QAFZA,CAAAA;QAaAC,MAAIV,IAAJU,4BAAAA,iCAA+BN,GAAD,EAAMC,QAApCK;AAAAA,UAAAA;;;UACEJ,aAAaC,gBAAUC,KAAAA,CAAKJ,GAAf,EAAoBC,QAAVG;UACvBE,OAAAJ,UAAUI,uBAAAA,CAAAA;QAFZA,CAAAA;;AAQAC,QAAAA,0BAAAA,sBAAeC,KAAfD;AAAAA,UAAAA;;;UACEE,gBAAYC,IAAAC,IAAAC,YAAAD,WAAAD,QAAmBN,KAAAA,CAAKI,KAALJ;UAC/BS,YAAYL,KAAKM,QAAAA,CAAAA,CAAOC,QAAAA,CAAAA;UAExBR,OAAAX,IAAAmB,QAAAA,CAAAA;QAJFR,CAAAA;;AAsBAS,QAAAA,oBAAAA,gBAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAGpB,IAAAqB,MAAAA,CAAAA,CAAIC,gBAAAA,CAAaF,GAAGD,QAAAA,CAAAA,CAAhBG,CAAP,CAAA;YACEF,OAAA;UADF,OAEA,IAAA,QAAMpB,IAAAqB,MAAAA,CAAAA,CAAIC,gBAAAA,CAAaF,QAAQD,QAAAA,CAAAA,CAArBG,CAAV,CAAA;YACEF,OAAA;UADF;YA3FRA,OAAA;UA2FQ;QAHFA,CAAAA;;AAYAG,QAAAA,uBAAAA,gCAAAA;AAAAA,UAAAA;;UACEA,OAAAvB,IAAAoB,MAAAA,CAAAA,CAAKI,OAAAA,CAAG,QAAHA;QADPD,CAAAA;;AAQAE,QAAAA,yBAAAA,kCAAAA;AAAAA,UAAAA;;UACEA,OAAAzB,IAAAoB,MAAAA,CAAAA,CAAKI,OAAAA,CAAG,UAAHA;QADPC,CAAAA;;AAWAD,QAAAA,kBAAAA,2BAAOE,KAAPF;AAAAA,UAAAA;;UACE,IAAA,QAAAG,CAAAA,YAAAD,KAAKE,UAAAA,CAAOC,IAAAC,YAAAD,YAAPD,CAALD,CAAA,CAAA;YACEH,OAAAX,aAAUW,OAAAA,CAAGE,KAAKK,UAAAA,CAAAA,CAARP;UADZ;YAAAA,OAAA;UAAA;QADFA,CAAAA;QAQAzB,OAAAiC,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAACA,4BAAD,GAAA,CAA6BnB,aAASoB,YAAAA,CAAAA,CAAWC,MAAAA,CAAAA,CAAjD,CAAA,GAAuDF,GAAvD,GAAA,CAA0DhC,IAAAqB,MAAAA,CAAAA,CAAIW,SAAAA,CAAAA,CAA9D,CAAA,GAAuEA;QADzEA,CAAAA;MA/GFjC,GAAAA,WAAAA,EAAAA,IAAAA;IAbFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>3395, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/source/comment/associator.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  module Source\n\n    ##\n    # A processor which associates AST nodes with comments based on their\n    # location in source code. It may be used, for example, to implement\n    # rdoc-style processing.\n    #\n    # @example\n    #   require 'parser/current'\n    #\n    #   ast, comments = Parser::CurrentRuby.parse_with_comments(<<-CODE)\n    #   # Class stuff\n    #   class Foo\n    #     # Attr stuff\n    #     # @see bar\n    #     attr_accessor :foo\n    #   end\n    #   CODE\n    #\n    #   p Parser::Source::Comment.associate(ast, comments)\n    #   # => {\n    #   #   (class (const nil :Foo) ...) =>\n    #   #     [#<Parser::Source::Comment (string):1:1 \"# Class stuff\">],\n    #   #   (send nil :attr_accessor (sym :foo)) =>\n    #   #     [#<Parser::Source::Comment (string):3:3 \"# Attr stuff\">,\n    #   #      #<Parser::Source::Comment (string):4:3 \"# @see bar\">]\n    #   # }\n    #\n    # @see {associate}\n    #\n    # @!attribute skip_directives\n    #  Skip file processing directives disguised as comments.\n    #  Namely:\n    #\n    #    * Shebang line,\n    #    * Magic encoding comment.\n    #\n    #  @return [Boolean]\n    #\n    # @api public\n    #\n    class Comment::Associator\n      attr_accessor :skip_directives\n\n      ##\n      # @param [Parser::AST::Node] ast\n      # @param [Array<Parser::Source::Comment>] comments\n      def initialize(ast, comments)\n        @ast         = ast\n        @comments    = comments\n\n        @skip_directives = true\n      end\n\n      ##\n      # Compute a mapping between AST nodes and comments.  Comment is\n      # associated with the node, if it is one of the following types:\n      #\n      # - preceding comment, it ends before the node start\n      # - sparse comment, it is located inside the node, after all child nodes\n      # - decorating comment, it starts at the same line, where the node ends\n      #\n      # This rule is unambiguous and produces the result\n      # one could reasonably expect; for example, this code\n      #\n      #     # foo\n      #     hoge # bar\n      #       + fuga\n      #\n      # will result in the following association:\n      #\n      #     {\n      #       (send (lvar :hoge) :+ (lvar :fuga)) =>\n      #         [#<Parser::Source::Comment (string):2:1 \"# foo\">],\n      #       (lvar :fuga) =>\n      #         [#<Parser::Source::Comment (string):3:8 \"# bar\">]\n      #     }\n      #\n      # Note that comments after the end of the end of a passed tree range are\n      # ignored (except root decorating comment).\n      #\n      # Note that {associate} produces unexpected result for nodes which are\n      # equal but have distinct locations; comments for these nodes are merged.\n      # You may prefer using {associate_by_identity} or {associate_locations}.\n      #\n      # @return [Hash<Parser::AST::Node, Array<Parser::Source::Comment>>]\n      # @deprecated Use {associate_locations}.\n      #\n      def associate\n        @map_using = :eql\n        do_associate\n      end\n\n      ##\n      # Same as {associate}, but uses `node.loc` instead of `node` as\n      # the hash key, thus producing an unambiguous result even in presence\n      # of equal nodes.\n      #\n      # @return [Hash<Parser::Source::Map, Array<Parser::Source::Comment>>]\n      #\n      def associate_locations\n        @map_using = :location\n        do_associate\n      end\n\n      ##\n      # Same as {associate}, but compares by identity, thus producing an unambiguous\n      # result even in presence of equal nodes.\n      #\n      # @return [Hash<Parser::Source::Node, Array<Parser::Source::Comment>>]\n      #\n      def associate_by_identity\n        @map_using = :identity\n        do_associate\n      end\n\n      private\n\n      POSTFIX_TYPES = Set[:if, :while, :while_post, :until, :until_post, :masgn].freeze\n      def children_in_source_order(node)\n        if POSTFIX_TYPES.include?(node.type)\n          # All these types have either nodes with expressions, or `nil`\n          # so a compact will do, but they need to be sorted.\n          node.children.compact.sort_by { |child| child.loc.expression.begin_pos }\n        else\n          node.children.select do |child|\n            child.is_a?(AST::Node) && child.loc && child.loc.expression\n          end\n        end\n      end\n\n      def do_associate\n        @mapping     = Hash.new { |h, k| h[k] = [] }\n        @mapping.compare_by_identity if @map_using == :identity\n        @comment_num = -1\n        advance_comment\n\n        advance_through_directives if @skip_directives\n\n        visit(@ast) if @ast\n\n        @mapping\n      end\n\n      def visit(node)\n        process_leading_comments(node)\n\n        return unless @current_comment\n\n        # If the next comment is beyond the last line of this node, we don't\n        # need to iterate over its subnodes\n        # (Unless this node is a heredoc... there could be a comment in its body,\n        # inside an interpolation)\n        node_loc = node.location\n        if @current_comment.location.line <= node_loc.last_line ||\n           node_loc.is_a?(Map::Heredoc)\n          children_in_source_order(node).each { |child| visit(child) }\n\n          process_trailing_comments(node)\n        end\n      end\n\n      def process_leading_comments(node)\n        return if node.type == :begin\n        while current_comment_before?(node) # preceding comment\n          associate_and_advance_comment(node)\n        end\n      end\n\n      def process_trailing_comments(node)\n        while current_comment_before_end?(node)\n          associate_and_advance_comment(node) # sparse comment\n        end\n        while current_comment_decorates?(node)\n          associate_and_advance_comment(node) # decorating comment\n        end\n      end\n\n      def advance_comment\n        @comment_num += 1\n        @current_comment = @comments[@comment_num]\n      end\n\n      def current_comment_before?(node)\n        return false if !@current_comment\n        comment_loc = @current_comment.location.expression\n        node_loc = node.location.expression\n        comment_loc.end_pos <= node_loc.begin_pos\n      end\n\n      def current_comment_before_end?(node)\n        return false if !@current_comment\n        comment_loc = @current_comment.location.expression\n        node_loc = node.location.expression\n        comment_loc.end_pos <= node_loc.end_pos\n      end\n\n      def current_comment_decorates?(node)\n        return false if !@current_comment\n        @current_comment.location.line == node.location.last_line\n      end\n\n      def associate_and_advance_comment(node)\n        key = @map_using == :location ? node.location : node\n        @mapping[key] << @current_comment\n        advance_comment\n      end\n\n      MAGIC_COMMENT_RE = /^#\\s*(-\\*-|)\\s*(frozen_string_literal|warn_indent|warn_past_scope):.*\\1$/\n\n      def advance_through_directives\n        # Skip shebang.\n        if @current_comment && @current_comment.text.start_with?('#!'.freeze)\n          advance_comment\n        end\n\n        # Skip magic comments.\n        if @current_comment && @current_comment.text =~ MAGIC_COMMENT_RE\n          advance_comment\n        end\n\n        # Skip encoding line.\n        if @current_comment && @current_comment.text =~ Buffer::ENCODING_RE\n          advance_comment\n        end\n      end\n    end\n\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<module:Source>", "<class:Comment::Associator>", "self", "attr_accessor", "initialize", "ast", "comments", "@ast", "@comments", "@skip_directives", "associate", "@map_using", "do_associate", "associate_locations", "associate_by_identity", "private", "Set", "[]", "freeze", "children_in_source_order", "node", "POSTFIX_TYPES", "include?", "type", "sort_by", "children", "compact", "block in children_in_source_order", "child", "block (2 levels) in children_in_source_order", "loc", "expression", "begin_pos", "select", "$ret_or_1", "$ret_or_2", "is_a?", "AST::Node", "AST", "@mapping", "new", "Hash", "block in do_associate", "h", "k", "block (2 levels) in do_associate", "[]=", "compare_by_identity", "@comment_num", "-1", "advance_comment", "advance_through_directives", "visit", "process_leading_comments", "@current_comment", "node_loc", "location", "<=", "line", "last_line", "Map::Heredoc", "Map", "each", "block in visit", "block (2 levels) in visit", "process_trailing_comments", "current_comment_before?", "associate_and_advance_comment", "current_comment_before_end?", "current_comment_decorates?", "+", "1", "comment_loc", "end_pos", "==", "key", "<<", "text", "start_with?", "=~", "MAGIC_COMMENT_RE", "Buffer::ENCODING_RE", "Buffer", "Comment"], :mappings=>"AAAAA,mDAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAyCEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEC,IAAAC,eAAAA,CAAc,iBAAdA;;AAKAC,QAAAA,0BAAAA,sBAAeC,GAAD,EAAMC,QAApBF;AAAAA,UAAAA;;;UACEG,WAAeF;UACfG,gBAAeF;UAEfF,OAAAK,CAAAA,uBAAmB,IAAnBA;QAJFL,CAAAA;;AAyCAM,QAAAA,yBAAAA,qBAAAA;AAAAA,UAAAA;;;UACEC,iBAAa;UACbD,OAAAR,IAAAU,cAAAA,CAAAA;QAFFF,CAAAA;;AAYAG,QAAAA,mCAAA