,EAAsDG,MAAMT,aAAAA,CAAAA,CAA5D,CAAA,CAAA,CAAH;cACE4G,OAAA,uDAAA,SAAQ1G,UAAR,EAAA,eAA6BO,MAAMT,aAAAA,CAAAA,CAAnC,EAAA,qBAAoEM,gBAApE;YADF;cAlOVsG,OAAA;YAkOU,CADFD,CAAAA,GAAAA,SAAAA,CAASH;QADXE,CAAAA;QAQApH,OAAA2D,uBAAAA,mBAAYpD,QAAZoD;AAAAA,UAAAA;;;UACWuD,MAATrG,aAASqG,QAAAA,EAAAA,CAAM,sBAANA,CAAAA,EAATK,cAAAA,EAAAC;AAAAA;;;YACEC,aAAqBC,MAARnH,QAAQmH,UAAAA,EAAAA,EAAAA,EAAS,YAAD1F,SAAAA,CAAAA,CAAR0F;YAErB,IAAA,QAA0DD,UAAUrG,WAAAA,CAAAA,CAApE,CAAA;cA5OVoG,OAAA;YA4OU;cAAAA,OAAA,+BAAA,SAAQ5G,UAAR,EAAA,YAAoC0C,MAAVmE,UAAUnE,OAAAA,EAAAA,EAAAA,EAAM,OAADtB,SAAAA,CAAAA,CAALsB,CAApC;YAAA,EAHFiE,CAAAA,GAAAA,SAAAA,CAASL;UAKTvD,OAAA;QANFA,CAAAA;MA3NF3D,GAAM2H,kBAAN3H,EAAAA,IAAAA;IAVFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>4781, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/source/map.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  module Source\n\n    ##\n    # {Map} relates AST nodes to the source code they were parsed from.\n    # More specifically, a {Map} or its subclass contains a set of ranges:\n    #\n    #  * `expression`: smallest range which includes all source corresponding\n    #    to the node and all `expression` ranges of its children.\n    #  * other ranges (`begin`, `end`, `operator`, ...): node-specific ranges\n    #    pointing to various interesting tokens corresponding to the node.\n    #\n    # Note that the {Map::Heredoc} map is the only one whose `expression` does\n    # not include other ranges. It only covers the heredoc marker (`<<HERE`),\n    # not the here document itself.\n    #\n    # All ranges except `expression` are defined by {Map} subclasses.\n    #\n    # Ranges (except `expression`) can be `nil` if the corresponding token is\n    # not present in source. For example, a hash may not have opening/closing\n    # braces, and so would its source map.\n    #\n    #     p Parser::CurrentRuby.parse('[1 => 2]').children[0].loc\n    #     # => <Parser::Source::Map::Collection:0x007f5492b547d8\n    #     #  @end=nil, @begin=nil,\n    #     #  @expression=#<Source::Range (string) 1...7>>\n    #\n    # The {file:doc/AST_FORMAT.md} document describes how ranges associated to source\n    # code tokens. For example, the entry\n    #\n    #     (array (int 1) (int 2))\n    #\n    #     \"[1, 2]\"\n    #      ^ begin\n    #           ^ end\n    #      ~~~~~~ expression\n    #\n    # means that if `node` is an {Parser::AST::Node} `(array (int 1) (int 2))`,\n    # then `node.loc` responds to `begin`, `end` and `expression`, and\n    # `node.loc.begin` returns a range pointing at the opening bracket, and so on.\n    #\n    # If you want to write code polymorphic by the source map (i.e. accepting\n    # several subclasses of {Map}), use `respond_to?` instead of `is_a?` to\n    # check whether the map features the range you need. Concrete {Map}\n    # subclasses may not be preserved between versions, but their interfaces\n    # will be kept compatible.\n    #\n    # You can visualize the source maps with `ruby-parse -E` command-line tool.\n    #\n    # @example\n    #  require 'parser/current'\n    #\n    #  p Parser::CurrentRuby.parse('[1, 2]').loc\n    #  # => #<Parser::Source::Map::Collection:0x007f14b80eccd8\n    #  #  @end=#<Source::Range (string) 5...6>,\n    #  #  @begin=#<Source::Range (string) 0...1>,\n    #  #  @expression=#<Source::Range (string) 0...6>>\n    #\n    # @!attribute [r] node\n    #  The node that is described by this map. Nodes and maps have 1:1 correspondence.\n    #  @return [Parser::AST::Node]\n    #\n    # @!attribute [r] expression\n    #  @return [Range]\n    #\n    # @api public\n    #\n    class Map\n      attr_reader :node\n      attr_reader :expression\n\n      ##\n      # @param [Range] expression\n      def initialize(expression)\n        @expression = expression\n      end\n\n      ##\n      # @api private\n      def initialize_copy(other)\n        super\n        @node = nil\n      end\n\n      ##\n      # @api private\n      def node=(node)\n        @node = node\n        freeze\n        @node\n      end\n\n      ##\n      # A shortcut for `self.expression.line`.\n      # @return [Integer]\n      #\n      def line\n        @expression.line\n      end\n\n      alias_method :first_line, :line\n\n      ##\n      # A shortcut for `self.expression.column`.\n      # @return [Integer]\n      #\n      def column\n        @expression.column\n      end\n\n      ##\n      # A shortcut for `self.expression.last_line`.\n      # @return [Integer]\n      #\n      def last_line\n        @expression.last_line\n      end\n\n      ##\n      # A shortcut for `self.expression.last_column`.\n      # @return [Integer]\n      #\n      def last_column\n        @expression.last_column\n      end\n\n      ##\n      # @api private\n      #\n      def with_expression(expression_l)\n        with { |map| map.update_expression(expression_l) }\n      end\n\n      ##\n      # Compares source maps.\n      # @return [Boolean]\n      #\n      def ==(other)\n        other.class == self.class &&\n          instance_variables.map do |ivar|\n            instance_variable_get(ivar) ==\n              other.send(:instance_variable_get, ivar)\n          end.reduce(:&)\n      end\n\n      ##\n      # Converts this source map to a hash with keys corresponding to\n      # ranges. For example, if called on an instance of {Collection},\n      # which adds the `begin` and `end` ranges, the resulting hash\n      # will contain keys `:expression`, `:begin` and `:end`.\n      #\n      # @example\n      #  require 'parser/current'\n      #\n      #  p Parser::CurrentRuby.parse('[1, 2]').loc.to_hash\n      #  # => {\n      #  #   :begin => #<Source::Range (string) 0...1>,\n      #  #   :end => #<Source::Range (string) 5...6>,\n      #  #   :expression => #<Source::Range (string) 0...6>\n      #  # }\n      #\n      # @return [Hash<Symbol, Parser::Source::Range>]\n      #\n      def to_hash\n        instance_variables.inject({}) do |hash, ivar|\n          next hash if ivar.to_sym == :@node\n          hash[ivar[1..-1].to_sym] = instance_variable_get(ivar)\n          hash\n        end\n      end\n\n      protected\n\n      def with(&block)\n        dup.tap(&block)\n      end\n\n      def update_expression(expression_l)\n        @expression = expression_l\n      end\n    end\n\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<module:Source>", "<class:Map>", "self", "attr_reader", "initialize", "initialize_copy", "other", "@node", "node=", "node", "freeze", "line", "@expression", "alias_method", "column", "last_line", "last_column", "with_expression", "expression_l", "with", "block in with_expression", "map", "block (2 levels) in with_expression", "update_expression", "==", "$ret_or_1", "class", "instance_variables", "block in ==", "ivar", "block (2 levels) in ==", "instance_variable_get", "send", "reduce", "to_hash", "inject", "block in to_hash", "hash", "block (2 levels) in to_hash", "to_sym", "[]=", "[]", "1", "-1", "protected", "tap", "dup", "block", "to_proc"], :mappings=>"AAAAA,oCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAkEEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEC,IAAAC,aAAAA,CAAY,MAAZA;QACAD,IAAAC,aAAAA,CAAY,YAAZA;;AAIAC,QAAAA,0BAAAA,aACE,YADFA,CAAAA;;AAMAC,QAAAA,+BAAAA,2BAAoBC,KAApBD;AAAAA,UAAAA;;UAAAA;;UACE,OAAAH,IAAA,EAAA,oEAAA,mBAAA,EAAA,CAAAI,KAAA,CAAA,EAAA,MAAA;UACAD,OAAAE,CAAAA,YAAQ,GAARA;QAFFF,CAAAA;;AAOAG,QAAAA,qBAAAA,wBAAUC,IAAVD;AAAAA,UAAAA;;;UACED,YAAQE;UACRP,IAAAQ,QAAAA,CAAAA;UACAF,OAAAD;QAHFC,CAAAA;;AAUAG,QAAAA,oBAAAA,gBAAAA;AAAAA,UAAAA;;UACEA,OAAAC,eAAWD,MAAAA,CAAAA;QADbA,CAAAA;QAIAT,IAAAW,cAAAA,CAAa,YAAb,EAA0B,MAA1BA;;AAMAC,QAAAA,sBAAAA,kBAAAA;AAAAA,UAAAA;;UACEA,OAAAF,eAAWE,QAAAA,CAAAA;QADbA,CAAAA;;AAQAC,QAAAA,yBAAAA,qBAAAA;AAAAA,UAAAA;;UACEA,OAAAH,eAAWG,WAAAA,CAAAA;QADbA,CAAAA;;AAQAC,QAAAA,2BAAAA,uBAAAA;AAAAA,UAAAA;;UACEA,OAAAJ,eAAWI,aAAAA,CAAAA;QADbA,CAAAA;;AAOAC,QAAAA,+BAAAA,2BAAoBC,YAApBD;AAAAA,UAAAA;;UACEA,OAAAE,MAAAjB,IAAAiB,QAAA