F,IAAA,EAAA,0DAAA,cAAA,EAAA,CAAMG,UAAUE,SAAAA,CAAAA,CAAhB,CAAA,EAAA,IAAA;MAFFH,CAAAA;IAHFH,GAAAA,WAAAA,EAAoBO,mBAApBP;EAVFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>5506, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/clobbering_error.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  ##\n  # {Parser::ClobberingError} is raised when {Parser::Source::Rewriter}\n  # detects a clobbering rewrite action. This class inherits {RuntimeError}\n  # rather than {StandardError} for backward compatibility.\n  #\n  # @api public\n  #\n  class ClobberingError < RuntimeError\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:ClobberingError>", "RuntimeError"], :mappings=>"AAAAA,0CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAQEA,OAAAC,QAAAA,WAAAA,EAAwBC,kBAAxBD;EARFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>5518, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/unknown_encoding_in_magic_comment_error.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  ##\n  # {Parser::UnknownEncodingInMagicComment} is raised when a magic encoding\n  # comment is encountered that the currently running Ruby version doesn't\n  # recognize. It inherits from {ArgumentError} since that is the exception\n  # Ruby itself raises when trying to execute a file with an unknown encoding.\n  # As such, it is also not a {Parser::SyntaxError}.\n  #\n  # @api public\n  #\n  class UnknownEncodingInMagicComment < ArgumentError\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:UnknownEncodingInMagicComment>", "ArgumentError"], :mappings=>"AAAAA,iEAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAUEA,OAAAC,QAAAA,WAAAA,EAAsCC,mBAAtCD;EAVFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>5530, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/diagnostic.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  ##\n  # @api public\n  #\n  # @!attribute [r] level\n  #  @see LEVELS\n  #  @return [Symbol] diagnostic level\n  #\n  # @!attribute [r] reason\n  #  @see Parser::MESSAGES\n  #  @return [Symbol] reason for error\n  #\n  # @!attribute [r] arguments\n  #  @see Parser::MESSAGES\n  #  @return [Symbol] extended arguments that describe the error\n  #\n  # @!attribute [r] message\n  #  @return [String] error message\n  #\n  # @!attribute [r] location\n  #  Main error-related source range.\n  #  @return [Parser::Source::Range]\n  #\n  # @!attribute [r] highlights\n  #  Supplementary error-related source ranges.\n  #  @return [Array<Parser::Source::Range>]\n  #\n  class Diagnostic\n    ##\n    # Collection of the available diagnostic levels.\n    #\n    # @return [Array]\n    #\n    LEVELS = [:note, :warning, :error, :fatal].freeze\n\n    attr_reader :level, :reason, :arguments\n    attr_reader :location, :highlights\n\n    ##\n    # @param [Symbol] level\n    # @param [Symbol] reason\n    # @param [Hash] arguments\n    # @param [Parser::Source::Range] location\n    # @param [Array<Parser::Source::Range>] highlights\n    #\n    def initialize(level, reason, arguments, location, highlights=[])\n      unless LEVELS.include?(level)\n        raise ArgumentError,\n              \"Diagnostic#level must be one of \#{LEVELS.join(', ')}; \" \\\n              \"\#{level.inspect} provided.\"\n      end\n      raise 'Expected a location' unless location\n\n      @level       = level\n      @reason      = reason\n      @arguments   = (arguments || {}).dup.freeze\n      @location    = location\n      @highlights  = highlights.dup.freeze\n\n      freeze\n    end\n\n    ##\n    # @return [String] the rendered message.\n    #\n    def message\n      Messages.compile(@reason, @arguments)\n    end\n\n    ##\n    # Renders the diagnostic message as a clang-like diagnostic.\n    #\n    # @example\n    #  diagnostic.render # =>\n    #  # [\n    #  #   \"(fragment:0):1:5: error: unexpected token $end\",\n    #  #   \"foo +\",\n    #  #   \"    ^\"\n    #  # ]\n    #\n    # @return [Array<String>]\n    #\n    def render\n      if @location.line == @location.last_line || @location.is?(\"\\n\")\n        [\"\#{@location}: \#{@level}: \#{message}\"] + render_line(@location)\n      else\n        # multi-line diagnostic\n        first_line = first_line_only(@location)\n        last_line  = last_line_only(@location)\n        num_lines  = (@location.last_line - @location.line) + 1\n        buffer     = @location.source_buffer\n\n        last_lineno, last_column = buffer.decompose_position(@location.end_pos)\n        [\"\#{@location}-\#{last_lineno}:\#{last_column}: \#{@level}: \#{message}\"] +\n          render_line(first_line, num_lines > 2, false) +\n          render_line(last_line, false, true)\n      end\n    end\n\n    private\n\n    ##\n    # Renders one source line in clang diagnostic style, with highlights.\n    #\n    # @return [Array<String>]\n    #\n    def render_line(range, ellipsis=false, range_end=false)\n      source_line    = range.source_line\n      highlight_line = ' ' * source_line.length\n\n      @highlights.each do |highlight|\n       line_range = range.source_buffer.line_range(range.line)\n        if highlight = highlight.intersect(line_range)\n          highlight_line[highlight.column_range] = '~' * highlight.size\n        end\n      end\n\n      if range.is?(\"\\n\")\n        highlight_line += \"^\"\n      else\n        if !range_end && range.size >= 1\n          highlight_line[range.column_range] = '^' + '~' * (range.size - 1)\n        else\n          highlight_line[range.column_range] = '~' * range.size\n        end\n      end\n\n      highlight_line += '...' if ellipsis\n\n      [source_line, highlight_line].\n        map { |line| \"\#{range.source_buffer.name}:\#{range.line}: \#{line}\" }\n    end\n\n    ##\n    # If necessary, shrink a `Range` so as to include only the first line.\n    #\n    # @return [Parser::Source::Range]\n    #\n    def first_line_only(range)\n      if range.line != range.last_line\n        range.resize(range.source =~ /\\n/)\n      else\n        range\n      end\n    end\n\n    ##\n    # If necessary, shrink a `Range` so as to include only the last line.\n    #\n    # @return [Parser::Source::Range]\n    #\n    def last_line_only(range)\n      if range.line != range.last_line\n        range.adjust(begin_pos: range.source =~ /[^\\n]*\\z/)\n      else\n        range\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Diagnostic>", "freeze", "self", "attr_reader", "initialize", "level", "reason", "arguments$", "location", "highlights", "LEVELS", "include?", "raise", "ArgumentError", "join", "inspect", "@level", "@reason", "@arguments", "$ret_or_1", "dup", "@location", "@highlights", "message", "Messages", "compile", "render", "line", "last_line", "is?", "+", "render_line", "first_line", "first_line_only", "last_line_only", "num_lines", "-", "1", "buffer", "source_buffer", "decompose_position", "end_pos", "last_lineno", "last_column", ">", "2", "private", "range", "ellipsis", "range_end", "source_line", "highlight_line", "*", "length", "each", "block in render_line", "highlight", "block (2 levels) in render_line", "line_range", "intersect", "[]=", "column_range", "size", ">=", "map", "name", "resize", "source", "=~", "adjust"], :mappings=>"AAAAA,oCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IA4BEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MAME,kCAAS,CAAC,MAAD,EAAQ,SAAR,EAAkB,OAAlB,EAA0B,OAA1B,CAAiCC,QAAAA,CAAAA,CAA1C;MAEAC,IAAAC,aAAAA,CAAY,OAAZ,EAAoB,QAApB,EAA6B,WAA7BA;MACAD,IAAAC,aAAAA,CAAY,UAAZ,EAAuB,YAAvBA;;AASAC,MAAAA,0BAAAA,sBAAeC,KAAD,EAAQC,MAAR,EAAgBC,UAAhB,EAA2BC,QAA3B,EAAqCC,UAAnDL;AAAAA,QAAAA;;;QAAmD,qCAAW;QAC5D,KAAA,QAAOM,YAAMC,aAAAA,CAAUN,KAAVM,CAAb,CAAA;UACET,IAAAU,OAAAA,CAAMC,mBAAN,EACM,EAAA,GAAA,CAACT,kCAAD,GAAA,CAAmCM,YAAMI,MAAAA,CAAMV,IAANU,CAAzC,CAAA,GAAqDV,IAArD,CAAA,GAAA,CACA,EAAA,GAAA,CAAGC,KAAKU,SAAAA,CAAAA,CAAR,CAAA,GAAiBX,YADjB,CADNQ;QADF;QAKA,KAAA,QAAmCJ,QAAnC,CAAA;UAAAN,IAAAU,O