CAAxB,EAA6CT,UAAJK,GAAIL,EAAEI,SAASM,MAAAA,CAAAA,CAAXV,CAA/BQ,CAAAA,EAAAA,MAAdT,cAAcS,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA;UADhB;YAnHRH,OAAA;UAmHQ,EAFFF,CAAWD;QAOX,IAAA,QAAGP,KAAKlB,QAAAA,CAAKE,IAALF,CAAR,CAAA;UACEsB,iBAAerB,SAAfqB,cAAerB,EAAGC,GAAHD;QADjB,OAGE,IAAG,CAAA,KAACmB,SAAD,CAAA,IAAA,CAAA,QAAyBc,OAAXhB,KAAKe,MAAAA,CAAAA,CAAMC,EAAG1B,CAAH0B,CAAzB,CAAA,CAAA,CAAH;UACEZ,cAAcS,QAAAA,CAACb,KAAKc,cAAAA,CAAAA,CAApB,EAAyC/B,SAAJC,GAAID,EAAMsB,UAAJrB,GAAIqB,EAAchB,UAAXW,KAAKe,MAAAA,CAAAA,CAAM1B,EAAEC,CAAFD,CAAdgB,CAANtB,CAA3B8B;QADhB;UAGET,cAAcS,QAAAA,CAACb,KAAKc,cAAAA,CAAAA,CAApB,EAAyCT,UAAJrB,GAAIqB,EAAEL,KAAKe,MAAAA,CAAAA,CAAPV,CAA3BQ;QAHhB;QAOF,IAAA,QAA2BZ,QAA3B,CAAA;UAAAG,iBAAerB,SAAfqB,cAAerB,EAAGC,KAAHD;QAAf;QAEAC,OAA6BiC,MAA7B,CAACd,WAAD,EAAcC,cAAd,CAA6Ba,OAAAA,EAAAA,EAAAA,EAA7BT,aACS5B,IADT4B;;UACS;UAAME,OAAA,EAAA,GAAA,CAAGV,KAAKR,eAAAA,CAAAA,CAAc0B,MAAAA,CAAAA,CAAtB,CAAA,GAA4BR,GAA5B,GAAA,CAA+BV,KAAKpB,MAAAA,CAAAA,CAApC,CAAA,GAA0C8B,IAA1C,GAAA,CAA8C9B,IAA9C,EADf4B,CAA6BS;MAvB/BjC,CAAAA,IAAAA;;AAgCAE,MAAAA,+BAAAA,2BAAoBc,KAApBd;AAAAA;QACE,IAAA,OAAGc,KAAKpB,MAAAA,CAAAA,CAAR,EAAiBoB,KAAKnB,WAAAA,CAAAA,CAAtB,CAAA;UACEK,OAAAc,KAAKmB,QAAAA,CAAQnB,KAAKoB,QAAAA,CAAAA,CAAQC,OAAAA,CAAG,IAAHA,CAArBF;QADP;UAGEjC,OAAAc;QAHF;MADFd,CAAAA;MAaAjC,OAAAkC,8BAAAA,0BAAmBa,KAAnBb;AAAAA;QACE,IAAA,OAAGa,KAAKpB,MAAAA,CAAAA,CAAR,EAAiBoB,KAAKnB,WAAAA,CAAAA,CAAtB,CAAA;UACEM,OAAAa,KAAKsB,QAAAA,CAAQ,uBAAA,aAAWtB,KAAKoB,QAAAA,CAAAA,CAAQC,OAAAA,CAAG,SAAHA,CAAxB,EAARC;QADP;UAGEnC,OAAAa;QAHF;MADFb,CAAAA;IA5HFlC,GAAAA,WAAAA,EAAAA,IAAAA;EA5BFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>5645, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/diagnostic/engine.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  ##\n  # {Parser::Diagnostic::Engine} provides a basic API for dealing with\n  # diagnostics by delegating them to registered consumers.\n  #\n  # @example\n  #  buffer      = Parser::Source::Buffer.new(__FILE__, source: 'foobar')\n  #\n  #  consumer = lambda do |diagnostic|\n  #    puts diagnostic.message\n  #  end\n  #\n  #  engine     = Parser::Diagnostic::Engine.new(consumer)\n  #  diagnostic = Parser::Diagnostic.new(\n  #      :warning, :unexpected_token, { :token => 'abc' }, buffer, 1..2)\n  #\n  #  engine.process(diagnostic) # => \"unexpected token abc\"\n  #\n  # @api public\n  #\n  # @!attribute [rw] consumer\n  #  @return [#call(Diagnostic)]\n  #\n  # @!attribute [rw] all_errors_are_fatal\n  #  When set to `true` any error that is encountered will result in\n  #  {Parser::SyntaxError} being raised.\n  #  @return [Boolean]\n  #\n  # @!attribute [rw] ignore_warnings\n  #  When set to `true` warnings will be ignored.\n  #  @return [Boolean]\n  #\n  class Diagnostic::Engine\n    attr_accessor :consumer\n\n    attr_accessor :all_errors_are_fatal\n    attr_accessor :ignore_warnings\n\n    ##\n    # @param [#call(Diagnostic)] consumer\n    #\n    def initialize(consumer=nil)\n      @consumer             = consumer\n\n      @all_errors_are_fatal = false\n      @ignore_warnings      = false\n    end\n\n    ##\n    # Processes a `diagnostic`:\n    #   * Passes the diagnostic to the consumer, if it's not a warning when\n    #     `ignore_warnings` is set.\n    #   * After that, raises {Parser::SyntaxError} when `all_errors_are_fatal`\n    #     is set to true.\n    #\n    # @param [Parser::Diagnostic] diagnostic\n    # @return [Parser::Diagnostic::Engine]\n    # @see ignore?\n    # @see raise?\n    #\n    def process(diagnostic)\n      if ignore?(diagnostic)\n        # do nothing\n      elsif @consumer\n        @consumer.call(diagnostic)\n      end\n\n      if raise?(diagnostic)\n        raise Parser::SyntaxError, diagnostic\n      end\n\n      self\n    end\n\n    protected\n\n    ##\n    # Checks whether `diagnostic` should be ignored.\n    #\n    # @param [Parser::Diagnostic] diagnostic\n    # @return [Boolean]\n    #\n    def ignore?(diagnostic)\n      @ignore_warnings &&\n            diagnostic.level == :warning\n    end\n\n    ##\n    # Checks whether `diagnostic` should be raised as an exception.\n    #\n    # @param [Parser::Diagnostic] diagnostic\n    # @return [Boolean]\n    #\n    def raise?(diagnostic)\n      (@all_errors_are_fatal &&\n          diagnostic.level == :error) ||\n        diagnostic.level == :fatal\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Diagnostic::Engine>", "self", "attr_accessor", "initialize", "consumer", "@consumer", "@all_errors_are_fatal", "@ignore_warnings", "process", "diagnostic", "ignore?", "call", "raise?", "raise", "Parser::SyntaxError", "Parser", "protected", "$ret_or_1", "level", "==", "$ret_or_2", "Diagnostic"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAiCEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACEC,IAAAC,eAAAA,CAAc,UAAdA;MAEAD,IAAAC,eAAAA,CAAc,sBAAdA;MACAD,IAAAC,eAAAA,CAAc,iBAAdA;;AAKAC,MAAAA,0BAAAA,sBAAeC,QAAfD;AAAAA,QAAAA;;;QAAe,iCAAS;QACtBE,gBAAwBD;QAExBE,4BAAwB;QACxBH,OAAAI,CAAAA,uBAAwB,KAAxBA;MAJFJ,CAAAA,IAAAA;;AAmBAK,MAAAA,uBAAAA,mBAAYC,UAAZD;AAAAA,QAAAA;;;QACE,KAAA,QAAGP,IAAAS,YAAAA,CAAQD,UAARC,CAAH,CAAA;UAEA,IAAA,QAAML,aAAN,CAAA;YACEA,aAASM,MAAAA,CAAMF,UAANE;UADX;QAFA;QAMA,IAAA,QAAGV,IAAAW,WAAAA,CAAOH,UAAPG,CAAH,CAAA;UACEX,IAAAY,OAAAA,CAAMC,IAAAC,YAAAD,gBAAN,EAA2BL,UAA3BI;QADF;QAIAL,OAAAP;MAXFO,CAAAA;MAcAP,IAAAe,WAAAA,CAAAA;;AAQAN,MAAAA,uBAAAA,+BAAYD,UAAZC;AAAAA,QAAAA;;QACE,IAAA,QAAAO,CAAAA,YAAAV,oBAAAU,CAAA,CAAA;UACMP,OAAAD,UAAUS,OAAAA,CAAAA,CAAOC,OAAAA,CAAG,SAAHA;QADvB;UAAAT,OAAA;QAAA;MADFA,CAAAA;MAWAV,OAAAY,sBAAAA,8BAAWH,UAAXG;AAAAA,QAAAA;;QACE,IAAA,QAAAK,CAAAA,YAAC,CAAA,QAAAG,CAAAA,YAAAd,yBAAAc,CAAA,CAAA,GAAA,CACGX,UAAUS,OAAAA,CAAAA,CAAOC,OAAAA,CAAG,OAAHA,CADpB,IAAA,CAAA,SAAA,CAAA,CAADF,CAAA,CAAA;UAAAL,OAAA;QAAA;UAEEA,OAAAH,UAAUS,OAAAA,CAAAA,CAAOC,OAAAA,CAAG,OAAHA;QAFnB;MADFP,CAAAA;IA7DFZ,GAAMqB,gBAANrB,EAAAA,IAAAA;EAjCFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>5712, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/static_environment.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  class StaticEnvironment\n    FORWARD_ARGS = :FORWARD_ARGS\n\n    ANONYMOUS_RESTARG_IN_CURRENT_SCOPE = :ANONYMOUS_RESTARG_IN_CURRENT_SCOPE\n    ANONYMOUS_RESTARG_INHERITED = :ANONYMOUS_RESTARG_INHERITED\n\n    ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE = :ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE\n    ANONYMOUS_KWRESTARG_INHERITED = :ANONYMOUS_KWRESTARG_INHERITED\n\n    ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE = :ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE\n    ANONYMOUS_BLOCKARG_INHERITED = :ANONYMOUS_BLOCKARG_INHERITED\n\n    def initialize\n      reset\n    end\n\n    def reset\n      @variables = Set[]\n      @stack     = []\n    end\n\n    def extend_static\n      @stack.push(@variables)\n      @variables = Set[]\n\n      self\n    end\n\n    def extend_dynamic\n      @stack.push(@variables)\n      @variables = @variables.dup\n      if @variables.delete(ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE)\n        @variables.add(ANONYMOUS_BLOCKARG_INHERITED)\n      end\n      if @variables.delete(ANONYMOUS_RESTARG_IN_CURRENT_SCOPE)\n        @variables.add(ANONYMOUS_RESTARG_INHERITED)\n      end\n      if @variables.delete(ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE)\n        @variables.add(ANONYMOUS_KWRESTARG_INHERITED)\n      end\n\n      self\n    end\n\n    def unextend\n      @variables = @stack.pop\n\n      self\n    end\n\n    def declare(name)\n      @variables.add(name.to_sym)\n\n      self\n    end\n\n    def declared?(name)\n      @variables.include?(name.to_sym)\n    end\n\n    # Forward args\n\n    def declare_forward_args\n      declare(FORWARD_ARGS)\n    end\n\n    def declared_forward_args?\n      declared?(FORWARD_ARGS)\n    end\n\n    # Anonymous blockarg\n\n    def declare_anonymous_blockarg\n      declare(ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE)\n    end\n\n    def declared_anonymous_blockarg?\n      declared?(ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE) || declared?(ANONYMOUS_BLOCKARG_INHERITED)\n    end\n\n    def declared_anonymous_blockarg_in_current_scpe?\n      declared?(ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE)\n    end\n\n    def parent_has_anonymous_blockarg?\n      @stack.any? { |variables| variables.include?(ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE) }\n    end\n\n    # Anonymous restarg\n\n    def declare_anonymous_restarg\n      declare(ANONYMOUS_RESTARG_IN_CURRENT_SCOPE)\n    end\n\n    def declared_anonymous_restarg?\n      declared?(ANONYMOUS_RESTARG_IN_CURRENT_SCOPE) || declared?(ANONYMOUS_RESTARG_INHERITED)\n    end\n\n    def declared_anonymous_restarg_in_current_scope?\n      declared?(ANONYMOUS_RESTARG_IN_CURRENT_SCOPE)\n    end\n\n    def parent_has_anonymous_restarg?\n      @stack.any? { |variables| variables.include?(ANONYMOUS_RESTARG_IN_CURRENT_SCOPE) }\n    end\n\n    # Anonymous kwresarg\n\n    def declare_anonymous_kwrestarg\n      declare(ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE)\n    end\n\n    def declared_anonymous_kwrestarg?\n      declared?(ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE) || declared?(ANONYMOUS_KWRESTARG_INHERITED)\n    end\n\n    def declared_anonymous_kwrestarg_in_current_scope?\n      declared?(ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE)\n    end\n\n    def parent_has_anonymous_kwrestarg?\n      @stack.any? { |variables| variables.include?(ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE) }\n    end\n\n    def empty?\n      @stack.empty?\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:StaticEnvironment>", "initialize", "self", "reset", "@variables", "Set", "[]", "@stack", "extend_static", "push", "extend_dynamic", "dup", "delete", "ANONYMOUS_BLOCKARG_IN_CURRENT_SCOPE", "add", "ANONYMOUS_BLOCKARG_INHERITED", "ANONYMOUS_RESTARG_IN_CURRENT_SCOPE", "ANONYMOUS_RESTARG_INHERITED", "ANONYMOUS_KWRESTARG_IN_CURRENT_SCOPE", "ANONYMOUS_KWRESTARG_INHERITED", "unextend", "pop", "declare", "name", "to_sym", "declared?", "include?", "declare_forward_args", "FORWARD_ARGS", "declared_forward_args?", "declare_anonymous_blockarg", "declared_anonymous_blockarg?", "$ret_o