=>["parser/lexer/stack_state.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  class Lexer::StackState\n    def initialize(name)\n      @name  = name.freeze\n      clear\n    end\n\n    def clear\n      @stack = 0\n    end\n\n    def push(bit)\n      bit_value = bit ? 1 : 0\n      @stack = (@stack << 1) | bit_value\n\n      bit\n    end\n\n    def pop\n      bit_value = @stack & 1\n      @stack  >>= 1\n\n      bit_value == 1\n    end\n\n    def lexpop\n      @stack = ((@stack >> 1) | (@stack & 1))\n      @stack[0] == 1\n    end\n\n    def active?\n      @stack[0] == 1\n    end\n\n    def empty?\n      @stack == 0\n    end\n\n    def to_s\n      \"[\#{@stack.to_s(2)} <= \#{@name}]\"\n    end\n\n    alias inspect to_s\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Lexer::StackState>", "initialize", "name", "@name", "freeze", "self", "clear", "0", "push", "bit", "bit_value", "1", "@stack", "<<", "|", "pop", "&", ">>", "==", "lexpop", "[]", "active?", "empty?", "to_s", "2", "Lexer"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAEEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;;AACEC,MAAAA,0BAAAA,sBAAeC,IAAfD;AAAAA,QAAAA;;;QACEE,YAASD,IAAIE,QAAAA,CAAAA;QACbH,OAAAI,IAAAC,OAAAA,CAAAA;MAFFL,CAAAA;;AAKAK,MAAAA,qBAAAA,iBACE,OADFA,EACWC,CADXD,CAAAA;;AAIAE,MAAAA,oBAAAA,gBAASC,GAATD;AAAAA,QAAAA;;;QACEE,YAAY,CAAA,QAAAD,GAAA,CAAA,GAAA,CAAME,CAAN,IAAA,CAAUJ,CAAV,CAAA;QACZK,aAAUA,UAAOC,OAAAA,CAAGF,CAAHE,CAAMC,MAAAA,CAAEJ,SAAFI;QAEvBN,OAAAC;MAJFD,CAAAA;;AAOAO,MAAAA,mBAAAA,eAAAA;AAAAA,QAAAA;;;QACEL,YAAYE,UAAOI,MAAAA,CAAEL,CAAFK;QACnBJ,aAAAA,UAAQK,OAAAA,CAAIN,CAAJM;QAERF,OAAAL,SAAUQ,OAAAA,CAAGP,CAAHO;MAJZH,CAAAA;;AAOAI,MAAAA,sBAAAA,kBAAAA;AAAAA,QAAAA;;;QACEP,aAAWA,UAAOK,OAAAA,CAAGN,CAAHM,CAAMH,MAAAA,CAAGF,UAAOI,MAAAA,CAAEL,CAAFK,CAAVF;QACxBK,OAAAP,UAAMQ,OAAAA,CAACb,CAADa,CAAIF,OAAAA,CAAGP,CAAHO;MAFZC,CAAAA;;AAKAE,MAAAA,uBAAAA,mCAAAA;AAAAA,QAAAA;;QACEA,OAAAT,UAAMQ,OAAAA,CAACb,CAADa,CAAIF,OAAAA,CAAGP,CAAHO;MADZG,CAAAA;;AAIAC,MAAAA,sBAAAA,kCAAAA;AAAAA,QAAAA;;QACEA,OAAAV,UAAOM,OAAAA,CAAGX,CAAHW;MADTI,CAAAA;;AAIAC,MAAAA,oBAAAA,gBAAAA;AAAAA,QAAAA;;QACEA,OAACA,GAAD,GAAA,CAAIX,UAAMW,MAAAA,CAAMC,CAAND,CAAV,CAAA,GAAmBA,MAAnB,GAAA,CAAyBpB,SAAzB,CAAA,GAA+BoB;MADjCA,CAAAA;MAIAvB,OAAA,aAAM,SAAN,EAAc,MAAd;IAzCFA,GAAMyB,WAANzB,EAAAA,IAAAA;EAFFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>18362, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/lexer/dedenter.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  class Lexer::Dedenter\n    # Tab (\\t) counts as 8 spaces\n    TAB_WIDTH = 8\n\n    def initialize(dedent_level)\n      @dedent_level = dedent_level\n      @at_line_begin = true\n      @indent_level  = 0\n    end\n\n    # For a heredoc like\n    #   <<-HERE\n    #     a\n    #     b\n    #   HERE\n    # this method gets called with \"  a\\n\" and \"  b\\n\"\n    #\n    # However, the following heredoc:\n    #\n    #   <<-HERE\n    #     a\\\n    #     b\n    #   HERE\n    # calls this method only once with a string \"  a\\\\\\n  b\\n\"\n    #\n    # This is important because technically it's a single line,\n    # but it has to be concatenated __after__ dedenting.\n    #\n    # It has no effect for non-squiggly heredocs, i.e. it simply removes \"\\\\\\n\"\n    # Of course, lexer could do it but once again: it's all because of dedenting.\n    #\n    def dedent(string)\n      original_encoding = string.encoding\n      # Prevent the following error when processing binary encoded source.\n      # \"\\xC0\".split # => ArgumentError (invalid byte sequence in UTF-8)\n      lines = string.force_encoding(Encoding::BINARY).split(\"\\\\\\n\")\n      if lines.length == 1\n        # If the line continuation sequence was found but there is no second\n        # line, it was not really a line continuation and must be ignored.\n        lines = [string.force_encoding(original_encoding)]\n      else\n        lines.map! {|s| s.force_encoding(original_encoding) }\n      end\n\n      if @at_line_begin\n        lines_to_dedent = lines\n      else\n        _first, *lines_to_dedent = lines\n      end\n\n      lines_to_dedent.each do |line|\n        left_to_remove = @dedent_level\n        remove = 0\n\n        line.each_char do |char|\n          break if left_to_remove <= 0\n          case char\n          when ?\\s\n            remove += 1\n            left_to_remove -= 1\n          when ?\\t\n            break if TAB_WIDTH * (remove / TAB_WIDTH + 1) > @dedent_level\n            remove += 1\n            left_to_remove -= TAB_WIDTH\n          else\n            # no more spaces or tabs\n            break\n          end\n        end\n\n        line.slice!(0, remove)\n      end\n\n      string.replace(lines.join)\n\n      @at_line_begin = string.end_with?(\"\\n\")\n    end\n\n    def interrupt\n      @at_line_begin = false\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Lexer::Dedenter>", "8", "initialize", "dedent_level", "@dedent_level", "@at_line_begin", "@indent_level", "0", "dedent", "string", "original_encoding", "encoding", "lines", "force_encoding", "Encoding::BINARY", "Encoding", "split", "length", "1", "map!", "block in dedent", "s", "block (2 levels) in dedent", "lines_to_dedent", "_first", "each", "line", "left_to_remove", "remove", "each_char", "char$", "block (3 levels) in dedent", "<=", "$ret_or_1", "+", "-", ">", "*", "TAB_WIDTH", "/", "slice!", "replace", "join", "end_with?", "interrupt", "Lexer"], :mappings=>"AAAAA,wCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAEEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MAEE,qCAAYC,CAAZ;;AAEAC,MAAAA,0BAAAA,sBAAeC,YAAfD;AAAAA,QAAAA;;;QACEE,oBAAgBD;QAChBE,qBAAiB;QACjBH,OAAAI,CAAAA,oBAAiBC,CAAjBD;MAHFJ,CAAAA;;AA2BAM,MAAAA,sBAAAA,kBAAWC,MAAXD;AAAAA,QAAAA;;;QACEE,oBAAoBD,MAAME,UAAAA,CAAAA;QAG1BC,QAAQH,MAAMI,gBAAAA,CAAgBC,IAAAC,cAAAD,WAAhBD,CAAiCG,OAAAA,CAAOR,MAAPQ;QAC/C,IAAA,MAAGJ,KAAKK,QAAAA,CAAAA,CAAR,EAAmBC,CAAnB,CAAA;UAGEN,QAAQ,CAACH,MAAMI,gBAAAA,CAAgBH,iBAAhBG,CAAP;QAHV;UAK