eck `lex_state == expr_fname`\n  # + :block - in the block body (tap {})\n  # + :lambda - in the lambda body (-> {})\n  #\n  class Context\n    FLAGS = %i[\n      in_defined\n      in_kwarg\n      in_argdef\n      in_def\n      in_class\n      in_block\n      in_lambda\n    ]\n\n    def initialize\n      reset\n    end\n\n    def reset\n      @in_defined = false\n      @in_kwarg = false\n      @in_argdef = false\n      @in_def = false\n      @in_class = false\n      @in_block = false\n      @in_lambda = false\n    end\n\n    attr_accessor(*FLAGS)\n\n    def in_dynamic_block?\n      in_block || in_lambda\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Context>", "initialize", "self", "reset", "@in_defined", "@in_kwarg", "@in_argdef", "@in_def", "@in_class", "@in_block", "@in_lambda", "attr_accessor", "FLAGS", "in_dynamic_block?", "$ret_or_1", "in_block", "in_lambda"], :mappings=>"AAAAA,iCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAeEA,OAAAC;IAAAA;;MAAAA;;;MACE,iCAAQ,CACN,YADM,EAEN,UAFM,EAGN,WAHM,EAIN,QAJM,EAKN,UALM,EAMN,UANM,EAON,WAPM,CAAR;;AAUAC,MAAAA,0BAAAA,sBAAAA;AAAAA,QAAAA;;QACEA,OAAAC,IAAAC,OAAAA,CAAAA;MADFF,CAAAA;;AAIAE,MAAAA,qBAAAA,iBAAAA;AAAAA,QAAAA;;;QACEC,kBAAc;QACdC,gBAAY;QACZC,iBAAa;QACbC,cAAU;QACVC,gBAAY;QACZC,gBAAY;QACZN,OAAAO,CAAAA,iBAAa,KAAbA;MAPFP,CAAAA;MAUAQ,MAAAT,IAAAS,iBAAAA,EAAc,MAACC,WAAD,CAAdD;MAEAX,OAAAa,iCAAAA,0CAAAA;AAAAA,QAAAA;;QACE,IAAA,QAAAC,CAAAA,YAAAZ,IAAAa,UAAAA,CAAAA,CAAAD,CAAA,CAAA;UAAAD,OAAA;QAAA;UAAYA,OAAAX,IAAAc,WAAAA,CAAAA;QAAZ;MADFH,CAAAA;IA3BFb,GAAAA,WAAAA,EAAAA,IAAAA;EAfFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>20802, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/max_numparam_stack.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  # Holds p->max_numparam from parse.y\n  #\n  # @api private\n  class MaxNumparamStack\n    attr_reader :stack\n\n    ORDINARY_PARAMS = -1\n\n    def initialize\n      @stack = []\n    end\n\n    def empty?\n      @stack.size == 0\n    end\n\n    def has_ordinary_params!\n      set(ORDINARY_PARAMS)\n    end\n\n    def has_ordinary_params?\n      top == ORDINARY_PARAMS\n    end\n\n    def has_numparams?\n      top && top > 0\n    end\n\n    def register(numparam)\n      set( [top, numparam].max )\n    end\n\n    def top\n      @stack.last[:value]\n    end\n\n    def push(static:)\n      @stack.push(value: 0, static: static)\n    end\n\n    def pop\n      @stack.pop[:value]\n    end\n\n    private\n\n    def set(value)\n      @stack.last[:value] = value\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:MaxNumparamStack>", "self", "attr_reader", "-1", "initialize", "@stack", "empty?", "size", "==", "0", "has_ordinary_params!", "set", "ORDINARY_PARAMS", "has_ordinary_params?", "top", "has_numparams?", "$ret_or_1", ">", "register", "numparam", "max", "last", "[]", "push", "$kwargs", "static$", "pop", "private", "value", "[]="], :mappings=>"AAAAA,4CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAKEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACEC,IAAAC,aAAAA,CAAY,OAAZA;MAEA,2CAAkBC,EAAlB;;AAEAC,MAAAA,0BAAAA,sBAAAA;AAAAA,QAAAA;;QACEA,OAAAC,CAAAA,aAAS,EAATA;MADFD,CAAAA;;AAIAE,MAAAA,sBAAAA,wCAAAA;AAAAA,QAAAA;;QACEA,OAAAD,UAAME,MAAAA,CAAAA,CAAMC,OAAAA,CAAGC,CAAHD;MADdF,CAAAA;;AAIAI,MAAAA,oCAAAA,sDAAAA;AAAAA,QAAAA;;QACEA,OAAAT,IAAAU,KAAAA,CAAIC,qBAAJD;MADFD,CAAAA;;AAIAG,MAAAA,oCAAAA,sDAAAA;AAAAA,QAAAA;;QACEA,OAAAZ,IAAAa,KAAAA,CAAAA,CAAIN,OAAAA,CAAGI,qBAAHJ;MADNK,CAAAA;;AAIAE,MAAAA,8BAAAA,gDAAAA;AAAAA,QAAAA;;QACE,IAAA,QAAAC,CAAAA,YAAAf,IAAAa,KAAAA,CAAAA,CAAAE,CAAA,CAAA;UAAOD,OAAIE,OAAJhB,IAAAa,KAAAA,CAAAA,CAAIG,EAAER,CAAFQ;QAAX;UAAAF,OAAA;QAAA;MADFA,CAAAA;;AAIAG,MAAAA,wBAAAA,oBAAaC,QAAbD;AAAAA,QAAAA;;QACEA,OAAAjB,IAAAU,KAAAA,CAAK,CAACV,IAAAa,KAAAA,CAAAA,CAAD,EAAMK,QAAN,CAAeC,KAAAA,CAAAA,CAApBT;MADFO,CAAAA;;AAIAJ,MAAAA,mBAAAA,eAAAA;AAAAA,QAAAA;;QACEA,OAAAT,UAAMgB,MAAAA,CAAAA,CAAKC,OAAAA,CAAC,OAADA;MADbR,CAAAA;;AAIAS,MAAAA,oBAAAA,gBAxCJC,OAwCID;AAAAA,QAAAA;;;QAxCJ;QAwCa;QACPA,OAAAlB,UAAMkB,MAAAA,CAAM,6BAAA,SAAOd,CAAP,EAAA,UAAkBgB,OAAlB,EAANF;MADRA,CAAAA;;AAIAG,MAAAA,mBAAAA,eAAAA;AAAAA,QAAAA;;QACEA,OAAArB,UAAMqB,KAAAA,CAAAA,CAAIJ,OAAAA,CAAC,OAADA;MADZI,CAAAA;MAIAzB,IAAA0B,SAAAA,CAAAA;MAEA3B,OAAAW,mBAAAA,eAAQiB,KAARjB;AAAAA,QAAAA;;QACEA,OAAWkB,MAAAA,CAAC,OAAZ,EAAsBD,KAAXC,CAAAA,EAAAA,MAAXxB,UAAMgB,MAAAA,CAAAA,CAAKQ,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA;MADblB,CAAAA;IA3CFX,GAAAA,WAAAA,EAAAA,IAAAA;EALFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>20890, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/current_arg_stack.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n  # Stack that holds names of current arguments,\n  # i.e. while parsing\n  #   def m1(a = (def m2(b = def m3(c = 1); end); end)); end\n  #                                   ^\n  # stack is [:a, :b, :c]\n  #\n  # Emulates `p->cur_arg` in MRI's parse.y\n  #\n  # @api private\n  #\n  class CurrentArgStack\n    attr_reader :stack\n\n    def initialize\n      @stack = []\n      freeze\n    end\n\n    def empty?\n      @stack.size == 0\n    end\n\n    def push(value)\n      @stack << value\n    end\n\n    def set(value)\n      @stack[@stack.length - 1] = value\n    end\n\n    def pop\n      @stack.pop\n    end\n\n    def reset\n      @stack.clear\n    end\n\n    def top\n      @stack.last\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:CurrentArgStack>", "self", "attr_reader", "initialize", "@stack", "freeze", "empty?", "size", "==", "0", "push", "value", "<<", "set", "[]=", "-", "length", "1", "pop", "reset", "clear", "top", "last"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAWEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACEC,IAAAC,aAAAA,CAAY,OAAZA;;AAEAC,MAAAA,0BAAAA,sBAAAA;AAAAA,QAAAA;;;QACEC,aAAS;QACTD,OAAAF,IAAAI,QAAAA,CAAAA;MAFFF,CAAAA;;AAKAG,MAAAA,sBAAAA,uCAAAA;AAAAA,QAAAA;;QACEA,OAAAF,UAAMG,MAAAA,CAAAA,CAAMC,OAAAA,CAAGC,CAAHD;MADdF,CAAAA;;AAIAI,MAAAA,oBAAAA,gBAASC,KAATD;AAAAA,QAAAA;;QACEA,OAAAN,UAAOQ,OAAAA,CAAGD,KAAHC;MADTF,CAAAA;;AAIAG,MAAAA,mBAAAA,eAAQF,KAARE;AAAAA,QAAAA;;QACEA,OAAMC,MAAAA,CAAeC,UAAdX,UAAMY,QAAAA,CAAAA,CAAQD,EAAEE,CAAFF,CAArB,EAA4BJ,KAAtBG,CAAAA,EAAAA,MAANV,UAAMU,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA;MADRD,CAAAA;;AAIAK,MAAAA,mBAAAA,eAAAA;AAAAA,QAAAA;;QACEA,OAAAd,UAAMc,KAAAA,CAAAA;MADRA,CAAAA;;AAIAC,MAAAA,qBAAAA,iBAAAA;AAAAA,QAAAA;;QACEA,OAAAf,UAAMgB,OAAAA,CAAAA;MADRD,CAAAA;MAIAnB,OAAAqB,mBAAAA,eAAAA;AAAAA,QAAAA;;QACEA,OAAAjB,UAAMkB,MAAAA,CAAAA;MADRD,CAAAA;IA5BFrB,GAAAA,WAAAA,EAAAA,IAAAA;EAXFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>20953, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/variables_stack.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  class VariablesStack\n    def initialize\n      @stack = []\n      push\n    end\n\n    def empty?\n      @stack.empty?\n    end\n\n    def push\n      @stack << Set.new\n    end\n\n    def pop\n      @stack.pop\n    end\n\n    def reset\n      @stack.clear\n    end\n\n    def declare(name)\n      @stack.last << name.to_sym\n    end\n\n    def declared?(name)\n      @stack.last.include?(name.to_sym)\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:VariablesStack>", "initialize", "@stack", "self", "push", "empty?", "<<", "Set", "new", "pop", "reset", "clear", "declare", "name", "last", "to_sym", "declared?", "include?"], :mappings=>"AAAAA,yCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAEEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;;AACEC,MAAAA,0BAAAA,sBAAAA;AAAAA,QAAAA;;;QACEC,aAAS;QACTD,OAAAE,IAAAC,MAAAA,CAAAA;MAFFH,CAAAA;;AAKAI,MAAAA,sBAAAA,sCAAAA;AAAAA,QAAAA;;QACEA,OAAAH,UAAMG,WAAAA,CAAAA;MADRA,CAAAA;;AAIAD,MAAAA,oBAAAA,gBAAAA;AAAAA,QAAAA;;QACEA,OAAAF,UAAOI,OAAAA,CAAGC,SAAGC,KAAAA,CAAAA,CAANF;MADTF,CAAAA;;AAIAK,MAAAA,mBAAAA,eAAAA;AAAAA,QAAAA;;QACEA,OAAAP,UAAMO,KAAAA,CAAAA;MADRA,CAAAA;;AAIAC,MAAAA,qBAAAA,iBAAAA;AAAAA,QAAAA;;QACEA,OAAAR,UAAMS,OAAAA,CAAAA;MADRD,CAAAA;;AAIAE,MAAAA,uBAAAA,mBAAYC,IAAZD;AAAAA,QAAAA;;QACEA,OAAAV,UAAMY,MAAAA,CAAAA,CAAMR,OAAAA,CAAGO,IAAIE,QAAAA,CAAAA,CAAPT;MADdM,CAAAA;MAIAZ,OAAAgB,yBAAAA,yCAAcH,IAAdG;AAAAA,QAAAA;;QACEA,OAAAd,UAAMY,MAAAA,CAAAA,CAAKG,aAAAA,CAAUJ,IAAIE,QAAAA,CAAAA,CAAdE;MADbD,CAAAA;IA1BFhB,GAAAA,WAAAA,EAAAA,IAAAA;EAFFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>21015, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["parser/base.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Parser\n\n  ##\n  # Base class for version-specific parsers.\n  #\n  # @api public\n  #\n  # @!attribute [r] diagnostics\n  #  @return [Parser::Diagnostic::Engine]\n  #\n  # @!attribute [r] static_env\n  #  @return [Parser::StaticEnvironment]\n  #\n  class Base < Racc::Parser\n    ##\n    # Parses a string of Ruby code and returns the AST. If the source\n    # cannot be parsed, {SyntaxError} is raised and a diagnostic is\n    # printed to `stderr`.\n    #\n    # @example\n    #  Parser::Base.parse('puts \"hello\"')\n    #\n    # @param [String] string The block of code to parse.\n    # @param [String] file The name of the file the code originated from.\n    # @param [Numeric] line The initial line number.\n    # @return [Parser::AST::Node]\n    #\n    def self.parse(string, file='(string)', line=1)\n      parser = default_parser\n      source_buffer = setup_source_buffer(file, line, string, parser.default_encoding)\n      parser.parse(source_buffer)\n    end\n\n    ##\n    # Parses a string of Ruby code and returns the AST and comments. If the\n    # source cannot be parsed, {SyntaxError} is raised and a diagnostic is\n    # printed to `stderr`.\n    #\n    # @example\n    #  Parser::Base.parse_with_comments('puts \"hello\"')\n    #\n    # @param [String] string The block of code to parse.\n    # @param [String] file The name of the file the code originated from.\n    # @param [Numeric] line The initial line number.\n    # @return [Array]\n    #\n    def self.parse_with_comments(string, file='(string)', line=1)\n      parser = default_parser\n      source_buffer = setup_source_buffer(file, line, string, parser.default_encoding)\n      parser.parse_with_comments(source_buffer)\n    end\n\n    ##\n    # Parses Ruby source code by reading it from a file. If the source\n    # cannot be parsed, {SyntaxError} is raised and a diagnostic is\n    # printed to `stderr`.\n    #\n    # @param [String] filename Path to the file to parse.\n    # @return [Parser::AST::Node]\n    # @see #parse\n    #\n    def self.parse_file(filename)\n      parse(File.read(filename), filename)\n    end\n\n    ##\n    # Parses Ruby source code by reading it from a file and returns the AST and\n    # comments. If the source cannot be parsed, {SyntaxError} is raised and a\n    # diagnostic is printed to `stderr`.\n    #\n    # @param [String] filename Path to the file to parse.\n    # @return [Array]\n    # @see #parse\n    #\n    def self.parse_file_with_comments(filename)\n      parse_with_comments(File.read(filename), filename)\n    end\n\n    ##\n    # @return [Parser::Base] parser with the default options set.\n    #\n    def self.default_parser\n      parser = new\n\n      parser.diagnostics.all_errors_are_fatal = true\n      parser.diagnostics.ignore_warnings      = true\n\n      parser.diagnostics.consumer = lambda do |diagnostic|\n        $stderr.puts(diagnostic.render)\n      end\n\n      parser\n    end\n\n    def self.setup_source_buffer(file, line, string, encoding)\n      string = string.dup.force_encoding(encoding)\n\n      source_buffer = Source::Buffer.new(file, line)\n\n      if name == 'Parser::Ruby18'\n        source_buffer.raw_source = string\n      else\n        source_buffer.source     = string\n      end\n\n      source_buffer\n    end\n    private_class_method :setup_source_buffer\n\n    attr_reader :lexer\n    attr_reader :diagnostics\n    attr_reader :builder\n    attr_reader :static_env\n    attr_reader :source_buffer\n    attr_reader :context\n    attr_reader :max_numparam_stack\n    attr_reader :current_arg_stack\n    attr_reader :pattern_variables\n    attr_reader :pattern_hash_keys\n\n    ##\n    # @param [Parser::Builders::Default] builder The AST builder to use.\n    #\n    def initialize(builder=Parser::Builders::Default.new)\n      @diagnostics = Diagnostic::Engine.new\n\n      @static_env  = StaticEnvironment.new\n\n      # Stack that holds current parsing context\n      @context = Context.new\n\n      # Maximum numbered parameters stack\n      @max_numparam_stack = MaxNumparamStack.new\n\n      # Current argument names stack\n      @current_arg_stack = CurrentArgStack.new\n\n      # Stack of set of variables used in the current pattern\n      @pattern_variables = VariablesStack.new\n\n      # Stack of set of keys used in the current hash in pattern matchinig\n      @pattern_hash_keys = VariablesStack.new\n\n      @lexer = Lexer.new(version)\n      @lexer.diagnostics = @diagnostics\n      @lexer.static_env  = @static_env\n      @lexer.context     = @context\n\n      @builder = builder\n      @builder.parser = self\n\n      # Last emitted token\n      @last_token = nil\n\n      if self.class::Racc_debug_parser && ENV['RACC_DEBUG']\n        @yydebug = true\n      end\n\n      reset\n    end\n\n    ##\n    # Resets the state of the parser.\n    #\n    def reset\n      @source_buffer = nil\n\n      @lexer.reset\n      @static_env.reset\n      @context.reset\n      @current_arg_stack.reset\n      @pattern_variables.reset\n      @pattern_hash_keys.reset\n\n      self\n    end\n\n    ##\n    # Parses a source buffer and returns the AST, or `nil` in case of a non fatal error.\n    #\n    # @param [Parser::Source::Buffer] source_buffer The source buffer to parse.\n    # @return [Parser::AST::Node, nil]\n    #\n    def parse(source_buffer)\n      @lexer.source_buffer = source_buffer\n      @source_buffer       = source_buffer\n\n      do_parse || nil # Force `false` to `nil`, see https://github.com/ruby/racc/pull/136\n    ensure\n      # Don't keep references to the source file.\n      @source_buffer       = nil\n      @lexer.source_buffer = nil\n    end\n\n    ##\n    # Parses a source buffer and returns the AST and the source code comments.\n    #\n    # @see #parse\n    # @see Parser::Source::Comment#associate\n    # @return [Array]\n    #\n    def parse_with_comments(source_buffer)\n      @lexer.comments = []\n\n      [ parse(source_buffer), @lexer.comments ]\n    ensure\n      @lexer.comments = nil\n    end\n\n    ##\n    # Parses a source buffer and returns the AST, the source code comments,\n    # and the tokens emitted by the lexer. In case of a fatal error, a {SyntaxError}\n    # is raised, unless `recover` is true. In case of an error\n    # (non-fatal or recovered), `nil` is returned instead of the AST, and\n    # comments as well as tokens are only returned up to the location of\n    # the error.\n    #\n    # Currently, token stream format returned by #tokenize is not documented,\n    # but is considered part of a public API and only changed according\n    # to Semantic Versioning.\n    #\n    # However, note that the exact token composition of various constructs\n    # might vary. For example, a string `\"foo\"` is represented equally well\n    # by `:tSTRING_BEG \" :tSTRING_CONTENT foo :tSTRING_END \"` and\n    # `:tSTRING \"foo\"`; such details must not be relied upon.\n    #\n    # @param [Parser::Source::Buffer] source_buffer\n    # @param [Boolean] recover If true, recover from syntax errors. False by default.\n    # @return [Array]\n    #\n    def tokenize(source_buffer, recover=false)\n      @lexer.tokens = []\n      @lexer.comments = []\n\n      begin\n        ast = parse(source_buffer)\n      rescue Parser::SyntaxError\n        raise if !recover\n      end\n\n      [ ast, @lexer.comments, @lexer.tokens ]\n    ensure\n      @lexer.tokens = nil\n      @lexer.comments = nil\n    end\n\n    private\n\n    def next_token\n      token = @lexer.advance\n      @last_token = token\n      token\n    end\n\n    def check_kwarg_name(name_t)\n      case name_t[0]\n      when /^[a-z_]/\n        # OK\n      when /^[A-Z]/\n        diagnostic :error, :argument_const, nil, name_t\n      end\n    end\n\n    def diagnostic(level, reason, arguments, location_t, highlights_ts=[])\n      _, location = location_t\n\n      highlights = highlights_ts.map do |token|\n        _, range = token\n        range\n      end\n\n      @diagnostics.process(\n          Diagnostic.new(level, reason, arguments, location, highlights))\n\n      if level == :error\n        yyerror\n      end\n    end\n\n    def on_error(error_token_id, error_value, value_stack)\n      token_name = token_to_str(error_token_id)\n      _, location = error_value\n\n      @diagnostics.process(Diagnostic.new(\n          :error, :unexpected_token, { :token => token_name }, location))\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Base>", "parse", "self", "string", "file", "line", "1", "parser", "default_parser", "source_buffer", "setup_source_buffer", "default_encoding", "parse_with_comments", "parse_file", "filename", "File", "read", "parse_file_with_comments", "new", "diagnostics", "all_errors_are_fatal=", "ignore_warnings=", "consumer=", "lambda", "block in default_parser", "diagnostic", "block (2 levels) in default_parser", "$stderr", "puts", "render", "encoding", "dup", "force_encoding", "Source::Buffer", "Source", "name", "raw_source=", "source=", "private_class_method", "attr_reader", "initialize", "builder", "Parser::Builders::Default", "Parser::Builders", "Parser", "@diagnostics", "Diagnostic::Engine", "Diagnostic", "@static_env", "StaticEnvironment", "@context", "Context", "@max_numparam_stack", "MaxNumparamStack", "@current_arg_stack", "CurrentArgStack", "@pattern_variables", "VariablesStack", "@pattern_hash_keys", "@lexer", "Lexer", "version", "diagnostics=", "static_env=", "context=", "@builder", "parser=", "@last_token", "class::Racc_debug_parser", "class", "ENV", "[]", "@yydebug", "reset", "@sou