ap(range, before, after)\n    end\n\n    ##\n    # Inserts new code before the given source range.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def insert_before(range, content)\n      @source_rewriter.insert_before(range, content)\n    end\n\n    ##\n    # Inserts new code after the given source range.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def insert_after(range, content)\n      @source_rewriter.insert_after(range, content)\n    end\n\n    ##\n    # Replaces the code of the source range `range` with `content`.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def replace(range, content)\n      @source_rewriter.replace(range, content)\n    end\n\n    DEPRECATION_WARNING = [\n      'Parser::Rewriter is deprecated.',\n      'Please update your code to use Parser::TreeRewriter instead'\n    ].join(\"\\n\").freeze\n\n    extend Deprecation\n\n    def initialize(*)\n      self.class.warn_of_deprecation\n      Source::Rewriter.warned_of_deprecation = true\n      super\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:Rewriter>", "rewrite", "source_buffer", "ast", "@source_rewriter", "Source::Rewriter", "Source", "new", "self", "process", "assignment?", "node", "include?", "type", "remove", "range", "wrap", "before", "after", "insert_before", "content", "insert_after", "replace", "join", "freeze", "extend", "Deprecation", "initialize", "class", "warn_of_deprecation", "warned_of_deprecation=", "$fwd_rest", "Parser::AST::Processor", "Parser::AST", "Parser"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAWEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;;AASEC,MAAAA,uBAAAA,mBAAYC,aAAD,EAAgBC,GAA3BF;AAAAA,QAAAA;;;QACEG,uBAAmBC,IAAAC,YAAAD,aAAgBE,KAAAA,CAAKL,aAALK;QAEnCC,IAAAC,SAAAA,CAAQN,GAARM;QAEAR,OAAAG,oBAAgBK,SAAAA,CAAAA;MALlBR,CAAAA;;AAeAS,MAAAA,2BAAAA,qCAAgBC,IAAhBD;AAAAA;QACEA,OAAA,CAAC,Q