 #     code = <<-EOF\n  #     while true do\n  #       puts 'hello'\n  #     end\n  #     EOF\n  #\n  #     ast           = Parser::CurrentRuby.parse code\n  #     buffer        = Parser::Source::Buffer.new('(example)', source: code)\n  #     rewriter      = RemoveDo.new\n  #\n  #     # Rewrite the AST, returns a String with the new form.\n  #     puts rewriter.rewrite(buffer, ast)\n  #\n  # This would result in the following Ruby code:\n  #\n  #     while true\n  #       puts 'hello'\n  #     end\n  #\n  # Keep in mind that {Parser::TreeRewriter} does not take care of indentation when\n  # inserting/replacing code so you'll have to do this yourself.\n  #\n  # See also [a blog entry](http://whitequark.org/blog/2013/04/26/lets-play-with-ruby-code/)\n  # describing rewriters in greater detail.\n  #\n  # @api public\n  #\n  class TreeRewriter < Parser::AST::Processor\n    ##\n    # Rewrites the AST/source buffer and returns a String containing the new\n    # version.\n    #\n    # @param [Parser::Source::Buffer] source_buffer\n    # @param [Parser::AST::Node] ast\n    # @param [Symbol] crossing_deletions:, different_replacements:, swallowed_insertions:\n    #                 policy arguments for TreeRewriter (optional)\n    # @return [String]\n    #\n    def rewrite(source_buffer,\n                ast,\n                **policy)\n      @source_rewriter = Parser::Source::TreeRewriter.new(source_buffer, **policy)\n\n      process(ast)\n\n      @source_rewriter.process\n    end\n\n    ##\n    # Returns `true` if the specified node is an assignment node, returns false\n    # otherwise.\n    #\n    # @param [Parser::AST::Node] node\n    # @return [Boolean]\n    #\n    def assignment?(node)\n      [:lvasgn, :ivasgn, :gvasgn, :cvasgn, :casgn].include?(node.type)\n    end\n\n    ##\n    # Removes the source range.\n    #\n    # @param [Parser::Source::Range] range\n    #\n    def remove(range)\n      @source_rewriter.remove(range)\n    end\n\n    ##\n    # Wraps the given source range with the given values.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def wrap(range, before, after)\n      @source_rewriter.wrap(range, before, after)\n    end\n\n    ##\n    # Inserts new code before the given source range.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def insert_before(range, content)\n      @source_rewriter.insert_before(range, content)\n    end\n\n    ##\n    # Inserts new code after the given source range.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def insert_after(range, content)\n      @source_rewriter.insert_after(range, content)\n    end\n\n    ##\n    # Replaces the code of the source range `range` with `content`.\n    #\n    # @param [Parser::Source::Range] range\n    # @param [String] content\n    #\n    def replace(range, content)\n      @source_rewriter.replace(range, content)\n    end\n  end\n\nend\n"], :names=>["<top (required)>", "<module:Parser>", "<class:TreeRewriter>", "rewrite", "source_buffer", "ast", "$kwargs", "@source_rewriter", "Parser::Source::TreeRewriter", "Parser::Source", "Parser", "new", "policy", "self", "process", "assignment?", "node", "include?", "type", "remove", "range", "wrap", "before", "after", "insert_before", "content", "insert_after", "replace", "Parser::AST::Processor", "Parser::AST"], :mappings=>"AAAAA,uCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAgDEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;;AAWEC,MAAAA,uBAAAA,mBAAYC,aAAD,EACCC,GADD,EA7DfC,OA6DIH;AAAAA,QAAAA;;;QA7DJ;QA+DgB;QACVI,uBAAmBC,IAAAC,IAAAC,YAAAD,WAAAD,iBAA4BG,KAAAA,CAAKP,aAAjC,EAAgD,aAAEQ,MAAF,CAApBD;QAE/CE,IAAAC,SAAAA,CAAQT,GAARS;QAEAX,OAAAI,oBAAgBO,SAAAA,CAAAA;MAPlBX,CAAAA,IAAAA;;AAiBAY,MAAAA,2BAAAA,yCAAgBC,IAAhBD;AAAAA;QACEA,OAAA,CAAC,QAAD,EAAU,QAAV,EAAmB,QAAnB,EAA4B,QAA5B,EAAqC,OAArC,CAA4CE,aAAAA,CAAUD,IAAIE,MAAAA,CAAAA,CAAdD;MAD9CF,CAAAA;;AASAI,MAAAA,sBAAAA,kBAAWC,KAAXD;AAAAA,QAAAA;;QACEA,OAAAZ,o