,GAAGhN,OAAAA,CAACwC,CAADxC;MADlCy7B,CAAAA;;AAMAC,MAAAA,2BAAAA,uBAAgB1uB,GAAD,EAAMC,OAAN,EAAeC,MAA9BwuB;AAAAA;QAC+BA,OAAA1uB,GAAGhN,OAAAA,CAACwC,CAADxC;MADlC07B,CAAAA;;AAMAC,MAAAA,2BAAAA,uBAAgB3uB,GAAD,EAAMC,OAAN,EAAeC,MAA9ByuB;AAAAA;QAC+BA,OAAA3uB,GAAGhN,OAAAA,CAACwC,CAADxC;MADlC27B,CAAAA;;AAUAC,MAAAA,2BAAAA,uBAAgB5uB,GAAD,EAAMC,OAAN,EAAeC,MAA9B0uB;AAAAA,QAAAA;;;QACoBz8B,IAAA08B,SAAAA,CAAAA;QAEhBD,OAAA1uB;MAHJ0uB,CAAAA;;AAYAE,MAAAA,2BAAAA,YAC6B,GAD7BA,CAAAA;MAMAv8B,OAAAw8B,4BAAAA,wBAAiB/uB,GAAD,EAAMC,OAAN,EAAeC,MAA/B6uB;AAAAA;QACEA,OAAA/uB,GAAGhN,OAAAA,CAACC,CAADD;MADL+7B,CAAAA;IA74YEx8B,GAAAA,WAAAA,EAAey8B,IAAAC,YAAAD,SAAfz8B;EADFD,GAAAA,WAAAA;AAZAJ;"}}, {:offset=>{:line=>25275, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/ast/builder.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/ast/node'\nrequire 'parser/ruby32'\n\nmodule Opal\n  module AST\n    class Builder < ::Parser::Builders::Default\n      self.emit_lambda = true\n\n      def n(type, children, location)\n        ::Opal::AST::Node.new(type, children, location: location)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:AST>", "<class:Builder>", "emit_lambda=", "n", "type", "children", "location", "Opal::AST::Node", "Opal::AST", "Opal", "new", "Parser::Builders::Default", "Parser::Builders", "Parser"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,eAARE;EACAD,IAAAC,SAAAA,CAAQF,eAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;;QACEJ,IAAIK,iBAAAA,CAAe,IAAfA;QAEJD,OAAAE,iBAAAA,aAAMC,IAAD,EAAOC,QAAP,EAAiBC,QAAtBH;AAAAA;UACEA,OAAAI,IAAAC,IAAAC,KAAAD,QAAAD,SAAiBG,KAAAA,CAAKN,IAAtB,EAA4BC,QAA5B,EAAsC,sBAAA,YAAUC,QAAV,EAArBI;QADnBP,CAAAA;MAHFF,GAAAA,WAAAA,EAAgBU,IAAAC,IAAAC,aAAAD,aAAAD,YAAhBV;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>25306, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/base.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'parser'\nrequire 'opal/ast/node'\n\nmodule Opal\n  module Rewriters\n    class Base < ::Parser::AST::Processor\n      class DummyLocation\n        def node=(*)\n          # stub\n        end\n\n        def expression\n          self\n        end\n\n        def begin_pos\n          0\n        end\n\n        def end_pos\n          0\n        end\n\n        def source\n          ''\n        end\n\n        def line\n          0\n        end\n\n        def column\n          0\n        end\n\n        def last_line\n          Float::INFINITY\n        end\n      end\n      DUMMY_LOCATION = DummyLocation.new\n\n      def s(type, *children)\n        loc = current_node ? current_node.loc : DUMMY_LOCATION\n        ::Opal::AST::Node.new(type, children, location: loc)\n      end\n\n      def self.s(type, *children)\n        ::Opal::AST::Node.new(type, children, location: DUMMY_LOCATION)\n      end\n\n      alias on_iter       process_regular_node\n      alias on_zsuper     process_regular_node\n      alias on_jscall     on_send\n      alias on_jsattr     process_regular_node\n      alias on_jsattrasgn process_regular_node\n      alias on_kwsplat    process_regular_node\n\n      # Prepends given +node+ to +body+ node.\n      #\n      # Supports +body+ to be one of:\n      # 1. nil                     - empty body\n      # 2. s(:begin) / s(:kwbegin) - multiline body\n      # 3. s(:anything_else)       - singleline body\n      #\n      # Returns a new body with +node+ injected as a first statement.\n      #\n      def prepend_to_body(body, node)\n        stmts = stmts_of(node) + stmts_of(body)\n        begin_with_stmts(stmts)\n      end\n\n      # Appends given +node+ to +body+ node.\n      #\n      # Supports +body+ to be one of:\n      # 1. nil                     - empty body\n      # 2. s(:begin) / s(:kwbegin) - multiline body\n      # 3. s(:anything_else)       - singleline body\n      #\n      # Returns a new body with +node+ injected as a last statement.\n      #\n      def append_to_body(body, node)\n        stmts = stmts_of(body) + stmts_of(node)\n        begin_with_stmts(stmts)\n      end\n\n      def stmts_of(node)\n        if node.nil?\n          []\n        elsif %i[begin kwbegin].include?(node.type)\n          node.children\n        else\n          [node]\n        end\n      end\n\n      def begin_with_stmts(stmts)\n        case stmts.length\n        when 0\n          nil\n        when 1\n          stmts[0]\n        else\n          s(:begin, *stmts)\n        end\n      end\n\n      # Store the current node for reporting.\n      attr_accessor :current_node\n\n      # Intercept the main call and assign current node.\n      def process(node)\n        self.current_node = node\n        super\n      ensure\n        self.current_node = nil\n      end\n\n      # This is called when a rewriting error occurs.\n      def error(msg)\n        error = ::Opal::RewritingError.new(msg)\n        error.location = current_node.loc if current_node\n        raise error\n      end\n\n      def on_top(node)\n        node = process_regular_node(node)\n        node.meta[:dynamic_cache_result] = true if @dynamic_cache_result\n        node\n      end\n\n      # Called when a given transformation is deemed to be dynamic, so\n      # that cache is conditionally disabled for a given file.\n      def dynamic!\n        @dynamic_cache_result = true\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:Base>", "<class:DummyLocation>", "node=", "expression", "begin_pos", "0", "end_pos", "source", "line", "column", "last_line", "Float::INFINITY", "Float", "DummyLocation", "new", "s", "type", "loc", "current_node", "DUMMY_LOCATION", "Opal::AST::Node", "Opal::AST", "Opal", "children", "prepend_to_body", "body", "node", "stmts", "+", "stmts_of", "begin_with_stmts", "append_to_body", "nil?", "include?", "length", "1", "[]", "attr_accessor", "proc