bG;AAAAA;UACE,IAAA,QAAGH,IAAIM,SAAAA,CAAAA,CAAP,CAAA;YACEH,OAAA;UADF,OAEA,IAAA,QAAM,CAAG,OAAH,EAAS,SAAT,CAAiBI,aAAAA,CAAUP,IAAIV,MAAAA,CAAAA,CAAdiB,CAAvB,CAAA;YACEJ,OAAAH,IAAIH,UAAAA,CAAAA;UADN;YAGEM,OAAA,CAACH,IAAD;UAHF;QAHFG,CAAAA;;AAUAC,QAAAA,gCAAAA,4BAAqBH,KAArBG;AAAAA,UAAAA;;;UAEE,QADKH,KAAKO,QAAAA,CAAAA,CACV;YAAA,KAAK7B,CAAL;cACEyB,OAAA;YACF,KAAKK,CAAL;cACEL,OAAAH,KAAKS,OAAAA,CAAC/B,CAAD+B;YADP;cAGEN,OAAAf,MAAAnB,IAAAmB,KAAAA,EAAA,CAAE,OAAF,CAAA,QAAU,MAACY,KAAD,CAAV,CAAAZ;UALF;QAFFe,CAAAA;QAYAlC,IAAAyC,eAAAA,CAAc,cAAdA;;AAGAC,QAAAA,uBAAAA,mBAAYZ,IAAZY;AAAAA,UAAAA;;UAAAA;UACEA,OAAA,cAAA;;UAAA1C,IAAI2C,kBAAAA,CAAgBb,IAAhBa;UACJD,OAAA,OAAA1C,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAA8B,IAAA,CAAA,EAAA,MAAA;UADA;YAGIa,MAAAA,CAAgB,GAAhBA,CAAAA,EAAAA,MAAJ3C,IAAI2C,iBAAAA,EAAAA,EAAAA,CAAAA,EAAAA;UAHJ,CAAA;QADFD,CAAAA;;AAQAE,QAAAA,qBAAAA,iBAAUC,GAAVD;AAAAA,UAAAA;;;UACEA,QAAQE,IAAApB,KAAAoB,mBAAsB5B,KAAAA,CAAK2B,GAAL3B;UAC9B,IAAA,QAAqClB,IAAAsB,cAAAA,CAAAA,CAArC,CAAA;YAAAsB,KAAKG,cAAAA,CAAY/C,IAAAsB,cAAAA,CAAAA,CAAYD,KAAAA,CAAAA,CAAxB0B;UAAL;UACAH,OAAA5C,IAAAgD,OAAAA,CAAMJ,KAANI;QAHFJ,CAAAA;;AAMAK,QAAAA,sBAAAA,kBAAWnB,IAAXmB;AAAAA,UAAAA;;;UACEnB,OAAO9B,IAAAkD,sBAAAA,CAAqBpB,IAArBoB;UACP,IAAA,QAA2CC,yBAA3C,CAAA;YAAArB,IAAIsB,MAAAA,CAAAA,CAAKC,QAAAA,CAAC,sBAAV,EAAmC,IAA1BA;UAAT;UACAJ,OAAAnB;QAHFmB,CAAAA;QAQA7C,OAAAkD,wBAAAA,iBACE,sBADFA,EAC0B,IAD1BA,CAAAA;MA/HFlD,GAAAA,WAAAA,EAAamD,IAAAC,IAAAC,aAAAD,QAAAD,cAAbnD;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>25469, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/opal_engine_check.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class OpalEngineCheck < Base\n      def on_if(node)\n        test, true_body, false_body = *node.children\n\n        if skip_check_present?(test)\n          process(true_body || s(:nil))\n        elsif skip_check_present_not?(test)\n          process(false_body || s(:nil))\n        else\n          super\n        end\n      end\n\n      def skip_check_present?(test)\n        test == RUBY_ENGINE_CHECK || test == RUBY_PLATFORM_CHECK\n      end\n\n      def skip_check_present_not?(test)\n        test == RUBY_ENGINE_CHECK_NOT || test == RUBY_PLATFORM_CHECK_NOT\n      end\n\n      RUBY_ENGINE_CHECK = s(:send, s(:const, nil, :RUBY_ENGINE),\n        :==, s(:str, 'opal')\n      )\n\n      RUBY_ENGINE_CHECK_NOT = s(:send, s(:const, nil, :RUBY_ENGINE),\n        :!=, s(:str, 'opal')\n      )\n\n      RUBY_PLATFORM_CHECK = s(:send, s(:const, nil, :RUBY_PLATFORM),\n        :==, s(:str, 'opal')\n      )\n\n      RUBY_PLATFORM_CHECK_NOT = s(:send, s(:const, nil, :RUBY_PLATFORM),\n        :!=, s(:str, 'opal')\n      )\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:OpalEngineCheck>", "on_if", "node", "children", "test", "true_body", "false_body", "skip_check_present?", "process", "$ret_or_1", "s", "skip_check_present_not?", "==", "RUBY_ENGINE_CHECK", "RUBY_PLATFORM_CHECK", "RUBY_ENGINE_CHECK_NOT", "RUBY_PLATFORM_CHECK_NOT", "Base"], :mappings=>"AAAAA,mDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;;AACEC,QAAAA,qBAAAA,iBAAUC,IAAVD;AAAAA,UAAAA;;UAAAA;;UACE,KAA8B,UAAA,MAACC,IAAIC,UAAAA,CAAAA,CAAL,CAAA,CAA9B,EAAAC,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,YAAN,6BAAMA,CAAN,EAAiBC,CAAAA,aAAjB,6BAAiBA,CAAjB;UAEA,IAAA,QAAGV,IAAAW,wBAAAA,CAAoBH,IAApBG,CAAH,CAAA;YACEN,OAAAL,IAAAY,SAAAA,CAAQ,CAAA,QAAAC,CAAAA,YAAAJ,SAAAI,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAab,IAAAc,GAAAA,CAAE,KAAFA,CAAb,CAAA,CAARF;UADF,OAEA,IAAA,QAAMZ,IAAAe,4BAAAA,CAAwBP,IAAxBO,CAAN,CAAA;YACEV,OAAAL,IAAAY,SAAAA,CAAQ,CAAA,QAAAC,CAAAA,YAAAH,UAAAG,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAcb,IAAAc,GAAAA,CAAE,KAAFA,CAAd,CAAA,CAARF;UADF;YAGEP,OAAA,OAAAL,IAAA,EAAA,gDAAA,SAAA,EAAA,CAAAM,IAAA,CAAA,EAAA,MAAA;UAHF;QALFD,CAAAA;;AAYAM,QAAAA,mCAAAA,oDAAwBH,IAAxBG;AAAAA,UAAAA;;UACE,IAAA,QAAAE,CAAAA,YAAAL,IAAKQ,OAAAA,CAAGC,uBAAHD,CAALH,CAAA,CAAA;YAAAF,OAAA;UAAA;YAA6BA,OAAAH,IAAKQ,OAAAA,CAAGE,yBAAHF;UAAlC;QADFL,CAAAA;;AAIAI,QAAAA,uCAAAA,wDAA4BP,IAA5BO;AAAAA,UAAAA;;UACE,IAAA,QAAAF,CAAAA,YAAAL,IAAKQ,OAAAA,CAAGG,2BAAHH,CAALH,CAAA,CAAA;YAAAE,OAAA;UAAA;YAAiCA,OAAAP,IAAKQ,OAAAA,CAAGI,6BAAHJ;UAAtC;QADFD,CAAAA;QAIA,6CAAoBf,IAAAc,GAAAA,CAAE,MAAF,EAASd,IAAAc,GAAAA,CAAE,OAAF,EAAU,GAAV,EAAe,aAAfA,CAAT,EAClB,IADkB,EACbd,IAAAc,GAAAA,CAAE,KAAF,EAAQV,MAARU,CADaA,CAApB;QAIA,iDAAwBd,IAAAc,GAAAA,CAAE,MAAF,EAASd,IAAAc,GAAAA,CAAE,OAAF,EAAU,GAAV,EAAe,aAAfA,CAAT,EACtB,IADsB,EACjBd,IAAAc,GAAAA,CAAE,KAAF,EAAQV,MAARU,CADiBA,CAAxB;QAIA,+CAAsBd,IAAAc,GAAAA,CAAE,MAAF,EAASd,IAAAc,GAAAA,CAAE,OAAF,EAAU,GAAV,EAAe,eAAfA,CAAT,EACpB,IADoB,EACfd,IAAAc,GAAAA,CAAE,KAAF,EAAQV,MAARU,CADeA,CAAtB;QAIAV,OAAA,mDAA0BJ,IAAAc,GAAAA,CAAE,MAAF,EAASd,IAAAc,GAAAA,CAAE,OAAF,EAAU,GAAV,EAAe,eAAfA,CAAT,EACxB,IADwB,EACnBd,IAAAc,GAAAA,CAAE,KAAF,EAAQV,MAARU,CADmBA,CAA1B;MAjCFV,GAAAA,WAAAA,EAAwBiB,UAAxBjB;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>25534, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/targeted_patches.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    # This module attempts to run some optimizations or compatibility\n    # improvements against some libraries used with Opal.\n    #\n    # This should be a last resort and must not break functionality in\n    # existing applications.\n    class TargetedPatches < Base\n      def on_def(node)\n        name, args, body = *node\n\n        if body && body.type == :begin && body.children.length >= 2\n          # parser/rubyxx.rb - racc generated code often looks like:\n          #\n          #     def _reduce_219(val, _values, result)\n          #       result = @builder.op_assign(val[0], val[1], val[2])\n          #       result\n          #     end\n          #\n          # This converter transform this into just\n          #\n          #     def _reduce_219(val, _values, result)\n          #       @builder.op_assign(val[0], val[1], val[2])\n          #     end\n\n          calls = body.children\n          assignment, ret = calls.last(2)\n          if assignment.type == :lvasgn && ret.type == :lvar &&\n             assignment.children.first == ret.children.first\n\n            if calls.length == 2\n              node.updated(nil, [name, args, assignment.children[1]])\n            else\n              calls = calls[0..-3] << assignment.children[1]\n              node.updated(nil, [name, args, body.updated(nil, calls)])\n            end\n          else\n            super\n          end\n        else\n          super\n        end\n      end\n\n      def on_array(node)\n        children = node.children\n\n        # Optimize large arrays produced by lexer, but mainly we are interested\n        # in improving compile times, by reducing the tree for the further\n        # compilation efforts (also reducing the bundle size a bit)\n        #\n        # This particular patch reduces compile time of the following command\n        # by 12.5%:\n        #\n        #     OPAL_CACHE_DISABLE=true OPAL_PREFORK_DISABLE=true bin/opal \\\n        #         --no-source-map -ropal-parser -ropal/platform -ce \\\n        #         'puts ::Opal.compile($stdin.read)' > _Cnow.js\n        #\n        # So, in short, an array of a kind:\n        #\n        #     [1, 2, 3, nil, nil, :something, :abc, nil, ...]\n        #\n        # Becomes compiled to:\n        #\n        #     Opal.large_array_unpack(\"1,2,3,,something,abc,,...\")\n\n        if children.length > 32\n          ssin_array = children.all? do |child|\n            # Break for wrong types\n            next false unless %i[str sym int nil].include?(child.type)\n            # Break for strings that may conflict with our numbers, nils and separator\n            next false if %i[str sym].include?(child.type) && child.children.first.to_s =~ /\\A[0-9-]|\\A\\z|,/\n            # Break for too numbers out of range, as there may be decoding issues\n            next false if child.type == :int && !(-1_000_000..1_000_000).cover?(child.children.first)\n            true\n          end\n\n          if ssin_array\n            str = children.map { |i| i.children.first.to_s }.join(',')\n            node.updated(:jscall, [s(:js_tmp, :Opal), :large_array_unpack, s(:sym, str)])\n          else\n            super\n          end\n        else\n          super\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:TargetedPatches>", "on_def", "node", "name", "args", "body", "type", ">=", "children", "length", "2", "calls", "last", "assignment", "ret", "first", "updated", "[]", "1", "0", "-3", "<<", "on_array", ">", "32", "ssin_array", "all?", "block in on_array", "child", "include?", "to_s", "=~", "-1000000", "1000000", "cover?", "block (2 levels) in on_array", "str", "map", "i", "join", "s", "Base"], :mappings=>"AAAAA,kDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAMEA,OAAAC;MAAAA;;;;;AACEC,QAAAA,sBAAAA,kBAAWC,IAAXD;AAAAA,UAAAA;;UAAAA;;UACE,KAAmB,UAAA,MAACC,IAAD,CAAA,CAAnB,EAAAC,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,OAAN,6BAAMA,CAAN,EAAYC,CAAAA,OAAZ,6BAAYA,CAAZ;UAEA,IAAG,CAAA,CAAA,QAAAA,IAAA,CAAA,IAAA,CAAA,MAAQA,IAAIC,MAAAA,CAAAA,CAAZ,EAAqB,OAArB,CAAA,CAAA,CAAA,IAAA,CAAA,QAAoDC,OAArBF,IAAIG,UAAAA,CAAAA,CAASC,QAAAA,CAAAA,CAAQF,EAAGG,CAAHH,CAApD,CAAA,CAAA,CAAH;;YAcEI,QAAQN,IAAIG,UAAAA,CAAAA;YACZ,KAAkBG,KAAKC,MAAAA,CAAMF,CAANE,CAAvB,kBAAA,EAAAC,CAAAA,aAAA,6BAAAA,CAAA,EAAYC,CAAAA,MAAZ,6BAAYA,CAAZ;YACA,IAAG,CAAA,CAAA,MAAAD,UAAUP,MAAAA,CAAAA,CAAV,EAAmB,QAAnB,CAAA,IAAA,CAAA,MAA8BQ,GAAGR,MAAAA,CAAAA,CAAjC,EAA0C,MAA1C,CAAA,CAAA,CAAA,IAAA,CAAA,MACAO,UAAUL,UAAAA,CAAAA,CAASO,OAAAA,CAAAA,CADnB,EAC6BD,GAAGN,UAAAA,CAAAA,CAASO,OAAAA,CAAAA,CADzC,CAAA,CAAA,CAAH;cAGE,IAAA,MAAGJ,KAAKF,QAAAA,CAAAA,CAAR,EAAmBC,CAAnB,