E,KAAU,UAAA,MAAChC,IAAD,CAAA,CAAV,EAAAiC,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,IAAN,6BAAMA,CAAN;YACA/C,IAAAwC,QAAAA,CAAAA,CAAOP,OAAAA,CAAGa,IAAHb;YACPY,OAAA,OAAA7C,IAAA,EAAA,wDAAA,aAAA,EAAA,CAAAa,IAAA,CAAA,EAAA,MAAA;UAHFgC,CAAAA;QAbFT,GAAAA,WAAAA,EAA6BY,UAA7BZ;MAjEFhC,GAAAA,WAAAA,EAAoB4C,UAApB5C;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>25707, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/regexp_anchors.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  self::REGEXP_START = RUBY_ENGINE == 'opal' ? '^' : '\\A'\n  self::REGEXP_END = RUBY_ENGINE == 'opal' ? '$' : '\\z'\n\n  # Unicode characters in ranges\n  # \\u0001 - \\u002F (blank unicode characters + space + !\"\#$%&'()*+,-./ chars)\n  # \\u003A - \\u0040 (:;<=>?@ chars)\n  # \\u005B - \\u005E ([\\]^ chars)\n  # \\u0060          (` char)\n  # \\u007B - \\u007F ({|}~ chars})\n  # are not allowed to be used in identifier in the beggining or middle of its name\n  self::FORBIDDEN_STARTING_IDENTIFIER_CHARS = '\\u0001-\\u002F\\u003A-\\u0040\\u005B-\\u005E\\u0060\\u007B-\\u007F'\n\n  # Unicode characters in ranges\n  # \\u0001 - \\u0020 (blank unicode characters + space)\n  # \\u0022 - \\u002F (\"\#$%&'()*+,-./ chars)\n  # \\u003A - \\u003E (:;<=> chars)\n  # \\u0040          (@ char)\n  # \\u005B - \\u005E ([\\]^ chars)\n  # \\u0060          (` char)\n  # \\u007B - \\u007F ({|}~ chars})\n  # are not allowed to be used in identifier in the end of its name\n  # In fact, FORBIDDEN_STARTING_IDENTIFIER_CHARS = FORBIDDEN_ENDING_IDENTIFIER_CHARS + \\u0021 ('?') + \\u003F ('!')\n  self::FORBIDDEN_ENDING_IDENTIFIER_CHARS   = '\\u0001-\\u0020\\u0022-\\u002F\\u003A-\\u003E\\u0040\\u005B-\\u005E\\u0060\\u007B-\\u007F'\n  self::INLINE_IDENTIFIER_REGEXP = Regexp.new(\"[^\#{self::FORBIDDEN_STARTING_IDENTIFIER_CHARS}]*[^\#{self::FORBIDDEN_ENDING_IDENTIFIER_CHARS}]\")\n\n  # For constants rules are pretty much the same, but ':' is allowed and '?!' are not.\n  # Plus it may start with a '::' which indicates that the constant comes from toplevel.\n  self::FORBIDDEN_CONST_NAME_CHARS = '\\u0001-\\u0020\\u0021-\\u002F\\u003B-\\u003F\\u0040\\u005B-\\u005E\\u0060\\u007B-\\u007F'\n  self::CONST_NAME_REGEXP = Regexp.new(\"\#{self::REGEXP_START}(::)?[A-Z][^\#{self::FORBIDDEN_CONST_NAME_CHARS}]*\#{self::REGEXP_END}\")\nend\n"], :names=>["<top (required)>", "<module:Opal>", "self", "Regexp", "new", "self::FORBIDDEN_STARTING_IDENTIFIER_CHARS", "self::FORBIDDEN_ENDING_IDENTIFIER_CHARS", "self::REGEXP_START", "self::FORBIDDEN_CONST_NAME_CHARS", "self::REGEXP_END"], :mappings=>"AAAAA,sCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;IACE,WAAAC,IAAA,kBAA6CD,GAA7C;IACA,WAAAC,IAAA,gBAA2CD,GAA3C;IASA,WAAAC,IAAA,yCAA4CD,qEAA5C;IAYA,WAAAC,IAAA,uCAA4CD,2FAA5C;IACA,WAAAC,IAAA,8BAAiCC,YAAMC,KAAAA,CAAMH,IAAD,GAAA,CAAKI,IAAAH,IAAAG,wCAAL,CAAA,GAA+CJ,MAA/C,GAAA,CAAqDK,IAAAJ,IAAAI,sCAArD,CAAA,GAA6FL,GAAlGG,CAAvC;IAIA,WAAAF,IAAA,gCAAmCD,2FAAnC;IACAA,OAAA,WAAAC,IAAA,uBAA0BC,YAAMC,KAAAA,CAAK,EAAA,GAAA,CAAGG,IAAAL,IAAAK,iBAAH,CAAA,GAAsBN,cAAtB,GAAA,CAAoCO,IAAAN,IAAAM,+BAApC,CAAA,GAAqEP,IAArE,GAAA,CAAyEQ,IAAAP,IAAAO,eAAzE,CAALL,CAAhC;EA7BFH,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>25726, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/js_reserved_words.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\nrequire 'opal/regexp_anchors'\n\nmodule Opal\n  module Rewriters\n    class JsReservedWords < Base\n      # Reserved javascript keywords - we cannot create variables with the\n      # same name (ref: http://stackoverflow.com/a/9337272/601782)\n      ES51_RESERVED_WORD = /\#{REGEXP_START}(?:do|if|in|for|let|new|try|var|case|else|enum|eval|false|null|this|true|void|with|break|catch|class|const|super|throw|while|yield|delete|export|import|public|return|static|switch|typeof|default|extends|finally|package|private|continue|debugger|function|arguments|interface|protected|implements|instanceof)\#{REGEXP_END}/.freeze\n\n      # ES3 reserved words that aren’t ES5.1 reserved words\n      ES3_RESERVED_WORD_EXCLUSIVE = /\#{REGEXP_START}(?:int|byte|char|goto|long|final|float|short|double|native|throws|boolean|abstract|volatile|transient|synchronized)\#{REGEXP_END}/.freeze\n\n      # Prototype special properties.\n      PROTO_SPECIAL_PROPS = /\#{REGEXP_START}(?:constructor|displayName|__proto__|__parent__|__noSuchMethod__|__count__)\#{REGEXP_END}/.freeze\n\n      # Prototype special methods.\n      PROTO_SPECIAL_METHODS = /\#{REGEXP_START}(?:hasOwnProperty|valueOf)\#{REGEXP_END}/.freeze\n\n      # Immutable properties of the global object\n      IMMUTABLE_PROPS = /\#{REGEXP_START}(?:NaN|Infinity|undefined)\#{REGEXP_END}/.freeze\n\n      # Doesn't take in account utf8\n      BASIC_IDENTIFIER_RULES = /\#{REGEXP_START}[$_a-z][$_a-z\\d]*\#{REGEXP_END}/i.freeze\n\n      # Defining a local function like Array may break everything\n      RESERVED_FUNCTION_NAMES = /\#{REGEXP_START}(?:Array)\#{REGEXP_END}/.freeze\n\n      def self.valid_name?(name)\n        BASIC_IDENTIFIER_RULES =~ name && !(\n          ES51_RESERVED_WORD =~ name ||\n          ES3_RESERVED_WORD_EXCLUSIVE =~ name ||\n          IMMUTABLE_PROPS =~ name\n        )\n      end\n\n      def self.valid_ivar_name?(name)\n        !(PROTO_SPECIAL_PROPS =~ name || PROTO_SPECIAL_METHODS =~ name)\n      end\n\n      def fix_var_name(name)\n        self.class.valid_name?(name) ? name : \"\#{name}$\".to_sym\n      end\n\n      def fix_ivar_name(name)\n        self.class.valid_ivar_name?(name.to_s[1..-1]) ? name : \"\#{name}$\".to_sym\n      end\n\n      def on_lvar(node)\n        name, _ = *node\n        node = node.updated(nil, [fix_var_name(name)])\n        super(node)\n      end\n\n      def on_lvasgn(node)\n        name, value = *node\n\n        node =\n          if value\n            node.updated(nil, [fix_var_name(name), value])\n          else\n            node.updated(nil, [fix_var_name(name)])\n          end\n\n        super(node)\n      end\n\n      def on_ivar(node)\n        name, _ = *node\n        node = node.updated(nil, [fix_ivar_name(name)])\n        super(node)\n      end\n\n      def on_ivasgn(node)\n        name, value = *node\n\n        node =\n          if value\n            node.updated(nil, [fix_ivar_name(name), value])\n          else\n            node.updated(nil, [fix_ivar_name(name)])\n          end\n\n        super(node)\n      end\n\n      # Restarg and kwrestarg are special cases\n      # because they may have no name\n      # def m(*, **); end\n      def on_restarg(node)\n        name, _ = *node\n\n        if name\n          node = node.updated(nil, [fix_var_name(name)], meta: { arg_name: name })\n        end\n\n        node\n      end\n\n      alias on_kwrestarg on_restarg\n\n      def on_argument(node)\n        node = super(node)\n        name, value = *node\n        fixed_name = fix_var_name(name)\n        new_children = value ? [fixed_name, value] : [fixed_name]\n\n        node.updated(nil, new_children, meta: { arg_name: name })\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:JsReservedWords>", "REGEXP_START", "REGEXP_END", "freeze", "valid_name?", "name", "$ret_or_1", "BASIC_IDENTIFIER_RULES", "=~", "$ret_or_2", "$ret_or_3", "ES51_RESERVED_WORD", "ES3_RESERVED_WORD_EXCLUSIVE", "IMMUTABLE_PROPS", "!", "valid_ivar_name?", "PROTO_SPECIAL_PROPS", "PROTO_SPECIAL_METHODS", "fix_var_name", "class", "to_sym", "fix_ivar_name", "to_s", "[]", "1", "-1", "on_lvar", "node", "_", "updated", "on_lvasgn", "value", "on_ivar", "on_ivasgn", "on_restarg", "on_argument", "fixed_name", "new_children", "Base"], :mappings=>"AAAAA,mDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EACAD,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QAGE,8CAAqB,SAAGC,kBAAH,EAAgBD,oTAAhB,EAAoUE,gBAApU,CAAA,CAAgVC,QAAAA,CAAAA,CAArW;QAGA,uDAA8B,SAAGF,kBAAH,EAAgBD,qHAA