C,IAAZ,EAAN,EAA5BwB;QANNM,CAAAA;MAhGFnC,GAAAA,WAAAA,EAAwBsC,UAAxBtC;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>25857, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/block_to_iter.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class BlockToIter < Base\n      def on_block(node)\n        recvr, args, body = *node\n        iter_node = s(:iter, args, body)\n        process recvr.updated(\n          nil,\n          (recvr.children + [iter_node]),\n        )\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:BlockToIter>", "on_block", "node", "recvr", "args", "body", "iter_node", "s", "process", "updated", "+", "children", "Base"], :mappings=>"AAAAA,+CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;QACEA,OAAAC,wBAAAA,oBAAaC,IAAbD;AAAAA,UAAAA;;;UACE,KAAoB,UAAA,MAACC,IAAD,CAAA,CAApB,EAAAC,CAAAA,QAAA,6BAAAA,CAAA,EAAOC,CAAAA,OAAP,6BAAOA,CAAP,EAAaC,CAAAA,OAAb,6BAAaA,CAAb;UACAC,YAAYV,IAAAW,GAAAA,CAAE,MAAF,EAASH,IAAT,EAAeC,IAAfE;UACZN,OAAAL,IAAAY,SAAAA,CAAQL,KAAKM,SAAAA,CACX,GADM,EAEUC,SAAfP,KAAKQ,UAAAA,CAAAA,CAAUD,EAAE,CAACJ,SAAD,CAAFI,CAFLD,CAAbD;QAHFP,CAAAA;MADFD,GAAAA,WAAAA,EAAoBY,UAApBZ;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>25889, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/dot_js_syntax.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class DotJsSyntax < Base\n      def on_send(node)\n        recv, meth, *args = *node\n        if recv && recv.type == :send\n          recv_of_recv, meth_of_recv, _ = *recv\n          if meth_of_recv == :JS\n            case meth\n            when :[]\n              if args.size != 1\n                error '.JS[:property] syntax supports only one argument'\n              end\n              property = args.first\n\n              node = to_js_attr_call(recv_of_recv, property)\n            when :[]=\n              if args.size != 2\n                error '.JS[:property]= syntax supports only two arguments'\n              end\n\n              property, value = *args\n              node = to_js_attr_assign_call(recv_of_recv, property, value)\n            else\n              node = to_native_js_call(recv_of_recv, meth, args)\n            end\n            super(node)\n          else\n            super\n          end\n        else\n          super\n        end\n      end\n\n      # @param recv [AST::Node] receiver of .JS. method\n      # @param meth [Symbol] name of the JS method\n      # @param args [Array<AST::Node>] list of the arguments passed to JS method\n      def to_native_js_call(recv, meth, args)\n        s(:jscall, recv, meth, *args)\n      end\n\n      # @param recv [AST::Node] receiver of .JS[] method\n      # @param property [AST::Node] argument passed to .JS[] method\n      def to_js_attr_call(recv, property)\n        s(:jsattr, recv, property)\n      end\n\n      # @param recv [AST::Node] receiver of .JS[]= method\n      # @param property [AST::Node] property passed to brackets\n      # @param value [AST::Node] value of assignment\n      def to_js_attr_assign_call(recv, property, value)\n        s(:jsattrasgn, recv, property, value)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:DotJsSyntax>", "on_send", "node", "recv", "meth", "args", "type", "recv_of_recv", "meth_of_recv", "_", "size", "1", "error", "property", "first", "to_js_attr_call", "2", "value", "to_js_attr_assign_call", "to_native_js_call", "s", "Base"], :mappings=>"AAAAA,+CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;;;AACEC,QAAAA,uBAAAA,mBAAYC,IAAZD;AAAAA,UAAAA;;UAAAA;;UACE,KAAoB,UAAA,MAACC,IAAD,CAAA,CAApB,EAAAC,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,OAAN,6BAAMA,CAAN,EAAaC,CAAAA,OAAb,aAAaA,CAAb;UACA,IAAG,CAAA,QAAAF,IAAA,CAAA,IAAA,CAAA,MAAQA,IAAIG,MAAAA,CAAAA,CAAZ,EAAqB,MAArB,CAAA,CAAA,CAAH;;YACE,KAAgC,UAAA,MAACH,IAAD,CAAA,CAAhC,EAAAI,CAAAA,eAAA,6BAAAA,CAAA,EAAcC,CAAAA,eAAd,6BAAcA,CAAd,EAA4BC,CAAAA,IAA5B,6BAA4BA,CAA5B;YACA,IAAA,MAAGD,YAAH,EAAmB,IAAnB,CAAA;;;cAEE,QADKJ,IACL;gBAAA,KAAK,IAAL;;kBACE,IAAA,OAAGC,IAAIK,MAAAA,CAAAA,CAAP,EAAgBC,CAAhB,CAAA;oBACEf,IAAAgB,OAAAA,CAAMX,kDAANW;kBADF;kBAGAC,WAAWR,IAAIS,OAAAA,CAAAA;kBAEfZ,OAAON,IAAAmB,iBAAAA,CAAgBR,YAAhB,EAA8BM,QAA9BE;kBANT;gBAOA,KAAK,KAAL;;kBACE,IAAA,OAAGV,IAAIK,MAAAA,CAAAA,CAAP,EAAgBM,CAAhB,CAAA;oBACEpB,IAAAgB,OAAAA,CAAMX,oDAANW;kBADF;kBAIA,KAAkB,UAAA,MAACP,IAAD,CAAA,CAAlB,EAAAQ,CAAAA,WAAA,6BAAAA,CAAA,EAAUI,CAAAA,QAAV,6BAAUA,CAAV;kBACAf,OAAON,IAAAsB,wBAAAA,CAAuBX,YAAvB,EAAqCM,QAArC,EAA+CI,KAA/CC;kBANT;gBAAA;kBAQEhB,OAAON,IAAAuB,mBAAAA,CAAkBZ,YAAlB,EAAgCH,IAAhC,EAAsCC,IAAtCc;cAfT;cAiBAlB,OAAA,OAAAL,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;YAnBF;cAqBED,OAAA,OAAAL,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAAM,IAAA,CAAA,EAAA,MAAA;YArBF;UAFF;YA0BED,OAAA,OAAAL,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAAM,IAAA,CAAA,EAAA,MAAA;UA1BF;QAFFD,CAAAA;;AAmCAkB,QAAAA,iCAAAA,6BAAsBhB,IAAD,EAAOC,IAAP,EAAaC,IAAlCc;AAAAA,UAAAA;;UACEA,OAAAC,MAAAxB,IAAAwB,KAAAA,EAAA,CAAE,QAAF,EAAWjB,IAAX,EAAiBC,IAAjB,CAAA,QAAuB,MAACC,IAAD,CAAvB,CAAAe;QADFD,CAAAA;;AAMAJ,QAAAA,+BAAAA,2BAAoBZ,IAAD,EAAOU,QAA1BE;AAAAA,UAAAA;;UACEA,OAAAnB,IAAAwB,GAAAA,CAAE,QAAF,EAAWjB,IAAX,EAAiBU,QAAjBO;QADFL,CAAAA;QAOAf,OAAAkB,sCAAAA,kCAA2Bf,IAAD,EAAOU,QAAP,EAAiBI,KAA3CC;AAAAA,UAAAA;;UACEA,OAAAtB,IAAAwB,GAAAA,CAAE,YAAF,EAAejB,IAAf,EAAqBU,QAArB,EAA+BI,KAA/BG;QADFF,CAAAA;MAjDFlB,GAAAA,WAAAA,EAAoBqB,UAApBrB;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>25972, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/pattern_matching.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class PatternMatching < Base\n      def initialize\n        @depth = 0\n        super\n      end\n\n      # a => b\n      def on_match_pattern(node)\n        from, pat = *node\n\n        s(:begin,\n          s(:lvasgn, :\"$pmvar\", from),\n          s(:if,\n            convert_full_pattern(from, pat),\n            nil,\n            raise_no_matching_pattern_error(:\"$pmvar\")\n          )\n        )\n      end\n\n      # a in b\n      def on_match_pattern_p(node)\n        from, pat = *node\n\n        s(:if,\n          convert_full_pattern(from, pat),\n          s(:true),\n          s(:false)\n        )\n      end\n\n      # case a; in b; end\n      def on_case_match(node)\n        @depth += 1\n\n        cmvar = :\"$cmvar\#{@depth}\"\n\n        from, *cases, els = *node\n\n        if els\n          process els\n        else\n          els = raise_no_matching_pattern_error(cmvar)\n        end\n\n        s(:begin,\n          s(:lvasgn, cmvar, from),\n          single_case_match(cmvar, *cases, els)\n        )\n      end\n\n      private\n\n      # raise NoMatchingPatternError, from\n      def raise_no_matching_pattern_error(from)\n        s(:send, nil, :raise,\n          s(:const, s(:cbase), :NoMatchingPatternError),\n          s(:lvar, from)\n        )\n      end\n\n      # in b\n      def single_case_match(from, *cases, els)\n        cas = cases.shift\n        pat, if_guard, body = *cas\n\n        pat = convert_full_pattern(from, pat)\n        if if_guard\n          guard, = *if_guard\n          case if_guard.type\n          when :if_guard\n            pat = s(:and, pat, guard)\n          when :unless_guard\n            pat = s(:and, pat, s(:send, guard, :!))\n          end\n        end\n\n        s(:if,\n          pat,\n          process(body),\n          if !cases.empty?\n            single_case_match(from, *cases, els)\n          elsif els != s(:empty_else)\n            els\n          end\n        )\n      end\n\n      def convert_full_pattern(from, pat)\n        if from.class == Symbol\n          from = s(:lvar, from)\n        end\n\n        converter = PatternConverter.new(pat)\n        converter.run!\n\n        # a, b, c = ::PatternMatching.(from, [...])\n        s(:masgn,\n          s(:mlhs,\n            *converter.variables\n          ),\n          s(:send,\n            s(:const, s(:cbase), :PatternMatching),\n            :call,\n            from,\n            converter.pattern,\n          )\n        )\n      end\n\n      class PatternConverter < ::Opal::Rewriters::Base\n        def initialize(pat)\n          @pat = pat\n          @variables = []\n        end\n\n        def run!\n          @outpat = process(@pat)\n        end\n\n        def pattern\n          @outpat\n        end\n\n        def variables\n          @variables.map { |i| s(:lvasgn, i) }\n        end\n\n        # a\n        def on_match_var(node)\n          var, = *node\n\n          @variables << var\n\n          s(:sym, :var)\n        end\n\n        # [...] => a\n        def on_match_as(node)\n          pat, save = *node\n\n          process(save)\n          array(s(:sym, :save), process(pat))\n        end\n\n        def on_literal(node)\n          array(s(:sym, :lit), node)\n        end\n\n        alias on_int on_literal\n        alias on_float on_literal\n        alias on_complex on_literal\n        alias on_rational on_literal\n        alias on_array on_literal\n        alias on_str on_literal\n        alias on_dstr on_literal\n        alias on_xstr on_literal\n        alias on_sym on_literal\n        alias on_irange on_literal\n        alias on_erange on_literal\n        alias on_const on_literal\n        alias on_regexp on_literal\n        alias on_lambda on_literal\n        alias on_begin on_literal\n\n        # ^a\n        def on_pin(node)\n          on_literal(node.children.first)\n        end\n\n        # *\n        def on_match_rest(node)\n          if node.children.empty?\n            array(s(:sym, :rest))\n          else\n            array(s(:sym, :rest), process(node.children.first))\n          end\n        end\n\n        # {} | []\n        def on_match_alt(node)\n          array(s(:sym, :any), *node.children.map(&method(:process)))\n        end\n\n        # MyStructName\n        def on_const_pattern(node)\n          array(s(:sym, :all), *node.children.map(&method(:process)))\n        end\n\n        # [0, 1, 2] or [*, 0, 1] or [0, 1, *]\n        def on_array_pattern(node, tail = false)\n          children = *node\n          children << s(:match_rest) if tail\n\n          fixed_size = true\n          array_size = 0\n\n          children = children.each do |i|\n            case i.type\n            when :match_rest\n              fixed_size = false\n            else\n              array_size += 1\n            end\n          end\n\n          array(\n            s(:sym, :array),\n            to_ast(fixed_size),\n            to_ast(array_size),\n            to_ast(children.map(&method(:process)))\n          )\n        end\n\n        # [0, 1, 2,]\n        def on_array_pattern_with_tail(node)\n          on_array_pattern(node, true)\n        end\n\n        # {a:, b:}\n        def on_hash_pattern(node)\n          children = *node\n\n          any_size = children.empty? ? to_ast(false) : to_ast(true)\n\n          children = children.map do |i|\n            case i.type\n            when :pair\n              array(i.children[0], process(i.children[1]))\n            when :match_var\n              array(s(:sym, i.children[0]), process(i))\n            when :match_nil_pattern\n              any_size = to_ast(false)\n              nil\n            when :match_rest\n              # Capturing rest?\n              if i.children.first\n                any_size = process(i.children.first)\n              else\n                any_size = to_ast(true)\n              end\n              nil\n            end\n          end.compact\n\n          array(s(:sym, :hash), any_size, array(*children))\n        end\n\n        # [*, a, b, *]\n        def on_find_pattern(node)\n          children = *node\n\n          children = children.map(&method(:process))\n\n          array(s(:sym, :find), array(*children))\n        end\n\n        private\n\n        def array(*args)\n          to_ast(args)\n        end\n\n        def to_ast(val)\n          case val\n          when Array\n            s(:array, *val)\n          when Integer\n            s(:int, val)\n          when true\n            s(:true)\n          when false\n            s(:false)\n          when nil\n            s(:nil)\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:PatternMatching>", "initialize", "@depth", "0", "on_match_pattern", "node", "from", "pat", "s", "convert_full_pattern", "raise_no_matching_pattern_error", "on_match_pattern_p", "on_case_match", "+", "1", "cmvar", "cases", "els", "process", "single_case_match", "private", "cas", "shift", "if_guard", "body", "guard", "type", "empty?", "class", "Symbol", "converter", "PatternConverter", "new", "run!", "variables", "pattern", "<class:PatternConverter>", "@pat", "@variables", "@outpat", "map", "block in variables", "i", "block (2 levels) in variables", "on_match_var", "var$", "<<", "on_match_as", "save", "array", "on_literal", "on_pin", "children", "first", "on_match_rest", "on_match_alt", "method", "to_proc", "on_const_pattern", "on_array_pattern", "tail", "fixed_size", "array_size", "each", "block in on_array_pattern", "block (2 levels) in on_array_pattern", "to_ast", "on_array_pattern_with_tail", "on_hash_pattern", "any_size", "block in on_hash_pattern", "block (2 levels) in on_hash_pattern", "[]", "compact", "on_find_pattern", "args", "val", "Array", "$ret_or_1", "Integer", "Opal::Rewriters::Base", "Opal::Rewriters", "Opal", "Base"], :mappings=>"AAAAA,kDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAA