AAAA;;AA6BAM,UAAAA,+BAAAA,2BAAoBrE,IAApBqE;AAAAA,YAAAA;;;YACEtB,WAAW,UAAA,MAAC/C,IAAD,CAAA;YAEX+C,WAAmBZ,MAARY,QAAQZ,OAAAA,EAAAA,EAAAA,EAAM5C,IAAA4D,QAAAA,CAAO,SAAPA,CAADC,SAAAA,CAAAA,CAALjB;YAEnBkC,OAAA9E,IAAAqD,OAAAA,CAAMrD,IAAAY,GAAAA,CAAE,KAAF,EAAQ,MAARA,CAAN,EAAsByC,MAAArD,IAAAqD,SAAAA,EAAM,MAACG,QAAD,CAANH,CAAtBA;UALFyB,CAAAA;UAQA9E,IAAAwB,SAAAA,CAAAA;;AAEA6B,UAAAA,qBAAAA,iBAzQR,EAyQQA;AAAAA,YAAAA;;;YAzQR;YAyQkB;YACRA,OAAArD,IAAAsE,QAAAA,CAAOS,IAAPT;UADFjB,CAAAA,IAAAA;UAIAb,OAAA8B,sBAAAA,kBAAWU,GAAXV;AAAAA,YAAAA;;YAEE,IAAA,QAAKW,WAAL,EADAC,CAAAA,YAAKF,GAALE,CACA,CAAA;cACEZ,OAAA1D,MAAAZ,IAAAY,KAAAA,EAAA,CAAE,OAAF,CAAA,QAAU,MAACoE,GAAD,CAAV,CAAApE;YADF,OAEA,IAAA,QAAKuE,aAAL,EAjRV,SAiRU,CAAA;cACEb,OAAAtE,IAAAY,GAAAA,CAAE,KAAF,EAAQoE,GAARpE;YADF,OAEA,IAAA,QAAK,IAAL,EAnRV,SAmRU,CAAA;cACE0D,OAAAtE,IAAAY,GAAAA,CAAE,MAAFA;YADF,OAEA,IAAA,QAAK,KAAL,EArRV,SAqRU,CAAA;cACE0D,OAAAtE,IAAAY,GAAAA,CAAE,OAAFA;YADF,OAEA,IAAA,QAAK,GAAL,EAvRV,SAuRU,CAAA;cACE0D,OAAAtE,IAAAY,GAAAA,CAAE,KAAFA;YADF;cATA0D,OAAA;YASA;UAVFA,CAAAA;QAzJF9B,GAAAA,WAAAA,EAAyB4C,IAAAC,IAAAC,KAAAD,cAAAD,SAAzB5C;MA9GFpC,GAAAA,WAAAA,EAAwBmF,UAAxBnF;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>26288, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/logical_operator_assignment.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class LogicalOperatorAssignment < Base\n      def self.reset_tmp_counter!\n        @@counter = 0\n      end\n\n      def self.new_temp\n        @@counter ||= 0\n        @@counter += 1\n        :\"$logical_op_recvr_tmp_\#{@@counter}\"\n      end\n\n      GET_SET = ->(get_type, set_type) {\n        ->(lhs, rhs, root_type) {\n          get_node = lhs.updated(get_type)              # lhs\n          condition_node = s(root_type, get_node, rhs)  # lhs || rhs\n\n          if %i[const cvar].include?(get_type) && root_type == :or\n            # defined?(lhs)\n            defined_node = s(:defined?, get_node)\n            # LHS = defined?(LHS) ? (LHS || rhs) : rhs\n            condition_node = s(:if, defined_node, s(:begin, condition_node), rhs)\n          end\n\n          lhs.updated(set_type, [*lhs, condition_node]) # lhs = lhs || rhs\n        }\n      }\n\n      # Takes    `lhs ||= rhs`\n      # Produces `lhs = lhs || rhs`\n      LocalVariableHandler = GET_SET[:lvar, :lvasgn]\n\n      # Takes    `@lhs ||= rhs`\n      # Produces `@lhs = @lhs || rhs`\n      InstanceVariableHandler = GET_SET[:ivar, :ivasgn]\n\n      # Takes    `LHS ||= rhs`\n      # Produces `LHS = defined?(LHS) ? (LHS || rhs) : rhs`\n      #\n      # Takes    `LHS &&= rhs`\n      # Produces `LHS = LHS && rhs`\n      ConstantHandler = GET_SET[:const, :casgn]\n\n      # Takes    `$lhs ||= rhs`\n      # Produces `$lhs = $lhs || rhs`\n      GlobalVariableHandler = GET_SET[:gvar, :gvasgn]\n\n      # Takes    `@@lhs ||= rhs`\n      # Produces `@@lhs = defined?(@@lhs) ? (@@lhs || rhs) : rhs`\n      #\n      # Takes    `@@lhs &&= rhs`\n      # Produces `@@lhs = @@lhs && rhs`\n      ClassVariableHandler = GET_SET[:cvar, :cvasgn]\n\n      # Takes    `recvr.meth ||= rhs`\n      # Produces `recvr.meth || recvr.meth = rhs`\n      # (lhs is a recvr.meth)\n      class SendHandler < self\n        def self.call(lhs, rhs, root_type)\n          recvr, reader_method, *args = *lhs\n\n          # If recvr is a complex expression it must be cached.\n          # MRI calls recvr in `recvr.meth ||= rhs` only once.\n          if recvr && recvr.type == :send\n            recvr_tmp = new_temp\n            cache_recvr = s(:lvasgn, recvr_tmp, recvr)                         # $tmp = recvr\n            recvr = s(:js_tmp, recvr_tmp)\n          end\n\n          writer_method = :\"\#{reader_method}=\"\n\n          call_reader = lhs.updated(:send, [recvr, reader_method, *args])      # $tmp.meth\n          call_writer = lhs.updated(:send, [recvr, writer_method, *args, rhs]) # $tmp.meth = rhs\n          get_or_set = s(root_type, call_reader, call_writer)\n\n          if cache_recvr\n            s(:begin, cache_recvr, get_or_set)\n          else\n            get_or_set\n          end\n        end\n      end\n\n      # Takes    `recvr&.meth ||= rhs`\n      # Produces `recvr.nil? ? nil : recvr.meth ||= rhs`\n      #   NOTE: Later output of this handler gets post-processed by this rewriter again\n      #   using SendHandler to `recvr.nil? ? nil : (recvr.meth || recvr.meth = rhs)`\n      class ConditionalSendHandler < self\n        def self.call(lhs, rhs, root_type)\n          root_type = :\"\#{root_type}_asgn\"\n\n          recvr, meth, *args = *lhs\n\n          recvr_tmp = new_temp\n          cache_recvr = s(:lvasgn, recvr_tmp, recvr) # $tmp = recvr\n          recvr = s(:js_tmp, recvr_tmp)\n\n          recvr_is_nil = s(:send, recvr, :nil?)                 # recvr.nil?\n          plain_send = lhs.updated(:send, [recvr, meth, *args]) # recvr.meth\n          plain_or_asgn = s(root_type, plain_send, rhs)         # recvr.meth ||= rhs\n\n          s(:begin,\n            cache_recvr,\n            s(:if, recvr_is_nil,                          # if recvr.nil?\n              s(:nil),                                    #   nil\n                                                          # else\n              plain_or_asgn                               #   recvr.meth ||= rhs\n            ),\n          )                                               # end\n        end\n      end\n\n      HANDLERS = {\n        lvasgn: LocalVariableHandler,\n        ivasgn: InstanceVariableHandler,\n        casgn:  ConstantHandler,\n        gvasgn: GlobalVariableHandler,\n        cvasgn: ClassVariableHandler,\n        send:   SendHandler,\n        csend:  ConditionalSendHandler\n      }.freeze\n\n      # lhs ||= rhs\n      def on_or_asgn(node)\n        lhs, rhs = *node\n\n        result = HANDLERS\n                 .fetch(lhs.type) { error \"cannot handle LHS type: \#{lhs.type}\" }\n                 .call(lhs, rhs, :or)\n\n        process(result)\n      end\n\n      # lhs &&= rhs\n      def on_and_asgn(node)\n        lhs, rhs = *node\n\n        result = HANDLERS\n                 .fetch(lhs.type) { error \"cannot handle LHS type: \#{lhs.type}\" }\n                 .call(lhs, rhs, :and)\n\n        process(result)\n      end\n\n      ASSIGNMENT_STRING_NODE = s(:str, 'assignment')\n\n      # Rewrites any or_asgn and and_asgn node like\n      #   `defined?(a ||= 1)`\n      # and\n      #   `defined?(a &&= 1)`\n      # to a static \"assignment\" string node\n      def on_defined?(node)\n        inner, _ = *node\n        if %i[or_asgn and_asgn].include?(inner.type)\n          ASSIGNMENT_STRING_NODE\n        else\n          super(node)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:LogicalOperatorAssignment>", "reset_tmp_counter!", "@@counter", "0", "new_temp", "$ret_or_1", "+", "1", "block in <class:LogicalOperatorAssignment>", "get_type", "set_type", "block (2 levels) in <class:LogicalOperatorAssignment>", "lhs", "rhs", "root_type", "block (3 levels) in <class:LogicalOperatorAssignment>", "get_node", "updated", "condition_node", "s", "include?", "defined_node", "GET_SET", "[]", "<class:SendHandler>", "call", "recvr", "reader_method", "args", "type", "recvr_tmp", "cache_recvr", "writer_method", "call_reader", "call_writer", "get_or_set", "<class:ConditionalSendHandler>", "meth", "recvr_is_nil", "plain_send", "plain_or_asgn", "LocalVariableHandler", "InstanceVariableHandler", "ConstantHandler", "GlobalVariableHandler", "ClassVariableHandler", "SendHandler", "ConditionalSendHandler", "freeze", "on_or_asgn", "node", "result", "fetch", "HANDLERS", "block in on_or_asgn", "block (2 levels) in on_or_asgn", "error", "process", "on_and_asgn", "block in on_and_asgn", "block (2 levels) in on_and_asgn", "on_defined?", "inner", "_", "ASSIGNMENT_STRING_NODE", "Base"], :mappings=>"AAAAA,6DAAA