SC,MADAC,cACAD,SAAAA,EAAAA,CAAOxC,GAAGiB,MAAAA,CAAAA,CAAVuB,CAAAA,EADAO,aAAAA,EAAAC;;YACmBA,OAAAhE,IAAA4D,OAAAA,CAAOI,0BAAD,GAAA,CAA2BhD,GAAGiB,MAAAA,CAAAA,CAA9B,CAAN2B,CADnBG,CAAAA,GAAAA,SAAAA,CACAP,CACA3B,MAAAA,CAAMb,GAFN,EAEWC,GAFX,EAEgB,KAAhBY;UAETiC,OAAA9D,IAAA6D,SAAAA,CAAQN,MAARM;QAPFC,CAAAA;QAUA,kDAAyB9D,IAAAuB,GAAAA,CAAE,KAAF,EAAQnB,YAARmB,CAAzB;QAOAnB,OAAA6D,2BAAAA,sDAAgBX,IAAhBW;AAAAA,UAAAA;;UAAAA;;UACE,KAAW,UAAA,MAACX,IAAD,CAAA,CAAX,EAAAY,CAAAA,QAAA,6BAAAA,CAAA,EAAOC,CAAAA,IAAP,6BAAOA,CAAP;UACA,IAAA,QAAG,CAAG,SAAH,EAAW,UAAX,CAAoB3C,aAAAA,CAAU0C,KAAKjC,MAAAA,CAAAA,CAAfT,CAAvB,CAAA;YACEyC,OAAAG;UADF;YAGEH,OAAA,OAAAjE,IAAA,EAAA,2FAAA,eAAA,EAAA,CAAMsD,IAAN,CAAA,EAAA,IAAA;UAHF;QAFFW,CAAAA;MAtJF7D,GAAAA,WAAAA,EAAkCiE,UAAlCjE;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>26431, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/binary_operator_assignment.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class BinaryOperatorAssignment < Base\n      def self.reset_tmp_counter!\n        @@counter = 0\n      end\n\n      def self.new_temp\n        @@counter ||= 0\n        @@counter += 1\n        :\"$binary_op_recvr_tmp_\#{@@counter}\"\n      end\n\n      GET_SET = ->(get_type, set_type) {\n        ->(node, lhs, operation, rhs) {\n          get_node = lhs.updated(get_type) # lhs\n          set_node = node.updated(:send, [get_node, operation, rhs]) # lhs + rhs\n\n          lhs.updated(set_type, [*lhs, set_node]) # lhs = lhs + rhs\n        }\n      }\n\n      # Takes    `lhs += rhs`\n      # Produces `lhs = lhs + rhs`\n      LocalVariableHandler = GET_SET[:lvar, :lvasgn]\n\n      # Takes    `@lhs += rhs`\n      # Produces `@lhs = @lhs + rhs`\n      InstanceVariableHandler = GET_SET[:ivar, :ivasgn]\n\n      # Takes    `LHS += rhs`\n      # Produces `LHS = LHS + rhs`\n      ConstantHandler = GET_SET[:const, :casgn]\n\n      # Takes    `$lhs += rhs`\n      # Produces `$lhs = $lhs + rhs`\n      GlobalVariableHandler = GET_SET[:gvar, :gvasgn]\n\n      # Takes    `@@lhs += rhs`\n      # Produces `@@lhs = @@lhs + rhs`\n      ClassVariableHandler = GET_SET[:cvar, :cvasgn]\n\n      # Takes    `recvr.meth += rhs`\n      # Produces `recvr.meth = recvr.meth + rhs`\n      # (lhs is a recvr.meth, op is :+)\n      class SendHandler < self\n        def self.call(node, lhs, operation, rhs)\n          recvr, reader_method, *args = *lhs\n\n          # If recvr is a complex expression it must be cached.\n          # MRI calls recvr in `recvr.meth ||= rhs` only once.\n          if recvr && recvr.type == :send\n            recvr_tmp = new_temp\n            cache_recvr = s(:lvasgn, recvr_tmp, recvr) # $tmp = recvr\n            recvr = s(:js_tmp, recvr_tmp)\n          end\n\n          writer_method = :\"\#{reader_method}=\"\n\n          call_reader = lhs.updated(:send, [recvr, reader_method, *args])          # $tmp.meth\n          call_op = node.updated(:send, [call_reader, operation, rhs])             # $tmp.meth + rhs\n          call_writer = lhs.updated(:send, [recvr, writer_method, *args, call_op]) # $tmp.meth = $tmp.meth + rhs\n\n          if cache_recvr\n            node.updated(:begin, [cache_recvr, call_writer])\n          else\n            call_writer\n          end\n        end\n      end\n\n      # Takes    `recvr.meth += rhs`\n      # Produces `recvr.nil? ? nil : recvr.meth += rhs`\n      #   NOTE: Later output of this handler gets post-processed by this rewriter again\n      #   using SendHandler to `recvr.nil? ? nil : (recvr.meth = recvr.meth + rhs)`\n      class ConditionalSendHandler < self\n        def self.call(node, lhs, operation, rhs)\n          recvr, meth, *args = *lhs\n\n          recvr_tmp = new_temp\n          cache_recvr = s(:lvasgn, recvr_tmp, recvr) # $tmp = recvr\n          recvr = s(:js_tmp, recvr_tmp)\n\n          recvr_is_nil = s(:send, recvr, :nil?)                   # recvr.nil?\n          plain_send = lhs.updated(:send, [recvr, meth, *args])   # recvr.meth\n          plain_op_asgn = node.updated(:op_asgn, [plain_send, operation, rhs]) # recvr.meth += rhs\n\n          s(:begin,\n            cache_recvr,\n            s(:if, recvr_is_nil,                          # if recvr.nil?\n              s(:nil),                                    #   nil\n                                                          # else\n              plain_op_asgn                               #   recvr.meth ||= rhs\n            ),\n          )                                               # end\n        end\n      end\n\n      HANDLERS = {\n        lvasgn: LocalVariableHandler,\n        ivasgn: InstanceVariableHandler,\n        casgn:  ConstantHandler,\n        gvasgn: GlobalVariableHandler,\n        cvasgn: ClassVariableHandler,\n        send:   SendHandler,\n        csend:  ConditionalSendHandler\n      }.freeze\n\n      # lhs += rhs\n      def on_op_asgn(node)\n        lhs, op, rhs = *node\n\n        result = HANDLERS\n                 .fetch(lhs.type) { error \"cannot handle LHS type: \#{lhs.type}\" }\n                 .call(node, lhs, op, rhs)\n\n        process(result)\n      end\n\n      ASSIGNMENT_STRING_NODE = s(:str, 'assignment')\n\n      # Rewrites any or_asgn and and_asgn node like\n      #   `defined?(a ||= 1)`\n      # and\n      #   `defined?(a &&= 1)`\n      # to a static \"assignment\" string node\n      def on_defined?(node)\n        inner, _ = *node\n        if inner.type == :op_asgn\n          ASSIGNMENT_STRING_NODE\n        else\n          super(node)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:BinaryOperatorAssignment>", "reset_tmp_counter!", "@@counter", "0", "new_temp", "$ret_or_1", "+", "1", "block in <class:BinaryOperatorAssignment>", "get_type", "set_type", "block (2 levels) in <class:BinaryOperatorAssignment>", "node", "lhs", "operation", "rhs", "block (3 lev