           key = element.type == :str ? key.inspect : \":\#{key}\"\n              Kernel.warn \"warning: key \#{key} is duplicated and overwritten\"\n            else\n              @set << element\n            end\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<module:Hashes>", "<class:KeyDuplicatesRewriter>", "initialize", "@keys", "UniqKeysSet", "new", "on_hash", "node", "previous_keys", "on_pair", "key", "_value", "include?", "type", "<<", "on_kwsplat", "hash", "_", "process_regular_node", "updated", "<class:UniqKeysSet>", "@set", "Set", "element", "inspect", "Kernel", "warn", "Opal::Rewriters::Base", "Opal::Rewriters", "Opal"], :mappings=>"AAAAA,gEAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EACAD,IAAAC,SAAAA,CAAQF,KAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC;QAAAA;;UAAAA;;AAAAA;;;AACEC,UAAAA,0BAAAA,sBAAAA;AAAAA,YAAAA;;YACEA,OAAAC,CAAAA,YAAQC,iBAAWC,KAAAA,CAAAA,CAAnBF;UADFD,CAAAA;;AAIAI,UAAAA,uBAAAA,mBAAYC,IAAZD;AAAAA,YAAAA;;YAAAA;YACEA,OAAA,cAAA;;YAAA,KAAuB,CAAAH,SAAA,EAAOC,iBAAWC,KAAAA,CAAAA,CAAlB,CAAvB,EAAAG,CAAAA,gBAAA,KAAAA,CAAA,EAAeL,CAAAA,YAAf,KAAeA,CAAf;YACAG,OAAA,OAAAV,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMW,IAAN,CAAA,EAAA,IAAA;YADA;cAGAJ,CAAAA,YAAQK,aAARL;YAHA,CAAA;UADFG,CAAAA;;AAOAG,UAAAA,uBAAAA,mBAAYF,IAAZE;AAAAA,YAAAA;;YAAAA;;YACE,KAAc,UAAA,MAACF,IAAD,CAAA,CAAd,EAAAG,CAAAA,MAAA,6BAAAA,CAAA,EAAKC,CAAAA,SAAL,6BAAKA,CAAL;YAEA,IAAA,QAAG,CAAG,KAAH,EAAO,KAAP,CAAWC,aAAAA,CAAUF,GAAGG,MAAAA,CAAAA,CAAbD,CAAd,CAAA;cACET,SAAMW,OAAAA,CAAGJ,GAAHI;YADR;YAIAL,OAAA,OAAAb,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMW,IAAN,CAAA,EAAA,IAAA;UAPFE,CAAAA;;AAUAM,UAAAA,0BAAAA,sBAAeR,IAAfQ;AAAAA,YAAAA;;;YACE,KAAU,UAAA,MAACR,IAAD,CAAA,CAAV,EAAAS,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,IAAN,6BAAMA,CAAN;YAEA,IAAA,MAAGD,IAAIH,MAAAA,CAAAA,CAAP,EAAgB,MAAhB,CAAA;cACEG,OAAOpB,IAAAsB,sBAAAA,CAAqBF,IAArBE;YADT;YAIAH,OAAAR,IAAIY,SAAAA,CAAS,GAAb,EAAkB,CAACH,IAAD,CAAdG;UAPNJ,CAAAA;UAUAd,OAAAmB;UAAAA;;YAAAA;;AAAAA;;;AACElB,YAAAA,0BAAAA,sBAAAA;AAAAA,cAAAA;;cACEA,OAAAmB,CAAAA,WAAOC,SAAGjB,KAAAA,CAAAA,CAAVgB;YADFnB,CAAAA;YAIAkB,OAAAN,kBAAAA,+BAAOS,OAAPT;AAAAA,cAAAA;;cACE,IAAA,QAAGO,QAAIT,aAAAA,CAAUW,OAAVX,CAAP,CAAA;;gBACE,KAAS,UAAA,MAACW,OAAD,CAAA,CAAT,EAAAb,CAAAA,MAAA,6BAAAA,CAAA,EAAKO,CAAAA,IAAL,6BAAKA,CAAL;gBACAP,MAAM,CAAA,MAAAa,OAAOV,MAAAA,CAAAA,CAAP,EAAgB,KAAhB,CAAA,GAAA,CAAuBH,GAAGc,SAAAA,CAAAA,CAA1B,IAAA,CAAsCV,GAAD,GAAA,CAAIJ,GAAJ,CAArC,CAAA;gBACNI,OAAAW,YAAMC,MAAAA,CAAOZ,eAAD,GAAA,CAAgBJ,GAAhB,CAAA,GAAoBI,gCAA1BY;cAHR;gBAKEZ,OAAAO,QAAKP,OAAAA,CAAGS,OAAHT;cALP;YADFA,CAAAA;UALFM,GAAAA,WAAAA,EAAAA,IAAAA;QAhCFnB,GAAAA,WAAAA,EAA8B0B,IAAAC,IAAAC,KAAAD,cAAAD,SAA9B1B;MADFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>26659, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/dump_args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class DumpArgs < Base\n      def on_def(node)\n        node = super(node)\n        _mid, args, _body = *node\n        node.updated(nil, nil, meta: { original_args: args })\n      end\n\n      def on_defs(node)\n        node = super(node)\n        _recv, _mid, args, _body = *node\n\n        node.updated(nil, nil, meta: { original_args: args })\n      end\n\n      def on_iter(node)\n        node = super(node)\n        args, _body = *node\n        node.updated(nil, nil, meta: { original_args: args })\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:DumpArgs>", "on_def", "node", "_mid", "args", "_body", "updated", "on_defs", "_recv", "on_iter", "Base"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;;;AACEC,QAAAA,sBAAAA,kBAAWC,IAAXD;AAAAA,UAAAA;;UAAAA;;UACEC,OAAO,OAAAN,IAAA,EAAA,kDAAA,UAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;UACP,KAAoB,UAAA,MAACA,IAAD,CAAA,CAApB,EAAAC,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,OAAN,6BAAMA,CAAN,EAAYC,CAAAA,QAAZ,6BAAYA,CAAZ;UACAJ,OAAAC,IAAII,SAAAA,CAAS,GAAb,EAAkB,GAAlB,EAAuB,kBAAA,QAAM,2BAAA,iBAAiBF,IAAjB,EAAN,EAAnBE;QAHNL,CAAAA;;AAMAM,QAAAA,uBAAAA,mBAAYL,IAAZK;AAAAA,UAAAA;;UAAAA;;UACEL,OAAO,OAAAN,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;UACP,KAA2B,UAAA,MAACA,IAAD,CAAA,CAA3B,EAAAM,CAAAA,QAAA,6BAAAA,CAAA,EAAOL,CAAAA,OAAP,6BAAOA,CAAP,EAAaC,CAAAA,OAAb,6BAAaA,CAAb,EAAmBC,CAAAA,QAAnB,6BAAmBA,CAAnB;UAEAE,OAAAL,IAAII,SAAAA,CAAS,GAAb,EAAkB,GAAlB,EAAuB,kBAAA,QAAM,2BAAA,iBAAiBF,IAAjB,EAAN,EAAnBE;QAJNC,CAAAA;QAOAP,OAAAS,uBAAAA,mBAAYP,IAAZO;AAAAA,UAAAA;;UAAAA;;UACEP,OAAO,OAAAN,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;UACP,KAAc,UAAA,MAACA,IAAD,CAAA,CAAd,EAAAE,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,QAAN,6BAAMA,CAAN;UACAI,OAAAP,IAAII,SAAAA,CAAS,GAAb,EAAkB,GAAlB,EAAuB,kBAAA,QAAM,2BAAA,iBAAiBF,IAAjB,EAAN,EAAnBE;QAHNG,CAAAA;MAdFT,GAAAA,WAAAA,EAAiBU,UAAjBV;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>26713, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/mlhs_args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    # Rewrites\n    #\n    # def m( (a, b), (c, d) )\n    #   body\n    # end\n    #\n    # To\n    #\n    # def m($mlhs_tmp1, $mlhs_tmp2)\n    #   (a, b) = $mlhs_tmp1\n    #   (c, d) = $mlhs_tmp2\n    #   body\n    # end\n    #\n    class MlhsArgs < Base\n      def on_def(node)\n        node = super(node)\n        mid, args, body = *node\n\n        arguments = Arguments.new(args)\n\n        args = args.updated(nil, arguments.rewritten)\n        if arguments.initialization\n          body ||= s(:nil) # prevent returning mlhs assignment\n          body = prepend_to_body(body, arguments.initialization)\n        end\n\n        node.updated(nil, [mid, args, body])\n      end\n\n      def on_defs(node)\n        node = super(node)\n        recv, mid, args, body = *node\n\n        arguments = Arguments.new(args)\n\n        args = args.updated(nil, arguments.rewritten)\n        if arguments.initialization\n          body ||= s(:nil) # prevent returning mlhs assignment\n          body = prepend_to_body(body, arguments.initialization)\n        end\n\n        node.updated(nil, [recv, mid, args, body])\n      end\n\n      def on_iter(node)\n        node = super(node)\n        args, body = *node\n\n        arguments = Arguments.new(args)\n\n        args = args.updated(nil, arguments.rewritten)\n        if arguments.initialization\n          body ||= s(:nil) # prevent returning mlhs assignment\n          body = prepend_to_body(body, arguments.initialization)\n        end\n\n        node.updated(nil, [args, body])\n      end\n\n      class Arguments < Base\n        attr_reader :rewritten, :initialization\n\n        def initialize(args)\n          @args = args\n          @rewritten = []\n          @initialization = []\n          @rewriter = MlhsRewriter.new\n\n          split!\n        end\n\n        def reset_tmp_counter!\n          @counter = 0\n        end\n\n        def new_mlhs_tmp\n          @counter ||= 0\n          @counter += 1\n          :\"$mlhs_tmp\#{@counter}\"\n        end\n\n        def split!\n          @args.children.each do |arg|\n            if arg.type == :mlhs\n              var_name = new_mlhs_tmp\n              rhs = s(:lvar, var_name)\n              mlhs = @rewriter.process(arg)\n              @initialization << s(:masgn, mlhs, rhs)\n              @rewritten << s(:arg, var_name).updated(nil, nil, meta: { arg_name: var_name })\n            else\n              @rewritten << arg\n            end\n          end\n\n          if @initialization.length == 1\n            @initialization = @initialization[0]\n          elsif @initialization.empty?\n            @initialization = nil\n          else\n            @initialization = s(:begin, *@initialization)\n          end\n        end\n      end\n\n      class MlhsRewriter < Base\n        def on_arg(node)\n          node.updated(:lvasgn)\n        end\n\n        def on_restarg(node)\n          name = node.children[0]\n          if name\n            s(:splat, node.updated(:lvasgn))\n          else\n            s(:splat)\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:MlhsArgs>", "on_def", "node", "mid", "args", "body", "arguments$", "Arguments", "new", "updated", "rewritten", "initialization", "$ret_or_1", "s", "prepend_to_body", "on_defs", "recv", "on_iter", "<class:Arguments>", "attr_reader", "initialize", "@args", "@rewritten", "@initialization", "@rewriter", "MlhsRewriter", "split!", "reset_tmp_counter!", "0", "new_mlhs_tmp", "@counter", "+", "1", "each", "children", "block in split!", "arg", "block (2 levels) in split!", "type", "var_name", "rhs", "mlhs", "process", "<<", "length", "[]", "empty?", "Base", "<class:MlhsRewriter>", "on_arg", "on_restarg", "name"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAeEA,OAAAC;MAAAA;;QAAAA;;;;AACEC,QAAAA,sBAAAA,kBAAWC,IAAXD;AAAAA,UAAAA;;UAAAA;;UACEC,OAAO,OAAAN,IAAA,EAAA,kDAAA,UAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;UACP,KAAkB,UAAA,MAACA,IAAD,CAAA,CAAlB,EAAAC,CAAAA,MAAA,6BAAAA,CAAA,EAAKC,CAAAA,OAAL,6BAAKA,CAAL,EAAWC,CAAAA,OAAX,6BAAWA,CAAX;UAEAC,aAAYC,eAASC,KAAAA,CAAKJ,IAALI;UAErBJ,OAAOA,IAAIK,SAAAA,CAAS,GAAb,EAAkBH,UAASI,WAAAA,CAAAA,CAAvBD;UACX,IAAA,QAAGH,UAASK,gBAAAA,CAAAA,CAAZ,CAAA;;YACEN,OA7BV,CAAA,QAAAO,CAAAA,YA6BUP,IA7BVO,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CA6BmBhB,IAAAiB,GAAAA,CAAE,KAAFA,CA7BnB,CAAA;YA8BUR,OAAOT,IAAAkB,iBAAAA,CAAgBT,IAAhB,EAAsBC,UAASK,gBAAAA,CAAAA,CAA/BG;UAFT;UAKAb,OAAAC,IAAIO,SAAAA,CAAS,GAAb,EAAkB,CAACN,GAAD,EAAMC,IAAN,EAAYC,IAAZ,CAAdI;QAZNR,CAAAA;;AAeAc,QAAAA,uBAAAA,mBAAYb,IAAZa;AAAAA,UAAAA;;UAAAA;;UACEb,OAAO,OAAAN,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;UACP,KAAwB,UAAA,MAACA,IAAD,CAAA,CAAxB,EAAAc,CAAAA,OAAA,6BAAAA,CAAA,EAAMb,CAAAA,MAAN,6BAAMA,CAAN,EAAWC,CAAAA,OAAX,6BAAWA,CAAX,EAAiBC,CAAAA,OAAjB,6BAAiBA,CAAjB;UAEAC,aAAYC,eAASC,KAAAA,CAAKJ,IAALI;UAErBJ,OAAOA,IAAIK,SAAAA,CAAS,GAAb,EAAkBH,UAASI,WAAAA,CAAAA,CAAvBD;UACX,IAAA,QAAGH,UAASK,gBAAAA,CAAAA,CAAZ,CAAA;;YACEN,OA5CV,CAAA,QAAAO,CAAAA,YA4CUP,IA5CVO,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CA4CmBhB,IAAAiB,GAAAA,CAAE,KAAFA,CA5CnB,CAAA;YA6CUR,OAAOT,IAAAkB,iBAAAA,CAAgBT,IAAhB,EAAsBC,UAASK,gBAAAA,CAAAA,CAA/BG;UAFT;UAKAC,OAAAb,IAAIO,SAAAA,CAAS,GAAb,EAAkB,CAACO,IAAD,EAAOb,GAAP,EAAYC,IAAZ,EAAkBC,IAAlB,CAAdI;QAZNM,CAAAA;;AAeAE,QAAAA,uBAAAA,mBAAYf,IAAZe;AAAAA,UAAAA;;UAAAA;;UACEf,OAAO,OAAAN,IAAA,EAAA,oDAAA,WAAA,EAAA,CAAMM,IAAN,CAAA,EAAA,IAAA;UACP,KAAa,UAAA,MAACA,IAAD,CAAA,CAAb,EAAAE,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,OAAN,6BAAMA,CAAN;UAEAC,aAAYC,eAASC,KAAAA,CAAKJ,IAALI;UAErBJ,OAAOA,IAAIK,SAAAA,CAAS,GAAb,EAAkBH,UAASI,WAAAA,CAAAA,CAAvBD;UACX,IAAA,QAAGH,UAASK,gBAAAA,CAAAA,CAAZ,CAAA;;YACEN,OA3DV,CAAA,QAAAO,CAAAA,YA2DUP,IA3DVO,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CA2DmBhB,IAAAiB,GAAAA,CAAE,KAAFA,CA3DnB,CAAA;YA4DUR,OAAOT,IAAAkB,iBAAAA,CAAgBT,IAAhB,EAAsBC,UAASK,gBAAAA,CAAAA,CAA/BG;UAFT;UAKAG,OAAAf,IAAIO,SAAAA,CAAS,GAAb,EAAkB,CAACL,IAAD,EAAOC,IAAP,CAAdI;QAZNQ,CAAAA;QAeAC;QAAAA;;UAAAA;;AAAAA;;UACEtB,IAAAuB,aAAAA,CAAY,WAAZ,EAAwB,gBAAxBA;;AAEAC,UAAAA,0BAAAA,sBAAehB,IAAfgB;AAAAA,YAAAA;;;YACEC,YAAQjB;YACRkB,iBAAa;YACbC,sBAAkB;YAClBC,gBAAYC,kBAAYjB,KAAAA,CAAAA;YAExBY,OAAAxB,IAAA8B,WAAAA,CAAAA;UANFN,CAAAA;;AASAO,UAAAA,kCAAAA,iBACE,SADFA,EACaC,CADbD,CAAAA;;AAIAE,UAAAA,4BAAAA,wBAAAA;AAAAA,YAAAA;;;YACEC,eAnFV,CAAA,QAAAlB,CAAAA,YAmFUkB,YAnFVlB,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAmFuBgB,CAnFvB,CAAA;YAoFUE,eAASC,SAATD,YAASC,EAAGC,CAAHD;YACTF,OAAEA,WAAF,GAAA,CAAaC,YAAb;UAHFD,CAAAA;UAMAX,OAAAQ,sBAAAA,iCAAAA;AAAAA,YAAAA;;;YACgBO,MAAdZ,SAAKa,UAAAA,CAAAA,CAASD,QAAAA,EAAAA,EAAAA,EAAdE,aAAwBC,GAAxBD,EAAAE;AAAAA;AAAAA;AAAAA;;;cAAwB;cACtB,IAAA,MAAGD,GAAGE,MAAAA,CAAAA,CAAN,EAAe,MAAf,CAAA;;gB