e\n          when :arg, :mlhs\n            (@restarg || @optargs.any? ? @postargs : @args) << arg\n          when :optarg\n            @optargs << arg\n          when :restarg\n            @restarg = arg\n          when :kwarg\n            @kwargs << arg\n          when :kwoptarg\n            @kwoptargs << arg\n          when :kwnilarg\n            @kwnilarg = true\n          when :kwrestarg\n            @kwrestarg = arg\n          when :shadowarg\n            @shadowargs << arg\n          when :blockarg\n            @blockarg = arg\n          else\n            raise \"Unsupported arg type \#{arg.type}\"\n          end\n        end\n      end\n\n      def has_post_args?\n        !@restarg.nil? || @postargs.any? || (has_any_kwargs? && !can_inline_kwargs?)\n      end\n\n      def has_any_kwargs?\n        @kwargs.any? || @kwoptargs.any? || !@kwrestarg.nil?\n      end\n\n      def can_inline_kwargs?\n        @optargs.empty? && @restarg.nil? && @postargs.empty?\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<module:Rewriters>", "<class:Arguments>", "self", "attr_reader", "initialize", "args", "@args", "@optargs", "@restarg", "@postargs", "@kwargs", "@kwoptargs", "@kwrestarg", "@kwnilarg", "@shadowargs", "@blockarg", "each", "block in initialize", "arg", "block (2 levels) in initialize", "type", "any?", "<<", "raise", "has_post_args?", "$ret_or_1", "$ret_or_2", "nil?", "!", "has_any_kwargs?", "can_inline_kwargs?", "empty?"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEC,IAAAC,aAAAA,CAAY,MAAZ,EAAmB,SAAnB,EAA6B,SAA7B,EAAuC,UAAvC,EACE,QADF,EACW,WADX,EACuB,WADvB,EACmC,UADnC,EAEE,YAFF,EAEe,UAFfA;;AAIAC,QAAAA,0BAAAA,sBAAeC,IAAfD;AAAAA,UAAAA;;;UACEE,YAAQ;UACRC,eAAW;UACXC,eAAW;UACXC,gBAAY;UACZC,cAAU;UACVC,iBAAa;UACbC,iBAAa;UACbC,gBAAY;UACZC,kBAAc;UACdC,gBAAY;UAEZX,OAAIY,MAAJX,IAAIW,QAAAA,EAAAA,EAAAA,EAAJC,aAAcC,GAAdD,EAAAE;AAAAA;AAAAA;AAAAA;AAAAA;AAAAA;AAAAA;AAAAA;;;YAAc;;YAEZ,QADKD,GAAGE,MAAAA,CAAAA,CACR;cAAA,KAAK,KAAL;cAAA,KAAW,MAAX;gBACED,OAAC,CAAA,CAAA,QAAAX,YAAA,CAAA,IAAA,CAAA,QAAYD,YAAQc,SAAAA,CAAAA,CAApB,CAAA,CAAA,CAAA,GAAA,CAA4BZ,aAA5B,IAAA,CAAwCH,SAAxC,CAAA,CAA+CgB,OAAAA,CAAGJ,GAAHI;cAClD,KAAK,QAAL;gBACEH,OAAAZ,YAASe,OAAAA,CAAGJ,GAAHI;cACX,KAAK,SAAL;gBACEH,OAAAX,CAAAA,eAAWU,GAAXV;cACF,KAAK,OAAL;gBACEW,OAAAT,WAAQY,OAAAA,CAAGJ,GAAHI;cACV,KAAK,UAAL;gBACEH,OAAAR,cAAWW,OAAAA,CAAGJ,GAAHI;cACb,KAAK,UAAL;gBACEH,OAAAN,CAAAA,gBAAY,IAAZA;cACF,KAAK,WAAL;gBACEM,OAAAP,CAAAA,iBAAaM,GAAbN;cACF,KAAK,WAAL;gBACEO,OAAAL,eAAYQ,OAAAA,CAAGJ,GAAHI;cACd,KAAK,UAAL;gBACEH,OAAAJ,CAAAA,gBAAYG,GAAZH;cADF;gBAGEI,OAAAjB,IAAAqB,OAAAA,CAAOJ,uBAAD,GAAA,CAAwBD,GAAGE,MAAAA,CAAAA,CAA3B,CAANG;YAnBF,EAFFN,CAAAA,GAAAA,SAAAA,CAAID;QAZNZ,CAAAA;;AAsCAoB,QAAAA,8BAAAA,yCAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAAC,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAClB,YAAQmB,SAAAA,CAAAA,CAATC,MAAAA,CAAAA,CAAAF,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAkBjB,aAASY,SAAAA,CAAAA,CAA3B,CAAA,CAAAI,CAAA,CAAA;YAAAD,OAAA;UAAA;;YAAqC,IAAA,QAAAE,CAAAA,YAAAxB,IAAA2B,oBAAAA,CAAAA,CAAAH,CAAA,CAAA;cAAmBF,OAACtB,IAAA4B,uBAAAA,CAAAA,CAADF,MAAAA,CAAAA;YAAnB;cAAAJ,OAAA;YAAA;UAArC;QADFA,CAAAA;;AAIAK,QAAAA,+BAAAA,0CAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAAJ,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAhB,WAAOW,SAAAA,CAAAA,CAAPK,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAgBf,cAAUU,SAAAA,CAAAA,CAA1B,CAAA,CAAAI,CAAA,CAAA;YAAAI,OAAA;UAAA;YAAmCA,OAACjB,cAAUe,SAAAA,CAAAA,CAAXC,MAAAA,CAAAA;UAAnC;QADFC,CAAAA;QAIA5B,OAAA6B,kCAAAA,6CAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAAL,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAnB,YAAQwB,WAAAA,CAAAA,CAARL,CAAA,CAAA,GAAA,CAAmBlB,YAAQmB,SAAAA,CAAAA,CAA3B,IAAA,CAAA,SAAA,CAAA,CAAAF,CAAA,CAAA;YAAoCK,OAAArB,aAASsB,WAAAA,CAAAA;UAA7C;YAAAD,OAAA;UAAA;QADFA,CAAAA;MAnDF7B,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>26983, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/inline_args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\nrequire 'opal/rewriters/arguments'\n\nmodule Opal\n  module Rewriters\n    # Converts\n    #\n    #   def m( a, b = 1, *c, d, e:, f: 1, **g, &blk )\n    #   end\n    #\n    # To something like\n    #\n    #   def m( a, <fake b>, <fake c>, <fake d>, <fake kwargs>)\n    #     blk = <extract block>\n    #     $post_args = arguments[1..-1]\n    #     $kwargs = $post_args.pop\n    #     a = <enough args> ? $post_args.shift : 1\n    #     c = <enough args> ? $post_args[0..-1] : []\n    #     d = $post_args.last\n    #     e = $kwargs.delete(:e)\n    #     f = $kwargs.delete(:f) || 1\n    #     g = $kwargs.except(:e, :f)\n    #   end\n    #\n    class InlineArgs < Base\n      def on_def(node)\n        node = super(node)\n        mid, args, body = *node\n\n        body ||= s(:nil) # prevent returning initialization statement\n\n        initializer = Initializer.new(args, type: :def)\n        inline_args = args.updated(nil, initializer.inline)\n        body = prepend_to_body(body, initializer.initialization)\n\n        node.updated(nil, [mid, inline_args, body])\n      end\n\n      def on_defs(node)\n        node = super(node)\n        recv, mid, args, body = *node\n\n        body ||= s(:nil) # prevent returning initialization statement\n\n        initializer = Initializer.new(args, type: :defs)\n        inline_args = args.updated(nil, initializer.inline)\n        body = prepend_to_body(body, initializer.initialization)\n\n        node.updated(nil, [recv, mid, inline_args, body])\n      end\n\n      def on_iter(node)\n        node = super(node)\n        args, body = *node\n\n        body ||= s(:nil) # prevent returning initialization statement\n\n        initializer = Initializer.new(args, type: :iter)\n        inline_args = args.updated(nil, initializer.inline)\n        body = prepend_to_body(body, initializer.initialization)\n\n        node.updated(nil, [inline_args, body])\n      end\n\n      class Initializer < ::Opal::Rewriters::Base\n        attr_reader :inline, :initialization\n\n        STEPS = %i[\n          extract_blockarg\n          initialize_shadowargs\n          extract_args\n\n          prepare_post_args\n          prepare_kwargs\n\n          extract_optargs\n          extract_restarg\n          extract_post_args\n\n          extract_kwargs\n          extract_kwoptargs\n          extract_kwrestarg\n        ].freeze\n\n        def initialize(args, type:)\n          @args = Arguments.new(args.children)\n\n          @inline = []\n          @initialization = []\n\n          @type = type\n          @underscore_found = false\n\n          STEPS.each do |step|\n            send(step)\n          end\n\n          if @initialization.any?\n            @initialization = s(:begin, *@initialization)\n          else\n            @initialization = nil\n          end\n        end\n\n        def extract_blockarg\n          if (arg = @args.blockarg)\n            @initialization << arg.updated(:extract_blockarg)\n          end\n        end\n\n        def initialize_shadowargs\n          @args.shadowargs.each do |arg|\n            @initialization << arg.updated(:initialize_shadowarg)\n          end\n        end\n\n        def extract_args\n          @args.args.each do |arg|\n            if @type == :iter\n              # block args are not required,\n              # so we neeed to tell compiler that required args\n              # must be initialized with nil-s\n              @initialization << arg.updated(:initialize_iter_arg)\n\n              if arg.children[0] == :_\n                if @underscore_found\n                  # for proc { |_, _| _ }.call(1, 2) result must be 1\n                  # here we convert all underscore args starting from the 2nd\n                  # to a \"fake\" arg\n                  arg = s(:fake_arg)\n                end\n\n                @underscore_found = true\n              end\n            else\n              # required inline def argument like 'def m(req)'\n              # no initialization is required\n            end\n            @inline << arg\n          end\n        end\n\n        def prepare_post_args\n          if @args.has_post_args?\n            @initialization << s(:prepare_post_args, @args.args.length)\n          end\n        end\n\n        def prepare_kwargs\n          return unless @args.has_any_kwargs?\n\n          if @args.can_inline_kwargs?\n            @inline << s(:arg, :'$kwargs')\n          else\n            @initialization << s(:extract_kwargs)\n            @inline << s(:fake_arg)\n          end\n\n          @initialization << s(:ensure_kwargs_are_kwargs)\n        end\n\n        def extract_kwargs\n          @args.kwargs.each do |arg|\n            @initialization << arg.updated(:extract_kwarg)\n          end\n        end\n\n        def extract_kwoptargs\n          @args.kwoptargs.each do |arg|\n            @initialization << arg.updated(:extract_kwoptarg)\n          end\n        end\n\n        def extract_kwrestarg\n          if (arg = @args.kwrestarg)\n            @initialization << arg.updated(:extract_kwrestarg)\n          end\n        end\n\n        def extract_post_args\n          # post arguments must be extracted with an offset\n          @args.postargs.each do |arg|\n            @initialization << arg.updated(:extract_post_arg)\n            @inline << s(:fake_arg)\n          end\n        end\n\n        def extract_optargs\n          has_post_args = @args.has_post_args?\n          @args.optargs.each do |arg|\n            if has_post_args\n              # optional post argument like 'def m(opt = 1, a)'\n              arg_name, default_value = *arg\n              @initialization << arg.updated(:extract_post_optarg, [arg_name, default_value, args_to_keep])\n              @inline << s(:fake_arg)\n            else\n              # optional inline argument like 'def m(a, opt = 1)'\n              @inline << arg.updated(:arg)\n              @initialization << arg.updated(:extract_optarg)\n            end\n          end\n        end\n\n        def extract_restarg\n          if (arg = @args.restarg)\n            arg_name = arg.children[0]\n            @initialization << arg.updated(:extract_restarg, [arg_name, args_to_keep])\n            @inline << s(:fake_arg)\n          end\n        end\n\n        def args_to_keep\n          @args.postargs.length\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:InlineArgs>", "on_def", "node", "mid", "args", "body", "$ret_or_1", "s", "initializer", "Initializer", "new", "inline_args", "updated", "inline", "prepend_to_body", "initialization", "on_defs", "recv", "on_iter", "<class:Initializer>", "attr_reader", "freeze", "initialize", "$kwargs", "@args", "Arguments", "children", "@inline", "@initialization", "@type", "type", "@underscore_found", "each", "STEPS", "block in initialize", "step", "block (2 levels) in initialize", "send", "any?", "extract_blockarg", "arg", "blockarg", "<<", "initialize_shadowargs", "shadowargs", "block in initialize_shadowargs", "block (2 levels) in initialize_shadowargs", "extract_args", "block in extract_args", "block (2 levels) in extract_args", "[]", "0", "prepare_post_args", "has_post_args?", "length", "prepare_kwargs", "has_any_kwargs?", "can_inline_kwargs?", "extract_kwargs", "kwargs", "block in extract_kwargs", "block (2 levels) in extract_kwargs", "extract_kwoptargs", "kwoptargs", "block in extract_kwoptargs", "block (2 levels) in extract_kwoptargs", "extract_kwrestarg", "kwrestarg", "extract_post_args", "postargs", "block in extract_post_args", "block (2 levels) in extract_post_args", "extract_optargs", "has_post_args", "optargs", "block in extract_optargs", "block (2 levels) in extract_optargs", "arg_name", "default_value", "args_to_keep", "extract_restarg", "restarg", "Opal::Rewriters::Base", "Opal::Rewriters", "Opal", "Base"], :mappings=>"AAAAA,6CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EACAD,IAAAC,SAAAA,CAAQF,0BAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IA