CAAHmC;cAJV;;gBAOEf,WAAQe,OAAAA,CAAGF,GAAG5B,SAAAA,CAAS,KAATA,CAAN8B;gBACRkC,OAAAhD,mBAAgBc,OAAAA,CAAGF,GAAG5B,SAAAA,CAAS,gBAATA,CAAN8B;cARlB,EADFiC,CAAAA,GAAAA,SAAAA,CAAa3C;UAFfwC,CAAAA;;AAgBAQ,UAAAA,+BAAAA,2BAAAA;AAAAA,YAAAA;;YACE,IAAA,QAAIxC,CAAAA,MAAMhB,SAAKyD,SAAAA,CAAAA,CAAXzC,CAAJ,CAAA;;cACEqC,WAAWrC,GAAGd,UAAAA,CAAAA,CAASwB,OAAAA,CAACC,CAADD;cACvBtB,mBAAgBc,OAAAA,CAAGF,GAAG5B,SAAAA,CAAS,iBAAZ,EAA8B,CAACiE,QAAD,EAAWjF,IAAAmF,cAAAA,CAAAA,CAAX,CAA3BnE,CAAN8B;cAChBsC,OAAArD,WAAQe,OAAAA,CAAG9C,IAAAW,GAAAA,CAAE,UAAFA,CAAHmC;YAHV;cA9MVsC,OAAA;YA8MU;UADFA,CAAAA;UAQA7D,OAAA4D,4BAAAA,wBAAAA;AAAAA,YAAAA;;YACEA,OAAAvD,SAAK6C,UAAAA,CAAAA,CAASf,QAAAA,CAAAA;UADhByB,CAAAA;QAnJF5D,GAAAA,WAAAA,EAAoB+D,IAAAC,IAAAC,KAAAD,cAAAD,SAApB/D;MAxCFnB,GAAAA,WAAAA,EAAmBqF,UAAnBrF;IApBFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>27244, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/numblocks.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    # This rewriter transforms the Ruby 2.7 numblocks to regular blocks:\n    #\n    # proc { _1 }\n    #      v\n    # proc { |_1| _1 }\n    class Numblocks < Base\n      def on_numblock(node)\n        left, arg_count, right = node.children\n\n        s(\n          :block,\n          left,\n          s(:args, *gen_args(arg_count)),\n          right\n        )\n      end\n\n      def gen_args(arg_count)\n        (1..arg_count).map do |i|\n          s(:arg, :\"_\#{i}\")\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:Numblocks>", "on_numblock", "node", "children", "left", "arg_count", "right", "s", "gen_args", "map", "1", "block in gen_args", "i", "block (2 levels) in gen_args", "Base"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAMEA,OAAAC;MAAAA;;;;;AACEC,QAAAA,2BAAAA,uBAAgBC,IAAhBD;AAAAA,UAAAA;;;UACE,KAAyBC,IAAIC,UAAAA,CAAAA,CAA7B,kBAAA,EAAAC,CAAAA,OAAA,6BAAAA,CAAA,EAAMC,CAAAA,YAAN,6BAAMA,CAAN,EAAiBC,CAAAA,QAAjB,6BAAiBA,CAAjB;UAEAL,OAAAL,IAAAW,GAAAA,CACE,OADF,EAEEH,IAFF,EAGEG,MAAAX,IAAAW,KAAAA,EAAA,CAAE,MAAF,CAAA,QAAS,MAACX,IAAAY,UAAAA,CAASH,SAATG,CAAD,CAAT,CAAAD,CAHF,EAIED,KAJFC;QAHFN,CAAAA;QAWAD,OAAAQ,wBAAAA,oBAAaH,SAAbG;AAAAA,UAAAA;;UACEA,OAAcC,MAAb,gBAAAC,CAAA,EAAGL,SAAH,QAAaI,OAAAA,EAAAA,EAAAA,EAAdE,aAAuBC,CAAvBD,EAAAE;;;YAAuB;YACrBA,OAAAjB,IAAAW,GAAAA,CAAE,KAAF,EAAUM,GAAF,GAAA,CAAKD,CAAL,CAARL,EADFI,CAAAA,GAAAA,SAAAA,CAAcF;QADhBD,CAAAA;MAZFR,GAAAA,WAAAA,EAAkBc,UAAlBd;IANFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>27286, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/returnable_logic.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class ReturnableLogic < Base\n      def next_tmp\n        @counter ||= 0\n        @counter += 1\n        \"$ret_or_\#{@counter}\"\n      end\n\n      def free_tmp\n        @counter -= 1\n      end\n\n      def reset_tmp_counter!\n        @counter = nil\n      end\n\n      def on_if(node)\n        test, = *node.children\n\n        check_control_flow!(test)\n\n        # The if_test metadata signifies that we don't care about the return value except if it's\n        # truthy or falsy. And those tests will be carried out by the respective $truthy helper calls.\n        test.meta[:if_test] = true if test\n        super\n      end\n\n      def on_case(node)\n        lhs, *whens, els = *node.children\n        els ||= s(:nil)\n        lhs_tmp = next_tmp if lhs\n\n        out = build_if_from_when(node, lhs, lhs_tmp, whens, els)\n        free_tmp if lhs\n        out\n      end\n\n      # `a || b` / `a or b`\n      def on_or(node)\n        lhs, rhs = *node.children\n\n        check_control_flow!(lhs)\n\n        if node.meta[:if_test]\n          # Let's forward the if_test to the lhs and rhs - since we don't care about the exact return\n          # value of our or, we neither do care about a return value of our lhs or rhs.\n          lhs.meta[:if_test] = rhs.meta[:if_test] = true\n          out = process(node.updated(:if, [lhs, s(:true), rhs]))\n        else\n          lhs_tmp = next_tmp\n          out = process(node.updated(:if, [s(:lvasgn, lhs_tmp, lhs), s(:js_tmp, lhs_tmp), rhs]))\n          free_tmp\n        end\n        out\n      end\n\n      # `a && b` / `a and b`\n      def on_and(node)\n        lhs, rhs = *node.children\n\n        check_control_flow!(lhs)\n\n        if node.meta[:if_test]\n          lhs.meta[:if_test] = rhs.meta[:if_test] = true\n          out = process(node.updated(:if, [lhs, rhs, s(:false)]))\n        else\n          lhs_tmp = next_tmp\n          out = process(node.updated(:if, [s(:lvasgn, lhs_tmp, lhs), rhs, s(:js_tmp, lhs_tmp)]))\n          free_tmp\n        end\n        out\n      end\n\n      # Parser sometimes generates parentheses as a begin node. If it's a single node begin value, then\n      # let's forward the if_test metadata.\n      def on_begin(node)\n        if node.meta[:if_test] && node.children.count == 1\n          node.children.first.meta[:if_test] = true\n        end\n        node.meta.delete(:if_test)\n        super\n      end\n\n      private\n\n      def check_control_flow!(node)\n        case node.type\n        when :break, :next, :redo, :retry, :return\n          error 'void value expression'\n        end\n      end\n\n      def build_if_from_when(node, lhs, lhs_tmp, whens, els)\n        first_when, *next_whens = *whens\n\n        *parts, expr = *first_when.children\n\n        rule = build_rule_from_parts(node, lhs, lhs_tmp, parts)\n\n        first_when.updated(:if, [rule, process(expr), next_whens.empty? ? process(els) : build_if_from_when(nil, nil, lhs_tmp, next_whens, els)])\n      end\n\n      def build_rule_from_parts(node, lhs, lhs_tmp, parts)\n        lhs = if node && lhs_tmp\n                node.updated(:lvasgn, [lhs_tmp, process(lhs)])\n              else\n                s(:js_tmp, lhs_tmp)\n              end\n\n        first_part, *next_parts = *parts\n\n        subrule = if first_part.type == :splat\n                    splat_on = first_part.children.first\n                    iter_val = next_tmp\n                    block = s(:send, process(splat_on), :any?,\n                      s(:iter,\n                        s(:args, s(:arg, iter_val)),\n                        build_rule_from_parts(nil, nil, lhs_tmp, [s(:lvar, iter_val)])\n                      )\n                    )\n                    if node && lhs_tmp\n                      s(:begin, lhs, block)\n                    else\n                      block\n                    end\n                  elsif lhs_tmp\n                    s(:send, process(first_part), :===, lhs)\n                  else\n                    process(first_part)\n                  end\n\n        if next_parts.empty?\n          subrule\n        else\n          s(:if, subrule, s(:true), build_rule_from_parts(nil, nil, lhs_tmp, next_parts))\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:ReturnableLogic>", "next_tmp", "@counter", "$ret_or_1", "0", "+", "1", "free_tmp", "-", "reset_tmp_counter!", "on_if", "node", "children", "test", "check_control_flow!", "meta", "[]=", "on_case", "lhs", "whens", "els", "s", "lhs_tmp", "out", "build_if_from_when", "on_or", "rhs", "[]", "process", "updated", "on_and", "on_begin", "count", "first", "delete", "private", "type", "error", "first_when", "next_whens", "parts", "expr", "rule", "build_rule_from_parts", "empty?", "first_part", "next_parts", "subrule", "splat_on", "iter_val", "block", "Base"], :mappings=>"AAAAA,kDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;;AACEC,QAAAA,wBAAAA,o