:offset=>{:line=>27449, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriters/forward_args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/base'\n\nmodule Opal\n  module Rewriters\n    class ForwardArgs < Base\n      def on_forward_args(_node)\n        process(\n          s(:args, s(:forward_arg, :\"$\"))\n        )\n      end\n\n      def on_forwarded_restarg(_node)\n        process(\n          s(:splat, s(:lvar, '$fwd_rest'))\n        )\n      end\n\n      def on_forwarded_kwrestarg(_node)\n        process(\n          s(:kwsplat, s(:lvar, '$fwd_kwrest'))\n        )\n      end\n\n      def on_block_pass(node)\n        if !node.children.first\n          process(\n            node.updated(nil,\n              [s(:lvar, '$fwd_block')]\n            )\n          )\n        else\n          super\n        end\n      end\n\n      def on_args(node)\n        if node.children.last && node.children.last.type == :forward_arg\n          prev_children = node.children[0..-2]\n\n          super(node.updated(nil,\n            [\n              *prev_children,\n              s(:restarg, '$fwd_rest'),\n              s(:blockarg, '$fwd_block')\n            ]\n          ))\n        else\n          super\n        end\n      end\n\n      def on_restarg(node)\n        if !node.children.first\n          node.updated(nil, ['$fwd_rest'])\n        else\n          super\n        end\n      end\n\n      def on_kwrestarg(node)\n        if !node.children.first\n          node.updated(nil, ['$fwd_kwrest'])\n        else\n          super\n        end\n      end\n\n      def on_blockarg(node)\n        if !node.children.first\n          node.updated(nil, ['$fwd_block'])\n        else\n          super\n        end\n      end\n\n      def on_send(node)\n        if node.children.last &&\n           node.children.last.class != Symbol &&\n           node.children.last.type == :forwarded_args\n\n          prev_children = node.children[0..-2]\n\n          super(node.updated(nil,\n            [\n              *prev_children,\n              s(:splat,\n                s(:lvar, '$fwd_rest')\n              ),\n              s(:block_pass,\n                s(:lvar, '$fwd_block')\n              )\n            ]\n          ))\n        else\n          super\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Rewriters>", "<class:ForwardArgs>", "on_forward_args", "_node", "process", "s", "on_forwarded_restarg", "on_forwarded_kwrestarg", "on_block_pass", "node", "children", "first", "updated", "on_args", "last", "type", "prev_children", "[]", "0", "-2", "on_restarg", "on_kwrestarg", "on_blockarg", "on_send", "class", "Symbol", "Base"], :mappings=>"AAAAA,8CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;;AACEC,QAAAA,+BAAAA,2BAAoBC,KAApBD;AAAAA,UAAAA;;UACEA,OAAAL,IAAAO,SAAAA,CACEP,IAAAQ,GAAAA,CAAE,MAAF,EAASR,IAAAQ,GAAAA,CAAE,aAAF,EAAgB,GAAhBA,CAATA,CADFD;QADFF,CAAAA;;AAMAI,QAAAA,oCAAAA,gCAAyBH,KAAzBG;AAAAA,UAAAA;;UACEA,OAAAT,IAAAO,SAAAA,CACEP,IAAAQ,GAAAA,CAAE,OAAF,EAAUR,IAAAQ,GAAAA,CAAE,MAAF,EAASC,WAATD,CAAVA,CADFD;QADFE,CAAAA;;AAMAC,QAAAA,sCAAAA,kCAA2BJ,KAA3BI;AAAAA,UAAAA;;UACEA,OAAAV,IAAAO,SAAAA,CACEP,IAAAQ,GAAAA,CAAE,SAAF,EAAYR,IAAAQ,GAAAA,CAAE,MAAF,EAASE,aAATF,CAAZA,CADFD;QADFG,CAAAA;;AAMAC,QAAAA,6BAAAA,yBAAkBC,IAAlBD;AAAAA,UAAAA;;UAAAA;UACE,IAAA,KAAIC,IAAIC,UAAAA,CAAAA,CAASC,OAAAA,CAAAA,CAAjB,CAAA;YACEH,OAAAX,IAAAO,SAAAA,CACEK,IAAIG,SAAAA,CAAS,GAAb,EACE,CAACf,IAAAQ,GAAAA,CAAE,MAAF,EAASG,YAATH,CAAD,CADEO,CADNR;UADF;YAOEI,OAAA,OAAAX,IAAA,EAAA,gEAAA,iBAAA,EAAA,CAAAY,IAAA,CAAA,EAAA,MAAA;UAPF;QADFD,CAAAA;;AAYAK,QAAAA,uBAAAA,mBAAYJ,IAAZI;AAAAA,UAAAA;;UAAAA;UACE,IAAG,CAAA,QAAAJ,IAAIC,UAAAA,CAAAA,CAASI,MAAAA,CAAAA,CAAb,CAAA,IAAA,CAAA,MAAsBL,IAAIC,UAAAA,CAAAA,CAASI,MAAAA,CAAAA,CAAKC,MAAAA,CAAAA,CAAxC,EAAiD,aAAjD,CAAA,CAAA,CAAH;;YACEC,gBAAgBP,IAAIC,UAAAA,CAAAA,CAASO,OAAAA,CAAC,OAAA