YAAME,OAAAD,KAAKE,MAAAA,CAAMnD,IAANmD,EAAjCH,CAAMF;UACNM,SAAS,qBAAA;UACUN,MAAbO,MAANN,MAAMM,OAAAA,EAAAA,EAAAA,EAAM,OAAD1C,SAAAA,CAAAA,CAAL0C,CAAaP,QAAAA,EAAAA,EAAAA,EAAO,KAADnC,SAAAA,CAAAA,CAANmC;UACnBxC,OAAA8C;QAJF9C,CAAAA,IAAAA;QAOAb,OAAAS,wBAAAA,oBAAaoD,OAAD,EAAUL,KAAtB/C;AAAAA,UAAAA;;UACE,IAAA,QAA6C+C,KAAKM,MAAAA,CAAAA,CAAlD,CAAA;YAAArD,OAAesD,MAAAA,CAAGtD,MAAF,GAAA,CAAQoD,OAAR,CAAhB,EAAqC,IAAtBE,CAAAA,EAAAA,MAAfP,KAAKM,MAAAA,CAAAA,CAAKE,MAAAA,CAAAA,CAAKD,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA;UAAf;YApFRtD,OAAA;UAoFQ;QADFA,CAAAA;MAzEFT,GAAAA,WAAAA,EAAsBiE,IAAAC,IAAAC,UAAAD,cAAAD,SAAtBjE;IANFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAHAD;"}}, {:offset=>{:line=>27753, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/rewriter.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/rewriters/opal_engine_check'\nrequire 'opal/rewriters/targeted_patches'\nrequire 'opal/rewriters/for_rewriter'\nrequire 'opal/rewriters/js_reserved_words'\nrequire 'opal/rewriters/block_to_iter'\nrequire 'opal/rewriters/dot_js_syntax'\nrequire 'opal/rewriters/pattern_matching'\nrequire 'opal/rewriters/logical_operator_assignment'\nrequire 'opal/rewriters/binary_operator_assignment'\nrequire 'opal/rewriters/hashes/key_duplicates_rewriter'\nrequire 'opal/rewriters/dump_args'\nrequire 'opal/rewriters/mlhs_args'\nrequire 'opal/rewriters/inline_args'\nrequire 'opal/rewriters/numblocks'\nrequire 'opal/rewriters/returnable_logic'\nrequire 'opal/rewriters/forward_args'\nrequire 'opal/rewriters/thrower_finder'\n\nmodule Opal\n  class Rewriter\n    @disabled = false\n\n    class << self\n      def list\n        @list ||= []\n      end\n\n      def use(rewriter)\n        list << rewriter\n      end\n\n      def delete(rewriter)\n        list.delete(rewriter)\n      end\n\n      def disable(except: nil)\n        old_disabled = @disabled\n        @disabled = except || true\n        yield\n      ensure\n        @disabled = old_disabled\n      end\n\n      def disabled?\n        @disabled == true\n      end\n\n      def rewritter_disabled?(rewriter)\n        return false if @disabled == false\n        @disabled != rewriter\n      end\n    end\n\n    use Rewriters::OpalEngineCheck\n    use Rewriters::ForRewriter\n    use Rewriters::Numblocks\n    use Rewriters::ForwardArgs\n    use Rewriters::BlockToIter\n    use Rewriters::TargetedPatches\n    use Rewriters::DotJsSyntax\n    use Rewriters::PatternMatching\n    use Rewriters::JsReservedWords\n    use Rewriters::LogicalOperatorAssignment\n    use Rewriters::BinaryOperatorAssignment\n    use Rewriters::Hashes::KeyDuplicatesRewriter\n    use Rewriters::ReturnableLogic\n    use Rewriters::DumpArgs\n    use Rewriters::MlhsArgs\n    use Rewriters::InlineArgs\n    use Rewriters::ThrowerFinder\n\n    def initialize(sexp)\n      @sexp = sexp\n    end\n\n    def process\n      return @sexp if self.class.disabled?\n\n      self.class.list.each do |rewriter_class|\n        next if self.class.rewritter_disabled?(rewriter_class)\n        rewriter = rewriter_class.new\n        @sexp = rewriter.process(@sexp)\n      end\n\n      @sexp\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<class:Rewriter>", "@disabled", "list", "@list", "$ret_or_1", "use", "rewriter", "<<", "delete", "disable", "$kwargs", "old_disabled", "except", "disabled?", "==", "rewritter_disabled?", "!=", "Rewriters::OpalEngineCheck", "Rewriters", "Rewriters::ForRewriter", "Rewriters::Numblocks", "Rewriters::ForwardArgs", "Rewriters::BlockToIter", "Rewriters::TargetedPatches", "Rewriters::DotJsSyntax", "Rewriters::PatternMatching", "Rewriters::JsReservedWords", "Rewriters::LogicalOperatorAssignment", "Rewriters::BinaryOperatorAssignment", "Rewriters::Hashes::KeyDuplicatesRewriter", "Rewriters::Hashes", "Rewriters::ReturnableLogic", "Rewriters::DumpArgs", "Rewriters::MlhsArgs", "Rewriters::InlineArgs", "Rewriters::ThrowerFinder", "initialize", "process", "class", "@sexp", "each", "block in process", "rewriter_class", "block (2 levels) in process", "new"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,kCAARE;EACAD,IAAAC,SAAAA,CAAQF,iCAARE;EACAD,IAAAC,SAAAA,CAAQF,6BAARE;EACAD,IAAAC,SAAAA,CAAQF,kCAARE;EACAD,IAAAC,SAAAA,CAAQF,8BAARE;EACAD,IAAAC,SAAAA,CAAQF,8BAARE;EACAD,IAAAC,SAAAA,CAAQF,iCAARE;EACAD,IAAAC,SAAAA,CAAQF,4CAARE;EACAD,IAAAC,SAAAA,CAAQF,2CAARE;EACAD,IAAAC,SAAAA,CAAQF,+CAARE;EACAD,IAAAC,SAAAA,CAAQF,0BAARE;EACAD,IAAAC,SAAAA,CAAQF,0BAARE;EACAD,IAAAC,SAAAA,CAAQF,4BAARE;EACAD,IAAAC,SAAAA,CAAQF,0BAARE;EACAD,IAAAC,SAAAA,CAAQF,iCAARE;EACAD,IAAAC,SAAAA,CAAQF,6BAARE;EACAD,IAAAC,SAAAA,CAAQF,+BAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACEC,gBAAY;MAEZ;;;;AACEC,QAAAA,oBAAAA,gBAAAA;AAAAA,UAAAA;AAAAA;;UACEA,OAAAC,CAAAA,YA1BR,CAAA,QAAAC,CAAAA,YA0BQD,SA1BRC,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CA0BkB,EA1BlB,CAAA,CA0BQD;QADFD,CAAAA;;AAIAG,QAAAA,mBAAAA,eAAQC,QAARD;AAAAA,UAAAA;;UACEA,OAAAR,IAAAK,MAAAA,CAAAA,CAAKK,OAAAA,CAAGD,QAAHC;QADPF,CAAAA;;AAIAG,QAAAA,sBAAAA,mBAAWF,QAAXE;AAAAA,UAAAA;;UACEA,OAAAX,IAAAK,MAAAA,CAAAA,CAAIM,QAAAA,CAAQF,QAARE;QADNA,CAAAA;;AAIAC,QAAAA,uBAAAA,mBArCNC,OAqCMD;AAAAA,UAAAA;AAAAA;;UAAAA;;UArCN;;UAqCkB,kCAAA,6BAAQ;UAClBA,OAAA,cAAA;;UAAAE,eAAeV;UACfA,gBAAY,CAAA,QAAAG,CAAAA,YAAAQ,MAAAR,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAU,IAAV,CAAA;UACZ,OAAA,qBAAA,EAAA;UAFA;YAIAH,CAAAA,gBAAYU,YAAZV;UAJA,CAAA;QADFQ,CAAAA,IAAAA;;AAQAI,QAAAA,yBAAAA,0BAAAA;AAAAA,UAAAA;AAAAA;;UACEA,OAAAZ,aAAUa,OAAAA,CAAG,IAAHA;QADZD,CAAAA;QAIA,OAAAE,mCAAAA,oCAAwBT,QAAxBS;AAAAA,UAAAA;AAAAA;;;UACE,IAAA,MAAgBd,aAAhB,EAA6B,KAA7B,CAAA;YAAA,OAAO;UAAP;UACAc,OAAAd,aAAUe,OAAAA,CAAGV,QAAHU;QAFZD,CAAAA;MAzBF,4BAASlB,IAAT;MA+BAA,IAAAQ,KAAAA,CAAIY,IAAAC,eAAAD,oBAAJZ;MACAR,IAAAQ,KAAAA,CAAIc,IAAAD,eAAAC,gBAAJd;MACAR,IAAAQ,KAAAA,CAAIe,IAAAF,eAAAE,cAAJf;MACAR,IAAAQ,KAAAA,CAAIgB,IAAAH,eAAAG,gBAAJhB;MACAR,IAAAQ,KAAAA,CAAIiB,IAAAJ,eAAAI,gBAAJjB;MACAR,IAAAQ,KAAAA,CAAIkB,IAAAL,eAAAK,oBAAJlB;MACAR,IAAAQ,KAAAA,CAAImB,IAAAN,eAAAM,gBAAJnB;MACAR,IAAAQ,KAAAA,CAAIoB,IAAAP,eAAAO,oBAAJpB;MACAR,IAAAQ,KAAAA,CAAIqB,IAAAR,eAAAQ,oBAAJrB;MACAR,IAAAQ,KAAAA,CAAIsB,IAAAT,eAAAS,8BAAJtB;MACAR,IAAAQ,KAAAA,CAAIuB,IAAAV,eAAAU,6BAAJvB;MACAR,IAAAQ,KAAAA,CAAIwB,IAAAC,IAAAZ,eAAAY,WAAAD,0BAAJxB;MACAR,IAAAQ,KAAAA,CAAI0B,IAAAb,eAAAa,oBAAJ1B;MACAR,IAAAQ,KAAAA,CAAI2B,IAAAd,eAAAc,aAAJ3B;MACAR,IAAAQ,KAAAA,CAAI4B,IAAAf,eAAAe,aAAJ5B;MACAR,IAAAQ,KAAAA,CAAI6B,IAAAhB,eAAAgB,eAAJ7B;MACAR,IAAAQ,KAAAA,CAAI8B,IAAAjB,eAAAiB,kBAAJ9B;;AAEA+B,MAAAA,0BAAAA,aACE,MADFA,CAAAA;MAIApC,OAAAqC,uBAAAA,mBAAAA;AAAAA,QAAAA;;;QACE,IAAA,QAAgBxC,IAAIyC,OAAAA,CAAAA,CAAMzB,cAAAA,CAAAA,CAA1B,CAAA;UAAA,OAAO0B;QAAP;QAEeC,MAAf3C,IAAIyC,OAAAA,CAAAA,CAAMpC,MAAAA,CAAAA,CAAKsC,QAAAA,EAAAA,EAAAA,EAAfC,aAAyBC,cAAzBD,EAAAE;AAAAA;;;UAAyB;UACvB,IAAA,QAAQ9C,IAAIyC,OAAAA,CAAAA,CAAMvB,wBAAAA,CAAqB2B,cAArB3B,CAAlB,CAAA;YAAA,OAAA;UAAA;UACAT,WAAWoC,cAAcE,KAAAA,CAAAA;UACzBD,OAAAJ,CAAAA,YAAQjC,QAAQ+B,SAAAA,CAASE,SAATF,CAAhBE,EAHFE,CAAAA,GAAAA,SAAAA,CAAeD;QAMfH,OAAAE;MATFF,CAAAA;IAxDFrC,GAAAA,WAAAA,EAAAA,IAAAA;EADFD,GAAAA,WAAAA;AApBAH;"}}, {:offset=>{:line=>27888, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/parser/source_buffer.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  module Parser\n    class SourceBuffer < ::Parser::Source::Buffer\n      def self.recognize_encoding(string)\n        super || Encoding::UTF_8\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<module:Parser>", "<class:SourceBuffer>", "recognize_encoding", "self", "string", "$ret_or_1", "Encoding::UTF_8", "Encoding", "Parser::Source::Buffer", "Parser::Source", "Parser"], :mappings=>"AAAAA,4CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC,MAAIC,IAAJD,yBAAAA,8BAA4BE,MAA5BF;AAAAA,UAAAA;;UAAAA;UACE,IAAA,QAAAG,CAAAA,YAAA,OAAAF,IAAA,EAAA,0EAAA,sBAAA,EAAA,CAAAC,MAAA,CAAA,EAAA,MAAA,CAAAC,CAAA,CAAA;YAAAH,OAAA;UAAA;YAASA,OAAAI,IAAAC,cAAAD;UAAT;QADFJ,CAAAA;MADFD,GAAAA,WAAAA,EAAqBO,IAAAC,IAAAC,aAAAD,WAAAD,WAArBP;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>27921, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/parser/default_config.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  module Parser\n    module DefaultConfig\n      module ClassMethods\n        attr_accessor :diagnostics_consumer\n\n        def default_parser\n          parser = super\n          parser.diagnostics.all_errors_are_fatal = true\n          parser.diagnostics.ignore_warnings      = false\n          parser.diagnostics.consumer             = diagnostics_consumer\n          parser\n        end\n      end\n\n      def self.included(klass)\n        klass.extend(ClassMethods)\n        klass.diagnostics_consumer = ->(diagnostic) do\n          if RUBY_ENGINE != 'opal'\n            $stderr.puts(diagnostic.render)\n          end\n        end\n      end\n\n      def initialize(*)\n        super(Opal::AST::Builder.new)\n      end\n\n      def parse(source_buffer)\n        parsed = super || ::Opal::AST::Node.new(:nil)\n        wrapped = ::Opal::AST::Node.new(:top, [parsed])\n        rewriten = rewrite(wrapped)\n        rewriten\n      end\n\n      def rewrite(node)\n        Opal::Rewriter.new(node).process\n      end\n    end\n\n    class << self\n      attr_accessor :default_parser_class\n\n      def default_parser\n        default_parser_class.default_parser\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<module:Parser>", "<module:DefaultConfig>", "<module:ClassMethods>", "self", "attr_accessor", "default_parser", "parser", "diagnostics", "all_errors_are_fatal=", "ignore_warnings=", "consumer=", "diagnostics_consumer", "included", "klass", "extend", "ClassMethods", "diagnostics_consumer=", "block in included", "diagnostic", "block (2 levels) in included", "initialize", "Opal::AST::Builder", "Opal::AST", "Opal", "new", "parse", "source_buffer", "parsed", "$ret_or_1", "Opal::AST::Node", "wrapped", "rewrite", "node", "Opal::Rewriter", "proc