ATFD,GAAOO,IAAAC,SAAAD,cAAPP;EAyBA/F,OAAAoC;EAAAA;;;;;IAGE,sBAAM,cAAN;IACAA,OAAAoE,4BAAAA,wBAAiBC,KAAjBD;AAAAA,MAAAA;;MACEA,OAAA/D,IAAAiE,OAAAA,CAAMD,KAANC;IADFF,CAAAA;EAJFpE,GAAMyB,IAAAnD,YAAAmD,aAANzB,EAAAA,IAAAA;AA/JApC;"}}, {:offset=>{:line=>28241, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/parser.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/ast/builder'\nrequire 'opal/rewriter'\nrequire 'opal/parser/source_buffer'\nrequire 'opal/parser/default_config'\nrequire 'opal/parser/with_ruby_lexer'\n\nrequire 'opal/parser/patch'\n"], :names=>["<top (required)>", "self", "require"], :mappings=>"AAAAA,8BAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,kBAARE;EACAD,IAAAC,SAAAA,CAAQF,eAARE;EACAD,IAAAC,SAAAA,CAAQF,2BAARE;EACAD,IAAAC,SAAAA,CAAQF,4BAARE;EACAD,IAAAC,SAAAA,CAAQF,6BAARE;EAEAF,OAAAC,IAAAC,SAAAA,CAAQF,mBAARE;AARAF;"}}, {:offset=>{:line=>28253, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/fragment.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  # A fragment holds a string of generated javascript that will be written\n  # to the destination. It also keeps hold of the original sexp from which\n  # it was generated. Using this sexp, when writing fragments in order, a\n  # mapping can be created of the original location => target location,\n  # aka, source-maps!\n  #\n  # These are generated by nodes, so will not have to create directly.\n  class Fragment\n    # String of javascript this fragment holds\n    # @return [String]\n    attr_reader :code\n\n    # Create fragment with javascript code and optional original [Opal::Sexp].\n    #\n    # @param code [String] javascript code\n    # @param sexp [Opal::Sexp] sexp used for creating fragment\n    def initialize(code, scope, sexp = nil)\n      @code = code.to_s\n      @sexp = sexp\n      @scope = scope\n    end\n\n    # Inspect the contents of this fragment, f(\"fooo\")\n    def inspect\n      \"f(\#{@code.inspect})\"\n    end\n\n    def source_map_name_for(sexp)\n      case sexp.type\n      when :top\n        case sexp.meta[:kind]\n        when :require\n          '<top (required)>'\n        when :eval\n          '(eval)'\n        when :main\n          '<main>'\n        end\n      when :begin, :newline, :js_return\n        source_map_name_for(@scope.sexp) if @scope\n      when :iter\n        scope = @scope\n        iters = 1\n        while scope\n          if scope.class == Nodes::IterNode\n            iters += 1\n            scope = scope.parent\n          else\n            break\n          end\n        end\n        level = \" (\#{iters} levels)\" if iters > 1\n        \"block\#{level} in \#{source_map_name_for(scope.sexp)}\"\n      when :self\n        'self'\n      when :module\n        const, = *sexp\n        \"<module:\#{source_map_name_for(const)}>\"\n      when :class\n        const, = *sexp\n        \"<class:\#{source_map_name_for(const)}>\"\n      when :const\n        scope, name = *sexp\n        if !scope || scope.type == :cbase\n          name.to_s\n        else\n          \"\#{source_map_name_for(scope)}::\#{name}\"\n        end\n      when :int\n        sexp.children.first\n      when :def\n        sexp.children.first\n      when :defs\n        sexp.children[1]\n      when :send\n        sexp.children[1]\n      when :lvar, :lvasgn, :lvdeclare, :ivar, :ivasgn, :gvar, :cvar, :cvasgn, :gvars, :gvasgn, :arg\n        sexp.children.first\n      when :str, :xstr # Inside xstr - JS calls\n        source_map_name_for(@scope.sexp)\n      else\n        # nil\n      end\n    end\n\n    def source_map_name\n      return nil unless @sexp\n\n      source_map_name_for(@sexp)\n    end\n\n    def location\n      case\n      when !@sexp\n        nil\n      when @sexp.type == :send\n        loc = @sexp.loc\n        if loc.respond_to? :dot # a>.b || a>+b / >a / a>[b]\n          loc.dot || loc.selector\n        elsif loc.respond_to? :operator # a >|= b\n          loc.operator\n        else\n          @sexp\n        end\n      when @sexp.type == :iter\n        if loc.respond_to? :begin\n          @sexp.loc.begin # [1,2].each >{ }\n        else\n          @sexp\n        end\n      else\n        @sexp\n      end\n    end\n\n    # Original line this fragment was created from\n    # @return [Integer, nil]\n    def line\n      location&.line\n    end\n\n    # Original column this fragment was created from\n    # @return [Integer, nil]\n    def column\n      location&.column\n    end\n\n    def skip_source_map?\n      @sexp == false\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<class:Fragment>", "self", "attr_reader", "initialize", "code", "scope", "sexp", "@code", "to_s", "@sexp", "@scope", "inspect", "source_map_name_for", "type", "meta", "[]", "iters", "1", "class", "Nodes::IterNode", "Nodes", "+", "parent", ">", "level", "const$", "name", "children", "first", "source_map_name", "location", "loc", "respond_to?", "$ret_or_1", "dot", "selector", "operator", "begin", "line", "column", "skip_source_map?", "=="], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAQEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MAGEC,IAAAC,aAAAA,CAAY,MAAZA;;AAMAC,MAAAA,0BAAAA,sBAAeC,IAAD,EAAOC,KAAP,EAAcC,IAA5BH;AAAAA,QAAAA;;;QAA4B,yBAAO;QACjCI,YAAQH,IAAII,MAAAA,CAAAA;QACZC,YAAQH;QACRH,OAAAO,CAAAA,aAASL,KAATK;MAHFP,CAAAA,IAAAA;;AAOAQ,MAAAA,uBAAAA,mBAAAA;AAAAA,QAAAA;;QACEA,OAACA,IAAD,GAAA,CAAKJ,SAAKI,SAAAA,CAAAA,CAAV,CAAA,GAAmBA;MADrBA,CAAAA;;AAIAC,MAAAA,mCAAAA,+BAAwBN,IAAxBM;AAAAA,QAAAA;;;QAEE,QADKN,IAAIO,MAAAA,CAAAA,CACT;UAAA,KAAK,KAAL;;YAEE,QADKP,IAAIQ,MAAAA,CAAAA,CAAKC,OAAAA,CAAC,MAADA,CACd;cAAA,KAAK,SAAL;gBACEH,OAAAA;cACF,KAAK,MAAL;gBACEA,OAAAA;cACF,KAAK,MAAL;gBACEA,OAAAA;cADF;gBALAA,OAAA;YACA;YAFF;UASA,KAAK,OAAL;UAAA,KAAa,SAAb;UAAA,KAAuB,WAAvB;YACE,IAAA,QAAoCF,UAApC,CAAA;cAAAE,OAAAX,IAAAW,qBAAAA,CAAoBF,UAAMJ,MAAAA,CAAAA,CAA1BM;YAAA;cA1CRA,OAAA;YA0CQ;YADF;UAEA,KAAK,MAAL;;YACEP,QAAQK;YACRM,QAAQC;YACR,OAAA,QAAMZ,KAAN,CAAA;YACE,IAAA,MAAGA,KAAKa,OAAAA,CAAAA,CAA