ames get prefixed with\n      # a '$', and if the name is a valid javascript identifier, it will\n      # have a '.' prefix (for dot-calling), otherwise it will be\n      # wrapped in brackets to use reference notation calling.\n      def mid_to_jsid(mid)\n        if %r{\\=|\\+|\\-|\\*|\\/|\\!|\\?|<|\\>|\\&|\\||\\^|\\%|\\~|\\[|`} =~ mid.to_s\n          \"['$\#{mid}']\"\n        else\n          '.$' + mid\n        end\n      end\n\n      def indent(&block)\n        compiler.indent(&block)\n      end\n\n      def current_indent\n        compiler.parser_indent\n      end\n\n      def line(*strs)\n        push fragment(\"\\n\#{current_indent}\", loc: false)\n        push(*strs)\n      end\n\n      def empty_line\n        push fragment(\"\\n\", loc: false)\n      end\n\n      def js_truthy(sexp)\n        if optimize = js_truthy_optimize(sexp)\n          return optimize\n        end\n\n        helper :truthy\n        [fragment('$truthy('), expr(sexp), fragment(')')]\n      end\n\n      def js_truthy_optimize(sexp)\n        case sexp.type\n        when :send\n          receiver, mid, *args = *sexp\n          receiver_handler_class = receiver && compiler.handlers[receiver.type]\n\n          # Only operator calls on the truthy_optimize? node classes should be optimized.\n          # Monkey patch method calls might return 'self'/aka a bridged instance and need\n          # the nil check - see discussion at https://github.com/opal/opal/pull/1097\n          allow_optimization_on_type = Compiler::COMPARE.include?(mid.to_s) &&\n                                       receiver_handler_class &&\n                                       receiver_handler_class.truthy_optimize?\n\n          if allow_optimization_on_type ||\n             mid == :block_given?\n            expr(sexp)\n          elsif args.count == 1\n            case mid\n            when :==\n              helper :eqeq\n              compiler.record_method_call mid\n              [fragment('$eqeq('), expr(receiver), fragment(', '), expr(args.first), fragment(')')]\n            when :===\n              helper :eqeqeq\n              compiler.record_method_call mid\n              [fragment('$eqeqeq('), expr(receiver), fragment(', '), expr(args.first), fragment(')')]\n            when :!=\n              helper :neqeq\n              compiler.record_method_call mid\n              [fragment('$neqeq('), expr(receiver), fragment(', '), expr(args.first), fragment(')')]\n            end\n          elsif args.count == 0\n            case mid\n            when :!\n              helper :not\n              compiler.record_method_call mid\n              [fragment('$not('), expr(receiver), fragment(')')]\n            end\n          end\n        when :begin\n          if sexp.children.count == 1\n            js_truthy_optimize(sexp.children.first)\n          end\n        when :if\n          _test, true_body, false_body = *sexp\n          if true_body == s(:true)\n            # Ensure we recurse the js_truthy call on the `false_body` of the if `expr`.\n            # This transforms an expression like:\n            #\n            # $truthy($truthy(a) || b)\n            #\n            # Into:\n            #\n            # $truthy(a) || $truthy(b)\n            sexp.meta[:do_js_truthy_on_false_body] = true\n            expr(sexp)\n          elsif false_body == s(:false)\n            sexp.meta[:do_js_truthy_on_true_body] = true\n            expr(sexp)\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Helpers>", "property", "name", "valid_name?", "inspect", "Opal::Rewriters::JsReservedWords", "Opal::Rewriters", "Opal", "mid_to_jsid", "mid", "=~", "to_s", "+", "indent", "compiler", "block", "to_proc", "current_indent", "parser_indent", "line", "push", "fragment", "strs", "empty_line", "js_truthy", "sexp", "optimize", "js_truthy_optimize", "helper", "expr", "type", "receiver", "args", "receiver_handler_class", "$ret_or_2", "handlers", "[]", "allow_optimization_on_type", "$ret_or_3", "Compiler::COMPARE", "Compiler", "include?", "truthy_optimize?", "count", "1", "record_method_call", "first", "0", "children", "_test", "true_body", "false_body", "s", "meta", "[]="], :mappings=>"AAAAA,qCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,qBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;;AACEC,QAAAA,wBAAAA,oBAAaC,IAAbD;AAAAA,UAAAA;;UACE,IAAA,QAAAL,IAAAO,gBAAAA,CAAYD,IAAZC,CAAA,CAAA;YAAoBF,OAACA,GAAD,GAAA,CAAIC,IAAJ;UAApB;YAAiCD,OAACA,GAAD,GAAA,CAAIC,IAAIE,SAAAA,CAAAA,CAAR,CAAA,GAAiBH;UAAlD;QADFA,CAAAA;;AAIAE,QAAAA,2BAAAA,oCAAgBD,IAAhBC;AAAAA;UACEA,OAAAE,IAAAC,IAAAC,UAAAD,cAAAD,oBAAgCF,gBAAAA,CAAaD,IAAbC;QADlCA,CAAAA;;AASAK,QAAAA,2BAAAA,uBAAgBC,GAAhBD;AAAAA;UACE,IAAA,QAAG,+CAAkDE,OAAAA,CAAGD,GAAGE,MAAAA,CAAAA,CAAND,CAArD,CAAA;YACEF,OAACA,KAAD,GAAA,CAAMC,GAAN,CAAA,GAAUD;UADZ;YAGEA,OAAKI,SAALJ,IAAKI,EAAEH,GAAFG;UAHP;QADFJ,CAAAA;;AAQAK,QAAAA,sBAAAA,kBAAAA;AAAAA,UAAAA;;UAAAA;;;UACEA,OAAQA,MAARjB,IAAAkB,UAAAA,CAAAA,CAAQD,UAAAA,EAAAA,EAAAA,EAASE,KAADC,SAAAA,CAAAA,CAARH;QADVA,CAAAA;;AAIAI,QAAAA,8BAAAA,0BAAAA;AAAAA,UAAAA;;UACEA,OAAArB,IAAAkB,UAAAA,CAAAA,CAAQI,eAAAA,CAAAA;QADVD,CAAAA;;AAIAE,QAAAA,oBAAAA,gBApCN,EAoCMA;AAAAA,UAAAA;;;UApCN;UAoCe;UACPvB,IAAAwB,MAAAA,CAAKxB,IAAAyB,UAAAA,CAAUF,IAAD,GAAA,CAAKvB,IAAAqB,gBAAAA,CAAAA,CAAL,CAAT,EAAgC,iBAAA,OAAK,KAAL,EAAhCI,CAALD;UACAD,OAAAC,MAAAxB,IAAAwB,QAAAA,EAAK,MAACE,IAAD,CAALF;QAFFD,CAAAA,IAAAA;;AAKAI,QAAAA,0BAAAA,sBAAAA;AAAAA,UAAAA;;UACEA,OAAA3B,IAAAwB,MAAAA,CAAKxB,IAAAyB,UAAAA,CAASE,IAAT,EAAe,iBAAA,OAAK,KAAL,EAAfF,CAALD;QADFG,CAAAA;;AAIAC,QAAAA,yBAAAA,qBAAcC,IAAdD;AAAAA,UAAAA;;;UACE,IAAA,QAAGE,CAAAA,WAAW9B,IAAA+B,oBAAAA,CAAmBF,IAAnBE,CAAXD,CAAH,CAAA;YACE,OAAOA;UADT;UAIA9B,IAAAgC,QAAAA,CAAO,QAAPA;UACAJ,OAAA,CAAC5B,IAAAyB,UAAAA,CAASG,UAATH,CAAD,EAAuBzB,IAAAiC,MAAAA,CAAKJ,IAALI,CAAvB,EAAmCjC,IAAAyB,UAAAA,CAASG,GAATH,CAAnC;QANFG,CAAAA;QASAxB,OAAA2B,kCAAAA,8BAAuBF,IAAvBE;AAAAA,UAAAA;;;UAEE,QADKF,IAAIK,MAAAA,CAAAA,CACT;YAAA,KAAK,MAAL;;cACE,KAAuB,UAAA,MAACL,IAAD,CAAA,CAAvB,EAAAM,CAAAA,WAAA,6BAAAA,CAAA,EAAUtB,CAAAA,MAAV,6BAAUA,CAAV,EAAgBuB,CAAAA,OAAhB,aAAgBA,CAAhB;cACAC,yBAAyB,CAAA,QAAAC,CAAAA,YAAAH,QAAAG,CAAA,CAAA,GAAA,CAAYtC,IAAAkB,UAAAA,CAAAA,CAAQqB,UAAAA,CAAAA,CAASC,OAAAA,CAACL,QAAQD,MAAAA,CAAAA,CAATM,CAA7B,IAAA,CAAA,SAAA,CAAA;cAKzBC,6BAA6B,CAAA,QAAAH,CAAAA,YAAA,CAAA,QAAAI,CAAAA,YAAAC,IAAAC,cAAAD,YAAiBE,aAAAA,CAAUhC,GAAGE,MAAAA,CAAAA,CAAb8B,CAAjBH,CAAA,CAAA,GAAA,CACAL,sBADA,IAAA,CAAA,SAAA,CAAA,CAAAC,CAAA,CAAA,GAAA,CAEAD,sBAAsBS,qBAAAA,CAAAA,CAFtB,IAAA,CAAA,SAAA,CAAA;cAI7B,IAAG,CAAA,QAAAL,0BAAA,CAAA,IAAA,CAAA,MACA5B,GADA,EACO,cADP,CAAA,CAAA,CAAH;gBAEEkB,OAAA/B,IAAAiC,MAAAA,CAAKJ,IAALI;cAFF,OAGA,IAAA,MAAMG,IAAIW,OAAAA,CAAAA,CAAV,EAAoBC,CAApB,CAAA;;gBAEE,QADKnC,GACL;kBAAA,KAAK,IAAL;;oBACEb,IAAAgC,QAAAA,CAAO,MAAPA;oBACAhC,IAAAkB,UAAAA,CAAAA,CAAQ+B,oBAAAA,CAAoBpC,GAApBoC;oBACRlB,OAAA,CAAC/B,IAAAyB,UAAAA,CAASM,QAATN,CAAD,EAAqBzB,IAAAiC,MAAAA,CAAKE,QAALF,CAArB,EAAqCjC,IAAAyB,UAAAA,CAASM,IAATN,CAArC,EAAqDzB,IAAAiC,MAAAA,CAAKG,IAAIc,OAAAA,CAAAA,CAATjB,CAArD,EAAuEjC,IAAAyB,UAAAA,CAASM,GAATN,CAAvE;kBACF,KAAK,KAAL;;oBACEzB,IAAAgC,QAAAA,CAAO,QAAPA;oBACAhC,IAAAkB,UAAAA,CAAAA,CAAQ+B,oBAAAA,CAAoBpC,GAApBoC;oBACRlB,OAAA,CAAC/B,IAAAyB,UAAAA,CAASM,UAATN,CAAD,EAAuBzB,IAAAiC,MAAAA,CAAKE,QAALF,CAAvB,EAAuCjC,IAAAyB,UAAAA,CAASM,IAATN,CAAvC,EAAuDzB,IAAAiC,MAAAA,CAAKG,IAAIc,OAAAA,CAAAA,CAATjB,CAAvD,EAAyEjC,IAAAyB,UAAAA,CAASM,GAATN,CAAzE;kBACF,KAAK,IAAL;;oBACEzB,IAAAgC,QAAAA,CAAO,OAAPA;oBACAhC,IAAAkB,UAAAA,CAAAA,CAAQ+B,oBAAAA,CAAoBpC,GAApBoC;oBACRlB,OAAA,CAAC/B,IAAAyB,UAAAA,CAASM,SAATN,CAAD,EAAsBzB,IAAAiC,MAAAA,CAAKE,QAALF,CAAtB,EAAsCjC,IAAAyB,UAAAA,CAASM,IAATN,CAAtC,EAAsDzB,IAAAiC,MAAAA,CAAKG,IAAIc,OAAAA,CAAAA,CAATjB,CAAtD,EAAwEjC,IAAAyB,UAAAA,CAASM,GAATN,CAAxE;kBAHF;oBATAM,OAAA;gBACA;cAFF,OAeA,IAAA,MAAMK,IAAIW,OAAAA,CAAAA,CAAV,EAAoBI,CAApB,CAAA;;gBAEE,QADKtC,GACL;kBAAA,KAAK,GAAL;;oBACEb,IAAAgC,QAAAA,CAAO,KAAPA;oBACAhC,IAAAkB,UAAAA,CAAAA,CAAQ+B,oBAAAA,CAAoBpC,GAApBoC;oBACRlB,OAAA,CAAC/B,IAAAyB,UAAAA,CAASM,OAATN,CAAD,EAAoBzB,IAAAiC,MAAAA,CAAKE,QAALF,CAApB,EAAoCjC,IAAAyB,UAAAA,CAASM,GAATN,CAApC;kBAHF;oBADAM,OAAA;gBACA;cAFF;gBArFVA,OAAA;cAqFU;cA7BF;YAqCA,KAAK,OAAL;cACE,IAAA,MAAGF,IAAIuB,UAAAA,CAAAA,CAASL,OAAAA,CAAAA,CAAhB,EAA0BC,CAA1B,CAAA;gBACEjB,OAAA/B,IAAA+B,oBAAAA,CAAmBF,IAAIuB,UAAAA,CAAAA,CAASF,OAAAA,CAAAA,CAAhCnB;cADF;gBA9FVA,OAAA;cA8FU;cADF;YAIA,KAAK,IAAL;;cACE,KAA+B,UAAA,MAACF,IAAD,CAAA,CAA/B,EAAAwB,CAAAA,QAAA,6BAAAA,CAAA,EAAOC,CAAAA,YAAP,6BAAOA,CAAP,EAAkBC,CAAAA,aAAlB,6BAAkBA,CAAlB;cACA,IAAA,MAAGD,SAAH,EAAgBtD,IAAAwD,GAAAA,CAAE,MAAFA,CAAhB,CAAA;;gBASE3B,IAAI4B,MAAAA,CAAAA,CAAKC,QAAAA,CAAC,4BAAV,EAAyC,IAAhCA;gBACT3B,OAAA/B,IAAAiC,MAAAA,CAAKJ,IAALI;cAVF,OAWA,IAAA,MAAMsB,UAAN,EAAoBvD,IAAAwD,GAAAA,CAAE,OAAFA,CAApB,CAAA;;gBACE3B,IAAI4B,MAAAA,CAAAA,CAAKC,QAAAA,CAAC,2BAAV,EAAwC,IAA/BA;gBACT3B,OAAA/B,IAAAiC,MAAAA,CAAKJ,IAALI;cAFF;gBA9GVF,OAAA;cA8GU;cAbF;YAAA;cA1CAA,OAAA;UACA;QAFFA,CAAAA;MAhDF3B,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>28963, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/base.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/helpers'\nrequire 'opal/nodes/closure'\n\nmodule Opal\n  module Nodes\n    class Base\n      include Helpers\n      include Closure::NodeSupport\n\n      def self.handlers\n        @handlers ||= {}\n      end\n\n      def self.handle(*types)\n        types.each do |type|\n          Base.handlers[type] = self\n        end\n      end\n\n      def self.children(*names)\n        names.each_with_index do |name, idx|\n          define_method(name) do\n            @sexp.children[idx]\n          end\n        end\n      end\n\n      def self.truthy_optimize?\n        false\n      end\n\n      attr_reader :compiler, :type, :sexp\n\n      def initialize(sexp, level, compiler)\n        @sexp = sexp\n        @type = sexp.type\n        @level = level\n        @compiler = compiler\n        @compiler.top_scope ||= self\n      end\n\n      def children\n        @sexp.children\n      end\n\n      def compile_to_fragments\n        return @fragments if defined?(@fragments)\n\n        @fragments = []\n        compile\n        @fragments\n      end\n\n      def compile\n        raise 'Not Implemented'\n      end\n\n      def push(*strs)\n        strs.each do |str|\n          str = fragment(str) if str.is_a?(String)\n          @fragments << str\n        end\n      end\n\n      def unshift(*strs)\n        strs.reverse_each do |str|\n          str = fragment(str) if str.is_a?(String)\n          @fragments.unshift str\n        end\n      end\n\n      def wrap(pre, post)\n        unshift pre\n        push post\n      end\n\n      def fragment(str, loc: true)\n        Opal::Fragment.new str, scope, loc && @sexp\n      end\n\n      def error(msg)\n        @compiler.error msg\n      end\n\n      def scope\n        @compiler.scope\n      end\n\n      def top_scope\n        @compiler.top_scope\n      end\n\n      def s(type, *children)\n        ::Opal::AST::Node.new(type, children, location: @sexp.loc)\n      end\n\n      def expr?\n        @level == :expr\n      end\n\n      def recv?\n        @level == :recv\n      end\n\n      def stmt?\n        @level == :stmt\n      end\n\n      def process(sexp, level = :expr)\n        @compiler.process sexp, level\n      end\n\n      def expr(sexp)\n        @compiler.process sexp, :expr\n      end\n\n      def recv(sexp)\n        @compiler.process sexp, :recv\n      end\n\n      def stmt(sexp)\n        @compiler.process sexp, :stmt\n      end\n\n      def expr_or_nil(sexp)\n        sexp ? expr(sexp) : 'nil'\n      end\n\n      def expr_or_empty(sexp)\n        sexp && sexp.type != :nil ? expr(sexp) : ''\n      end\n\n      def add_local(name)\n        scope.add_scope_local name.to_sym\n      end\n\n      def add_ivar(name)\n        scope.add_scope_ivar name\n      end\n\n      def add_gvar(name)\n        scope.add_scope_gvar name\n      end\n\n      def add_temp(temp)\n        scope.add_scope_temp temp\n      end\n\n      def helper(name)\n        @compiler.helper name\n      end\n\n      def with_temp(&block)\n        @compiler.with_temp(&block)\n      end\n\n      def in_while?\n        @compiler.in_while?\n      end\n\n      def while_loop\n        @compiler.instance_variable_get(:@while_loop)\n      end\n\n      def has_rescue_else?\n        scope.has_rescue_else?\n      end\n\n      def in_ensure(&block)\n        scope.in_ensure(&block)\n      end\n\n      def in_ensure?\n        scope.in_ensure?\n      end\n\n      def in_resbody(&block)\n        scope.in_resbody(&block)\n      end\n\n      def in_resbody?\n        scope.in_resbody?\n      end\n\n      def in_rescue(node, &block)\n        scope.in_rescue(node, &block)\n      end\n\n      def class_variable_owner_nesting_level\n        cvar_scope = scope\n        nesting_level = 0\n\n        while cvar_scope && !cvar_scope.class_scope?\n          # Needs only `class << self`, `module`, and `class`\n          # can increase nesting, but `class` & `module` are\n          # covered by `class_scope?`.\n          nesting_level += 1 if cvar_scope.sclass?\n\n          cvar_scope = cvar_scope.parent\n        end\n\n        nesting_level\n      end\n\n      def class_variable_owner\n        if scope\n          \"\#{scope.nesting}[\#{class_variable_owner_nesting_level}]\"\n        else\n          'Opal.Object'\n        end\n      end\n\n      def comments\n        compiler.comments[@sexp.loc]\n      end\n\n      def source_location\n        expr = @sexp.loc.expression\n        if expr.respond_to? :source_buffer\n          file = expr.source_buffer.name\n          file = \"<internal:\#{file}>\" if file.start_with?(\"corelib/\")\n          file = \"<js:\#{file}>\" if file.end_with?(\".js\")\n        else\n          file = \"(eval)\"\n        end\n        line = @sexp.loc.line\n        \"['\#{file}', \#{line}]\"\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:Base>", "include", "Helpers", "Closure::NodeSupport", "Closure", "handlers", "@handlers", "$ret_or_1", "handle", "each", "types", "block in handle", "type", "block (2 levels) in handle", "[]=", "Base", "children", "each_with_index", "names", "block in children", "name", "idx", "block (2 levels) in children", "define_method", "block (3 levels) in children", "@sexp", "[]", "truthy_optimize?", "attr_reader", "initialize", "sexp", "level", "compiler", "@type", "@level", "@compiler", "top_scope", "top_scope=", "compile_to_fragments", "@fragments", "compile", "raise", "push", "strs", "block in push", "str", "block (2 levels) in push", "is_a?", "String", "fragment", "<<", "unshift", "reverse_each", "block in unshift", "block (2 levels) in unshift", "wrap", "pre", "post", "$kwargs", "Opal::Fragment", "Opal", "new", "scope", "loc", "error", "msg", "s", "Opal::AST::Node", "Opal::AST", "expr?", "==", "recv?", "stmt?", "process", "expr", "recv", "stmt", "expr_or_nil", "expr_or_empty", "add_local", "add_scope_local", "to_sym", "add_ivar", "add_scope_ivar", "add_gvar", "add_scope_gvar", "add_temp", "temp", "add_scope_temp", "helper", "with_temp", "block", "to_proc", "in_while?", "while_loop", "instance_variable_get", "has_rescue_else?", "in_ensure", "in_ensure?", "in_resbody", "in_resbody?", "in_rescue", "node", "class_variable_owner_nesting_level", "cvar_scope", "nesting_level", "0", "class_scope?", "!", "sclass?", "+", "1", "parent", "class_variable_owner", "nesting", "comments", "source_location", "expression", "respond_to?", "file", "source_buffer", "start_with?", "end_with?", "line"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,oBAARE;EACAD,IAAAC,SAAAA,CAAQF,oBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEJ,IAAAK,SAAAA,CAAQC,aAARD;QACAL,IAAAK,SAAAA,CAAQE,IAAAC,aAAAD,gBAARF;QAEAI,MAAIT,IAAJS,eAAAA,oBAAAA;AAAAA,UAAAA;AAAAA;;UACEA,OAAAC,CAAAA,gBAZR,CAAA,QAAAC,CAAAA,YAYQD,aAZRC,