,QAAAnG,CAAAA,YAAAiG,UAAAjG,CAAA,CAAA,GAAA,CAAeiG,UAAUG,iBAAAA,CAAAA,CAAXC,MAAAA,CAAAA,CAAd,IAAA,CAAA,SAAA,CAAA,CAAN,CAAA;;YAIE,IAAA,QAAsBJ,UAAUK,YAAAA,CAAAA,CAAhC,CAAA;cAAAJ,gBAAcK,SAAdL,aAAcK,EAAGC,CAAHD;YAAd;YAEAN,aAAaA,UAAUQ,QAAAA,CAAAA;UANzB;UASAT,OAAAE;QAbFF,CAAAA;;AAgBAU,QAAAA,oCAAAA,gCAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAGrH,IAAAkE,OAAAA,CAAAA,CAAH,CAAA;YACEmD,OAAA,EAAA,GAAA,CAAGrH,IAAAkE,OAAAA,CAAAA,CAAKoD,SAAAA,CAAAA,CAAR,CAAA,GAAiBD,GAAjB,GAAA,CAAoBrH,IAAA2G,oCAAAA,CAAAA,CAApB,CAAA,GAAuDU;UADzD;YAGEA,OAAAA;UAHF;QADFA,CAAAA;;AAQAE,QAAAA,wBAAAA,oBAAAA;AAAAA,UAAAA;;UACEA,OAAAvH,IAAAoC,UAAAA,CAAAA,CAAQmF,UAAAA,CAAAA,CAASzF,OAAAA,CAACD,SAAKsC,KAAAA,CAAAA,CAANrC;QADnByF,CAAAA;QAIAnH,OAAAoH,+BAAAA,2BAAAA;AAAAA,UAAAA;;;UACE1C,OAAOjD,SAAKsC,KAAAA,CAAAA,CAAIsD,YAAAA,CAAAA;UAChB,IAAA,QAAG3C,IAAI4C,gBAAAA,CAAa,eAAbA,CAAP,CAAA;;YACEC,OAAO7C,IAAI8C,eAAAA,CAAAA,CAAcpG,MAAAA,CAAAA;YACzB,IAAA,QAA+BmG,IAAIE,gBAAAA,CAAaL,UAAbK,CAAnC,CAAA;cAAAF,OAAQH,YAAD,GAAA,CAAaG,IAAb,CAAA,GAAkBH;YAAzB;YACA,IAAA,QAAyBG,IAAIG,cAAAA,CAAWN,KAAXM,CAA7B,CAAA;cAAAH,OAAQH,MAAD,GAAA,CAAOG,IAAP,CAAA,GAAYH;YAAnB;UAHF;YAKEG,OAAOH;UALT;UAOAO,OAAOlG,SAAKsC,KAAAA,CAAAA,CAAI4D,MAAAA,CAAAA;UAChBP,OAACA,IAAD,GAAA,CAAKG,IAAL,CAAA,GAAUH,KAAV,GAAA,CAAeO,IAAf,CAAA,GAAoBP;QAVtBA,CAAAA;MAnNFpH,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>29359, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/literal.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    class ValueNode < Base\n      handle :true, :false, :self, :nil\n\n      def compile\n        if type == :self\n          push scope.self\n        else\n          push type.to_s\n        end\n      end\n\n      def self.truthy_optimize?\n        true\n      end\n    end\n\n    class NumericNode < Base\n      handle :int, :float\n\n      children :value\n\n      def compile\n        push value.to_s\n        wrap '(', ')' if recv?\n      end\n\n      def self.truthy_optimize?\n        true\n      end\n    end\n\n    class StringNode < Base\n      handle :str\n\n      children :value\n\n      ESCAPE_CHARS = {\n        'a' => '\\\\u0007',\n        'e' => '\\\\u001b'\n      }.freeze\n\n      ESCAPE_REGEX = /(\\\\+)([\#{ ESCAPE_CHARS.keys.join('') }])/.freeze\n\n      def translate_escape_chars(inspect_string)\n        inspect_string.gsub(ESCAPE_REGEX) do |original|\n          if Regexp.last_match(1).length.even?\n            original\n          else\n            Regexp.last_match(1).chop + ESCAPE_CHARS[Regexp.last_match(2)]\n          end\n        end\n      end\n\n      def compile\n        string_value = value\n\n        sanitized_value = string_value.inspect.gsub(/\\\\u\\{([0-9a-f]+)\\}/) do\n          code_point = Regexp.last_match(1).to_i(16)\n          to_utf16(code_point)\n        end\n        push translate_escape_chars(sanitized_value)\n\n        if RUBY_ENGINE != 'opal'\n          encoding = string_value.encoding\n\n          unless encoding == Encoding::UTF_8\n            helper :enc\n            wrap \"$enc(\", \", \\\"\#{encoding.name}\\\")\"\n          end\n        end\n\n        unless value.valid_encoding?\n          helper :binary\n          wrap \"$binary(\", \")\"\n        end\n      end\n\n      # http://www.2ality.com/2013/09/javascript-unicode.html\n      def to_utf16(code_point)\n        ten_bits = 0b1111111111\n        u = ->(code_unit) { '\\\\u' + code_unit.to_s(16).upcase }\n\n        return u.call(code_point) if code_point <= 0xFFFF\n\n        code_point -= 0x10000\n\n        # Shift right to get to most significant 10 bits\n        lead_surrogate = 0xD800 + (code_point >> 10)\n\n        # Mask to get least significant 10 bits\n        tail_surrogate = 0xDC00 + (code_point & ten_bits)\n\n        u.call(lead_surrogate) + u.call(tail_surrogate)\n      end\n    end\n\n    class SymbolNode < Base\n      handle :sym\n\n      children :value\n\n      def compile\n        push value.to_s.inspect\n      end\n    end\n\n    class RegexpNode < Base\n      handle :regexp\n\n      attr_accessor :value, :flags\n\n      # https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/RegExp\n      SUPPORTED_FLAGS = /[gimuy]/.freeze\n\n      def initialize(*)\n        super\n        extract_flags_and_value\n      end\n\n      def compile\n        flags.select! do |flag|\n          if SUPPORTED_FLAGS =~ flag\n            true\n          else\n            compiler.warning \"Skipping the '\#{flag}' Regexp flag as it's not widely supported by JavaScript vendors.\"\n            false\n          end\n        end\n\n        if value.type == :str\n          compile_static_regexp\n        else\n          compile_dynamic_regexp\n        end\n      end\n\n      def compile_dynamic_regexp\n        helper :regexp\n\n        push '$regexp(['\n        value.children.each_with_index do |v, index|\n          push ', ' unless index.zero?\n          push expr(v)\n        end\n        push ']'\n        push \", '\#{flags.join}'\" if flags.any?\n        push \")\"\n      end\n\n      def compile_static_regexp\n        value = self.value.children[0]\n        case value\n        when ''\n          push('/(?:)/')\n        when /\\(\\?<=|\\(\\?<!/\n          # Safari/WebKit will not execute javascript code if it contains a lookbehind literal RegExp\n          # and they fail with \"Syntax Error\". This tricks their parser by disguising the literal RegExp\n          # as string for the dynamic $regexp helper. Safari/Webkit will still fail to execute the RegExp,\n          # but at least they will parse and run everything else.\n          static_as_dynamic(value)\n        else\n          push \"\#{Regexp.new(value).inspect}\#{flags.join}\"\n        end\n      end\n\n      def static_as_dynamic(value)\n        helper :regexp\n\n        push '$regexp([\"'\n        push value.gsub('\\\\', '\\\\\\\\\\\\\\\\')\n        push '\"]'\n        push \", '\#{flags.join}'\" if flags.any?\n        push \")\"\n      end\n\n      def extract_flags_and_value\n        *values, flags_sexp = *children\n        self.flags = flags_sexp.children.map(&:to_s)\n\n        self.value = if values.empty?\n                       # empty regexp, we can process it inline\n                       s(:str, '')\n                     elsif single_line?(values)\n                       # simple plain regexp, we can put it inline\n                       values[0]\n                     else\n                       s(:dstr, *values)\n                     end\n\n        # trimming when //x provided\n        # required by parser gem, but JS doesn't support 'x' flag\n        if flags.include?('x')\n          parts = value.children.map do |part|\n            if part.is_a?(::Opal::AST::Node) && part.type == :str\n              trimmed_value = part.children[0].gsub(/\\A\\s*\\#.*/, '').gsub(/\\s/, '')\n              s(:str, trimmed_value)\n            else\n              part\n            end\n          end\n\n          self.value = value.updated(nil, parts)\n          flags.delete('x')\n        end\n\n        if value.type == :str\n          # Replacing \\A -> ^, \\z -> $, required for the parser gem\n          self.value = s(:str, value.children[0].gsub('\\A', '^').gsub('\\z', '$'))\n        end\n      end\n\n      def raw_value\n        self.value = @sexp.loc.expression.source\n      end\n\n      private\n\n      def single_line?(values)\n        return false if values.length > 1\n\n        value = values[0]\n        # JavaScript doesn't support multiline regexp\n        value.type != :str || !value.children[0].include?(\"\\n\")\n      end\n    end\n\n    # $_ = 'foo'; call if /foo/\n    # s(:if, s(:match_current_line, /foo/, true))\n    class MatchCurrentLineNode < Base\n      handle :match_current_line\n\n      children :regexp\n\n      # Here we just convert it to\n      # ($_ =~ regexp)\n      # and let :send node to handle it\n      def compile\n        gvar_sexp = s(:gvar, :$_)\n        send_node = s(:send, gvar_sexp, :=~, regexp)\n        push expr(send_node)\n      end\n    end\n\n    class DynamicStringNode < Base\n      handle :dstr\n\n      def compile\n        if children.length > 1 && children.first.type == :str\n          skip_empty = true\n        else\n          push '\"\"'\n        end\n\n        children.each do |part|\n          if skip_empty\n            skip_empty = false\n          else\n            push ' + '\n          end\n\n          if part.type == :str\n            push expr(part)\n          else\n            push '(', expr(part), ')'\n          end\n\n          wrap '(', ')' if recv?\n        end\n      end\n    end\n\n    class DynamicSymbolNode < DynamicStringNode\n      handle :dsym\n    end\n\n    class RangeNode < Base\n      children :start, :finish\n\n      SIMPLE_CHILDREN_TYPES = %i[int float str sym].freeze\n\n      def compile\n        if compile_inline?\n          helper :range\n          compile_inline\n        else\n          compile_range_initialize\n        end\n      end\n\n      def compile_inline?\n        (\n          !start || (start.type && SIMPLE_CHILDREN_TYPES.include?(start.type))\n        ) && (\n          !finish || (finish.type && SIMPLE_CHILDREN_TYPES.include?(finish.type))\n        )\n      end\n\n      def compile_inline\n        raise NotImplementedError\n      end\n\n      def compile_range_initialize\n        raise NotImplementedError\n      end\n    end\n\n    class InclusiveRangeNode < RangeNode\n      handle :irange\n\n      def compile_inline\n        push '$range(', expr_or_nil(start), ', ', expr_or_nil(finish), ', false)'\n      end\n\n      def compile_range_initialize\n        push 'Opal.Range.$new(', expr_or_nil(start), ', ', expr_or_nil(finish), ', false)'\n      end\n    end\n\n    class ExclusiveRangeNode < RangeNode\n      handle :erange\n\n      def compile_inline\n        push '$range(', expr_or_nil(start), ', ', expr_or_nil(finish), ', true)'\n      end\n\n      def compile_range_initialize\n        push 'Opal.Range.$new(', expr_or_nil(start), ',', expr_or_nil(finish), ', true)'\n      end\n    end\n\n    # 0b1111r -> s(:rational, (15/1))\n    # -0b1111r -> s(:rational, (-15/1))\n    class RationalNode < Base\n      handle :rational\n\n      children :value\n\n      def compile\n        push \"\#{top_scope.absolute_const}('Rational').$new(\#{value.numerator}, \#{value.denominator})\"\n      end\n    end\n\n    # 0b1110i -> s(:complex, (0+14i))\n    # -0b1110i -> s(:complex, (0-14i))\n    class ComplexNode < Base\n      handle :complex\n\n      children :value\n\n      def compile\n        push \"\#{top_scope.absolute_const}('Complex').$new(\#{value.real}, \#{value.imag})\"\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:ValueNode>", "handle", "compile", "type", "push", "scope", "to_s", "truthy_optimize?", "Base", "<class:NumericNode>", "children", "value", "recv?", "wrap", "<class:StringNode>", "freeze", "ESCAPE_CHARS", "keys", "join", "translate_escape_chars", "inspect_string", "gsub", "ESCAPE_REGEX", "block in translate_escape_chars", "original", "Regexp", "last_match", "1", "length", "even?", "block (2 levels) in translate_escape_chars", "+", "chop", "[]", "2", "string_value", "sanitized_value", "inspect", "block in compile", "block (2 levels) in compile", "code_point", "to_i", "16", "to_utf16", "valid_encoding?", "helper", "ten_bits", "1023", "u", "block in to_utf16", "code_unit", "block (2 levels) in to_utf16", "upcase", "<=", "65535", "call", "-", "65536", "lead_surrogate", "55296", ">>", "10", "tail_surrogate", "56320", "&", "<class:SymbolNode>", "<class:RegexpNode>", "attr_accessor", "initialize", "$fwd_rest", "extract_flags_and_value", "select!", "flags", "flag", "SUPPORTED_FLAGS", "=~", "compiler", "warning", "compile_static_regexp", "compile_dynamic_regexp", "each_with_index", "block in compile_dynamic_regexp", "v", "index"