AAzB,EAA6CT,IAA7C,EAAmD3I,IAAAoJ,aAAAA,CAAYpJ,IAAAgJ,QAAAA,CAAAA,CAAZI,CAAnD,EAAwET,UAAxEnI;QADFmI,CAAAA;MAPFQ,GAAAA,WAAAA,EAA2BE,eAA3BF;MAYAG;MAAAA;;;;QACEtJ,IAAAK,QAAAA,CAAO,QAAPA;;AAEAqI,QAAAA,8BAAAA,0BAAAA;AAAAA,UAAAA;;UACEA,OAAA1I,IAAAQ,MAAAA,CAAKkI,SAAL,EAAgB1I,IAAAoJ,aAAAA,CAAYpJ,IAAA6I,OAAAA,CAAAA,CAAZO,CAAhB,EAAoCV,IAApC,EAA0C1I,IAAAoJ,aAAAA,CAAYpJ,IAAAgJ,QAAAA,CAAAA,CAAZI,CAA1C,EAA+DV,SAA/DlI;QADFkI,CAAAA;QAIAY,OAAAX,wCAAAA,oCAAAA;AAAAA,UAAAA;;UACEA,OAAA3I,IAAAQ,MAAAA,CAAKmI,kBAAL,EAAyB3I,IAAAoJ,aAAAA,CAAYpJ,IAAA6I,OAAAA,CAAAA,CAAZO,CAAzB,EAA6CT,GAA7C,EAAkD3I,IAAAoJ,aAAAA,CAAYpJ,IAAAgJ,QAAAA,CAAAA,CAAZI,CAAlD,EAAuET,SAAvEnI;QADFmI,CAAAA;MAPFW,GAAAA,WAAAA,EAA2BD,eAA3BC;MAcAC;MAAAA;;;;QACEvJ,IAAAK,QAAAA,CAAO,UAAPA;QAEAL,IAAAc,UAAAA,CAAS,OAATA;QAEAyI,OAAAjJ,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAAAN,IAAAQ,MAAAA,CAAK,EAAA,GAAA,CAAGR,IAAAwJ,WAAAA,CAAAA,CAASC,gBAAAA,CAAAA,CAAZ,CAAA,GAA4BnJ,oBAA5B,GAAA,CAAgDN,IAAAe,OAAAA,CAAAA,CAAK2I,WAAAA,CAAAA,CAArD,CAAA,GAAgEpJ,IAAhE,GAAA,CAAoEN,IAAAe,OAAAA,CAAAA,CAAK4I,aAAAA,CAAAA,CAAzE,CAAA,GAAsFrJ,GAA3FE;QADFF,CAAAA;MALFiJ,GAAAA,WAAAA,EAAqB3I,UAArB2I;MAYApJ,OAAAyJ;MAAAA;;;;QACE5J,IAAAK,QAAAA,CAAO,SAAPA;QAEAL,IAAAc,UAAAA,CAAS,OAATA;QAEA8I,OAAAtJ,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAAAN,IAAAQ,MAAAA,CAAK,EAAA,GAAA,CAAGR,IAAAwJ,WAAAA,CAAAA,CAASC,gBAAAA,CAAAA,CAAZ,CAAA,GAA4BnJ,mBAA5B,GAAA,CAA+CN,IAAAe,OAAAA,CAAAA,CAAK8I,MAAAA,CAAAA,CAApD,CAAA,GAA0DvJ,IAA1D,GAAA,CAA8DN,IAAAe,OAAAA,CAAAA,CAAK+I,MAAAA,CAAAA,CAAnE,CAAA,GAAyExJ,GAA9EE;QADFF,CAAAA;MALFsJ,GAAAA,WAAAA,EAAoBhJ,UAApBgJ;IAzVFzJ,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>29809, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/variables.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    class LocalVariableNode < Base\n      handle :lvar\n\n      children :var_name\n\n      def using_irb?\n        compiler.irb? && scope.top?\n      end\n\n      def compile\n        return push(var_name.to_s) unless using_irb?\n\n        with_temp do |tmp|\n          push property(var_name.to_s)\n          wrap \"((\#{tmp} = Opal.irb_vars\", \") == null ? nil : \#{tmp})\"\n        end\n      end\n    end\n\n    class LocalAssignNode < Base\n      handle :lvasgn\n\n      children :var_name, :value\n\n      def using_irb?\n        compiler.irb? && scope.top?\n      end\n\n      def compile\n        if using_irb?\n          push \"Opal.irb_vars\#{property var_name.to_s} = \"\n        else\n          add_local var_name.to_s\n\n          push \"\#{var_name} = \"\n        end\n\n        push expr(value)\n\n        wrap '(', ')' if (recv? || expr?) && value\n      end\n    end\n\n    class LocalDeclareNode < Base\n      handle :lvdeclare\n\n      children :var_name\n\n      def compile\n        add_local(var_name.to_s)\n        nil\n      end\n    end\n\n    class InstanceVariableNode < Base\n      handle :ivar\n\n      children :name\n\n      def var_name\n        name.to_s[1..-1]\n      end\n\n      def compile\n        name = property(var_name)\n        add_ivar name\n        push \"\#{scope.self}\#{name}\"\n      end\n    end\n\n    class InstanceAssignNode < Base\n      handle :ivasgn\n\n      children :name, :value\n\n      def var_name\n        name.to_s[1..-1]\n      end\n\n      def compile\n        name = property(var_name)\n        push \"\#{scope.self}\#{name} = \"\n        push expr(value)\n\n        wrap '(', ')' if (recv? || expr?) && value\n      end\n    end\n\n    class GlobalVariableNode < Base\n      handle :gvar\n\n      children :name\n\n      def var_name\n        name.to_s[1..-1]\n      end\n\n      def compile\n        helper :gvars\n\n        name = property var_name\n        add_gvar name\n        push \"$gvars\#{name}\"\n      end\n    end\n\n    # back_ref can be:\n    # $`\n    # $'\n    # $&\n    # $+ (currently unsupported)\n    class BackRefNode < GlobalVariableNode\n      handle :back_ref\n\n      def compile\n        helper :gvars\n\n        case var_name\n        when '&'\n          handle_global_match\n        when \"'\"\n          handle_post_match\n        when '`'\n          handle_pre_match\n        when '+'\n          super\n        else\n          raise NotImplementedError\n        end\n      end\n\n      def handle_global_match\n        with_temp do |tmp|\n          push \"((\#{tmp} = $gvars['~']) === nil ? nil : \#{tmp}['$[]'](0))\"\n        end\n      end\n\n      def handle_pre_match\n        with_temp do |tmp|\n          push \"((\#{tmp} = $gvars['~']) === nil ? nil : \#{tmp}.$pre_match())\"\n        end\n      end\n\n      def handle_post_match\n        with_temp do |tmp|\n          push \"((\#{tmp} = $gvars['~']) === nil ? nil : \#{tmp}.$post_match())\"\n        end\n      end\n    end\n\n    class GlobalAssignNode < Base\n      handle :gvasgn\n\n      children :name, :value\n\n      def var_name\n        name.to_s[1..-1]\n      end\n\n      def compile\n        helper :gvars\n        name = property var_name\n        push \"$gvars\#{name} = \"\n        push expr(value)\n\n        wrap '(', ')' if (recv? || expr?) && value\n      end\n    end\n\n    # $1 => s(:nth_ref, 1)\n    class NthrefNode < Base\n      handle :nth_ref\n\n      children :index\n\n      def compile\n        helper :gvars\n\n        with_temp do |tmp|\n          push \"((\#{tmp} = $gvars['~']) === nil ? nil : \#{tmp}['$[]'](\#{index}))\"\n        end\n      end\n    end\n\n    class ClassVariableNode < Base\n      handle :cvar\n\n      children :name\n\n      def compile\n        helper :class_variable_get\n\n        tolerant = false\n        # We should be tolerant of expressions like: def x; @@notexist; 0; end\n        # (NB: Shouldn't we actually optimize them out?)\n        tolerant = true if stmt?\n        # We should be tolerant of expressions like: @@notexist ||= 6\n        # (those are handled with logical_operator_assignment)\n\n        push \"$class_variable_get(\#{class_variable_owner}, '\#{name}', \#{tolerant.inspect})\"\n      end\n    end\n\n    class ClassVarAssignNode < Base\n      handle :cvasgn\n\n      children :name, :value\n\n      def compile\n        helper :class_variable_set\n\n        push \"$class_variable_set(\#{class_variable_owner}, '\#{name}', \", expr(value), ')'\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:LocalVariableNode>", "handle", "children", "using_irb?", "$ret_or_1", "compiler", "irb?", "scope", "top?", "compile", "push", "var_name", "to_s", "with_temp", "block in compile", "tmp", "block (2 levels) in compile", "property", "wrap", "Base", "<class:LocalAssignNode>", "add_local", "expr", "value", "recv?", "expr?", "<class:LocalDeclareNode>", "<class:InstanceVariableNode>", "name", "[]", "1", "-1", "add_ivar", "<class:InstanceAssignNode>", "<class:GlobalVariableNode>", "helper", "add_gvar", "<class:BackRefNode>", "handle_global_match", "handle_post_match", "handle_pre_match", "raise", "NotImplementedError", "block in handle_global_match", "block (2 levels) in handle_global_match", "block in handle_pre_match", "block (2 levels) in handle_pre_match", "block in handle_post_match", "block (2 levels) in handle_post_match", "GlobalVariableNode", "<class:GlobalAssignNode>", "<class:NthrefNode>", "index", "<class:ClassVariableNode>", "tolerant", "stmt?", "class_variable_owner", "inspect", "<class:ClassVarAssignNode>"], :mappings=>"AAAAA,uCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MACEC;MAAAA;;;;QACEJ,IAAAK,QAAAA,CAAO,MAAPA;QAEAL,IAAAM,UAAAA,CAAS,UAATA;;AAEAC,QAAAA,0BAAAA,6CAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAAC,CAAAA,YAAAR,IAAAS,UAAAA,CAAAA,CAAQC,SAAAA,CAAAA,CAARF,CAAA,CAAA;YAAiBD,OAAAP,IAAAW,OAAAA,CAAAA,CAAKC,SAAAA,CAAAA;UAAtB;YAAAL,OAAA;UAAA;QADFA,CAAAA;QAIAH,OAAAS,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACE,KAAA,QAAkCb,IAAAO,eAAAA,CAAAA,CAAlC,CAAA;YAAA,OAAOP,IAAAc,MAAAA,CAAKd,IAAAe,UAAAA,CAAAA,CAAQC,MAAAA