(self[\"$<=>\"] == Opal.Kernel[\"$<=>\"]) {\n        return false;\n      }\n\n      // check for infinite recursion\n      if (self.$$comparable) {\n        self.$$comparable = false;\n        return false;\n      }\n    }\n\n    return false unless cmp = (self <=> other)\n\n    `normalize(cmp) == 0`\n  end\n\n  def >(other)\n    `cmp_or_fail(self, other) > 0`\n  end\n\n  def >=(other)\n    `cmp_or_fail(self, other) >= 0`\n  end\n\n  def <(other)\n    `cmp_or_fail(self, other) < 0`\n  end\n\n  def <=(other)\n    `cmp_or_fail(self, other) <= 0`\n  end\n\n  def between?(min, max)\n    return false if self < min\n    return false if self > max\n    true\n  end\n\n  def clamp(min, max = nil)\n    %x{\n      var c, excl;\n\n      if (max === nil) {\n        // We are dealing with a new Ruby 2.7 behaviour that we are able to\n        // provide a single Range argument instead of 2 Comparables.\n\n        if (!Opal.is_a(min, Opal.Range)) {\n          \#{::Kernel.raise ::TypeError, \"wrong argument type \#{min.class} (expected Range)\"}\n        }\n\n        excl = min.excl;\n        max = min.end;\n        min = min.begin;\n\n        if (max !== nil && excl) {\n          \#{::Kernel.raise ::ArgumentError, 'cannot clamp with an exclusive range'}\n        }\n      }\n\n      if (min !== nil && max !== nil && cmp_or_fail(min, max) > 0) {\n        \#{::Kernel.raise ::ArgumentError, 'min argument must be smaller than max argument'}\n      }\n\n      if (min !== nil) {\n        c = cmp_or_fail(self, min);\n\n        if (c == 0) return self;\n        if (c < 0) return min;\n      }\n\n      if (max !== nil) {\n        c = cmp_or_fail(self, max);\n\n        if (c > 0) return max;\n      }\n\n      return self;\n    }\n  end\nend\n"], :names=>["<top (required)>", "<module:Comparable>", ">", "0", "<", "$ret_or_1", "Integer", "Float", "Kernel", "raise", "ArgumentError", "class", "<=>", "==", "other", "self", "equal?", "cmp", ">=", "<=", "between?", "min", "max", "clamp", "TypeError"], :mappings=>"AAAAA,qCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;;AAEAA;AACAA;;AAEAA,UAAmBC,OAAND,IAAMC,EAAEC,CAAFD,CAAID;AACvBA,UAAmBG,OAANH,IAAMG,EAAED,CAAFC,CAAIH;AACvBA;AACAA;;AAEAA;AACAA;AACAA,MAEQ,CAhBR,CAAA,QAgBa,GAhBb,EAeQI,CAAAA,YAAMJ,GAANI,CAfR,CAAA,IAAA,CAAA,CAAA,QAgBkB,IAhBlB,EAAA,SAAA,CAAA,IAAA,CAAA,CAAA,QAgBwB,KAhBxB,EAAA,SAAA,CAAA,IAAA,CAAA,CAAA,QAgB+BC,cAhB/B,EAAA,SAAA,CAAA,IAAA,CAAA,QAgB0CC,YAhB1C,EAAA,SAAA,CAAA,CAAA,CAAA,CAAA,CAAA,CAAA,CAAA,CAAA,CAgBQ,GAAA,CACGN,2BADH,IAAA,CAGGA,wBAHH,CAAA;AAMRA,MAAQO,OAAQC,OAAAA,CAAOC,oBAAf,EAAiCT,gBAAD,GAAA,CAAiBA,CAACA,GAADA,CAAKU,OAAAA,CAAAA,CAAtB,CAAA,GAA6BV,QAA7B,GAAA,CAAsCA,UAAtC,CAAA,GAAkDA,SAA1EQ;AAChBR;;AAEAA;AACAA,gBAAkBA,CAACA,GAADA,CAAMW,QAAAA,CAAKX,GAALW,CAAUX;AAClCA;AACAA;AACAA;AACAA;;AAEEY,IAAAA,kBAAAA,8BAAOC,KAAPD;AAAAA,MAAAA;;;MACE,IAAA,QAAeE,IAAAC,WAAAA,CAAOF,KAAPE,CAAf,CAAA;QAAA,OAAO;MAAP;;AAGJH;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;MAEI,KAAA,QAAoBI,CAAAA,MAAOF,IAAKH,QAAAA,CAAIE,KAAJF,CAAZK,CAApB,CAAA;QAAA,OAAO;MAAP;MAEAJ,OAACA,mBAADA;IAjBFA,CAAAA;;AAoBAX,IAAAA,iBAAAA,2BAAMY,KAANZ;AAAAA,MAAAA;;MACEA,OAACA,4BAADA;IADFA,CAAAA;;AAIAgB,IAAAA,kBAAAA,8BAAOJ,KAAPI;AAAAA,MAAAA;;MACEA,OAACA,6BAADA;IADFA,CAAAA;;AAIAd,IAAAA,iBAAAA,2BAAMU,KAANV;AAAAA,MAAAA;;MACEA,OAACA,4BAADA;IADFA,CAAAA;;AAIAe,IAAAA,kBAAAA,8BAAOL,KAAPK;AAAAA,MAAAA;;MACEA,OAACA,6BAADA;IADFA,CAAAA;;AAIAC,IAAAA,wBAAAA,oCAAaC,GAAD,EAAMC,GAAlBF;AAAAA,MAAAA;;;MACE,IAAqBhB,OAALW,IAAKX,EAAEiB,GAAFjB,CAArB;QAAA,OAAO;MAAP;MACA,IAAqBF,OAALa,IAAKb,EAAEoB,GAAFpB,CAArB;QAAA,OAAO;MAAP;MACAkB,OAAA;IAHFA,CAAAA;IAMAnB,OAAAsB,qBAAAA,iBAAUF,GAAD,EAAMC,GAAfC;AAAAA,MAAAA;;;MAAe,uBAAM;;AAEvBA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA,UAAYf,OAAQC,OAAAA,CAAOe,gBAAf,EAA6BD,sBAAD,GAAA,CAAuBF,GAAGV,OAAAA,CAAAA,CAA1B,CAAA,GAAiCY,mBAArDd;AACpBc;;AAEAA;AACAA;AACAA;;AAEAA;AACAA,UAAYf,OAAQC,OAAAA,CAAOC,oBAAf,EAAgCa,sCAAxBd;AACpBc;AACAA;;AAEAA;AACAA,QAAUf,OAAQC,OAAAA,CAAOC,oBAAf,EAAgCa,gDAAxBd;AAClBc;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;IAvCEA,CAAAA,IAAAA;EAxEFtB,GAAO,IAAPA;AAFAD;"}}, {:offset=>{:line=>30362, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./pathname.rb"], :sourcesContent=>["require 'corelib/comparable'\n\n# Portions from Author:: Tanaka Akira <akr@m17n.org>\nclass Pathname\n  include Comparable\n  SEPARATOR_PAT = /\#{Regexp.quote File::SEPARATOR}/\n\n  def initialize(path)\n    if Pathname === path\n      @path = path.path.to_s\n    elsif path.respond_to?(:to_path)\n      @path = path.to_path\n    elsif path.is_a?(String)\n      @path = path\n    elsif path.nil?\n      raise TypeError, 'no implicit conversion of nil into String'\n    else\n      raise TypeError, \"no implicit conversion of \#{path.class} into String\"\n    end\n    raise ArgumentError if @path == \"\\0\"\n  end\n\n  def self.pwd\n    new(Dir.pwd)\n  end\n\n  attr_reader :path\n\n  def ==(other)\n    other.path == @path\n  end\n\n  def absolute?\n    !relative?\n  end\n\n  def relative?\n    path = @path\n    while (r = chop_basename(path))\n      path, = r\n    end\n    path == ''\n  end\n\n  def chop_basename(path) # :nodoc:\n    base = File.basename(path)\n    # ruby uses /^\#{SEPARATOR_PAT}?$/o but having issues with interpolation\n    if Regexp.new(\"^\#{Pathname::SEPARATOR_PAT.source}?$\") =~ base\n      return nil\n    else\n      return path[0, path.rindex(base)], base\n    end\n  end\n\n  def root?\n    @path == '/'\n  end\n\n  def parent\n    new_path = @path.sub(%r{/([^/]+/?$)}, '')\n    new_path = absolute? ? '/' : '.' if new_path == ''\n    Pathname.new(new_path)\n  end\n\n  def sub(*args)\n    Pathname.new(@path.sub(*args))\n  end\n\n  def cleanpath\n    `return Opal.normalize(\#{@path})`\n  end\n\n  def to_path\n    @path\n  end\n\n  def hash\n    @path\n  end\n\n  def expand_path\n    Pathname.new(File.expand_path(@path))\n  end\n\n  def +(other)\n    other = Pathname.new(other) unless Pathname === other\n    Pathname.new(plus(@path, other.to_s))\n  end\n\n  def plus(path1, path2) # -> path # :nodoc:\n    prefix2 = path2\n    index_list2 = []\n    basename_list2 = []\n    while (r2 = chop_basename(prefix2))\n      prefix2, basename2 = r2\n      index_list2.unshift prefix2.length\n      basename_list2.unshift basename2\n    end\n    return path2 if prefix2 != ''\n    prefix1 = path1\n    while true\n      while !basename_list2.empty? && basename_list2.first == '.'\n        index_list2.shift\n        basename_list2.shift\n      end\n      break unless (r1 = chop_basename(prefix1))\n      prefix1, basename1 = r1\n      next if basename1 == '.'\n      if basename1 == '..' || basename_list2.empty? || basename_list2.first != '..'\n        prefix1 += basename1\n        break\n      end\n      index_list2.shift\n      basename_list2.shift\n    end\n    r1 = chop_basename(prefix1)\n    if !r1 && /\#{SEPARATOR_PAT}/ =~ File.basename(prefix1)\n      while !basename_list2.empty? && basename_list2.first == '..'\n        index_list2.shift\n        basename_list2.shift\n      end\n    end\n    if !basename_list2.empty?\n      suffix2 = path2[index_list2.first..-1]\n      r1 ? File.join(prefix1, suffix2) : prefix1 + suffix2\n    else\n      r1 ? prefix1 : File.dirname(prefix1)\n    end\n  end\n\n  def join(*args)\n    return self if args.empty?\n    result = args.pop\n    result = Pathname.new(result) unless Pathname === result\n    return result if result.absolute?\n    args.reverse_each do |arg|\n      arg = Pathname.new(arg) unless Pathname === arg\n      result = arg + result\n      return result if result.absolute?\n    end\n    self + result\n  end\n\n  def split\n    [dirname, basename]\n  end\n\n  def dirname\n    Pathname.new(File.dirname(@path))\n  end\n\n  def basename\n    Pathname.new(File.basename(@path))\n  end\n\n  def directory?\n    File.directory?(@path)\n  end\n\n  def extname\n    File.extname(@path)\n  end\n\n  def <=>(other)\n    path <=> other.path\n  end\n\n  SAME_PATHS = if File::FNM_SYSCASE.nonzero?\n                 # Avoid #zero? here because #casecmp can return nil.\n                 proc { |a, b| a.casecmp(b) == 0 }\n               else\n                 proc { |a, b| a == b }\n               end\n\n  def relative_path_from(base_directory)\n    dest_directory = cleanpath.to_s\n    base_directory = base_directory.cleanpath.to_s\n    dest_prefix = dest_directory\n    dest_names = []\n    while (r = chop_basename(dest_prefix))\n      dest_prefix, basename = r\n      dest_names.unshift basename if basename != '.'\n    end\n    base_prefix = base_directory\n    base_names = []\n    while (r = chop_basename(base_prefix))\n      base_prefix, basename = r\n      base_names.unshift basename if basename != '.'\n    end\n    unless SAME_PATHS[dest_prefix, base_prefix]\n      raise ArgumentError, \"different prefix: \#{dest_prefix.inspect} and \#{base_directory.inspect}\"\n    end\n    while !dest_names.empty? &&\n          !base_names.empty? &&\n          SAME_PATHS[dest_names.first, base_names.first]\n      dest_names.shift\n      base_names.shift\n    end\n    if base_names.include? '..'\n      raise ArgumentError, \"base_directory has ..: \#{base_directory.inspect}\"\n    end\n    base_names.fill('..')\n    relpath_names = base_names + dest_names\n    if relpath_names.empty?\n      Pathname.new('.')\n    else\n      Pathname.new(File.join(*relpath_names))\n    end\n  end\n\n  def entries\n    Dir.entries(@path).map { |f| self.class.new(f) }\n  end\n\n  alias === ==\n  alias eql? ==\n  alias to_s to_path\n  alias to_str to_path\nend\n\nmodule Kernel\n  def Pathname(path)\n    Pathname.new(path)\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<class:Pathname>", "include", "Comparable", "Regexp", "quote", "File::SEPARATOR", "File", "initialize", "path", "Pathname", "@path", "to_s", "respond_to?", "to_path", "is_a?", "String", "nil?", "raise", "TypeError", "class", "ArgumentError", "pwd", "new", "Dir", "attr_reader", "==", "other", "absolute?", "relative?", "!", "r", "chop_basename",