  end\n\n    class JsCallNode < CallNode\n      handle :jscall\n\n      def initialize(*)\n        super\n\n        # For .JS. call we pass a block\n        # as a plain JS callback\n        if @iter\n          @arglist = @arglist << @iter\n        end\n        @iter = nil\n      end\n\n      def compile\n        default_compile\n      end\n\n      def method_jsid\n        \".\#{meth}\"\n      end\n\n      def compile_using_send\n        push recv(receiver_sexp), method_jsid, '.apply(null'\n        compile_arguments\n        if iter\n          push '.concat(', expr(iter), ')'\n        end\n        push ')'\n      end\n    end\n\n    # /regexp/ =~ rhs\n    # s(:match_with_lvasgn, lhs, rhs)\n    class Match3Node < Base\n      handle :match_with_lvasgn\n\n      children :lhs, :rhs\n\n      def compile\n        sexp = s(:send, lhs, :=~, rhs)\n        # Handle named matches like: /(?<abc>b)/ =~ 'b'\n        if lhs.type == :regexp && lhs.children.first.type == :str\n          re = lhs.children.first.children.first\n          names = re.scan(/\\(\\?<([^>]*)>/).flatten.map(&:to_sym)\n          unless names.empty?\n            # $m3names = $~ ? $~.named_captures : {}\n            names_def = s(:lvasgn, :$m3names,\n              s(:if,\n                s(:gvar, :$~),\n                s(:send, s(:gvar, :$~), :named_captures),\n                s(:hash)\n              )\n            )\n\n            names = names.map do |name|\n              # abc = $m3names[:abc]\n              s(:lvasgn, name,\n                s(:send,\n                  s(:lvar, :$m3names),\n                  :[],\n                  s(:sym, name)\n                )\n              )\n            end\n\n            if stmt?\n              # We don't care about a return value of this one, so we\n              # ignore it and just assign the local variables.\n              #\n              # (/(?<abc>b)/ =~ 'f')\n              # $m3names = $~ ? $~.named_captures : {}\n              # abc = $m3names[:abc]\n              sexp = s(:begin, sexp, names_def, *names)\n            else\n              # We actually do care about a return value, so we must\n              # keep it saved.\n              #\n              # $m3tmp = (/(?<abc>b)/ =~ 'f')\n              # $m3names = $~ ? $~.named_captures : {}\n              # abc = $m3names[:abc]\n              # $m3tmp\n              sexp = s(:begin,\n                s(:lvasgn, :$m3tmp, sexp),\n                names_def,\n                *names,\n                s(:lvar, :$m3tmp)\n              )\n            end\n          end\n        end\n        push process(sexp, @level)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:JsAttrNode>", "handle", "children", "compile", "push", "recv", "recvr", "expr", "property", "Base", "<class:JsAttrAsgnNode>", "value", "<class:JsCallNode>", "initialize", "$fwd_rest", "@iter", "@arglist", "<<", "default_compile", "method_jsid", "meth", "compile_using_send", "receiver_sexp", "compile_arguments", "iter", "CallNode", "<class:Match3Node>", "sexp", "s", "lhs", "rhs", "type", "first", "re", "names", "map", "scan", "flatten", "to_proc", "empty?", "names_def", "block in compile", "name", "block (2 levels) in compile", "stmt?", "process", "@level"], :mappings=>"AAAAA,0CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EACAD,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MAGEC;MAAAA;;;;QACEJ,IAAAK,QAAAA,CAAO,QAAPA;QACAL,IAAAM,UAAAA,CAAS,OAAT,EAAiB,UAAjBA;QAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAAAP,IAAAQ,MAAAA,CAAKR,IAAAS,MAAAA,CAAKT,IAAAU,OAAAA,CAAAA,CAALD,CAAL,EAAkBF,GAAlB,EAAuBP,IAAAW,MAAAA,CAAKX,IAAAY,UAAAA,CAAAA,CAALD,CAAvB,EAAuCJ,GAAvCC;QADFD,CAAAA;MAJFH,GAAAA,WAAAA,EAAmBS,UAAnBT;MAWAU;MAAAA;;;;QACEd,IAAAK,QAAAA,CAAO,YAAPA;QAEAL,IAAAM,UAAAA,CAAS,OAAT,EAAiB,UAAjB,EAA4B,OAA5BA;QAEAQ,OAAAP,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAAAP,IAAAQ,MAAAA,CAAKR,IAAAS,MAAAA,CAAKT,IAAAU,OAAAA,CAAAA,CAALD,CAAL,