AgC,GAAAA,CAAE,MAAF,EAAS,IAATA,CAAT,EAAwB,gBAAxBA,CAFF,EAGEhC,IAAAgC,GAAAA,CAAE,MAAFA,CAHFA,CADUA;cAQZM,QAAaC,MAALD,KAAKC,OAAAA,EAAAA,EAAAA,EAALM,aAAcC,IAAdD,EAAAE;;;gBAAc;gBAEpBA,OAAA/C,IAAAgC,GAAAA,CAAE,QAAF,EAAWc,IAAX,EACE9C,IAAAgC,GAAAA,CAAE,MAAF,EACEhC,IAAAgC,GAAAA,CAAE,MAAF,EAAS,UAATA,CADF,EAEE,IAFF,EAGEhC,IAAAgC,GAAAA,CAAE,KAAF,EAAQc,IAARd,CAHFA,CADFA,EAFMa,CAAAA,GAAAA,SAAAA,CAAKN;cAWb,IAAA,QAAGvC,IAAAgD,UAAAA,CAAAA,CAAH,CAAA;gBAOEjB,OAAOC,MAAAhC,IAAAgC,KAAAA,EAAA,CAAE,OAAF,EAAUD,IAAV,EAAgBa,SAAhB,CAAA,QAA2B,MAACN,KAAD,CAA3B,CAAAN;cAPT;gBAgBED,OAAOC,MAAAhC,IAAAgC,KAAAA,EAAA,CAAE,OAAF,EACLhC,IAAAgC,GAAAA,CAAE,QAAF,EAAW,QAAX,EAAoBD,IAApBC,CADK,EAELY,SAFK,CAAA,QAGL,MAACN,KAAD,CAHK,CAAA,SAILtC,IAAAgC,GAAAA,CAAE,MAAF,EAAS,QAATA,CAJK,EAAAA;cAhBT;YArBF;UAHF;UAiDAzB,OAAAP,IAAAQ,MAAAA,CAAKR,IAAAiD,SAAAA,CAAQlB,IAAR,EAAcmB,UAAdD,CAALzC;QApDFD,CAAAA;MALFuB,GAAAA,WAAAA,EAAmBjB,UAAnBiB;IA1DF3B,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>31573, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/scope.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    class ScopeNode < Base\n      # Every scope can have a parent scope\n      attr_accessor :parent\n\n      # The class or module name if this scope is a class scope\n      attr_accessor :name\n\n      # The given block name for a def scope\n      attr_accessor :block_name\n\n      attr_reader :scope_name\n      attr_reader :locals\n      attr_reader :ivars\n      attr_reader :gvars\n\n      attr_accessor :mid\n\n      # true if singleton def, false otherwise\n      attr_accessor :defs\n\n      # used by modules to know what methods to donate to includees\n      attr_reader :methods\n\n      attr_accessor :catch_return, :has_break, :has_retry\n\n      attr_accessor :rescue_else_sexp\n\n      def initialize(*)\n        super\n\n        @locals   = []\n        @temps    = []\n        @args     = []\n        @ivars    = []\n   