mpty body\n          if stmt?\n            unshift '$module(', base, \", '\#{name}')\"\n          else\n            unshift '($module(', base, \", '\#{name}'), nil)\"\n          end\n        else\n          line \"  var self = $module($base, '\#{name}');\"\n          in_scope do\n            scope.name = name\n            in_closure(Closure::MODULE | Closure::JS_FUNCTION) do\n              compile_body\n            end\n          end\n\n          if await_encountered\n            await_begin = '(await '\n            await_end = ')'\n            async = 'async '\n            parent.await_encountered = true\n          else\n            await_begin, await_end, async = '', '', ''\n          end\n\n          unshift \"\#{await_begin}(\#{async}function($base\#{', $parent_nesting' if @define_nesting}) {\"\n          line '})(', base, \"\#{', ' + scope.nesting if @define_nesting})\#{await_end}\"\n        end\n      end\n\n      private\n\n      # cid is always s(:const, scope_sexp_or_nil, :ConstName)\n      def name_and_base\n        base, name = cid.children\n\n        if base.nil?\n          [name, \"\#{scope.nesting}[0]\"]\n        else\n          [name, expr(base)]\n        end\n      end\n\n      def compile_body\n        body_code = stmt(compiler.returns(body))\n        empty_line\n\n        add_temp \"$nesting = [self].concat($parent_nesting)\" if @define_nesting\n        add_temp '$$ = Opal.$r($nesting)' if @define_relative_access\n\n        line scope.to_vars\n        line body_code\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:ModuleNode>", "handle", "children", "compile", "name_and_base", "name", "base", "helper", "body", "nil?", "stmt?", "unshift", "line", "in_scope", "block in compile", "block (2 levels) in compile", "scope", "name=", "in_closure", "Closure::MODULE", "Closure", "|", "Closure::JS_FUNCTION", "block (3 levels) in compile", "compile_body", "await_encountered", "await_