lative_access\n\n          line scope.to_vars\n          line body_stmt\n        end\n\n        line '})(Opal.get_singleton_class(', recv(object), \"), \#{scope.nesting})\"\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:SingletonClassNode>", "handle", "children", "compile", "push", "in_scope", "block in compile", "block (2 levels) in compile", "body_stmt", "stmt", "compiler", "returns", "body", "@define_nesting", "add_temp", "@define_relative_access", "line", "scope", "to_vars", "recv", "object", "nesting", "ScopeNode"], :mappings=>"AAAAA,6CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,kBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;;QACEJ,IAAAK,QAAAA,CAAO,QAAPA;QAEAL,IAAAM,UAAAA,CAAS,QAAT,EAAkB,MAAlBA;QAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACEP,IAAAQ,MAAAA,CAAKD,oCAALC;UAEAC,MAAAT,IAAAS,YAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;AAAAA;AAAAA;;;YACEC,YAAYZ,IAAAa,MAAAA,CAAKb,IAAAc,UAAAA,CAAAA,CAAQC,SAAAA,CAASf,IAAAgB,MAAAA,CAAAA,CAATD,CAAbF;YAEZ,IAAA,QAAwDI,mBAAxD,CAAA;cAAAjB,IAAAkB,UAAAA,CAASP,2CAATO;YAAA;YACA,IAAA,QAAqCC,2BAArC,CAAA;cAAAnB,IAAAkB,UAAAA,CAASP,wBAATO;YAAA;YAEAlB,IAAAoB,MAAAA,CAAKpB,IAAAqB,OAAAA,CAAAA,CAAKC,SAAAA,CAAAA,CAAVF;YACAT,OAAAX,IAAAoB,MAAAA,CAAKR,SAALQ,EAPFV,CAAAA,GAAAA,SAAAA,CAAAD;UAUAF,OAAAP,IAAAoB,MAAAA,CAAKb,8BAAL,EAAqCP,IAAAuB,MAAAA,CAAKvB,IAAAwB,QAAAA,CAAAA,CAALD,CAArC,EAAoDhB,KAAD,GAAA,CAAMP,IAAAqB,OAAAA,CAAAA,CAAKI,SAAAA,CAAAA,CAAX,CAAA,GAAoBlB,GAAvEa;QAbFb,CAAAA;MALFH,GAAAA,WAAAA,EAA2BsB,eAA3BtB;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32368, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/arg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # Compiles a single inline required argument\n      # def m(a); end\n      #       ^\n      class ArgNode < Base\n        handle :arg\n        children