le Args\n      # Compiles extraction of the block argument\n      # def m(&block); end\n      #       ^^^^^^\n      #\n      # This node doesn't exist in the original AST,\n      # InlineArgs rewriter creates it to simplify compilation\n      class ExtractBlockarg < Base\n        handle :extract_blockarg\n        children :name\n\n        def compile\n          scope.uses_block!\n          scope.add_arg name\n\n          scope.prepare_block(name)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractBlockarg>", "handle", "children", "compile", "scope", "uses_block!", "add_arg", "name", "prepare_block", "Base"], :mappings=>"AAAAA,oDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAOEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,kBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAATA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACER,IAAAS,OAAAA,CAAAA,CAAKC,gBAAAA,CAAAA;YACLV,IAAAS,OAAAA,CAAAA,CAAKE,SAAAA,CAASX,IAAAY,MAAAA,CAAAA,CAATD;YAELH,OAAAR,IAAAS,OAAAA,CAAAA,CAAKI,eAAAA,CAAeb,IAAAY,MAAAA,CAAAA,CAAfC;UAJPL,CAAAA;QAJFH,GAAAA,WAAAA,EAAwBS,UAAxBT;MAPFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32691, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_kwarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for extracting a single\n      # required keyword argument from $kwargs\n      #\n      # $kwargs always exist (as argument when inlining is possible\n      # and as a local variable when it's not)\n      #\n      class ExtractKwarg < Base\n        handle :extract_kwarg\n        children :lvar_name\n\n        def compile\n          key_name = @sexp.meta[:arg_name]\n          scope.used_kwargs << key_name\n\n          add_temp lvar_name\n\n          helper :get_kwarg\n\n          push \"\#{lvar_name} = $get_kwarg($kwargs, \#{key_name.to_s.inspect})\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractKwarg>", "handle", "children", "compile", "key_name", "@sexp", "meta", "[]", "scope", "used_kwargs", "<<", "add_temp", "lvar_name", "helper", "push", "to_s", "inspect", "Base"], :mappings=>"AAAAA,gDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAOEA,OAAAC;QAAAA;;UAAAA;;AAAAA;;UACEL,IAAAM,QAAAA,CAAO,eAAPA;UACAN,IAAAO,UAAAA,CAAS,WAATA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACEC,WAAWC,SAAKC,MAAAA,CAAAA,CAAKC,OAAAA,CAAC,UAADA;YACrBZ,IAAAa,OAAAA,CAAAA,CAAKC,aAAAA,CAAAA,CAAaC,OAAAA,CAAGN,QAAHM;YAElBf,IAAAgB,UAAAA,CAAShB,IAAAiB,WAAAA,CAAAA,CAATD;YAEAhB,IAAAkB,QAAAA,CAAO,WAAPA;YAEAV,OAAAR,IAAAmB,MAAAA,CAAK,EAAA,GAAA,CAAGnB,IAAAiB,WAAAA,CAAAA,CAAH,CAAA,GAAaT,yBAAb,GAAA,CAAsCC,QAAQW,MAAAA,CAAAA,CAAKC,SAAAA,CAAAA,CAAnD,CAAA,GAA4Db,GAAjEW;UARFX,CAAAA;QAJFH,GAAAA,WAAAA,EAAqBiB,UAArBjB;MAPFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32736, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_kwargs.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # A utility node responsible for extracting\n      # post-kwargs from post-arguments.\n      #\n      # This node is used when kwargs cannot be inlined:\n      #   def m(a = 1, kw:); end\n      #\n      # This node is NOT used when kwargs can be inlined:\n      #   def m(a, kw:); end\n      #\n      class ExtractKwargs < Base\n        handle :extract_kwargs\n\n        def compile\n          add_temp '$kwargs'\n\n          helper :extract_kwargs\n\n          push '$kwargs = $extract_kwargs($post_args)'\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractKwargs>", "handle", "compile", "add_temp", "helper", "push", "Base"], :mappings=>"AAAAA,iDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAUEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,gBAAPA;UAEAD,OAAAE,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACEP,IAAAQ,UAAAA,CAASD,SAATC;YAEAR,IAAAS,QAAAA,CAAO,gBAAPA;YAEAF,OAAAP,IAAAU,MAAAA,CAAKH,uCAALG;UALFH,CAAAA;QAHFF,GAAAA,WAAAA,EAAsBM,UAAtBN;MAVFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32776, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_kwoptarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for extracting a single\n      # optional keyword argument from $kwargs\n      #\n      # $kwargs always exist (as argument when inlining is possible\n      # and as a local variable when it's not)\n      #\n      class ExtractKwoptarg < Base\n        handle :extract_kwoptarg\n        children :lvar_name, :default_value\n\n        def compile\n          key_name = @sexp.meta[:arg_name]\n          scope.used_kwargs << key_name\n\n          add_temp lvar_name\n\n          line \"\#{lvar_name} = $kwargs.$$smap[\#{key_name.to_s.inspect}];\"\n\n          return if default_value.children[1] == :undefined\n\n          push \"if (\#{lvar_name} == null) \#{lvar_name} = \", expr(default_value)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractKwoptarg>", "handle", "children", "compile", "key_name", "@sexp", "meta", "[]", "scope", "used_kwargs", "<<", "add_temp", "lvar_name", "line", "to_s", "inspect", "default_value", "1", "