    args = scope.used_kwargs.map do |arg_name|\n            \"'\#{arg_name}': true\"\n          end\n\n          \"{\#{args.join ','}}\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractKwrestarg>", "handle", "children", "compile", "name", "$ret_or_1", "add_temp", "helper", "push", "used_kwargs", "args", "map", "scope", "block in used_kwargs", "arg_name", "block (2 levels) in used_kwargs", "join", "Base"], :mappings=>"AAAAA,oDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAOEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,mBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAATA;;AAEAC,UAAAA,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YAGEC,OAAO,CAAA,QAAAC,CAAAA,YAAAV,IAAIS,MAAAA,CAAAA,CAAJC,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAaF,cAAb,CAAA;YAEPR,IAAAW,UAAAA,CAASF,IAATE;YAEAX,IAAAY,QAAAA,CAAO,YAAPA;YAEAJ,OAAAR,IAAAa,MAAAA,CAAK,EAAA,GAAA,CAAGJ,IAAH,CAAA,GAAQD,0BAAR,GAAA,CAAkCR,IAAAc,aAAAA,CAAAA,CAAlC,CAAA,GAA8CN,GAAnDK;UATFL,CAAAA;UAYAH,OAAAS,2BAAAA,uBAAAA;AAAAA,YAAAA;;;YACEC,OAAwBC,MAAjBhB,IAAAiB,OAAAA,CAAAA,CAAKH,aAAAA,CAAAA,CAAYE,OAAAA,EAAAA,EAAAA,EAAjBE,aAA0BC,QAA1BD;;cAA0B;cAC/BE,OAACA,GAAD,GAAA,CAAID,QAAJ,CAAA,GAAaC,UADRF,CAAiBF;YAIxBF,OAACA,GAAD,GAAA,CAAIC,IAAIM,MAAAA,CAAMP,GAANO,CAAR,CAAA,GAAkBP;UALpBA,CAAAA;QAhBFT,GAAAA,WAAAA,EAAyBiB,UAAzBjB;MAPFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32877, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_optarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # Compiles extraction of a single inline optional argument\n      # def m(a = 1); end\n      #       ^^^^^\n      #\n      # This node doesn't exist in the original AST,\n      # InlineArgs rewriter creates it to simplify compilation\n      #\n      # Sometimes the argument can't be inlined.\n      # In such cases InlineArgs rewriter replaces\n      #   s(:optarg, :arg_name, ...default value...)\n      # to:\n      #   s(:fakearg) + s(:extract_post_optarg, :arg_name, ...default value...)\n      #\n      class ExtractOptargNode < Base\n        handle :extract_optarg\n        children :name, :default_value\n\n        def compile\n          return if default_value.children[1] == :undefined\n\n          push \"if (\#{name} == null) \#{name} = \", expr(default_value)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractOptargNode>", "handle", "children", "compile", "default_value", "[]", "1", "push", "name", "expr", "Base"], :mappings=>"AAAAA,iDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAcEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,gBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAAT,EAAgB,eAAhBA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACE,IAAA,MAAUR,IAAAS,eAAAA,CAAAA,CAAaF,UAAAA,CAAAA,CAASG,OAAAA,CAACC,CAADD,CAAhC,EAAuC,WAAvC,CAAA;cAAA,OAAA;YAAA;YAEAF,OAAAR,IAAAY,MAAAA,CAAMJ,MAAD,GAAA,CAAOR,IAAAa,MAAAA,CAAAA,CAAP,CAAA,GAAYL,YAAZ,GAAA,CAAwBR,IAAAa,MAAAA,CAAAA,CAAxB,CAAA,GAA6BL,KAAlC,EAAwCR,IAAAc,MAAAA,CAAKd,IAAAS,eAAAA,CAAAA,CAALK,CAAxCF;UAHFJ,CAAAA;QAJFH,GAAAA,WAAAA,EAA0BU,UAA1BV;MAdFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32919, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_post_arg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for extracting a single\n      # required post-argument from $post_args\n      #\n      class ExtractPostArg < Base\n        handle :extract_post_arg\n        children :name\n\n        def compile\n          add_temp name\n\n          line \"\#{name} = $post_args.shift();\"\n\n          push \"if (\#{name} == null) \#{name} = nil\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractPostArg>", "handle", "children", "compile", "add_temp", "name", "line", "push", "Base"], :mappings=>"AAAAA,mDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAIEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,kBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAATA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACER,IAAAS,UAAAA,CAAST,IAAAU,MAAAA,CAAAA,CAATD;YAEAT,IAAAW,MAAAA,CAAK,EAAA,GAAA,CAAGX,IAAAU,MAAAA,CAAAA,CAAH,CAAA,GAAQF,wBAAbG;YAEAH,OAAAR,IAAAY,MAAAA,CAAMJ,MAAD,GAAA,CAAOR,IAAAU,MAAAA,CAAAA,CAAP,CAAA,GAAYF,YAAZ,GAAA,CAAwBR,IAAAU,MAAAA,CAAAA,CAAxB,CAAA,GAA6BF,QAAlCI;UALFJ,CAAAA;QAJFH,GAAAA,WAAAA,EAAuBQ,UAAvBR;MAJFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>32960, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_post_optarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for extracting a single\n      # optional post-argument\n      #\n      # args_to_keep is the number of required post-arguments\n      #\n      #   def m(a = 1, b, c, d); end\n      # becomes something like:\n      #   if post_args.length > 3\n      #     a = post_args[0]\n      #     post_args = post_args[1..-1]\n      #   end\n      #\n      class ExtractPostOptarg < Base\n        handle :extract_post_optarg\n        children :name, :default_value, :args_to_keep\n\n        def compile\n          add_temp name\n\n          line \"if ($post_args.length > \#{args_to_keep}) \#{name} = $post_args.shift();\"\n\n          return if default_value.children[1] == :undefined\n\n          push \"if (\#{name} == null) \#{name} = \", expr(default_value)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractPostOptarg>", "handle", "children", "compile", "add_temp", "name", "line", "args_to_keep", "default_value", "[]", "1", "push", "expr", "Base"], :mappings=>"AAAAA,sDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAaEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,qBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAAT,EAAgB,eAAhB,EAAgC,cAAhCA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACER,IAAAS,UAAAA,CAAST,IAAAU,MAAAA,CAAAA,CAATD;YAEAT,IAAAW,MAAAA,CAAMH,0BAAD,GAAA,CAA2BR,IAAAY,cAAAA,CAAAA,CAA3B,CAAA,GAAwCJ,IAAxC,GAAA,CAA4CR,IAAAU,MAAAA,CAAAA,CAA5C,CAAA,GAAiDF,wBAAtDG;YAEA,IAAA,MAAUX,IAAAa,eAAAA,CAAAA,CAAaN,UAAAA,CAAAA,CAASO,OAAAA,CAACC,CAADD,CAAhC,EAAuC,WAAvC,CAAA;cAAA,OAAA;YAAA;YAEAN,OAAAR,IAAAgB,MAAAA,CAAMR,MAAD,GAAA,CAAOR,IAAAU,MAAAA,CAAAA,CAAP,CAAA,GAAYF,YAAZ,GAAA,CAAwBR,IAAAU,MAAAA,CAAAA,CAAxB,CAAA,GAA6BF,KAAlC,EAAwCR,IAAAiB,MAAAA,CAAKjB,IAAAa,eAAAA,CAAAA,CAALI,CAAxCD;UAPFR,CAAAA;QAJFH,GAAAA,WAAAA,EAA0Ba,UAA1Bb;MAbFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33004, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/extract_restarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for extracting a splat argument from post-arguments\n      #\n      # args_to_keep is the number of required post-arguments\n      #\n      #   def m(*a, b, c, d); end\n      # becomes something like:\n      #   a = post_args[0..-3]\n      #   post_args = post_args[-3..-1]\n      #\n      class ExtractRestarg < Base\n        handle :extract_restarg\n        children :name, :args_to_keep\n\n        def compile\n          # def m(*)\n          # arguments are assigned to `$rest_arg` for super call\n          name = self.name || '$rest_arg'\n\n          add_temp name\n\n          if args_to_keep == 0\n            # no post-args, we are free to grab everything\n            push \"\#{name} = $post_args\"\n          else\n            push \"\#{name} = $post_args.splice(0, $post_args.length - \#{args_to_keep})\"\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:ExtractRestarg>", "handle", "children", "compile", "name", "$ret_or_1", "add_temp", "args_to_keep", "0", "push", "Base"], :mappings=>"AAAAA,kDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAUEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,iBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAAT,EAAgB,cAAhBA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YAGEC,OAAO,CAAA,QAAAC,CAAAA,YAAAV,IAAIS,MAAAA,CAAAA,CAAJC,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAaF,WAAb,CAAA;YAEPR,IAAAW,UAAAA,CAASF,IAATE;YAEA,IAAA,MAAGX,IAAAY,cAAAA,CAAAA,CAAH,EAAmBC,CAAnB,CAAA;cAEEL,OAAAR,IAAAc,MAAAA,CAAK,EAAA,GAAA,CAAGL,IAAH,CAAA,GAAQD,eAAbM;YAFF;cAIEN,OAAAR,IAAAc,MAAAA,CAAK,EAAA,GAAA,CAAGL,IAAH,CAAA,GAAQD,8CAAR,GAAA,CAAsDR,IAAAY,cAAAA,CAAAA,CAAtD,CAAA,GAAmEJ,GAAxEM;YAJF;UAPFN,CAAAA;QAJFH,GAAAA,WAAAA,EAAuBU,UAAvBV;MAVFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33049, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/fake_arg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # Compiles a fake argument produced by the InlineArgs rewriter.\n      #\n      # This argument represents an argument from the\n      # Ruby code that gets initialized later in the function body.\n      #\n      # def m(a = 1, b); end\n      #              ^\n      class FakeArgNode < Base\n        handle :fake_arg\n\n        def compile\n          name = scope.next_temp\n          scope.add_arg name\n          push name\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:FakeArgNode>", "handle", "compile", "name", "scope", "next_temp", "add_arg", "push", "Base"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAQEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,UAAPA;UAEAD,OAAAE,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACEC,OAAOR,IAAAS,OAAAA,CAAAA,CAAKC,WAAAA,CAAAA;YACZV,IAAAS,OAAAA,CAAAA,CAAKE,SAAAA,CAASH,IAATG;YACLJ,OAAAP,IAAAY,MAAAA,CAAKJ,IAALI;UAHFL,CAAAA;QAHFF,GAAAA,WAAAA,EAAoBQ,UAApBR;MARFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33089, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/initialize_iterarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for initializing a single\n      # required block arg\n      #\n      #   proc { |a| }\n      #\n      # Procs don't have arity checking and code like\n      #   proc { |a| }.call\n      # must return nil\n      class InitializeIterarg < Base\n        handle :initialize_iter_arg\n        children :name\n\n        def compile\n          push \"if (\#{name} == null) \#{name} = nil\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:InitializeIterarg>", "handle", "children", "compile", "push", "name", "Base"], :mappings=>"AAAAA,qDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QASEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,qBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAATA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;YACEA,OAAAR,IAAAS,MAAAA,CAAMD,MAAD,GAAA,CAAOR,IAAAU,MAAAA,CAAAA,CAAP,CAAA,GAAYF,YAAZ,GAAA,CAAwBR,IAAAU,MAAAA,CAAAA,CAAxB,CAAA,GAA6BF,QAAlCC;UADFD,CAAAA;QAJFH,GAAAA,WAAAA,EAA0BM,UAA1BN;MATFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33127, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/initialize_shadowarg.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # This node is responsible for initializing a shadow arg\n      #\n      # proc { |;a| }\n      #\n      class InitializeShadowarg < Base\n        handle :initialize_shadowarg\n        children :name\n\n        def compile\n          scope.locals << name\n          scope.add_arg(name)\n          push \"\#{name} = nil\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:InitializeShadowarg>", "handle", "children", "compile", "scope", "locals", "<<", "name", "add_arg", "push", "Base"], :mappings=>"AAAAA,uDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAKEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,sBAAPA;UACAN,IAAAO,UAAAA,CAAS,MAATA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACER,IAAAS,OAAAA,CAAAA,CAAKC,QAAAA,CAAAA,CAAQC,OAAAA,CAAGX,IAAAY,MAAAA,CAAAA,CAAHD;YACbX,IAAAS,OAAAA,CAAAA,CAAKI,SAAAA,CAASb,IAAAY,MAAAA,CAAAA,CAATC;YACLL,OAAAR,IAAAc,MAAAA,CAAK,EAAA,GAAA,CAAGd,IAAAY,MAAAA,CAAAA,CAAH,CAAA,GAAQJ,QAAbM;UAHFN,CAAAA;QAJFH,GAAAA,WAAAA,EAA4BU,UAA5BV;MALFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33168, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/parameters.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  module Nodes\n    module Args\n      class Parameters\n        def initialize(args)\n          @args = args.children\n        end\n\n        def to_code\n          stringified_parameters = @args.map do |arg|\n            public_send(:\"on_\#{arg.type}\", *arg)\n          end\n\n          \"[\#{stringified_parameters.compact.join(', ')}]\"\n        end\n\n        def on_arg(arg_name)\n          %{['req', '\#{arg_name}']}\n        end\n\n        def on_mlhs(*)\n          %{['req']}\n        end\n\n        def on_optarg(arg_name, _default_value)\n          %{['opt', '\#{arg_name}']}\n        end\n\n        def on_restarg(arg_name = nil)\n          if arg_name\n            arg_name = :* if arg_name == :fwd_rest_arg\n            %{['rest', '\#{arg_name}']}\n          else\n            %{['rest']}\n          end\n        end\n\n        def on_kwarg(arg_name)\n          %{['keyreq', '\#{arg_name}']}\n        end\n\n        def on_kwoptarg(arg_name, _default_value)\n          %{['key', '\#{arg_name}']}\n        end\n\n        def on_kwrestarg(arg_name = nil)\n          if arg_name\n            %{['keyrest', '\#{arg_name}']}\n          else\n            %{['keyrest']}\n          end\n        end\n\n        def on_blockarg(arg_name)\n          arg_name = :& if arg_name == :fwd_block_arg\n          %{['block', '\#{arg_name}']}\n        end\n\n        def on_kwnilarg\n          %{['nokey']}\n        end\n\n        def on_shadowarg(_arg_name); end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:Parameters>", "initialize", "args", "@args", "children", "to_code", "stringified_parameters", "map", "block in to_code", "arg", "block (2 levels) in to_code", "public_send", "self", "type", "compact", "join", "on_arg", "arg_name", "on_mlhs", "on_optarg", "_default_value", "on_restarg", "on_kwarg", "on_kwoptarg", "on_kwrestarg", "on_blockarg", "on_kwnilarg", "on_shadowarg"], :mappings=>"AAAAA,6CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QACEA,OAAAC;QAAAA;;UAAAA;;AAAAA;;;AACEC,UAAAA,0BAAAA,sBAAeC,IAAfD;AAAAA,YAAAA;;YACEA,OAAAE,CAAAA,YAAQD,IAAIE,UAAAA,CAAAA,CAAZD;UADFF,CAAAA;;AAIAI,UAAAA,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACEC,yBAA8BC,MAALJ,SAAKI,OAAAA,EAAAA,EAAAA,EAALC,aAAcC,GAAdD,EAAAE;;;cAAc;cACrCA,OAAAC,MAAAC,IAAAD,eAAAA,EAAA,CAAcD,KAAF,GAAA,CAAOD,GAAGI,MAAAA,CAAAA,CAAV,CAAZ,CAAA,QAA+B,MAACJ,GAAD,CAA/B,CAAAE,EADuBH,CAAAA,GAAAA,SAAAA,CAAKD;YAI9BF,OAACA,GAAD,GAAA,CAAIC,sBAAsBQ,SAAAA,CAAAA,CAAQC,MAAAA,CAAMV,IAANU,CAAlC,CAAA,GAA8CV;UALhDA,CAAAA;;AAQAW,UAAAA,sBAAAA,kBAAWC,QAAXD;AAAAA;YACEA,OAAEA,WAAF,GAAA,CAAaC,QAAb,CAAA,GAAsBD;UADxBA,CAAAA;;AAIAE,UAAAA,uBAAAA,mBAtBR,EAsBQA;AAAAA,YAAAA;;;YAtBR;YAsBoB;YACVA,OAAAA;UADFA,CAAAA,IAAAA;;AAIAC,UAAAA,yBAAAA,qBAAcF,QAAD,EAAWG,cAAxBD;AAAAA;YACEA,OAAEA,WAAF,GAAA,CAAaF,QAAb,CAAA,GAAsBE;UADxBA,CAAAA;;AAIAE,UAAAA,0BAAAA,sBAAeJ,QAAfI;AAAAA;;YAAe,iCAAW;YACxB,IAAA,QAAGJ,QAAH,CAAA;;cACE,IAAA,MAAiBA,QAAjB,EAA6B,cAA7B,CAAA;gBAAAA,WAAW;cAAX;cACAI,OAAEA,YAAF,GAAA,CAAcJ,QAAd,CAAA,GAAuBI;YAFzB;cAIEA,OAAAA;YAJF;UADFA,CAAAA,IAAAA;;AASAC,UAAAA,wBAAAA,oBAAaL,QAAbK;AAAAA;YACEA,OAAEA,cAAF,GAAA,CAAgBL,QAAhB,CAAA,GAAyBK;UAD3BA,CAAAA;;AAIAC,UAAAA,2BAAAA,uBAAgBN,QAAD,EAAWG,cAA1BG;AAAAA;YACEA,OAAEA,WAAF,GAAA,CAAaN,QAAb,CAAA,GAAsBM;UADxBA,CAAAA;;AAIAC,UAAAA,4BAAAA,wBAAiBP,QAAjBO;AAAAA;;YAAiB,iCAAW;YAC1B,IAAA,QAAGP,QAAH,CAAA;cACEO,OAAEA,eAAF,GAAA,CAAiBP,QAAjB,CAAA,GAA0BO;YAD5B;cAGEA,OAAAA;YAHF;UADFA,CAAAA,IAAAA;;AAQAC,UAAAA,2BAAAA,uBAAgBR,QAAhBQ;AAAAA;;YACE,IAAA,MAAiBR,QAAjB,EAA6B,eAA7B,CAAA;cAAAA,WAAW;YAAX;YACAQ,OAAEA,aAAF,GAAA,CAAeR,QAAf,CAAA,GAAwBQ;UAF1BA,CAAAA;;AAKAC,UAAAA,2BAAAA,YACE1B,WADF0B,CAAAA;UAIA1B,OAAA2B,4BAAAA,YAhER,GAgEQA,CAAAA;QA3DF3B,GAAAA,WAAAA,EAAAA,IAAAA;MADFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>33284, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args/prepare_post_args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    module Args\n      # A utility node responsible for preparing\n      # post-argument for :extract_post_* nodes\n      class PreparePostArgs < Base\n        handle :prepare_post_args\n        children :offset\n\n        def compile\n          add_temp '$post_args'\n\n          helper :slice\n\n          if offset == 0\n            push \"$post_args = $slice(arguments)\"\n          else\n            push \"$post_args = $slice(arguments, \#{offset})\"\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<module:Args>", "<class:PreparePostArgs>", "handle", "children", "compile", "add_temp", "helper", "offset", "0", "push", "Base"], :mappings=>"AAAAA,oDAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;QAGEA,OAAAC;QAAAA;;;;UACEL,IAAAM,QAAAA,CAAO,mBAAPA;UACAN,IAAAO,UAAAA,CAAS,QAATA;UAEAF,OAAAG,uBAAAA,mBAAAA;AAAAA,YAAAA;;;YACER,IAAAS,UAAAA,CAASD,YAATC;YAEAT,IAAAU,QAAAA,CAAO,OAAPA;YAEA,IAAA,MAAGV,IAAAW,QAAAA,CAAAA,CAAH,EAAaC,CAAb,CAAA;cACEJ,OAAAR,IAAAa,MAAAA,CAAKL,gCAALK;YADF;cAGEL,OAAAR,IAAAa,MAAAA,CAAML,iCAAD,GAAA,CAAkCR,IAAAW,QAAAA,CAAAA,CAAlC,CAAA,GAAyCH,GAA9CK;YAHF;UALFL,CAAAA;QAJFH,GAAAA,WAAAA,EAAwBS,UAAxBT;MAHFD,GAAAA,WAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33329, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nrequire 'opal/nodes/args/arg'\nrequire 'opal/nodes/args/arity_check'\nrequire 'opal/nodes/args/ensure_kwargs_are_kwargs'\nrequire 'opal/nodes/args/extract_block_arg'\nrequire 'opal/nodes/args/extract_kwarg'\nrequire 'opal/nodes/args/extract_kwargs'\nrequire 'opal/nodes/args/extract_kwoptarg'\nrequire 'opal/nodes/args/extract_kwrestarg'\nrequire 'opal/nodes/args/extract_optarg'\nrequire 'opal/nodes/args/extract_post_arg'\nrequire 'opal/nodes/args/extract_post_optarg'\nrequire 'opal/nodes/args/extract_restarg'\nrequire 'opal/nodes/args/fake_arg'\nrequire 'opal/nodes/args/initialize_iterarg'\nrequire 'opal/nodes/args/initialize_shadowarg'\nrequire 'opal/nodes/args/parameters'\nrequire 'opal/nodes/args/prepare_post_args'\n\nmodule Opal\n  module Nodes\n    class ArgsNode < Base\n      handle :args\n\n      # ruby allows for args with the same name, if the arg starts with a '_', like:\n      #   def funny_method_name(_, _)\n      #     puts _\n      #   end\n      # but javascript in strict mode does not allow for args with the same name\n      # ruby assigns the value of the first arg given\n      #   funny_method_name(1, 2) => 1\n      # 1. check for args starting with '_' and check if they appear multiple times\n      # 2. leave the first appearance as it is and rename the other ones\n      # compiler result:\n      #   function $$funny_method_name(_, __$2)\n\n      def compile\n        same_arg_counter = {}\n        children.each_with_index do |arg, idx|\n          if multiple_underscore?(arg)\n            same_arg_counter[arg] ||= 0\n            same_arg_counter[arg]  += 1\n            if same_arg_counter[arg] > 1\n              arg = s(arg.type, :\"\#{arg.children[0]}_$\#{same_arg_counter[arg]}\")\n            end\n          end\n\n          push ', ' if idx != 0\n          push process(arg)\n        end\n      end\n\n      def multiple_underscore?(arg)\n        arg.type == :arg &&\n          arg.children.count == 1 &&\n          arg.children.first.to_s.start_with?('_') &&\n          children.count(arg) > 1\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:ArgsNode>", "handle", "compile", "same_arg_counter", "each_with_index", "children", "block in compile", "arg", "idx", "block (2 levels) in compile", "multiple_underscore?", "$ret_or_1", "[]", "[]=", "0", "+", "1", ">", "s", "type", "push", "process", "$ret_or_2", "$ret_or_3", "==", "count", "first", "to_s", "start_with?", "Base"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAD,IAAAC,SAAAA,CAAQF,qBAARE;EACAD,IAAAC,SAAAA,CAAQF,6BAARE;EACAD,IAAAC,SAAAA,CAAQF,0CAARE;EACAD,IAAAC,SAAAA,CAAQF,mCAARE;EACAD,IAAAC,SAAAA,CAAQF,+BAARE;EACAD,IAAAC,SAAAA,CAAQF,gCAARE;EACAD,IAAAC,SAAAA,CAAQF,kCAARE;EACAD,IAAAC,SAAAA,CAAQF,mCAARE;EACAD,IAAAC,SAAAA,CAAQF,gCAARE;EACAD,IAAAC,SAAAA,CAAQF,kCAARE;EACAD,IAAAC,SAAAA,CAAQF,qCAARE;EACAD,IAAAC,SAAAA,CAAQF,iCAARE;EACAD,IAAAC,SAAAA,CAAQF,0BAARE;EACAD,IAAAC,SAAAA,CAAQF,oCAARE;EACAD,IAAAC,SAAAA,CAAQF,sCAARE;EACAD,IAAAC,SAAAA,CAAQF,4BAARE;EACAD,IAAAC,SAAAA,CAAQF,mCAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;;QACEJ,IAAAK,QAAAA,CAAO,MAAPA;;AAcAC,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACEC,mBAAmB,YAAA;UACnBD,OAAQE,MAARR,IAAAS,UAAAA,CAAAA,CAAQD,mBAAAA,EAAAA,EAAAA,EAARE,aAA6BC,GAAD,EAAMC,GAAlCF,EAAAG;;;YAA6B;YAAK;YAChC,IAAA,QAAGb,IAAAc,yBAAAA,CAAqBH,GAArBG,CAAH,CAAA;;cA1CV,IAAA,QAAAC,CAAAA,YA2CYR,gBAAgBS,OAAAA,CAACL,GAADK,CA3C5BD,CAAA,CAAA;gBAAA;cAAA;gBA2CYR,gBAAgBU,QAAAA,CAACN,GAAjB,EAA0BO,CAAVD;cA3C5B;cA4CYV,gBAAgBU,QAAAA,CAACN,GAAjB,EAAgBQ,SAAhBZ,gBAAgBS,OAAAA,CAACL,GAADK,CAAAG,EAAUC,CAAVD,CAAAF;cAChB,IAAA,QAAyBI,OAAtBd,gBAAgBS,OAAAA,CAACL,GAADK,CAAMK,EAAED,CAAFC,CAAzB,CAAA;gBACEV,MAAMX,IAAAsB,GAAAA,CAAEX,GAAGY,MAAAA,CAAAA,CAAL,EAAY,EAAA,GAAA,CAAIZ,GAAGF,UAAAA,CAAAA,CAASO,OAAAA,CAACE,CAADF,CAAhB,CAAA,GAAoBH,IAApB,GAAA,CAAwBN,gBAAgBS,OAAAA,CAACL,GAADK,CAAxC,CAAZM;cADR;YAHF;YAQA,IAAA,OAAaV,GAAb,EAAoBM,CAApB,CAAA;cAAAlB,IAAAwB,MAAAA,CAAKX,IAALW;YAAA;YACAX,OAAAb,IAAAwB,MAAAA,CAAKxB,IAAAyB,SAAAA,CAAQd,GAARc,CAALD,EAVFd,CAAAA,GAAAA,SAAAA,CAAQF;QAFVF,CAAAA;QAgBAF,OAAAU,oCAAAA,8CAAyBH,GAAzBG;AAAAA,UAAAA;;UACE,IAAA,QAAAC,CAAAA,YAAA,CAAA,QAAAW,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAhB,GAAGY,MAAAA,CAAAA,CAAMK,OAAAA,CAAG,KAAHA,CAATD,CAAA,CAAA,GAAA,CACEhB,GAAGF,UAAAA,CAAAA,CAASoB,OAAAA,CAAAA,CAAOD,OAAAA,CAAGR,CAAHQ,CADrB,IAAA,CAAA,SAAA,CAAA,CAAAF,CAAA,CAAA,GAAA,CAEEf,GAAGF,UAAAA,CAAAA,CAASqB,OAAAA,CAAAA,CAAMC,MAAAA,CAAAA,CAAKC,gBAAAA,CAAalB,GAAbkB,CAFzB,IAAA,CAAA,SAAA,CAAA,CAAAjB,CAAA,CAAA;YAGED,OAAoBO,OAApBrB,IAAAS,UAAAA,CAAAA,CAAQoB,OAAAA,CAAOlB,GAAPkB,CAAYR,EAAED,CAAFC;UAHtB;YAAAP,OAAA;UAAA;QADFA,CAAAA;MA/BFV,GAAAA,WAAAA,EAAiB6B,UAAjB7B;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAtBAH;"}}, {:offset=>{:line=>33409, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/node_with_args/shortcuts.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  module Nodes\n    class NodeWithArgs < ScopeNode\n      # Shortcuts for the simplest kinds of methods\n      Shortcut = Struct.new(:name, :for, :when, :transform) do\n        def match?(node)\n          node.instance_exec(&self.when)\n        end\n\n        def compile(node)\n          node.helper name\n          node.instance_exec(&transform)\n        end\n      end\n\n      @shortcuts = []\n      @shortcuts_for = {}\n      def self.define_shortcut(name, **kwargs, &block)\n        kwargs[:for] ||= :def\n        @shortcuts << Shortcut.new(name, kwargs[:for], kwargs[:when], block)\n      end\n\n      def self.shortcuts_for(node_type)\n        @shortcuts_for[node_type] ||=\n          @shortcuts.select do |shortcut|\n            [node_type, :*].include? shortcut.for\n          end\n      end\n\n      def compile_body_or_shortcut\n        # The shortcuts don't check arity. If we want to check arity,\n        # we can't use them.\n        return compile_body if compiler.arity_check?\n\n        node_type = is_a?(DefNode) ? :def : :iter\n\n        NodeWithArgs.shortcuts_for(node_type).each do |shortcut|\n          if shortcut.match?(self)\n            if ENV['OPAL_DEBUG_SHORTCUTS']\n              node_desc = node_type == :def ? \"def \#{mid}\" : \"iter\"\n              warn \"* shortcut \#{shortcut.name} used for \#{node_desc}\"\n            end\n\n            return shortcut.compile(self)\n          end\n        end\n\n        compile_body\n      end\n\n      # Shortcut definitions\n      # --------------------\n\n      # def a; self; end\n      define_shortcut :return_self, when: -> { stmts.type == :self } do\n        push '$return_self'\n      end\n\n      def simple_value?(node = stmts)\n        %i[true false nil int float str sym].include?(node.type)\n      end\n\n      # def a; 123; end\n      define_shortcut :return_val, for: :*, when: -> { simple_value? } do\n        push '$return_val(', expr(stmts), ')'\n      end\n\n      # def a; @x; end\n      define_shortcut :return_ivar, when: -> { stmts.type == :ivar } do\n        name = stmts.children.first.to_s[1..-1].to_sym\n        push '$return_ivar(', expr(stmts.updated(:sym, [name])), ')'\n      end\n\n      # def a; @x = 5; end\n      define_shortcut :assign_ivar, when: -> {\n        stmts.type == :ivasgn &&\n          inline_args.children.length == 1 &&\n          inline_args.children.last.type == :arg &&\n          stmts.children.last.type == :lvar &&\n          stmts.children.last.children.last == inline_args.children.last.children.last\n      } do\n        name = stmts.children.first.to_s[1..-1].to_sym\n        name = expr(stmts.updated(:sym, [name]))\n        push '$assign_ivar(', name, ')'\n      end\n\n      # def a(x); @x = x; end\n      define_shortcut :assign_ivar_val, when: -> {\n        stmts.type == :ivasgn &&\n          simple_value?(stmts.children.last)\n      } do\n        name = stmts.children.first.to_s[1..-1].to_sym\n        name = expr(stmts.updated(:sym, [name]))\n        push '$assign_ivar_val(', name, ', ', expr(stmts.children.last), ')'\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<module:Nodes>", "<class:NodeWithArgs>", "new", "Struct", "block in <class:NodeWithArgs>", "block (2 levels) in <class:NodeWithArgs>", "match?", "node", "instance_exec", "self", "when", "to_proc", "compile", "helper", "name", "transform", "@shortcuts", "@shortcuts_for", "define_shortcut", "$kwargs", "$ret_or_1", "kwargs", "[]", "[]=", "<<", "Shortcut", "block", "shortcuts_for", "node_type", "select", "block in shortcuts_for", "shortcut", "block (2 levels) in shortcuts_for", "include?", "for", "compile_body_or_shortcut", "compiler", "arity_check?", "compile_body", "is_a?", "DefNode", "each", "NodeWithArgs", "block in compile_body_or_shortcut", "block (2 levels) in compile_body_or_shortcut", "ENV", "node_desc", "mid", "warn", "stmts", "type", "==", "push", "simple_value?", "expr", "children", "first", "to_s", "1", "-1", "to_sym", "updated", "$ret_or_2", "$ret_or_3", "$ret_or_4", "inline_args", "length", "last", "ScopeNode"], :mappings=>"AAAAA,sDAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QAEE,oCAAiBC,MAANC,YAAMD,OAAAA,EAAAA,CAAK,MAAX,EAAkB,KAAlB,EAAwB,MAAxB,EAA+B,WAAzBA,CAAAA,EAANE,yBAAAA,EAAAC;;;;AACTC,UAAAA,sBAAAA,uBAAWC,IAAXD;AAAAA,YAAAA;;YACEA,OAAIE,MAAJD,IAAIC,iBAAAA,EAAAA,EAAAA,EAAgBC,IAAIC,MAAAA,CAAAA,CAALC,SAAAA,CAAAA,CAAfH;UADNF,CAAAA;UAIAD,OAAAO,uBAAAA,mBAAYL,IAAZK;AAAAA,YAAAA;;;YACEL,IAAIM,QAAAA,CAAQJ,IAAAK,MAAAA,CAAAA,CAARD;YACJD,OAAIJ,MAAJD,IAAIC,iBAAAA,EAAAA,EAAAA,EAAgBC,IAAAM,WAAAA,CAAAA,CAADJ,SAAAA,CAAAA,CAAfH;UAFNI,CAAAA,EALSR,CAAAA,GAAAA,SAAAA,CAAMF,CAAjB;QAWAc,iBAAa;QACbC,qBAAiB,YAAA;QACjBC,MAAIT,IAAJS,sBAAAA,2BAAyBJ,IAAD,EAnB9BK,OAmBMD;AAAAA,UAAAA;AAAAA;;UAAAA;;;UAnBN;UAmBqC;UAnBrC,IAAA,QAAAE,CAAAA,YAoBQC,MAAMC,OAAAA,CAAC,KAADA,CApBdF,CAAA,CAAA;YAAA;UAAA;YAoBQC,MAAME,QAAAA,CAAC,KAAP,EAAiB,KAAXA;UApBd;UAqBQL,OAAAF,cAAWQ,OAAAA,CAAGC,cAAQvB,KAAAA,CAAKY,IAAb,EAAmBO,MAAMC,OAAAA,CAAC,KAADA,CAAzB,EAAiCD,MAAMC,OAAAA,CAAC,MAADA,CAAvC,EAAgDI,KAAxCxB,CAAXsB;QAFbN,CAAAA,IAAAA;QAKAS,MAAIlB,IAAJkB,oBAAAA,yBAAuBC,SAAvBD;AAAAA,UAAAA;AAAAA;AAAAA;;UAxBN,IAAA,QAAAP,CAAAA,YAyBQH,kBAAcK,OAAAA,CAACM,SAADN,CAzBtBF,CAAA,CAAA;YAAAO,OAAA;UAAA;YAyBQA,OAAcJ,MAAAA,CAACK,SAAf,EACYC,MAAVb,cAAUa,UAAAA,EAAAA,EAAAA,EAAVC,aAAsBC,QAAtBD;;cAAsB;cACpBE,OAAA,CAACJ,SAAD,EAAY,GAAZ,CAAeK,aAAAA,CAAUF,QAAQG,KAAAA,CAAAA,CAAlBD,EADjBH,CAAUD,CADEN,CAAAA,EAAAA,MAAdN,kBAAcM,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA;UAzBtB;QAwBMI,CAAAA;;AAOAQ,QAAAA,wCAAAA,oCAAAA,GAAAA,MAAAA,IAAAA,8BAAAA;AAAAA,UAAAA;;;UAGE,IAAA,QAAuB1B,IAAA2B,UAAAA,CAAAA,CAAQC,iBAAAA,CAAAA,CAA/B,CAAA;YAAA,OAAO5B,IAAA6B,cAAAA,CAAAA;UAAP;UAEAV,YAAY,CAAA,QAAAnB,IAAA8B,UAAAA,CAAMC,aAAND,CAAA,CAAA,GAAA,CAAiB,KAAjB,IAAA,CAAwB,MAAxB,CAAA;UAEyBE,MAArCC,kBAAYf,eAAAA,CAAeC,SAAfD,CAAyBc,QAAAA,EAAAA,EAAAA,EAArCE,aAA+CZ,QAA/CY,EAAAC;;;YAA+C;YAC7C,IAAA,QAAGb,QAAQzB,WAAAA,CAAQG,IAARH,CAAX,CAAA;;cACE,IAAA,QAAGuC,SAAGvB,OAAAA,CAACsB,sBAADtB,CAAN,CAAA;;gBACEwB,YAAY,CAAA,MAAAlB,SAAA,EAAa,KAAb,CAAA,GAAA,CAAqBgB,MAAD,GAAA,CAAOnC,IAAAsC,KAAAA,CAAAA,CAAP,CAApB,IAAA,CAAmCH,MAAnC,CAAA;gBACZnC,IAAAuC,MAAAA,CAAMJ,aAAD,GAAA,CAAcb,QAAQjB,MAAAA,CAAAA,CAAtB,CAAA,GAA4B8B,YAA5B,GAAA,CAAwCE,SAAxC,CAALE;cAFF;cAKA,SAAA,QAAOjB,QAAQnB,SAAAA,CAASH,IAATG,CAAf;YANF;cAvCVgC,OAAA;YAuCU,EADFD,CAAAA,GAAAA,2BAAAA,CAAqCF;UAWrCN,OAAA1B,IAAA6B,cAAAA,CAAAA,EAlBFH;YAAAA;YAAAA;UAAAA;QAAAA,CAAAA;QAyBAjB,MAAAT,IAAAS,mBAAAA,EAAAA,CAAgB,aAAhB,EAA8B,kBAAA,QAAM,QAAAd,yBAAAA,EAAAC;;UAAKA,OAAAI,IAAAwC,OAAAA,CAAAA,CAAKC,MAAAA,CAAAA,CAAMC,OAAAA,CAAG,MAAHA,CAAhB/C,CAAAA,GAAAA,SAAAA,CAAA,CAAN,EAA9Bc,CAAAA,EAAAd,yBAAAA,EAAAC;;UACEA,OAAAI,IAAA2C,MAAAA,CAAK/C,cAAL+C,CADFhD,CAAAA,GAAAA,SAAAA,CAAAc;;AAIAmC,QAAAA,6BAAAA,2CAAkB9C,IAAlB8C;AAAAA,UAAAA;;;UAAkB,yBAAO5C,IAAAwC,OAAAA,CAAAA;UACvBI,OAAA,CAAG,MAAH,EAAQ,OAAR,EAAc,KAAd,EAAkB,KAAlB,EAAsB,OAAtB,EAA4B,KAA5B,EAAgC,KAAhC,CAAoCpB,aAAAA,CAAU1B,IAAI2C,MAAAA,CAAAA,CAAdjB;QADtCoB,CAAAA,IAAAA;QAKAnC,MAAAT,IAAAS,mBAAAA,EAAAA,CAAgB,YAAhB,EAA6B,yBAAA,OAAK,GAAL,EAAA,QAAe,QAAAd,yBAAAA,EAAAC;;UAAKA,OAAAI,IAAA4C,kBAAAA,CAAAA,CAALjD,CAAAA,GAAAA,SAAAA,CAAA,CAAf,EAA7Bc,CAAAA,EAAAd,yBAAAA,EAAAC;;UACEA,OAAAI,IAAA2C,MAAAA,CAAK/C,cAAL,EAAqBI,IAAA6C,MAAAA,CAAK7C,IAAAwC,OAAAA,CAAAA,CAALK,CAArB,EAAkCjD,GAAlC+C,CADFhD,CAAAA,GAAAA,SAAAA,CAAAc;QAKAA,MAAAT,IAAAS,mBAAAA,EAAAA,CAAgB,aAAhB,EAA8B,kBAAA,QAAM,QAAAd,0BAAAA,EAAAC;;UAAKA,OAAAI,IAAAwC,OAAAA,CAAAA,CAAKC,MAAAA,CAAAA,CAAMC,OAAAA,CAAG,MAAHA,CAAhB/C,CAAAA,GAAAA,SAAAA,CAAA,CAAN,EAA9Bc,CAAAA,E