AAA,CAA5Bd;UADF;YAAAhD,OAAA;UAAA,CADsCD,CAAAA,GAAAA,SAAAA,CAAA,CAAN,EAAlCc,CAAAA,EAAAd,0BAAAA,EAAAC;;;UAIES,OAAOL,IAAAwC,OAAAA,CAAAA,CAAKM,UAAAA,CAAAA,CAASC,OAAAA,CAAAA,CAAMC,MAAAA,CAAAA,CAAKnC,OAAAA,CAAC,OAAAoC,CAAA,EAAGC,EAAH,QAADrC,CAAOsC,QAAAA,CAAAA;UACvC9C,OAAOL,IAAA6C,MAAAA,CAAK7C,IAAAwC,OAAAA,CAAAA,CAAKY,SAAAA,CAAS,KAAd,EAAoB,CAAC/C,IAAD,CAAf+C,CAAVP;UACPjD,OAAAI,IAAA2C,MAAAA,CAAK/C,mBAAL,EAA0BS,IAA1B,EAAgCT,IAAhC,EAAsCI,IAAA6C,MAAAA,CAAK7C,IAAAwC,OAAAA,CAAAA,CAAKM,UAAAA,CAAAA,CAASY,MAAAA,CAAAA,CAAnBb,CAAtC,EAAiEjD,GAAjE+C,EANFhD,CAAAA,GAAAA,SAAAA,CAAAc;MArFFjB,GAAAA,WAAAA,EAAqBmE,eAArBnE;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>33559, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/node_with_args.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/scope'\nrequire 'opal/nodes/args/parameters'\nrequire 'opal/nodes/node_with_args/shortcuts'\n\nmodule Opal\n  module Nodes\n    class NodeWithArgs < ScopeNode\n      attr_reader :used_kwargs\n      attr_accessor :arity\n      attr_reader :original_args\n\n      def initialize(*)\n        super\n\n        @original_args = @sexp.meta[:original_args]\n        @used_kwargs = []\n        @arity = 0\n      end\n\n      def arity_check_node\n        s(:arity_check, original_args)\n      end\n\n      # Returns code used in debug mode to check arity of method call\n      def compile_arity_check\n        push process(arity_check_node)\n      end\n\n      def compile_block_arg\n        if scope.uses_block?\n          scope.prepare_block\n        end\n      end\n\n      def parameters_code\n        Args::Parameters.new(original_args).to_code\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:NodeWithArgs>", "attr_reader", "attr_accessor", "initialize", "$fwd_rest", "@original_args", "@sexp", "meta", "[]", "@used_kwargs", "@arity", "0", "arity_check_node", "s", "original_args", "compile_arity_check", "push", "process", "compile_block_arg", "scope", "uses_block?", "prepare_block", "parameters_code", "Args::Parameters", "Args", "new", "to_code", "ScopeNode"], :mappings=>"AAAAA,4CAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,kBAARE;EACAD,IAAAC,SAAAA,CAAQF,4BAARE;EACAD,IAAAC,SAAAA,CAAQF,qCAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QACEJ,IAAAK,aAAAA,CAAY,aAAZA;QACAL,IAAAM,eAAAA,CAAc,OAAdA;QACAN,IAAAK,aAAAA,CAAY,eAAZA;;AAEAE,QAAAA,0BAAAA,sBAbN,EAaMA;AAAAA,UAAAA;;UAAAA;;UAbN;UAaqB;UACb,OAAAP,IAAA,EAAA,0DAAA,cAAA,EAAA,MAAAQ,SAAA,CAAA,EAAA,MAAA;UAEAC,qBAAiBC,SAAKC,MAAAA,CAAAA,CAAKC,OAAAA,CAAC,eAADA;UAC3BC,mBAAe;UACfN,OAAAO,CAAAA,aAASC,CAATD;QALFP,CAAAA,IAAAA;;AAQAS,QAAAA,gCAAAA,4BAAAA;AAAAA,UAAAA;;UACEA,OAAAhB,IAAAiB,GAAAA,CAAE,aAAF,EAAgBjB,IAAAkB,eAAAA,CAAAA,CAAhBD;QADFD,CAAAA;;AAKAG,QAAAA,mCAAAA,+BAAAA;AAAAA,UAAAA;;UACEA,OAAAnB,IAAAoB,MAAAA,CAAKpB,IAAAqB,SAAAA,CAAQrB,IAAAgB,kBAAAA,CAAAA,CAARK,CAALD;QADFD,CAAAA;;AAIAG,QAAAA,iCAAAA,6BAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAGtB,IAAAuB,OAAAA,CAAAA,CAAKC,gBAAAA,CAAAA,CAAR,CAAA;YACEF,OAAAtB,IAAAuB,OAAAA,CAAAA,CAAKE,eAAAA,CAAAA;UADP;YA/BRH,OAAA;UA+BQ;QADFA,CAAAA;QAMAlB,OAAAsB,+BAAAA,2BAAAA;AAAAA,UAAAA;;UACEA,OAAAC,IAAAC,UAAAD,eAAgBE,KAAAA,CAAK7B,IAAAkB,eAAAA,CAAAA,CAALW,CAAmBC,SAAAA,CAAAA;QADrCJ,CAAAA;MA5BFtB,GAAAA,WAAAA,EAAqB2B,eAArB3B;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AANAH;"}}, {:offset=>{:line=>33631, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/iter.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/node_with_args'\n\nmodule Opal\n  module Nodes\n    class IterNode < NodeWithArgs\n      handle :iter\n\n      children :inline_args, :stmts\n\n      def compile\n        is_lambda! if scope.lambda_definition?\n\n        compile_body_or_shortcut\n\n        blockopts = {}\n        blockopts[\"$$arity\"] = arity if arity < 0\n        blockopts[\"$$s\"] = scope.self if @define_self\n        blockopts[\"$$brk\"] = @closure.throwers[:break] if @closure&.throwers&.key? :break\n        blockopts[\"$$ret\"] = @closure.throwers[:return] if @closure&.throwers&.key? :return\n\n        if compiler.arity_check?\n          blockopts[\"$$parameters\"] = parameters_code\n        end\n\n        if compiler.enable_source_location?\n          blockopts[\"$$source_location\"] = source_location\n        end\n\n        # MRI expands a passed argument if the block:\n        # 1. takes a single argument that is an array\n        # 2. has more that one argument\n        # With a few exceptions:\n        # 1. mlhs arg: if a block takes |(a, b)| argument\n        # 2. trailing ',' in the arg list (|a, |)\n        # This flag on the method indicates that a block has a top level mlhs argument\n        # which means that we have to expand passed array explicitly in runtime.\n        if has_top_level_mlhs_arg?\n          blockopts[\"$$has_top_level_mlhs_arg\"] = \"true\"\n        end\n\n        if has_trailing_comma_in_args?\n          blockopts[\"$$has_trailing_comma_in_args\"] = \"true\"\n        end\n\n        if blockopts.keys == [\"$$arity\"]\n          push \", \#{arity}\"\n        elsif !blockopts.empty?\n          push ', {', blockopts.map { |k, v| \"\#{k}: \#{v}\" }.join(', '), '}'\n        end\n\n        scope.nesting if @define_nesting\n        scope.relative_access if @define_relative_access\n      end\n\n      def compile_body\n        inline_params = nil\n\n        to_vars = identity = body_code = nil\n\n        in_scope do\n          identity = scope.identify!\n\n          inline_params = process(inline_args)\n\n          compile_arity_check\n\n          in_closure(Closure::JS_FUNCTION | Closure::ITER | (@is_lambda ? Closure::LAMBDA : 0)) do\n            body_code = stmt(returned_body)\n\n            add_temp \"self = \#{identity}.$$s == null ? this : \#{identity}.$$s\" if @define_self\n\n            to_vars = scope.to_vars\n\n            line body_code\n          end\n        end\n\n        unshift to_vars\n\n        if await_encountered\n          unshift \"async function \#{identity}(\", inline_params, '){'\n        else\n          unshift \"function \#{identity}(\", inline_params, '){'\n        end\n        push '}'\n      end\n\n      def compile_block_arg\n        if block_arg\n          scope.prepare_block\n        end\n      end\n\n      def extract_underscore_args\n        valid_args = []\n        caught_blank_argument = false\n\n        args.children.each do |arg|\n          arg_name = arg.children.first\n          if arg_name == :_\n            unless caught_blank_argument\n              caught_blank_argument = true\n              valid_args << arg\n            end\n          else\n            valid_args << arg\n          end\n        end\n\n        @sexp = @sexp.updated(\n          nil, [\n            args.updated(nil, valid_args),\n            stmts\n          ]\n        )\n      end\n\n      def returned_body\n        compiler.returns(stmts || s(:nil))\n      end\n\n      def has_top_level_mlhs_arg?\n        original_args.children.any? { |arg| arg.type == :mlhs }\n      end\n\n      def has_trailing_comma_in_args?\n        if original_args.loc && original_args.loc.expression\n          args_source = original_args.loc.expression.source\n          args_source.match(/,\\s*\\|/)\n        end\n      end\n\n      def arity_check_node\n        s(:iter_arity_check, original_args)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:IterNode>", "handle", "children", "compile", "scope", "lambda_definition?", "is_lambda!", "compile_body_or_shortcut", "blockopts", "<", "arity", "0", "[]=", "@define_self", "@closure", "throwers", "[]", "compiler", "arity_check?", "parameters_code", "enable_source_location?", "source_location", "has_top_level_mlhs_arg?", "has_trailing_comma_in_args?", "keys", "push", "empty?", "map", "block in compile", "k", "v", "block (2 levels) in compile"