FA,CAAAA;QAOAvB,OAAA8F,gCAAAA,4BAAAA;AAAAA,UAAAA;;UACEA,OAAAlG,IAAAsF,GAAAA,CAAE,kBAAF,EAAqBtF,IAAAwF,eAAAA,CAAAA,CAArBF;QADFY,CAAAA;MAhIF9F,GAAAA,WAAAA,EAAiB+F,kBAAjB/F;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>33811, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/def.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/node_with_args'\n\nmodule Opal\n  module Nodes\n    class DefNode < NodeWithArgs\n      handle :def\n\n      children :mid, :inline_args, :stmts\n\n      def compile\n        compile_body_or_shortcut\n\n        blockopts = {}\n\n        blockopts[\"$$arity\"] = arity if arity < 0\n\n        if compiler.arity_check?\n          blockopts[\"$$parameters\"] = parameters_code\n        end\n\n        if compiler.parse_comments?\n          blockopts[\"$$comments\"] = comments_code\n        end\n\n        if compiler.enable_source_location?\n          blockopts[\"$$source_location\"] = source_location\n        end\n\n        if blockopts.keys == [\"$$arity\"]\n          push \", \#{arity}\"\n        elsif !blockopts.empty?\n          push ', {', blockopts.map { |k, v| \"\#{k}: \#{v}\" }.join(', '), '}'\n        end\n\n        wrap_with_definition\n\n        scope.nesting if @define_nesting\n        scope.relative_access if @define_relative_access\n      end\n\n      def compile_body\n        inline_params = nil\n        scope_name = nil\n\n        in_scope do\n          scope.mid = mid\n          scope.defs = true if @sexp.type == :defs\n\n          scope.identify!\n          scope_name = scope.identity\n\n          # Setting a default block name (later can be overwritten by a blockarg)\n          scope.block_name = '$yield'\n\n          inline_params = process(inline_args)\n\n          in_closure(Closure::DEF | Closure::JS_FUNCTION) do\n            stmt_code = stmt(compiler.returns(stmts))\n\n            compile_block_arg\n\n            add_temp 'self = this' if @define_self\n\n            compile_arity_check\n\n            unshift \"\\n\#{current_indent}\", scope.to_vars\n\n            line stmt_code\n          end\n        end\n\n        unshift ') {'\n        unshift(inline_params)\n        unshift \"function \#{scope_name}(\"\n        if await_encountered\n          unshift \"async \"\n        end\n        line '}'\n      end\n\n      def wrap_with_definition\n        helper :def\n        wrap \"$def(\#{scope.self}, '$\#{mid}', \", ')'\n\n        unshift \"\\n\#{current_indent}\" unless expr?\n      end\n\n      def comments_code\n        '[' + comments.map { |comment| comment.text.inspect }.join(', ') + ']'\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:DefNode>", "handle", "children", "compile", "compile_body_or_shortcut", "blockopts", "<", "arity", "0", "[]=", "compiler", "arity_check?", "parameters_code", "parse_comments?", "comments_code", "enable_source_location?", "source_location", "keys", "push", "empty?", "map", "block in compile", "k", "v", "block (2 levels) in compile", "join", "wrap_with_definition", "@define_nesting", "scope", "nesting", "@define_relative_access", "relative_access", "compile_body", "inline_params", "scope_name", "in_scope", "block in compile_body", "block (2 levels) in compile_body", "mid=", "mid", "@sexp", "type", "defs=", "identify!", "identity", "block_name=", "process", "inline_args", "in_closure", "Closure::DEF", "Closure", "|", "Closure::JS_FUNCTION", "block (3 levels) in compile_body", "stmt_code", "stmt", "returns", "stmts", "compile_block_arg", "@define_self", "add_temp", "compile_arity_check", "unshift", "current_indent", "to_vars", "line", "await_encountered", "helper", "wrap", "expr?", "+", "comments", "block in comments_code", "comment", "block (2 levels) in comments_code", "text", "inspect", "NodeWithArgs"], :mappings=>"AAAAA,iCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,2BAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;I