em.is_a?(Node) && self_elem.type == :capture\n              capture = true\n              self_elem = self_elem.children.first\n            end\n\n            res = case self_elem\n                  when Node\n                    self_elem.match(ast_elem, matcher)\n                  when Array\n                    self_elem.include?(ast_elem)\n                  when :*\n                    true\n                  else\n                    self_elem == ast_elem\n                  end\n\n            matcher.captures << ast_elem if capture\n            res\n          end\n        end\n\n        def inspect\n          if type == :capture\n            \"{\#{children.first.inspect}}\"\n          else\n            \"s(\#{type.inspect}, \#{children.inspect[1..-2]})\"\n          end\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:AST>", "<class:Matcher>", "initialize", "@root", "instance_exec", "block", "to_proc", "s", "type", "Node", "new", "children", "cap", "capture", "match", "ast", "@captures", "$ret_or_1", "inspect", "attr_accessor", "Struct", "block in <class:Matcher>", "block (2 levels) in <class:Matcher>", "matcher", "nil?", "ast_parts", "+", "self_parts", "length", "all?", "times", "block in match", "i", "block (2 levels) in match", "ast_elem", "[]", "self_elem", "is_a?", "first", "res", "Array", "include?", "==", "captures", "<<", "1", "-2"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,KAARE;EACAD,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;;AACEC,QAAAA,0BAAAA,sBAAAA;AAAAA,UAAAA;;UAAAA;;;UACEA,OAAAC,CAAAA,YAAQC,MAAAP,IAAAO,iBAAAA,EAAAA,EAAAA,EAAeC,KAADC,SAAAA,CAAAA,CAAdF,CAARD;QADFD,CAAAA;;AAIAK,QAAAA,iBAAAA,aAAMC,IAAD,EAZX,EAYMD;AAAAA,UAAAA;;;UAZN;UAYkB;UACVA,OAAAE,UAAIC,KAAAA,CAAKF,IAAT,EAAeG,QAAXD;QADNH,CAAAA,IAAAA;;AAIAK,QAAAA,mBAAAA,eAAQC,OAARD;AAAAA;UACEA,OAAAH,UAAIC,KAAAA,CAAK,SAAT,EAAmB,CAACG,OAAD,CAAfH;QADNE,CAAAA;;AAIAE,QAAAA,qBAAAA,iBAAUC,GAAVD;AAAAA,UAAAA;;;UACEE,gBAAY;UACZ,IAAA,QAAAC,CAAAA,YAAAd,SAAKW,OAAAA,CAAOC,GAAZ,EAAiBlB,IAAZiB,CAALG,CAAA,CAAA;YAAA;UAAA;;YAA2B,OAAO;UAAlC;UACAH,OAAAE;QAHFF,CAAAA;;AAMAI,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAACA,wBAAD,GAAA,CAAyBf,SAAKe,SAAAA,CAAAA,CAA9B,CAAA,GAAuCA;QADzCA,CAAAA;QAIArB,IAAAsB,eAAAA,CAAc,UAAdA;QAEAlB,OAAA,gCAAaS,MAANU,YAAMV,OAAAA,EAAAA,CAAK,MAAX,EAAkB,UAAZA,CAAAA,EAANW,oBAAAA,EAAAC;;;;AACLR,UAAAA,qBAAAA,iBAAUC,GAAD,EAAMQ,OAAfT;AAAAA,YAAAA;;;YACE,IAAA,QAAgBC,GAAGS,SAAAA,CAAAA,CAAnB,CAAA;cAAA,OAAO;YAAP;YAEAC,YAAuBC,SAAX,CAACX,GAAGP,MAAAA,CAAAA,CAAJ,CAAWkB,EAAEX,GAAGJ,UAAAA,CAAAA,CAALe;YACvBC,aAAoBD,SAAP,CAAC7B,IAAAW,MAAAA,CAAAA,CAAD,CAAOkB,EAAE7B,IAAAc,UAAAA,CAAAA,CAAFe;YAEpB,IAAA,OAAgBD,SAASG,QAAAA,CAAAA,CAAzB,EAAoCD,UAAUC,QAAAA,CAAAA,CAA9C,CAAA;cAAA,OAAO;YAAP;YAEAd,OAAsBe,MAAtBJ,SAASG,QAAAA,CAAAA,CAAOE,OAAAA,CAAAA,CAAMD,QAAAA,EAAAA,EAAAA,EAAtBE,aAAgCC,CAAhCD,EAAAE;;;cAAgC;cAC9BC,WAAWT,SAASU,OAAAA,CAACH,CAADG;cACpBC,YAAYT,UAAUQ,OAAAA,CAACH,CAADG;cAEtB,IAAG,CAAA,QAAAC,SAASC,UAAAA,CAAO5B,UAAP4B,CAAT,CAAA,IAAA,CAAA,MAAyBD,SAAS5B,MAAAA,CAAAA,CAAlC,EAA2C,SAA3C,CAAA,CAAA,CAAH;;gBACEK,UAAU;gBACVuB,YAAYA,SAASzB,UAAAA,CAAAA,CAAS2B,OAAAA,CAAAA;cAFhC;cAKAC,MACM,CAAA,QAAK9B,UAAL,EADAQ,CAAAA,YAAKmB,SAALnB,CACA,CAAA,GAAA,CACEmB,SAAStB,OAAAA,CAAOoB,QAAhB,EAA0BX,OAAjBT,CADX,IAEA,CAAA,QAAK0B,WAAL,EArDlB,SAqDkB,CAAA,GAAA,CACEJ,SAASK,aAAAA,CAAUP,QAAVO,CADX,IAEA,CAAA,QAAK,GAAL,EAvDlB,SAuDkB,CAAA,IAAA,CAGEL,SAAUM,OAAAA,CAAGR,QAAHQ,CAHZ,CAAA,CAFA,CAFA;cAUN,IAAA,QAAgC7B,OAAhC,CAAA;gBAAAU,OAAOoB,UAAAA,CAAAA,CAAUC,OAAAA,CAAGV,QAAHU;cAAjB;cACAX,OAAAM,IArBFR,CAAsBF;UARxBf,CAAAA;UAiCAQ,OAAAJ,uBAAAA,mBAAAA;AAAAA,YAAAA;;YACE,IAAA,MAAGrB,IAAAW,MAAAA,CAAAA,CAAH,EAAW,SAAX,CAAA;cACEU,OAACA,GAAD,GAAA,CAAIrB,IAAAc,UAAAA,CAAAA,CAAQ2B,OAAAA,CAAAA,CAAMpB,SAAAA,CAAAA,CAAlB,CAAA,GAA2BA;YAD7B;cAGEA,OAACA,IAAD,GAAA,CAAKrB,IAAAW,MAAAA,CAAAA,CAAIU,SAAAA,CAAAA,CAAT,CAAA,GAAkBA,IAAlB,GAAA,CAAsBrB,IAAAc,UAAAA,CAAAA,CAAQO,SAAAA,CAAAA,CAAQiB,OAAAA,CAAC,OAAAU,CAAA,EAAGC,EAAH,QAADX,CAAtC,CAAA,GAA8CjB;YAHhD;UADFA,CAAAA,EAlCKG,CAAAA,GAAAA,SAAAA,CAAMX,CAAb;MAzBFT,GAAAA,WAAAA,EAAAA,IAAAA;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AALAH;"}}, {:offset=>{:line=>34087, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/if.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\nrequire 'opal/ast/matcher'\n\nmodule Opal\n  module Nodes\n    class IfNode < Base\n      handle :if\n\n      children :test, :true_body, :false_body\n\n      def compile\n        if should_compile_as_simple_expression?\n          if true_body == s(:true)\n            compile_with_binary_or\n          elsif false_body == s(:false)\n            compile_with_binary_and\n          else\n            compile_with_ternary\n          end\n        elsif could_become_switch?\n          compile_with_switch\n        else\n          compile_with_if\n        end\n      end\n\n      def compile_with_if\n        push_closure if expects_expression?\n\n        truthy = self.truthy\n        falsy = self.falsy\n\n        if falsy && !truthy\n          # Let's optimize a little bit `unless` calls.\n          push 'if (!', js_truthy(test), ') {'\n          falsy, truthy = truthy, falsy\n        else\n          push 'if (', js_truthy(test), ') {'\n        end\n\n        # skip if-body if no truthy sexp\n        indent { line stmt(truthy) } if truthy\n\n        if falsy\n          if falsy.type == :if\n            line '} else ', stmt(falsy)\n          else\n            line '} else {'\n            indent do\n              line stmt(falsy)\n            end\n\n            line '}'\n          end\n        else\n          line '}'\n\n          # This resolution isn't finite. Let's ensure this block\n          # always return something if we expect a return\n          line 'return nil;' if expects_expression?\n        end\n\n        pop_closure if expects_expression?\n\n        if expects_expression?\n          return_kw = 'return ' if returning_if?\n\n          if scope.await_encountered\n            wrap \"\#{return_kw}(await (async function() {\", '})())'\n          else\n            wrap \"\#{return_kw}(function() {\", '})()'\n          end\n        end\n      end\n\n      def returning_if?\n        @sexp.meta[:returning]\n      end\n\n      def truthy\n        returnify(true_body)\n      end\n\n      def falsy\n        returnify(false_body)\n      end\n\n      def returnify(body)\n        if expects_expression? && body\n          compiler.returns(body)\n        else\n          body\n        end\n      end\n\n      def expects_expression?\n        expr? || recv?\n      end\n\n      # There was a particular case in the past, that when we\n      # expected an expression from if, we always had to closure\n      # it. This produced an ugly code that was hard to minify.\n      # This addition tries to make a few cases compiled with\n      # a ternary operator instead and possibly a binary operator\n      # even?\n      def should_compile_as_simple_expression?\n        expects_expression? && simple?(true_body) && simple?(false_body)\n      end\n\n      def compile_with_ternary\n        truthy = true_body\n        falsy = false_body\n\n        push '('\n\n        push js_truthy(test), ' ? '\n\n        push '(', expr(truthy || s(:nil)), ') : '\n        if !falsy || falsy.type == :if\n          push expr(falsy || s(:nil))\n        else\n          push '(', expr(falsy || s(:nil)), ')'\n        end\n\n        push ')'\n      end\n\n      def compile_with_binary_and\n        if sexp.meta[:do_js_truthy_on_true_body]\n          truthy = js_truthy(true_body || s(:nil))\n        else\n          truthy = expr(true_body || s(:nil))\n        end\n\n        push '('\n        push js_truthy(test), ' && '\n        push '(', truthy, ')'\n        push ')'\n      end\n\n      def compile_with_binary_or\n        if sexp.meta[:do_js_truthy_on_false_body]\n          falsy = js_truthy(false_body || s(:nil))\n        else\n          falsy = expr(false_body || s(:nil))\n        end\n\n        push '('\n        push js_truthy(test), ' || '\n        push '(', falsy, ')'\n        push ')'\n      end\n\n      # Let's ensure there are no control flow statements inside.\n      def simple?(body)\n        case body\n        when AST::Node\n          case body.type\n          when :return, :js_return, :break, :next, :redo, :retry\n            false\n          when :xstr\n            XStringNode.single_line?(\n              XStringNode.strip_empty_children(body.children)\n            )\n          else\n            body.children.all? { |i| simple?(i) }\n          end\n        else\n          true\n        end\n      end\n\n      # NOTE: all following matcher will act on case/when statements in their rewitten form:\n      #\n      #   bin/opal --sexp -e'case some_value_or_expression; when 123; when 456, 789; end'\n      #\n      #   s(:top,\n      #     s(:if,\n      #       s(:send,\n      #         s(:int, 123), :===,\n      #         s(:lvasgn, \"$ret_or_1\",\n      #           s(:send, nil, :some_value_or_expression))), nil,\n      #       s(:if,\n      #         s(:if,\n      #           s(:send,\n      #             s(:int, 456), :===,\n      #             s(:js_tmp, \"$ret_or_1\")),\n      #           s(:true),\n      #           s(:send,\n      #             s(:int, 789), :===,\n      #             s(:js_tmp, \"$ret_or_1\"))), nil,\n      #         s(:nil))))\n      #\n\n      # Matches: `case some_value_or_expression; when 123`\n      # Captures: [s(:int, 123), \"$ret_or_1\", s(:send, nil, :some_value_or_expression))]\n      SWITCH_TEST_MATCH = AST::Matcher.new do\n        s(:send,\n          cap(s(%i[float int sym str true false nil], :*)),\n          :===,\n          s(:lvasgn, cap(:*), cap(:*))\n        )\n      end\n\n      # Matches: case some_value_or_expression; when 123, 456; end\n      # Captures: [\n      #   s(:int, 123),\n      #   \"$ret_or_1\",\n      #   s(:send, nil, :some_value_or_expression)),\n      #   …here we delegate to either SWITCH_BRANCH_TEST_MATCH or SWITCH_BRANCH_TEST_MATCH_CONTINUED\n      # ]\n      SWITCH_TEST_MATCH_CONTINUED = AST::Matcher.new do\n        s(:if,\n          s(:send,\n            cap(s(%i[float int sym str true false nil], :*)),\n            :===,\n            s(:lvasgn, cap(:*), cap(:*))\n          ),\n          s(:true),\n          cap(:*)\n        )\n      end\n\n      # Matches: `when 456` (from `case foo; when 123; when 456; end`)\n      # Captures: [s(:int, 456), \"$ret_or_1\"]\n      SWITCH_BRANCH_TEST_MATCH = AST::Matcher.new do\n        s(:send,\n          cap(s(%i[float int sym str true false nil], :*)),\n          :===,\n          s(:js_tmp, cap(:*))\n        )\n      end\n\n      # Matches: `when 456`\n      # Captures: [\n      #   s(:int, 789),\n      #   \"$ret_or_1\",\n      #   …here we delegate to either SWITCH_BRANCH_TEST_MATCH or SWITCH_BRANCH_TEST_MATCH_CONTINUED\n      # ]\n      SWITCH_BRANCH_TEST_MATCH_CONTINUED = AST::Matcher.new do\n        s(:if,\n          s(:send,\n            cap(s(%i[float int sym str true false nil], :*)),\n            :===,\n            s(:js_tmp, cap(:*))\n          ),\n          s(:true),\n          cap(:*)\n        )\n      end\n\n      def could_become_switch?\n        return false if expects_expression?\n\n        return true if sexp.meta[:switch_child]\n\n        test_match = SWITCH_TEST_MATCH.match(test) || SWITCH_TEST_MATCH_CONTINUED.match(test)\n        return false unless test_match\n        @switch_test, @switch_variable, @switch_first_test, additional_rules = *test_match\n\n        additional_rules = handle_additional_switch_rules(additional_rules)\n        return false unless additional_rules # It's ok for them to be empty, but false denotes a mismatch\n        @switch_additional_rules = additional_rules\n\n        return false unless valid_switch_body?(true_body)\n\n        could_become_switch_branch?(false_body)\n      end\n\n      def handle_additional_switch_rules(additional_rules)\n        switch_additional_rules = []\n        while additional_rules\n          match = SWITCH_BRANCH_TEST_MATCH.match(additional_rules) || SWITCH_BRANCH_TEST_MATCH_CONTINUED.match(additional_rules)\n          return false unless match\n\n          switch_test, switch_variable, additional_rules = *match\n          return false unless switch_variable == @switch_variable\n\n          switch_additional_rules << switch_test\n        end\n        switch_additional_rules\n      end\n\n      def could_become_switch_branch?(body)\n        if !body\n          return true\n        elsif body.type != :if\n          if valid_switch_body?(body)\n            body.meta[:switch_default] = true\n            return true\n          end\n          return false\n        end\n\n        test, true_body, false_body = *body\n\n        test_match = SWITCH_BRANCH_TEST_MATCH.match(test) || SWITCH_BRANCH_TEST_MATCH_CONTINUED.match(test)\n        unless test_match\n          if valid_switch_body?(body, true)\n            body.meta[:switch_default] = true\n            return true\n          end\n        end\n        switch_test, switch_variable, additional_rules = *test_match\n\n        switch_additional_rules = handle_additional_switch_rules(additional_rules)\n        return false unless switch_additional_rules # It's ok for them to be empty, but false denotes a mismatch\n\n        return false unless switch_variable == @switch_variable\n\n        return false unless valid_switch_body?(true_body)\n        return false unless could_become_switch_branch?(false_body)\n\n        body.meta.merge!(switch_child: true,\n                         switch_test: switch_test,\n                         switch_variable: @switch_variable,\n                         switch_additional_rules: switch_additional_rules\n        )\n\n        true\n      end\n\n      def valid_switch_body?(body, check_variable = false)\n        case body\n        when AST::Node\n          case body.type\n          when :break, :redo, :retry\n            false\n          when :iter, :while\n            # Don't traverse the iters or whiles!\n            true\n          else\n            body.children.all? { |i| valid_switch_body?(i, check_variable) }\n          end\n        when @switch_variable\n          # Perhaps we ended abruptly and we lack a $ret_or variable... but sometimes\n          # we can ignore this.\n          !check_variable\n        else\n          true\n        end\n      end\n\n      def compile_with_switch\n        if sexp.meta[:switch_child]\n          @switch_variable = sexp.meta[:switch_variable]\n          @switch_additional_rules = sexp.meta[:switch_additional_rules]\n          compile_switch_case(sexp.meta[:switch_test])\n        else\n          line \"switch (\", expr(@switch_first_test), \".valueOf()) {\"\n          indent do\n            compile_switch_case(@switch_test)\n          end\n          line \"}\"\n        end\n      end\n\n      def returning?(body)\n        %i[return js_return next].include?(body.type) ||\n          (body.type == :begin && %i[return js_return next].include?(body.children.last.type))\n      end\n\n      def compile_switch_case(test)\n        line \"case \", expr(test), \":\"\n        if @switch_additional_rules\n          @switch_additional_rules.each do |rule|\n            line \"case \", expr(rule), \":\"\n          end\n        end\n        indent do\n          line stmt(true_body)\n          line \"break;\" if !true_body || !returning?(true_body)\n        end\n        if false_body\n          if false_body.meta[:switch_default]\n            compile_switch_default\n          elsif false_body.meta[:switch_child]\n            push stmt(false_body)\n          end\n        else\n          push stmt(s(:nil))\n        end\n      end\n\n      def compile_switch_default\n        line \"default:\"\n        indent do\n          line stmt(false_body)\n        end\n      end\n    end\n\n    class IFlipFlop < Base\n      handle :iflipflop\n\n      children :from, :to\n\n      # Is this an exclusive flip flop? If no, run both branches\n      def excl\n        \"\"\n      end\n\n      # We create a function that we put in the top scope, that stores the state of our\n      # flip-flop. We pass to it functions that are ran with the current binding.\n      def compile\n        helper :truthy\n\n        fun_name = top_scope.new_temp\n        ff = \"\#{fun_name}.$$ff\"\n\n        push \"(typeof \#{fun_name} === 'undefined' ? (\#{fun_name} = function(from, to){\"\n        push \"  if (typeof \#{ff} === 'undefined') \#{ff} = false;\"\n        push \"  var retval = \#{ff};\"\n        push \"  if (!\#{ff}) {\"\n        push \"    \#{ff} = retval = $truthy(from());\"\n        push \"  }\"\n        push \"  \#{excl}if (\#{ff}) {\"\n        push \"    if ($truthy(to())) \#{ff} = false;\"\n        push \"  }\"\n        push \"  return retval;\"\n        push \"}) : \#{fun_name})(\"\n        push \"  function() { \", stmt(compiler.returns(from)), \" },\"\n        push \"  function() { \", stmt(compiler.returns(to)), \" }\"\n        push \")\"\n      end\n    end\n\n    class EFlipFlop < IFlipFlop\n      handle :eflipflop\n\n      # Is this an exclusive flip flop? If yes, run only a single branch\n      def excl\n        \"else \"\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:IfNode>", "handle", "children", "compile", "should_compile_as_simple_expression?", "true_body", "s", "compile_with_binary_or", "false_body", "compile_with_binary_and", "compile_with_ternary", "could_become_switch?", "compile_with_switch", "compile_with_if", "expects_expression?", "push_closure", "truthy", "falsy", "push", "js_truthy", "test", "indent", "block in compile_with_if", "block (2 levels) in compile_with_if", "line", "stmt", "type", "pop_closure", "returning_if?", "return_kw", "scope", "await_encountered", "wrap", "@sexp", "meta", "[]", "returnify", "body", "compiler", "returns", "$ret_or_1", "expr?", "recv?", "$ret_or_2", "simple?", "expr", "sexp", "AST::Node", "AST", "XStringNode", "single_line?", "strip_empty_children", "all?", "block in simple?", "i", "block (2 levels) in simple?", "new", "AST::Matcher", "block in <class:IfNode>", "block (2 levels) in <class:IfNode>", "cap", "test_match", "SWITCH_TEST_MATCH", "match", "SWITCH_TEST_MATCH_CONTINUED", "@switch_test", "@switch_variable", "@switch_first_test", "additional_rules", "handle_additional_switch_rules", "@switch_additional_rules", "valid_switch_body?", "could_become_switch_branch?", "switch_additional_rules", "SWITCH_BRANCH_TEST_MATCH", "SWITCH_BRANCH_TEST_MATCH_CONTINUED", "switch_test", "switch_variable", "<<", "[]=", "merge!", "check_variable", "block in valid_switch_body?", "block (2 levels) in valid_switch_body?", "!", "compile_switch_case", "block in compile_with_switch", "block (2 levels) in compile_with_switch", "returning?", "include?", "==", "last", "each", "block in compile_switch_case", "rule", "block (2 levels) in compile_switch_case", "compile_switch_default", "block in compile_switch_default", "block (2 levels) in compile_switch_default", "Base", "<class:IFlipFlop>", "excl", "helper", "fun_name", "top_scope", "new_temp", "ff", "from", "to", "<class:EFlipFlop>", "IFlipFlop"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EACAD,IAAAC,SAAAA,CAAQF,kBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MACEC;MAAAA;;QAAAA;;AAAAA;;QACEJ,IAAAK,QAAAA,CAAO,IAAPA;QAEAL,IAAAM,UAAAA,CAAS,MAAT,EAAgB,WAAhB,EAA4B,YAA5BA;;AAEAC,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAGP,IAAAQ,yCAAAA,CAAAA,CAAH,CAAA;YACE,IAAA,MAAGR,IAAAS,WAAAA,CAAAA,CAAH,EAAgBT,IAAAU,GAAAA,CAAE,MAAFA,CAAhB,CAAA;cACEH,OAAAP,IAAAW,wBAAAA,CAAAA;YADF,OAEA,IAAA,MAAMX,IAAAY,YAAAA,CAAAA,CAAN,EAAoBZ,IAAAU,GAAAA,CAAE,OAAFA,CAApB,CAAA;cACEH,OAAAP,IAAAa,yBAAAA,CAAAA;YADF;cAGEN,OAAAP,IAAAc,sBAAAA,CAAAA;YAHF;UAHF,OAQA,IAAA,QAAMd,IAAAe,