         compile_iter\n        else\n          push 'REDO()'\n        end\n      end\n\n      def compile_while\n        push \"\#{while_loop[:redo_var]} = true;\"\n        thrower(:redo)\n      end\n\n      def compile_iter\n        helper :slice\n        push \"return \#{scope.identity}.apply(null, $slice(arguments))\"\n      end\n    end\n\n    class SplatNode < Base\n      handle :splat\n\n      children :value\n\n      def empty_splat?\n        value == s(:array)\n      end\n\n      def compile\n        if empty_splat?\n          push '[]'\n        else\n          helper :to_a\n          push '$to_a(', recv(value), ')'\n        end\n      end\n    end\n\n    class RetryNode < Base\n      handle :retry\n\n      def compile\n        thrower(:retry)\n      end\n    end\n\n    class ReturnNode < Base\n      handle :return\n\n      children :value\n\n      def return_val\n        if value.nil?\n          s(:nil)\n        elsif children.size > 1\n          s(:array, *children)\n        else\n          value\n        end\n      end\n\n      def compile\n        thrower(:return, return_val)\n      end\n    end\n\n    class JSReturnNode < Base\n      handle :js_return\n\n      children :value\n\n      def compile\n        push 'return '\n        push expr(value)\n      end\n    end\n\n    class JSTempNode < Base\n      handle :js_tmp\n\n      children :value\n\n      def compile\n        push value.to_s\n      end\n    end\n\n    class BlockPassNode < Base\n      handle :block_pass\n\n      children :value\n\n      def compile\n        push expr(s(:send, value, :to_proc, s(:arglist)))\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:NextNode>", "handle", "compile", "thrower", "value", "children", "size", "0", "s", "1", "first", "Base", "<class:BreakNode>", "<class:RedoNode>", "in_while?", "compile_while", "scope", "iter?", "compile_iter", "push", "while_loop", "[]", "helper", "identity", "<cl