:arglist, *children))\n\n          if uses_splat?(children)\n            wrap \"Opal.yieldX(\#{block_name}, \", ')'\n          else\n            wrap \"Opal.yieldX(\#{block_name}, [\", '])'\n          end\n        end\n      end\n\n      def find_yielding_scope\n        working = scope\n        while working\n          if working.block_name || working.def?\n            break\n          end\n          working = working.parent\n        end\n\n        working\n      end\n\n      def yields_single_arg?(children)\n        !uses_splat?(children) && children.size == 1\n      end\n\n      def uses_splat?(children)\n        children.any? { |child| child.type == :splat }\n      end\n    end\n\n    class YieldNode < BaseYieldNode\n      handle :yield\n\n      def compile\n        compile_call\n      end\n    end\n\n    # Created by `#returns()` for when a yield statement should return\n    # it's value (its last in a block etc).\n    class ReturnableYieldNode < BaseYieldNode\n      handle :returnable_yield\n\n      def compile\n        compile_call\n\n        wrap 'return ', ';'\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:BaseYieldNode>", "compile_call", "yielding_scope", "find_yielding_scope", "uses_block!", "$ret_or_1", "block_name", "block_name=", "yields_single_arg?", "children", "push", "expr", "first", "wrap", "s", "uses_splat?", "working", "scope", "def?", "parent", "!", "size", "==", "1", "any?", "block in uses_splat?", "child", "block (2 levels) in uses_splat?", "type", "Base", "<class:YieldNode>", "handle", "compile", "BaseYieldNode", "<class:ReturnableYieldNode>"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MACEC;MAAAA;;;;;AACEC,QAAAA,4BAAAA,wBAAAA;AAAAA,UAAAA;;;UACEC,iBAAiBN,IAAAO,qBAAAA,CAAAA;UAEjBD,cAAcE,gBAAAA,CAAAA;UAVtB,IAAA,QAAAC,CAAAA,YAWQH,cAAcI,YAAAA,CAAAA,CAXtBD,CAAA,CAAA;YAAA;UAAA;YAWQH,cAAcK