t=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    class EnsureNode < Base\n      handle :ensure\n\n      children :begn, :ensr\n\n      def compile\n        push_closure if wrap_in_closure?\n\n        push 'try {'\n\n        in_ensure do\n          line stmt(body_sexp)\n        end\n\n        line '} finally {'\n\n        indent do\n          if has_rescue_else?\n            # $no_errors indicates thate there were no error raised\n            unshift 'var $no_errors = true; '\n\n            # when there's a begin;rescue;else;ensure;end statement,\n            # ruby returns a result of the 'else' branch\n            # but invokes it before 'ensure'.\n            # so, here we\n            # 1. save the result of calling else to $rescue_else_result\n            # 2. call ensure\n            # 2. return $rescue_else_result\n            line 'var $rescue_else_result;'\n            line 'if ($no_errors) { '\n            indent do\n              line '$rescue_else_result = (function() {'\n              indent do\n                line stmt(rescue_else_code)\n              end\n              line '})();'\n            end\n            line '}'\n            line compiler.process(ensr_sexp, @level)\n            line 'if ($no_errors) { return $rescue_else_result; }'\n          else\n            line compiler.process(ensr_sexp, @level)\n          end\n        end\n\n        line '}'\n\n        pop_closure if wrap_in_closure?\n\n        if wrap_in_closure?\n          if scope.await_encountered\n            wrap '(await (async function() { ', '; })())'\n          else\n            wrap '(function() { ', '; })()'\n          end\n        end\n      end\n\n      def body_sexp\n        if wrap_in_closure?\n          compiler.returns(begn)\n        else\n          begn\n        end\n      end\n\n      def ensr_sexp\n        ensr || s(:nil)\n      end\n\n      def wrap_in_closure?\n        recv? || expr? || has_rescue_else?\n      end\n\n      def rescue_else_code\n        rescue_else_code = scope.rescue_else_sexp\n        rescue_else_code = compiler.returns(rescue_else_code) unless stmt?\n        rescue_else_code\n      end\n\n      def has_rescue_else?\n        @sexp.meta[:has_rescue_else]\n      end\n    end\n\n    class RescueNode < Base\n      handle :rescue\n\n      children :body\n\n      def compile\n        scope.rescue_else_sexp = children[1..-1].detect { |sexp| sexp && sexp.type != :resbody }\n        _has_rescue_handlers = false\n\n        if handle_rescue_else_manually?\n          line 'var $no_errors = true;'\n        end\n\n        closure_type = Closure::NONE\n        closure_type |= Closure::JS_FUNCTION if expr? || recv?\n        if has_retry?\n          closure_type |= Closure::JS_LOOP        \\\n                       |  Closure::JS_LOOP_INSIDE \\\n                       |  Closure::RESCUE_RETRIER\n        end\n        push_closure(closure_type) if closure_type != Closure::NONE\n\n        in_rescue(self) do\n          push 'try {'\n          indent do\n            line stmt(body_code)\n          end\n          line '} catch ($err) {'\n\n          indent do\n            if has_rescue_else?\n              line '$no_errors = false;'\n            end\n\n            children[1..-1].each_with_index do |child, idx|\n              # counting only rescue, ignoring rescue-else statement\n              next unless child && child.type == :resbody\n              _has_rescue_handlers = true\n\n              push ' else ' unless idx == 0\n              line process(child, @level)\n            end\n\n            # if no resbodys capture our error, then rethrow\n            push ' else { throw $err; }'\n          end\n\n          line '}'\n\n          if handle_rescue_else_manually?\n            # here we must add 'finally' explicitly\n            push 'finally {'\n            indent do\n              line 'if ($no_errors) { '\n              indent do\n                line stmt(rescue_else_code)\n              end\n              line '}'\n            end\n            push '}'\n          end\n        end\n\n        pop_closure if closure_type != Closure::NONE\n\n        wrap 'do { ', ' break; } while(1)' if has_retry?\n\n        # Wrap a try{} catch{} into a function\n        # when it's an expression\n        # or when there's a method call after begin;rescue;end\n        if expr? || recv?\n          if scope.await_encountered\n            wrap '(await (async function() { ', '})())'\n          else\n            wrap '(function() { ', '})()'\n          end\n        end\n      end\n\n      def body_code\n        body_code = (body.nil? || body.type == :resbody ? s(:nil) : body)\n        body_code = compiler.returns(body_code) unless stmt?\n        body_code\n      end\n\n      def rescue_else_code\n        rescue_else_code = scope.rescue_else_sexp\n        rescue_else_code = compiler.returns(rescue_else_code) unless stmt?\n        rescue_else_code\n      end\n\n      # Returns true when there's no 'ensure' statement\n      #  wrapping current rescue.\n      #\n      def handle_rescue_else_manually?\n        !in_ensure? && has_rescue_else?\n      end\n\n      def has_retry?\n        @sexp.meta[:has_retry]\n      end\n    end\n\n    class ResBodyNode < Base\n      handle :resbody\n\n      children :klasses_sexp, :lvar, :body\n\n      def compile\n        push 'if (Opal.rescue($err, ', expr(klasses), ')) {'\n        indent do\n          if lvar\n            push expr(lvar.updated(nil, [*lvar.children, s(:js_tmp, '$err')]))\n          end\n\n          # Need to ensure we clear the current exception out after the rescue block ends\n          line 'try {'\n          indent do\n            in_resbody do\n              line stmt(rescue_body)\n            end\n          end\n          line '} finally { Opal.pop_exception(); }'\n        end\n        line '}'\n      end\n\n      def klasses\n        klasses_sexp || s(:array, s(:const, nil, :StandardError))\n      end\n\n      def rescue_body\n        body_code = (body || s(:nil))\n        body_code = compiler.returns(body_code) unless stmt?\n        body_code\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:EnsureNode>", "handle", "children", "compile", "wrap_in_closure?", "push_closure", "push", "in_ensure", "block in compile", "block (2 levels) in compile", "line", "stmt", "body_sexp", "indent", "has_rescue_else?", "unshift", "block (3 levels) in compile", "block (4 levels) in compile", "rescue_else_code", "compiler", "process", "ensr_sexp", "@level", "pop_closure", "scope", "await_encountered", "wrap", "returns", "begn", "$ret_or_1", "ensr", "s", "$ret_or_2", "recv?", "expr?", "rescue_else_sexp", "stmt?", "@sexp", "meta", "[]", "Base", "<class:RescueNode>", "rescue_else_sexp=", "detect", "1", "-1", "sexp", "type", "!=", "_has_rescue_handlers", "handle_rescue_else_manually?", "closure_type", "Closure::NONE", "Closure", "|", "Closure::JS_FUNCTION", "has_retry?", "Closure::JS_LOOP", "Closure::JS_LOOP_INSIDE", "Closure::RESCUE_RETRIER", "in_rescue", "body_code", "each_with_index", "child", "idx", "0", "body", "nil?", "in_ensure?", "!", "<class:ResBodyNode>", "expr", "klasses", "lvar", "updated", "in_resbody", "rescue_body", "klasses_sexp"], :mappings=>"AAAAA,oCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MACEC;MAAAA;;QAAAA;;AAAAA;;QACEJ,IAAAK,QAAAA,CAAO,QAAPA;QAEAL,IAAAM,UAAAA,CAAS,MAAT,EAAgB,MAAhBA;;AAEAC,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACE,IAAA,QAAgBP,IAAAQ,qBAAAA,CAAAA,CAAhB,CAAA;YAAAR,IAAAS,cAAAA,CAAAA;UAAA;UAEAT,IAAAU,MAAAA,CAAKH,OAALG;UAEAC,MAAAX,IAAAW,aAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;;YACEA,OAAAb,IAAAc,MAAAA,CAAKd,IAAAe,MAAAA,CAAKf,IAAAgB,WAAAA,CAAAA,CAALD,CAALD,CADFF,CAAAA,GAAAA,SAAAA,CAAAD;UAIAX,IAAAc,MAAAA,CAAKP,aAALO;UAEAG,MAAAjB,IAAAiB,UAAAA,EAAAA,EAAAA,EAAAL,aAAAA,EAAAC;AAAAA;;YACE,IAAA,QAAGb,IAAAkB,qBAAAA,CAAAA,CAAH,CAAA;;cAEE