OAAAtD,IAAAkB,qBAAAA,CAAAA;UAAf;YAAAoC,OAAA;UAAA;QADFA,CAAAA;QAIAT,OAAAe,0BAAAA,uCAAAA;AAAAA,UAAAA;;UACEA,OAAAnB,SAAKC,MAAAA,CAAAA,CAAKC,OAAAA,CAAC,WAADA;QADZiB,CAAAA;MAlGFf,GAAAA,WAAAA,EAAmBD,UAAnBC;MAuGA1C,OAAAuE;MAAAA;;;;QACE1E,IAAAK,QAAAA,CAAO,SAAPA;QAEAL,IAAAM,UAAAA,CAAS,cAAT,EAAwB,MAAxB,EAA+B,MAA/BA;;AAEAC,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACEP,IAAAU,MAAAA,CAAKH,wBAAL,EAA+BP,IAAA2E,MAAAA,CAAK3E,IAAA4E,SAAAA,CAAAA,CAALD,CAA/B,EAA8CpE,MAA9CG;UACAO,MAAAjB,IAAAiB,UAAAA,EAAAA,EAAAA,EAAAL,cAAAA,EAAAC;;;YACE,IAAA,QAAGb,IAAA6E,MAAAA,CAAAA,CAAH,CAAA;cACE7E,IAAAU,MAAAA,CAAKV,IAAA2E,MAAAA,CAAK3E,IAAA6E,MAAAA,CAAAA,CAAIC,SAAAA,CAAS,GAAb,EAAkB,UAAC,MAAC9E,IAAA6E,MAAAA,CAAAA,CAAIvE,UAAAA,CAAAA,CAAL,CAAD,CAAA,QAAA,CAAiBN,IAAAmC,GAAAA,CAAE,QAAF,EAAWtB,MAAXsB,CAAjB,CAAA,CAAd2C,CAATH,CAALjE;YADF;YAKAV,IAAAc,MAAAA,CAAKD,OAALC;YACAG,MAAAjB,IAAAiB,UAAAA,EAAAA,EAAAA,EAAAJ,cAAAA,EAAAO;;cACEA,OAAA2D,MAAA/E,IAAA+E,cAAAA,EAAAA,EAAAA,EAAA3D,cAAAA,EAAAC;;gBACEA,OAAArB,IAAAc,MAAAA,CAAKd,IAAAe,MAAAA,CAAKf,IAAAgF,aAAAA,CAAAA,CAALjE,CAALD,CADFM,CAAAA,GAAAA,SAAAA,CAAA2D,CADFlE,CAAAA,GAAAA,SAAAA,CAAAI;YAKAJ,OAAAb,IAAAc,MAAAA,CAAKD,qCAALC,EAZFF,CAAAA,GAAAA,SAAAA,CAAAK;UAcAV,OAAAP,IAAAc,MAAAA,CAAKP,GAALO;QAhBFP,CAAAA;;AAmBAqE,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACE,IAAA,QAAA3C,CAAAA,YAAAjC,IAAAiF,cAAAA,CAAAA,CAAAhD,CAAA,CAAA;YAAA2C,OAAA;UAAA;YAAgBA,OAAA5E,IAAAmC,GAAAA,CAAE,OAAF,EAAUnC,IAAAmC,GAAAA,CAAE,OAAF,EAAU,GAAV,EAAe,eAAfA,CAAVA;UAAhB;QADFyC,CAAAA;QAIAF,OAAAM,2BAAAA,uBAAAA;AAAAA,UAAAA;;;UACEf,YAAa,CAAA,QAAAhC,CAAAA,YAAAjC,IAAAsE,MAAAA,CAAAA,CAAArC,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAQjC,IAAAmC,GAAAA,CAAE,KAAFA,CAAR,CAAA;UACb,KAAA,QAA+CnC,IAAAwC,UAAAA,CAAAA,CAA/C,CAAA;YAAAyB,YAAYjE,IAAAuB,UAAAA,CAAAA,CAAQQ,SAAAA,CAASkC,SAATlC;UAApB;UACAiD,OAAAf;QAHFe,CAAAA;MA5BFN,GAAAA,WAAAA,EAAoB9B,UAApB8B;IA7LFvE,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>35339, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/super.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    # This base class is used just to child the find_super_dispatcher method\n    # body. This is then used by actual super calls, or a defined?(super) style\n    # call.\n    class BaseSuperNode < CallNode\n      def initialize(*)\n        super\n        args = *@sexp\n        *rest, last_child = *args\n\n        if last_child && %i[iter block_pass].include?(last_child.type)\n          @iter = last_child\n          args = rest\n        else\n          @iter = s(:js_tmp, 'null')\n        end\n\n        @arglist = s(:arglist, *args)\n        @recvr = s(:self)\n      end\n\n      def compile_using_send\n        helper :send2\n\n        push '$send2('\n        compile_receiver\n        compile_method_body\n        compile_method_name\n        compile_arguments\n        compile_block_pass\n        push ')'\n      end\n\n      private\n\n      # Using super in a block inside a method is allowed, e.g.\n      # def a\n      #  { super }\n      # end\n      #\n      # This method finds returns a closest s(:def) (or s(:defs))\n      def def_scope\n        @def_scope ||= scope.def? ? scope : scope.find_parent_def\n      end\n\n      def defined_check_param\n        'false'\n      end\n\n      def implicit_arguments_param\n        'false'\n      end\n\n      def method_id\n        def_scope.mid.to_s\n      end\n\n      def def_scope_identity\n        def_scope.identify!(def_scope.mid)\n      end\n\n      def allow_stubs\n        'true'\n      end\n\n      def super_method_invocation\n        helper :find_super\n        \"$find_super(\#{scope.self}, '\#{method_id}', \#{def_scope_identity}, \#{defined_check_param}, \#{allow_stubs})\"\n      end\n\n      def super_block_invocation\n        helper :find_block_super\n        chain, cur_defn, mid = scope.super_chain\n        trys = chain.map { |c| \"\#{c}.$$def\" }.join(' || ')\n        \"$find_block_super(\#{scope.self}, \#{mid}, (\#{trys} || \#{cur_defn}), \#{defined_check_param}, \#{implicit_arguments_param})\"\n      end\n\n      def compile_method_body\n        push ', '\n        if scope.def?\n          push super_method_invocation\n        elsif scope.iter?\n          push super_block_invocation\n        else\n          raise 'super must be called from method body or block'\n        end\n      end\n\n      def compile_method_name\n        if scope.def?\n          push \", '\#{method_id}'\"\n        elsif scope.iter?\n          _chain, _cur_defn, mid = scope.super_chain\n          push \", \#{mid}\"\n        end\n      end\n    end\n\n    class DefinedSuperNode < BaseSuperNode\n      handle :defined_super\n\n      def allow_stubs\n        'false'\n      end\n\n      def defined_check_param\n        'true'\n      end\n\n      def compile\n        compile_receiver\n        compile_method_body\n\n        wrap '((', ') != null ? \"super\" : nil)'\n      end\n    end\n\n    # super with explicit args\n    class SuperNode < BaseSuperNode\n      handle :super\n\n      def initialize(*)\n        super\n\n        if scope.def?\n          scope.uses_block!\n        end\n      end\n\n      def compile\n        compile_using_send\n      end\n    end\n\n    # super with implicit args\n    class ZsuperNode < SuperNode\n      handle :zsuper\n\n      def implicit_arguments_param\n        'true'\n      end\n\n      def initialize(*)\n        super\n\n        # preserve a block if we have one already but otherwise, assume a block is coming from higher\n        # up the chain\n        unless iter.type == :iter\n          # Need to support passing block up even if it's not referenced in this method at all\n          scope.uses_block!\n          @iter = s(:js_tmp, scope.block_name || '$yield')\n        end\n      end\n\n      def compile\n        if def_scope\n          implicit_args = implicit_arglist\n          # If the method we're in has a block and we're using a default super call with no args, we need to grab the block\n          # If an iter (block via braces) is provided, that takes precedence\n          if block_name && !iter\n            block_pass = s(:block_pass, s(:lvar, block_name))\n            implicit_args << block_pass\n          end\n\n          @arglist = s(:arglist, *implicit_args)\n        end\n\n        compile_using_send\n      end\n\n      def implicit_arglist\n        args = []\n        kwargs = []\n        same_arg_counter = Hash.new(0)\n\n        def_scope.original_args.children.each do |sexp|\n          lvar_name = sexp.children[0]\n\n          case sexp.type\n          when :arg, :optarg\n            arg_node = s(:lvar, lvar_name)\n            #   def m(_, _)\n            # is compiled to\n            #   function $$m(_, __$2)\n            # See Opal::Node::ArgsNode\n            if lvar_name[0] == '_'\n              same_arg_counter[lvar_name] += 1\n              arg_node = s(:js_tmp, \"\#{lvar_name}_$\#{same_arg_counter[lvar_name]}\") if same_arg_counter[lvar_name] > 1\n            end\n            args << arg_node\n          when :restarg\n            arg_node = lvar_name ? s(:lvar, lvar_name) : s(:js_tmp, '$rest_arg')\n            args << s(:splat, arg_node)\n          when :kwarg, :kwoptarg\n            key_name = sexp.meta[:arg_name]\n            kwargs << s(:pair, s(:sym, key_name), s(:lvar, lvar_name))\n          when :kwrestarg\n            arg_node = lvar_name ? s(:lvar, lvar_name) : s(:js_tmp, '$kw_rest_arg')\n            kwargs << s(:kwsplat, arg_node)\n          end\n        end\n\n        args << s(:hash, *kwargs) unless kwargs.empty?\n        args\n      end\n\n      def block_name\n        case def_scope\n        when Opal::Nodes::IterNode\n          def_scope.block_name\n        when Opal::Nodes::DefNode\n          def_scope.block_name\n        else\n          raise \"Don't know what to do with super in the scope \#{def_scope}\"\n        end\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:BaseSuperNode>", "initialize", "$fwd_rest", "args", "@sexp", "rest", "last_child", "include?", "type", "@iter", "s", "@arglist", "@recvr", "compile_using_send", "helper", "push", "compile_receiver", "compile_method_body", "compile_method_name", "compile_arguments", "compile_block_pass", "private", "def_scope", "@def_scope", "$ret_or_1", "scope", "def?", "find_parent_def", "defined_check_param", "implicit_arguments_param", "method_id", "mid", "to_s", "def_scope_identity", "identify!", "allow_stubs", "super_method_invocation", "super_block_invocation", "super_chain", "chain", "cur_defn", "trys", "map", "block in super_block_invocation", "c", "block (2 levels) in super_block_invocation", "join", "iter?", "raise", "_chain", "_cur_defn", "CallNode", "<class:DefinedSuperNode>", "handle", "compile", "wrap", "BaseSuperNode", "<class:SuperNode>", "uses_block!", "<class:ZsuperNode>", "iter", "block_name", "implicit_args", "implicit_arglist", "block_pass", "<<", "kwargs", "same_arg_counter", "Hash", "new", "0", "each", "original_args", "children", "block in implicit_arglist", "sexp", "block (2 levels) in implicit_arglist", "lvar_name", "[]", "arg_node", "[]=", "+", "1", ">", "key_name", "meta", "empty?", "Opal::Nodes::IterNode", "Opal::Nodes", "Opal", "Opal::Nodes::DefNode", "SuperNode"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MAIEC;MAAAA;;QAAAA;;AAAAA;;;AACEC,QAAAA,0BAAAA,sBAVN,EAUMA;AAAAA,UAAAA;;UAAAA;;UAVN;UAUqB;UACb,OAAAL,IAAA,EAAA,0DAAA,cAAA,EAAA,MAAAM,SAAA,CAAA,EAAA,MAAA;UACAC,OAAO,UAAA,MAACC,SAAD,CAAA;UACP,KAAoB,UAAA,MAACD,IAAD,CAAA,CAApB,oBAAA,wBAAA,EAACE,CAAAA,OAAD,iBAACA,CAAD,EAAOC,CAAAA,aAAP,+BAAOA,CAAP;UAEA,IAAG,CAAA,QAAAA,UAAA,CAAA,IAAA,CAAA,QAAc,CAAG,MAAH,EAAQ,YAAR,CAAmBC,aAAAA,CAAUD,UAAUE,MAAAA,CAAAA,CAApBD,CAAjC,CAAA,CAAA,CAAH;;YACEE,YAAQH;YACRH,OAAOE;UAFT;YAIEI,YAAQb,IAAAc,GAAAA,CAAE,QAAF,EAAWT,MAAXS;UAJV;UAOAC,eAAWD,MAAAd,IAAAc,KAAAA,EAAA,CAAE,SAAF,CAAA,QAAY,MAACP,IAAD,CA