ase 'undefined':\n          return nil;\n\n        case 'object':\n          if (!value) return nil;\n\n          if (value.$$is_array) {\n            arr = \#{`options.array_class`.new};\n\n            for (i = 0, ii = value.length; i < ii; i++) {\n              \#{`arr`.push(`to_opal(value[i], options)`)};\n            }\n\n            return arr;\n          }\n          else {\n            hash = \#{`options.object_class`.new};\n\n            for (k in value) {\n              if ($hasOwn.call(value, k)) {\n                \#{`hash`[`k`] = `to_opal(value[k], options)`};\n              }\n            }\n\n            if (!options.parse && (klass = \#{`hash`[JSON.create_id]}) != nil) {\n              return \#{::Object.const_get(`klass`).json_create(`hash`)};\n            }\n            else {\n              return hash;\n            }\n          }\n        }\n    };\n  }\n\n  class << self\n    attr_accessor :create_id\n  end\n\n  self.create_id = :json_class\n\n  def self.[](value, options = {})\n    if String === value\n      parse(value, options)\n    else\n      generate(value, options)\n    end\n  end\n\n  def self.parse(source, options = {})\n    from_object(`$parse(source)`, options.merge(parse: true))\n  end\n\n  def self.parse!(source, options = {})\n    parse(source, options)\n  end\n\n  def self.load(source, options = {})\n    from_object(`$parse(source)`, options)\n  end\n\n  # Raw js object => opal object\n  def self.from_object(js_object, options = {})\n    options[:object_class] ||= Hash\n    options[:array_class]  ||= Array\n\n    `to_opal(js_object, options.$$smap)`\n  end\n\n  def self.generate(obj, options = {})\n    obj.to_json(options)\n  end\n\n  def self.dump(obj, io = nil, limit = nil)\n    string = generate(obj)\n\n    if io\n      io = io.to_io if io.responds_to? :to_io\n      io.write string\n\n      io\n    else\n      string\n    end\n  end\nend\n\nclass Object\n  def to_json\n    to_s.to_json\n  end\nend\n\n# BUG: Enumerable must come before Array, otherwise it overrides #to_json\n#      this is due to how modules are implemented.\nmodule Enumerable\n  def to_json\n    to_a.to_json\n  end\nend\n\nclass Array\n  def to_json\n    %x{\n      var result = [];\n\n      for (var i = 0, length = \#{self}.length; i < length; i++) {\n        result.push(\#{`self[i]`.to_json});\n      }\n\n      return '[' + result.join(',') + ']';\n    }\n  end\nend\n\nclass Boolean\n  def to_json\n    `(self == true) ? 'true' : 'false'`\n  end\nend\n\nclass Hash\n  def to_json\n    %x{\n      var result = [];\n\n      for (var i = 0, keys = self.$$keys, length = keys.length, key, value; i < length; i++) {\n        key = keys[i];\n\n        if (key.$$is_string) {\n          value = self.$$smap[key];\n        } else {\n          value = key.value;\n          key = key.key;\n        }\n\n        result.push(\#{`key`.to_s.to_json} + ':' + \#{`value`.to_json});\n      }\n\n      return '{' + result.join(',') + '}';\n    }\n  end\nend\n\nclass NilClass\n  def to_json\n    'null'\n  end\nend\n\nclass Numeric\n  def to_json\n    `self.toString()`\n  end\nend\n\nclass String\n  def to_json\n    `JSON.stringify(self)`\n  end\nend\n\nclass Time\n  def to_json\n    strftime('%FT%T%z').to_json\n  end\nend\n\nclass Date\n  def to_json\n    to_s.to_json\n  end\n\n  def as_json\n    to_s\n  end\nend\n"], :names=>["<top (required)>", "<module:JSON>", "<class:JSONError>", "StandardError", "<class:ParserError>", "JSONError", "self", "raise", "JSON::ParserError", "JSON", "new", "push", "[]=", "[]", "create_id", "Object", "const_get", "json_create", "attr_accessor", "create_id=", "value", "options", "String", "parse", "generate", "source", "from_object", "merge", "parse!", "load", "js_object", "$ret_or_1", "Hash", "Array", "obj", "to_json", "dump", "io", "limit", "string", "responds_to?", "to_io", "write", "<class:Object>", "to_s", "<module:Enumerable>", "to_a", "<class:Array>", "<class:Boolean>", "<class:Hash>", "<class:NilClass>", "<class: