ef compile_with_redo(test_code)\n        compile_while(test_code, \"\#{@redo_var} = false;\")\n      end\n\n      def compile_without_redo(test_code)\n        compile_while(test_code)\n      end\n\n      def compile_while(test_code, redo_code = nil)\n        unshift redo_code if redo_code\n        unshift while_open, test_code, while_close\n        unshift redo_code if redo_code\n        line '}'\n      end\n\n      def while_open\n        if uses_redo?\n          redo_part = \"\#{@redo_var} || \"\n        end\n\n        \"while (\#{redo_part}\"\n      end\n\n      def while_close\n        ') {'\n      end\n\n      def uses_redo?\n        @sexp.meta[:has_redo]\n      end\n\n      def wrap_in_closure?\n        expr? || recv?\n      end\n    end\n\n    class UntilNode < WhileNode\n      handle :until\n\n      private\n\n      def while_open\n        if uses_redo?\n          redo_part = \"\#{@redo_var} || \"\n        end\n\n        \"while (\#{redo_part}!(\"\n      end\n\n      def while_close\n        ')) {'\n      end\n    end\n\n    class WhilePostNode < WhileNode\n      handle :while_post\n\n      private\n\n      def compile_while(test_code, redo_code = nil)\n        unshift redo_code if redo_code\n        unshift \"do {\"\n        line \"} \", while_open, test_code, while_close\n      end\n\n      def while_close\n        ');'\n      end\n    end\n\n    class UntilPostNode < WhilePostNode\n      handle :until_post\n\n      private\n\n      def while_open\n        if uses_redo?\n          redo_part = \"\#{@redo_var} || \"\n        end\n\n        \"while (\#{redo_part}!(\"\n      end\n\n      def while_close\n        '));'\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:WhileNode>", "handle", "children", "compile", "test_code", "js_truthy", "test", "uses_redo?", "@redo_var", "scope", "new_temp", "in_while", "compiler", "block in compile", "block (2 levels) in compile", "wrap_in_closure?