;;;QACE3D,IAAAK,QAAAA,CAAO,YAAPA;QAEAL,IAAA2C,SAAAA,CAAAA;;AAEAC,QAAAA,6BAAAA,yBAAkBpC,SAAD,EAAYqC,SAA7BD;AAAAA,UAAAA;;;UAA6B,mCAAY;UACvC,IAAA,QAAqBC,SAArB,CAAA;YAAA7C,IAAA8C,SAAAA,CAAQD,SAARC;UAAA;UACA9C,IAAA8C,SAAAA,CAAQF,MAARE;UACAF,OAAA5C,IAAAiC,MAAAA,CAAKW,IAAL,EAAW5C,IAAA+C,YAAAA,CAAAA,CAAX,EAAuBvC,SAAvB,EAAkCR,IAAAgD,aAAAA,CAAAA,CAAlCf;QAHFW,CAAAA,IAAAA;QAMAe,OAAAX,2BAAAA,YACEW,IADFX,CAAAA;MAXFW,GAAAA,WAAAA,EAAsBD,eAAtBC;MAgBAxD,OAAAyD;MAAAA;;QAAAA;;AAAAA;;QACE5D,IAAAK,QAAAA,CAAO,YAAPA;QAEAL,IAAA2C,SAAAA,CAAAA;;AAEAI,QAAAA,0BAAAA,sBAAAA;AAAAA,UAAAA;;;UACE,IAAA,QAAG/C,IAAAW,eAAAA,CAAAA,CAAH,CAAA;YACEsC,YAAY,EAAA,GAAA,CAAGrC,aAAH,CAAA,GAAamC;UAD3B;UAIAA,OAACA,SAAD,GAAA,CAAUE,SAAV,CAAA,GAAoBF;QALtBA,CAAAA;QAQAa,OAAAZ,2BAAAA,YACEY,KADFZ,CAAAA;MAbFY,GAAAA,WAAAA,EAAsBC,mBAAtBD;IA/GFzD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>36340, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/hash.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    class HashNode < Base\n      handle :hash\n\n      attr_accessor :has_kwsplat, :keys, :values\n\n      def initialize(*)\n        super\n        @has_kwsplat = false\n        @keys = []\n        @values = []\n\n        children.each do |child|\n          case child.type\n          when :kwsplat\n            @has_kwsplat = true\n          when :pair\n            @keys << child.children[0]\n            @values << child.children[1]\n          end\n        end\n      end\n\n      def simple_keys?\n        keys.all? { |key| %i[sym str].include?(key.type) }\n      end\n\n      def compile\n        if has_kwsplat\n          compile_merge\n        elsif simple_keys?\n          compile_hash2\n        else\n          compile_hash\n        end\n      end\n\n      # Compiles hashes containing kwsplats inside.\n      # hash like { **{ nested: 1 }, a: 1, **{ nested: 2} }\n      # should be compiled to\n      # { nested: 1}.merge(a: 1).merge(nested: 2)\n      # Each kwsplat overrides previosly defined keys\n      # Hash k/v pairs override previously defined kwsplat values\n      def compile_merge\n        helper :hash\n\n        result, seq = [], []\n\n        children.each do |child|\n          if child.type == :kwsplat\n            unless seq.empty?\n              result << expr(s(:hash, *seq))\n            end\n            result << expr(child)\n            seq = []\n          else\n            seq << child\n          end\n        end\n        unless seq.empty?\n          result << expr(s(:hash, *seq))\n        end\n\n        result.each_with_index do |fragment, idx|\n          if idx == 0\n            push fragment\n          else\n            push '.$merge(', fragment, ')'\n          end\n        end\n      end\n\n      # Compiles a hash without kwsplats\n      # with complex keys.\n      def compile_hash\n        helper :hash\n\n        children.each_with_index do |pair, idx|\n          key, value = pair.children\n          push ', ' unless idx == 0\n          push expr(key), ', ', expr(value)\n        end\n\n        wrap '$hash(', ')'\n      end\n\n      # Compiles a hash without kwsplats\n      # and containing **only** string/symbols as keys.\n      def compile_hash2\n        hash_obj, hash_keys = {}, []\n        helper :hash2\n\n        keys.size.times do |idx|\n          key = keys[idx].children[0].to_s.inspect\n          hash_keys << key unless hash_obj.include? key\n          hash_obj[key] = expr(values[idx])\n        end\n\n        hash_keys.each_with_index do |key, idx|\n          push ', ' unless idx == 0\n          push \"\#{key}: \"\n          push hash_obj[key]\n        end\n\n        wrap \"$hash2([\#{hash_keys.join ', '}], {\", '})'\n      end\n    end\n\n    class KwSplatNode < Base\n      handle :kwsplat\n      children :value\n\n      def compile\n        push 'Opal.to_hash(', expr(value), ')'\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", 