 << part << fragment(')')\n              else\n                code << fragment('.concat(') << part << fragment(')')\n              end\n            else\n              if code.empty?\n                code << fragment('[') << work << fragment(']')\n              else\n                code << fragment('.concat([') << work << fragment('])')\n              end\n\n              code << fragment('.concat(') << part << fragment(')')\n            end\n            work = []\n          else\n            work << fragment(', ') unless work.empty?\n            work << part\n          end\n        end\n\n        unless work.empty?\n          join = [fragment('['), work, fragment(']')]\n\n          if code.empty?\n            code = join\n          else\n            code.push([fragment('.concat('), join, fragment(')')])\n          end\n        end\n\n        push code\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:ArrayNode>", "handle", "compile", "children", "empty?", "push", "code", "work", "each", "block in compile", "child", "block (2 levels) in compile", "splat", "type", "==", "part", "expr", "<<", "fragment", "join", "Base"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;;;QACEJ,IAAAK,QAAAA,CAAO,OAAPA;QAEAD,OAAAE,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACE,IAAA,QAAqBN,IAAAO,UAAAA,CAAAA,CAAQC,WAAAA,CAAAA,CAA7B,CAAA;YAAA,OAAOR,IAAAS,MAAAA,CAAKH,IAALG;UAAP;UAEA,KAAa,CAAA,EAAA,EAAI,EAAJ,CAAb,EAAAC,CAAAA,OAAA,KAAAA,CAAA,EAAMC,CAAAA,OAAN,KAAMA,CAAN;UAEQC,MAARZ,IAAAO,UAAAA,CAAAA,CAAQK,QAAAA,EAAAA,EAAAA,EAARC,aAAkBC,KAAlBD,EAAAE;;;YAAkB;YAChBC,QAAQF,KAAKG,MAAAA,CAAAA,CAAMC,OAAAA,CAAG,OAAHA;YACnBC,OAAQnB,IAAAoB,MAAAA,CAAKN,KAALM;YAER,IAAA,QAAGJ,KAAH,CAAA;;cACE,IAAA,QAAGL,IAAIH,WAAAA,CAAAA,CAAP,CAAA;gBACE,IAAA,QAAGE,IAAIF,WAAAA,CAAAA,CAAP,CAAA;kBACEE,IAAKW,OAAAA,CAAGrB,IAAAsB,UAAAA,CAASP,YAATO,CAAHD,CAA0BA,OAAAA,CAAGF,IA