AA,CAAKC,UAAAA,CAAAA;UACnBnC,IAAAU,MAAAA,CAAMiB,GAAD,GAAA,CAAImD,WAAJ,CAAA,GAAgBnD,kBAAhB,GAAA,CAAkCmD,WAAlC,CAAA,GAA8CnD,cAA9C,GAAA,CAA4DmD,WAA5D,CAAA,GAAwEnD,UAA7EjB;UACAiB,OAAAmD;QALFnD,CAAAA;QAQAvB,OAAAwB,qCAAAA,iCAA0BE,IAA1BF;AAAAA,UAAAA;;UACEA,OAAamD,MAAbjD,IAAIxB,UAAAA,CAAAA,CAASyE,mBAAAA,EAAAA,EAAAA,EAAbC,aAAkCC,KAAD,EAAQC,GAAzCF,EAAAG;;;YAAkC;YAAO;YACvC,KAAA,MAAmBD,GAAnB,EAA0BlE,CAA1B,CAAA;cAAAhB,IAAAU,MAAAA,CAAKyE,MAALzE;YAAA;YACAyE,OAAAnF,IAAA6B,iBAAAA,CAAgBoD,KAAhBpD,EAFFmD,CAAAA,GAAAA,SAAAA,CAAaD;QADfnD,CAAAA;MAhNFxB,GAAAA,WAAAA,EAAoBgF,UAApBhF;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>36877, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/masgn.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'opal/nodes/base'\n\nmodule Opal\n  module Nodes\n    class MassAssignNode < Base\n      SIMPLE_ASSIGNMENT = %i[lvasgn ivasgn lvar gvasgn cdecl casgn].freeze\n\n      handle :masgn\n      children :lhs, :rhs\n\n      def compile\n        with_temp do |array|\n          if rhs.type == :array\n            push \"\#{array} = \", expr(rhs)\n            rhs_len = rhs.children.any? { |c| c.type == :splat } ? nil : rhs.children.size\n            compile_masgn(lhs.children, array, rhs_len)\n            push \", \#{array}\" # a mass assignment evaluates to the RHS\n          else\n            helper :to_ary\n            with_temp do |retval|\n              push \"\#{retval} = \", expr(rhs)\n              push \", \#{array} = $to_ary(\#{retval})\"\n              compile_masgn(lhs.children, array)\n              push \", \#{retval}\"\n            end\n          end\n        end\n      end\n\n      # 'len' is how many rhs items are we sure we have\n      def compile_masgn(lhs_items, array, len = nil)\n        pre_splat  = lhs_items.take_while { |child| child.type != :splat }\n        post_splat = lhs_items.drop(pre_splat.size)\n\n        pre_splat.each_with_index do |child, idx|\n          compile_assignment(child, array, idx, len)\n        end\n\n        unless post_splat.empty?\n          splat = post_splat.shift\n\n          if post_splat.empty? # trailing splat\n            if part = splat.children[0]\n              helper :slice\n              part = part.dup << s(:js_tmp, \"$slice(\#{array}, \#{pre_splat.size})\")\n              push ', '\n              push expr(part)\n            end\n          else\n            tmp = scope.new_temp # end index for items consumed by splat\n            push \", \#{tmp} = \#{array}.length - \#{post_splat.size}\"\n            push \", \#{tmp} = (\#{tmp} < \#{pre_splat.size}) ? \#{pre_splat.size} : \#{tmp}\"\n\n            if part = splat.children[0]\n              helper :slice\n              part = part.dup << s(:js_tmp, \"$slice(\#{array}, \#{pre_splat.size}, \#{tmp})\")\n              push ', '\n              push expr(part)\n            end\n\n            post_splat.each_with_index do |child, idx|\n              if idx == 0\n                compile_assignment(child, array, tmp)\n              else\n                compile_assignment(child, array, \"\#{tmp} + \#{idx}\")\n              end\n            end\n\n            scope.queue_temp(tmp)\n          end\n        end\n      end\n\n      def compile_assignment(child, array, idx, len = nil)\n        assign =\n          if !len || idx >= len\n            s(:js_tmp, \"(\#{array}[\#{idx}] == null ? nil : \#{array}[\#{idx}])\")\n          else\n            s(:js_tmp, \"\#{array}[\#{idx}]\")\n          end\n\n        part = child.updated\n        if SIMPLE_ASSIGNMENT.include?(child.type)\n          part = part.updated(nil, part.children + [assign])\n        elsif child.type == :send\n          part = part.updated(nil, part.children + [assign])\n        elsif child.type == :attrasgn\n          part.last << assign\n        elsif child.type == :mlhs\n          helper :to_ary\n          # nested destructuring\n          tmp = scope.new_temp\n          push \", (\#{tmp} = $to_ary(\#{assign.children[0]})\"\n          compile_masgn(child.children, tmp)\n          push ')'\n          scope.queue_temp(tmp)\n          return\n        else\n          raise \"Bad child node in masgn LHS: \#{child}. LHS: \#{lhs}\"\n        end\n\n        push ', '\n        push expr(part)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:MassAssignNode>", "freeze", "handle", "children", "compile", "with_temp", "block in compile", "array", "block (2 levels) in compile", "rhs", "type", "push", "expr", "rhs_len", "any?", "c", "block (3 levels) in compile", "==", "size", "compile_masgn", "lhs", "helper", "retval", "lhs_items", "len", "pre_splat", "take_while", "block in compile_masgn", "child", "block (2 levels) in compile_masgn", "!=", "post_splat", "drop", "each_with_index", "idx", "compile_assignment", "empty?", "splat", "shift", "part", "[]", "0", "dup", "<<", "s", "tmp", "scope", "new_temp", "queue_temp", "assign", ">=", "updated", "SIMPLE_ASSIGNMENT", "include?", "+", "last", "raise", "Base"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QACE,6CAAoB,CAAG,QAAH,EAAU,QAAV,EAAiB,MAAjB,EAAsB,QAAtB,EAA6B,OAA7B,EAAmC,OAAnC,CAAyCC,QAAAA,CAAAA,CAA7D;QAEAL,IAAAM,QAAAA,CAAO,OAAPA;QACAN,IAAAO,UAAAA,CAAS,KAAT,EAAe,KAAfA;;AAEAC,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;UACEA,OAAAC,MAAAT,IAAAS,aAAAA,EAAAA,EAAAA,EAAAC,aAAcC,KAAdD,EAAAE;;;YAAc;YACZ,IAAA,MAAGZ,IAAAa,KAAAA,CAAAA,CAAGC,MAAAA,CAAAA,CAAN,EAAe,OAAf,CAAA;;cACEd,IAAAe,MAAAA,CAAK,EAAA,GAAA,CAAGJ,KAAH,CAAA,GAASC,KAAd,EAAoBZ,IAAAgB,MAAAA,CAAKhB,IAAAa,KAAAA,CAAAA,CAALG,CAApBD;cACAE,UAAU,CAAA,QAAYC,MAAZlB,IAAAa,KAAAA,CAAAA,CAAGN,UAAAA,CAAAA,CAASW,QAAAA,EAAAA,EAAAA,EAAZN,aAAqBO,CAArBP;;gBAAqB;gBAAGQ,OAAAD,CAACL,MAAAA,CAAAA,CAAMO,OAAAA,CAAG,OAAHA,EAA/BT,CAAYM,CAAZ,CAAA,GAAA,CAA6C,GAA7C,IAAA,CAAmDlB,IAAAa,KAAAA,CAAAA,CAAGN,UAAAA,CAAAA,CAASe,MAAAA,CAAAA,CAA/D,CAAA;cACVtB