nless work.empty?\n          join = work\n\n          if code.empty?\n            code = join\n          else\n            code << fragment('.concat([') << join << fragment('])')\n          end\n        end\n\n        push(*code)\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:Nodes>", "<class:ArglistNode>", "handle", "compile", "code", "work", "each", "children", "block in compile", "current", "block (2 levels) in compile", "splat", "type", "==", "arg", "expr", "empty?", "<<", "fragment", "join", "push", "Base"], :mappings=>"AAAAA,qCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,iBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MAEEA,OAAAC;MAAAA;;;;QACEJ,IAAAK,QAAAA,CAAO,SAAPA;QAEAD,OAAAE,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACE,KAAa,CAAA,EAAA,EAAI,EAAJ,CAAb,EAAAC,CAAAA,OAAA,KAAAA,CAAA,EAAMC,CAAAA,OAAN,KAAMA,CAAN;UAEQC,MAART,IAAAU,UAAAA,CAAAA,CAAQD,QAAAA,EAAAA,EAAAA,EAARE,aAAkBC,OAAlBD,EAAAE;;;YAAkB;YAChBC,QAAQF,OAAOG,MAAAA,CAAAA,CAAMC,OAAAA,CAAG,OAAHA;YACrBC,MAAMjB,IAAAkB,MAAAA,CAAKN,OAALM;YAEN,IAAA,QAAGJ,KAAH,CAAA;;cACE,IAAA,QAAGN,IAAIW,WAAAA,CAAAA,CAAP,CAAA;gBACE,IAAA,QAAGZ,IAAIY,WAAAA,CAAAA,CAAP,CAAA;kBACEZ,IAAKa,OAAAA,CAAGH,GAAHG;gBADP;kBAGEb,IAAKa,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,UAATQ,CAAHD,CAAwBA,OAAAA,CAAGH,GAAHG,CAAOA,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,GAATQ,CAAHD;gBAHtC;cADF;;gBAOE,IAAA,QAAGb,IAAIY,WAAAA,CAAAA,CAAP,CAAA;kBACEZ,IAAKa,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,GAATQ,CAAHD,CAAiBA,OAAAA,CAAGZ,IAAHY,CAAQA,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,GAATQ,CAAHD;gBADhC;kBAGEb,IAAKa,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,WAATQ,CAAHD,CAAyBA,OAAAA,CAAGZ,IAAHY,CAAQA,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,IAATQ,CAAHD;gBAHxC;gBAMAb,IAAKa,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,UAATQ,CAAHD,CAAwBA,OAAAA,CAAGH,GAAHG,CAAOA,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,GAATQ,CAAHD;cAbtC;cAgBAP,OAAAL,CAAAA,OAAO,EAAPA;YAjBF;;cAmBE,KAAA,QAA8BA,IAAIW,WAAAA,CAAAA,CAAlC,CAAA;gBAAAX,IAAKY,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASR,IAATQ,CAAHD;cAAL;cACAP,OAAAL,IAAKY,OAAAA,CAAGH,GAAHG;YApBP,EAJFT,CAAAA,GAAAA,SAAAA,CAAQF;UA4BR,KAAA,QAAOD,IAAIW,WAAAA,CAAAA,CAAX,CAAA;;YACEG,OAAOd;YAEP,IAAA,QAAGD,IAAIY,WAAAA,CAAAA,CAAP,CAAA;cACEZ,OAAOe;YADT;cAGEf,IAAKa,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASf,WAATe,CAAHD,CAAyBA,OAAAA,CAAGE,IAAHF,CAAQA,OAAAA,CAAGpB,IAAAqB,UAAAA,CAASf,IAATe,CAAHD;YAHxC;UAHF;UAUAd,OAAAiB,MAAAvB,IAAAuB,QAAAA,EAAK,MAAChB,IAAD,CAALgB;QAzCFjB,CAAAA;MAHFF,GAAAA,WAAAA,EAAoBoB,UAApBpB;IAFFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>37095, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/nodes/x_string.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  module Nodes\n    class XStringNode < Base\n      handle :xstr\n\n      def compile\n        @should_add_semicolon = false\n        unpacked_children = unpack_return(children)\n        stripped_children = XStringNode.strip_empty_children(unpacked_children)\n\n        if XStringNode.single_line?(stripped_children)\n          # If it's a single line we'll try to:\n          #\n          # - strip empty lines\n          # - remove a trailing `;`\n          # - detect an embedded `return`\n          # - prepend a `return` when needed\n          # - append a `;` when needed\n          # - warn the user not to use the semicolon in single-line x-strings\n          compile_single_line(stripped_children)\n        else\n          # Here we leave to the user the responsibility to add\n          # a return where it's due.\n          unpacked_children.each { |c| compile_child(c) }\n        end\n\n        wrap '(', ')' if recv?\n        push ';' if @should_add_semicolon\n      end\n\n      # Check if there's only one child or if they're all part of\n      # the same line (e.g. because of interpolations)\n      def self.single_line?(children)\n        (children.size == 1) || children.none? do |c|\n          c.type == :str && c.loc.expression.source.end_with?(\"\\n\")\n        end\n      end\n\n      # Will remove empty :str lines coming from cosmetic newlines in x-strings\n      #\n      # @example\n      #   # this will generate two additional empty\n      #   # children before and after `foo()`\n      #   %x{\n      #     foo()\n      #   }\n      def self.strip_empty_children(children)\n        children = children.dup\n        empty_line = ->(child) { child.nil? || (child.type == :str && child.loc.expression.source.rstrip.empty?) }\n\n        children.shift while children.any? && empty_line[children.first]\n        children.pop while children.any? && empty_line[children.last]\n\n        children\n      end\n\n      private\n\n      def compile_child(child)\n        case child.type\n        when :str\n          value = child.loc.expression.source\n          scope.self if value.include? 'self'\n          push Fragment.new(value, scope, child)\n        when :begin, :gvar, :ivar, :nil\n          push expr(child)\n        else\n          raise \"Unsupported xstr part: \#{child.type}\"\n        end\n      end\n\n      def compile_single_line(children)\n        has_embeded_return = false\n\n        first_child  = children.shift\n        single_child = children.empty?\n\n        first_child ||= s(:nil)\n\n        if first_child.type == :str\n          first_value = first_child.loc.expression.source.strip\n          has_embeded_return = first_value =~ /^return\\b/\n        end\n\n        push('return ') if @returning && !has_embeded_return\n\n        last_child = children.pop || first_child\n        last_value = extract_last_value(last_child) if last_child.type == :str\n\n        unless single_child\n          # assuming there's an interpolation somewhere (type != :str)\n          @should_add_semicolon = false\n          compile_child(first_child)\n          children.each { |c| compile_child(c) }\n        end\n\n        if last_child.type == :str\n          push Fragment.new(last_value, scope, last_child)\n        else\n          compile_child(last_child)\n        end\n      end\n\n      # Will drop the trailing semicolon if all conditions are met\n      def extract_last_value(last_child)\n        last_value = last_child.loc.expression.source.rstrip\n\n        scope.self if last_value.include? 'self'\n\n        if (@returning || expr?) && last_value.end_with?(';')\n          compiler.warning(\n            'Removed semicolon ending x-string expression, interpreted as unintentional',\n            last_child.line,\n          )\n          last_value = last_value[0..-2]\n        end\n\n        @should_add_semicolon = true if @returning\n\n        last_value\n      end\n\n      # A case for manually created :js_return statement in Compiler#returns\n      # Since we need to take original source of :str we have to use raw source\n      # so we need to combine \"return\" with \"raw_source\"\n      def unpack_return(children)\n        first_child = children.first\n        @returning  = false\n\n        if first_child.type == :js_return\n          @returning = true\n          children = first_child.children\n        end\n\n        children\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<module:Nodes>", "<class:XStringNode>", "self", "handle", "compile", "@should_add_semicolon", "unpacked_children", "unpack_return", "children", "stripped_children", "XStringNode", "strip_empty_children", "single_line?", "compile_single_line", "each", "block in compile", "c", "block (2 levels) in compile", "compile_child", "recv?", "wrap", "push", "$ret_or_1", "size", "==", "1", "none?", "block in single_line?", "block (2 levels) in single_line?", "$ret_or_2", "type", "loc", "expression", "source", "end_with?", "dup", "empty_line", "block in strip_empty_children", "child", "block (2 levels) in strip_empty_children", "nil?", "rstrip", "empty?", "any?", "[]", "first", "shift", "last", "pop", "private", "value", "include?", "scope", "Fragment", "new", "expr", "raise", "has_embeded_return", "first_child", "single_child", "s", "first_value", "strip", "=~", "@returning", "last_child