ate", "last", "_", "last_token_info", "last_token_range", "end_pos"], :mappings=>"AAAAA,mCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACE,0CAAiBA,WAAjB;;AAEAC,MAAAA,0BAAAA,sBAAeC,MAAD,EAASC,MAAvBF;AAAAA,QAAAA;;;QACEG,cAAUF;QACVD,OAAAI,CAAAA,cAAUF,MAAVE;MAFFJ,CAAAA;;AAKAK,MAAAA,mBAAAA,eAAAA;AAAAA,QAAAA;;;QACE,IAAA,QAAcF,WAAOG,WAAAA,CAAAA,CAArB,CAAA;UAAA,OAAO;QAAP;QAEAC,cAAcH,WAAOI,OAAAA,CAAC,gBAAAC,IAAAC,qBAAAA,CAAAA,CAAA,EAAqBC,EAArB,QAADH;QACrB,KAAA,QAAkBD,WAAlB,CAAA;UAAA,OAAO;QAAP;QAKAA,cAA+BK,MAAjBL,WAAWM,OAAAA,CAAAA,CAAMD,cAAAA,EAAAA,EAAAA,EAAjBE,aAAgCC,IAAhCD,EAAAE;;;UAAgC;UAAM,IAAA,QAAAC,CAAAA,YAAA,YAAcC,WAAAA,CAAQH,IAARG,CAAdD,CAAA,CAAA;YAA+BD,OAACD,IAAII,gBAAAA,CAAaH,SAAbG,CAALC,MAAAA,CAAAA;UAA/B;YAAAJ,OAAA;UAAA,EAAtCF,CAAiBF;QAE/B,IAAA,QAAG,iBAAmBM,WAAAA,CAAQX,WAAWC,OAAAA,CAACa,CAADb,CAAnBU,CAAtB,CAAA;;UACEX,cAAc,CAAA,QAAAU,CAAAA,YAAAV,WAAWC,OAAAA,CAAC,OAAAc,CAAA,EAAGX,EAAH,QAADH,CAAXS,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAsB,EAAtB,CAAA;UACdZ,OAAAE,WAAWgB,MAAAA,CAAAA;QAFb,OAGA,IAAA,MAAMhB,WAAN,EAAqB,CAACF,SAAD,CAArB,CAAA;UACEA,OAAAA;QADF;UAzBNA,OAAA;QAyBM;MAdFA,CAAAA;MAmBAI,IAAAe,SAAAA,CAAAA;MAEAzB,OAAAW,mCAAAA,+BAAAA;AAAAA,QAAAA;;;QACE,KAAqBP,WAAOsB,MAAAA,CAAAA,CAA5B,kBAAA,EAAAC,CAAAA,IAAA,6BAAAA,CAAA,EAAGC,CAAAA,kBAAH,6BAAGA,CAAH;QACA,KAAsBA,eAAtB,kBAAA,EAAAD,CAAAA,IAAA,6BAAAA,CAAA,EAAGE,CAAAA,mBAAH,6BAAGA,CAAH;QACAlB,OAAAkB,gBAAgBC,SAAAA,CAAAA;MAHlBnB,CAAAA;IA7BFX,GAAAA,WAAAA,EAAAA,IAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>37423, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/errors.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal\n  # Generic Opal error\n  class Error < StandardError\n  end\n\n  # raised if Gem not found in Opal#use_gem\n  class GemNotFound < Error\n    # name of gem that not found\n    attr_reader :gem_name\n\n    # @param gem_name [String] name of gem that not found\n    def initialize(gem_name)\n      @gem_name = gem_name\n      super(\"can't find gem \#{gem_name}\")\n    end\n  end\n\n  class CompilationError < Error\n    attr_accessor :location\n  end\n\n  class ParsingError < CompilationError\n  end\n\n  class RewritingError < ParsingError\n  end\n\n  class SyntaxError < ::SyntaxError\n    attr_accessor :location\n  end\n\n  def self.opal_location_from_error(error)\n    opal_location = OpalBacktraceLocation.new\n    opal_location.location = error.location if error.respond_to?(:location)\n    opal_location.diagnostic = error.diagnostic if error.respond_to?(:diagnostic)\n    opal_location\n  end\n\n  def self.add_opal_location_to_error(opal_location, error)\n    backtrace = error.backtrace.to_a\n    backtrace.unshift opal_location.to_s\n    error.set_backtrace backtrace\n    error\n  end\n\n  # Loosely compatible with Thread::Backtrace::Location\n  class OpalBacktraceLocation\n    attr_accessor :path, :lineno, :label\n\n    def initialize(path = nil, lineno = nil, label = nil)\n      @path, @lineno, @label = path, lineno, label\n    end\n\n    def to_s\n      string = path\n      string += \":\#{lineno}\" if lineno\n      string += ':in '\n      if label\n        string += \"`\#{label}'\"\n      else\n        string += 'unknown'\n      end\n      string\n    end\n\n    alias line lineno\n\n    def diagnostic=(diagnostic)\n      return unless diagnostic\n      self.location = diagnostic.location\n    end\n\n    def location=(location)\n      return unless location\n      self.lineno = location.line\n      if location.respond_to?(:source_line)\n        self.label = location.source_line\n      elsif location.respond_to?(:expression)\n        self.label = location.expression.source_line\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "<class:Error>", "StandardError", "<class:GemNotFound>", "self", "attr_reader", "initialize", "gem_name", "@gem_name", "Error", "<class:CompilationError>", "attr_accessor", "<class:ParsingError>", "CompilationError", "<class:RewritingError>", "ParsingError", "<class:SyntaxError>", "SyntaxError", "opal_location_from_error", "error", "opal_location", "OpalBacktraceLocation", "new", "respond_to?", "location=", "location", "diagnostic=", "diagnostic", "add_opal_location_to_error", "backtrace", "to_a", "unshift", "to_s", "set_backtrace", "<class:OpalBacktraceLocation>", "path", "lineno", "label", "@path", "@lineno", "@label", "string", "+", "lineno=", "line", "label=", "source_line", "expression"], :mappings=>"AAAAA,8BAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;IAEEC,OAAAA,WAAAA,EAAcC,mBAAdD;IAIAE;IAAAA;;;;MAEEC,IAAAC,aAAAA,CAAY,UAAZA;MAGAF,OAAAG,0BAAAA,sBAAeC,QAAfD;AAAAA,QAAAA;;QAAAA;;QACEE,gBAAYD;QACZD,OAAA,OAAAF,IAAA,EAAA,0DAAA,cAAA,EAAA,CAAOE,iBAAD,GAAA,CAAkBC,QAAlB,CAAN,CAAA,EAAA,IAAA;MAFFD,CAAAA;IALFH,GAAAA,WAAAA,EAAoBM,WAApBN;IAWAO;IAAAA;;;MACEA,OAAAN,IAAAO,eAAAA,CAAc,UAAdA;IADFD,GAAAA,WAAAA,EAAyBD,WAAzBC;IAIAE,OAAAA,WAAAA,EAAqBC,sBAArBD;IAGAE,OAAAA,WAAAA,EAAuBC,kBAAvBD;IAGAE;IAAAA;;;MACEA,OAAAZ,IAAAO,eAAAA,CAAc,UAAdA;IADFK,GAAAA,WAAAA,EAAoBC,kBAApBD;IAIAE,MAAId,IAAJc,+BAAAA,oCAAkCC,KAAlCD;AAAAA,MAAAA;;;MACEE,gBAAgBC,2BAAqBC,KAAAA,CAAAA;MACrC,IAAA,QAA2CH,KAAKI,gBAAAA,CAAa,UAAbA,CAAhD,CAAA;QAAAH,aAAaI,cAAAA,CAAYL,KAAKM,UAAAA,CAAAA,CAAjBD;MAAb;MACA,IAAA,QAA+CL,KAAKI,gBAAAA,CAAa,YAAbA,CAApD,CAAA;QAAAH,aAAaM,gBAAAA,CAAcP,KAAKQ,YAAAA,CAAAA,CAAnBD;MAAb;MACAR,OAAAE;IAJFF,CAAAA;IAOAU,MAAIxB,IAAJwB,iCAAAA,sCAAoCR,aAAD,EAAgBD,KAAnDS;AAAAA,MAAAA;;;MACEC,YAAYV,KAAKU,WAAAA,CAAAA,CAAUC,MAAAA,CAAAA;MAC3BD,SAASE,SAAAA,CAASX,aAAaY,MAAAA,CAAAA,CAAtBD;MACTZ,KAAKc,eAAAA,CAAeJ,SAAfI;MACLL,OAAAT;IAJFS,CAAAA;IAQA5B,OAAAkC;IAAAA;;;;MACE9B,IAAAO,eAAAA,CAAc,MAAd,EAAqB,QAArB,EAA8B,OAA9BA;;AAEAL,MAAAA,0BAAAA,sBAAe6B,IAAD,EAAaC,MAAb,EAA2BC,KAAzC/B;AAAAA,QAAAA;;;QAAe,yBAAO;QAAK,6BAAS;QAAK,2BAAQ;QAC/CA,OAAA,KAAyB,CAAA6B,IAAA,EAAMC,MAAN,EAAcC,KAAd,CAAzB,EAAAC,CAAAA,YAAA,KAAAA,CAAA,EAAOC,CAAAA,cAAP,KAAOA,CAAP,EAAgBC,CAAAA,aAAhB,KAAgBA,CAAhB;MADFlC,CAAAA,IAAAA;;AAIA0B,MAAAA,oBAAAA,gBAAAA;AAAAA,QAAAA;;;QACES,SAASrC,IAAA+B,MAAAA,CAAAA;QACT,IAAA,QAA0B/B,IAAAgC,QAAAA,CAAAA,CAA1B,CAAA;UAAAK,SAAOC,SAAPD,MAAOC,EAAIV,GAAD,GAAA,CAAI5B,IAAAgC,QAAAA,CAAAA,CAAJ,CAAHM;QAAP;QACAD,SAAOC,SAAPD,MAAOC,EAAGV,MAAHU;QACP,IAAA,QAAGtC,IAAAiC,OAAAA,CAAAA,CAAH,CAAA;UACEI,SAAOC,SAAPD,MAAOC,EAAIV,GAAD,GAAA,CAAI5B,IAAAiC,OAAAA,CAAAA,CAAJ,CAAA,GAAUL,GAAbU;QADT;UAGED,SAAOC,SAAPD,MAAOC,EAAGV,SAAHU;QAHT;QAKAV,OAAAS;MATFT,CAAAA;MAYA,aAAM,MAAN,EAAW,QAAX;;AAEAN,MAAAA,2BAAAA,gDAAgBC,UAAhBD;AAAAA,QAAAA;;;QACE,KAAA,QAAcC,UAAd,CAAA;UAAA,OAAA;QAAA;QACAD,OAAIF,MAAAA,CAAYG,UAAUF,UAAAA,CAAAA,CAAtBD,CAAAA,EAAAA,MAAJpB,IAAIoB,aAAAA,EAAAA,EAAAA,CAAAA,EAAAA;MAFNE,CAAAA;MAKAQ,OAAAV,yBAAAA,8CAAcC,QAAdD;AAAAA,QAAAA;;;QACE,KAAA,QAAcC,QAAd,CAAA;UAAA,OAAA;QAAA;QACArB,IAAIuC,YAAAA,CAAUlB,QAAQmB,MAAAA,CAAAA,CAAlBD;QACJ,IAAA,QAAGlB,QAAQF,gBAAAA,CAAa,aAAbA,CAAX,CAAA;UACEC,OAAIqB,MAAAA,CAASpB,QAAQqB,aAAAA,CAAAA,CAAjBD,CAAAA,EAAAA,MAAJzC,IAAIyC,UAAAA,EAAAA,EAAAA,CAAAA,EAAAA;QADN,OAEA,IAAA,QAAMpB,QAAQF,gBAAAA,CAAa,YAAbA,CAAd,CAAA;UACEC,OAAIqB,MAAAA,CAASpB,QAAQsB,YAAAA,CAAAA,CAAWD,aAAAA,CAAAA,CAA5BD,CAAAA,EAAAA,MAAJzC,IAAIyC,UAAAA,EAAAA,EAAAA,CAAAA,EAAAA;QADN;UA/ENrB,OAAA;QA+EM;MALFA,CAAAA;IA1BFU,GAAAA,WAAAA,EAAAA,IAAAA;EA9CFlC,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>37548, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/magic_comments.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule Opal::MagicComments\n  MAGIC_COMMENT_RE = /\\A# *(\\w+) *: *(\\S+.*?) *$/.freeze\n  EMACS_MAGIC_COMMENT_RE = /\\A# *-\\*- *(\\w+) *: *(\\S+.*?) *-\\*- *$/.freeze\n\n  def self.parse(sexp, comments)\n    flags = {}\n\n    # We have an upper limit at the first line of code\n    if sexp\n      first_line = sexp.loc.line\n      comments = comments.take(first_line)\n    end\n\n    comments.each do |comment|\n      next if first_line && comment.loc.line >= first_line\n\n      if (parts = comment.text.scan(MAGIC_COMMENT_RE)).any? ||\n         (parts = comment.text.scan(EMACS_MAGIC_COMMENT_RE)).any?\n        parts.each do |key, value|\n          flags[key.to_sym] =\n            case value\n            when 'true' then true\n            when 'false' then false\n            else value\n            end\n        end\n      end\n    end\n\n    flags\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal::MagicComments>", "freeze", "parse", "self", "sexp", "comments", "flags", "first_line", "loc", "line", "take", "each", "block in parse", "comment", "block (2 levels) in parse", ">=", "parts", "text", "scan", "MAGIC_COMMENT_RE", "any?", "EMACS_MAGIC_COMMENT_RE", "key", "value", "block (3 levels) in parse", "[]=", "to_sym", "$ret_or_1", "Opal"], :mappings=>"AAAAA,sCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;IACE,4CAAmB,2BAA4BC,QAAAA,CAAAA,CAA/C;IACA,kDAAyB,uCAAwCA,QAAAA,CAAAA,CAAjE;IAEAD,OAAAE,MAAIC,IAAJD,YAAAA,iBAAeE,IAAD,EAAOC,QAArBH;AAAAA,MAAAA;;;MACEI,QAAQ,YAAA;MAGR,IAAA,QAAGF,IAAH,CAAA;;QACEG,aAAaH,IAAII,KAAAA,CAAAA,CAAIC,MAAAA,CAAAA;QACrBJ,WAAWA,QAAQK,MAAAA,CAAMH,UAANG;MAFrB;MAKQC,MAARN,QAAQM,QAAAA,EAAAA,EAAAA,EAARC,aAAkBC,OAAlBD,EAAAE;;;QAAkB;QAChB,IAAQ,CAAA,QAAAP,UAAA,CAAA,IAAA,CAAA,QAA+BQ,OAAjBF,OAAOL,KAAAA,CAAAA,CAAIC,MAAAA,CAAAA,CAAMM,EAAGR,UAAHQ,CAA/B,CAAA,CAAA,CAAR;UAAA,OAAA;QAAA;QAEA,IAAG,CAAA,QAACC,CAAAA,QAAQH,OAAOI,MAAAA,CAAAA,CAAKC,MAAAA,CAAMC,sBAAND,CAApBF,CAA4CI,SAAAA,CAAAA,CAA7C,CAAA,IAAA,CAAA,QACCJ,CAAAA,QAAQH,OAAOI,MAAAA,CAAAA,CAAKC,MAAAA,CAAMG,4BAANH,CAApBF,CAAkDI,SAAAA,CAAAA,CADnD,CAAA,CAAA,CAAH;UAEEN,OAAKH,MAALK,KAAKL,QAAAA,EAAAA,EAAAA,EAALG,aAAeQ,GAAD,EAAMC,KAApBT,EAAAU;;;YAAe;YAAK;YAClBA,OAAKC,MAAAA,CAACH,GAAGI,QAAAA,CAAAA,CAAT,EAEE,CAAA,QAAKF,MAAL,EADAG,CAAAA,YAAKJ,KAALI,CACA,CAAA,IAAA,CACA,CAAA,QAAKH,OAAL,EAxBZ,SAwBY,CAAA,GAAA,CAAkB,KAAlB,IAAA,CACKD,KADL,CAAA,CADA,CAAA,CAFGE,CAAAA,EAAAA,MAALnB,KAAKmB,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBADPX,CAAKH;QAFP;UAlBNG,OAAA;QAkBM,EAHFF,CAAQD;MAgBRT,OAAAI;IAzBFJ,CAAAA;EAJFF,GAAO4B,UAAP5B;AAFAD;"}}, {:offset=>{:line=>37591, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/compiler.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nrequire 'set'\nrequire 'opal/parser'\nrequire 'opal/fragment'\nrequire 'opal/nodes'\nrequire 'opal/eof_content'\nrequire 'opal/errors'\nrequire 'opal/magic_comments'\nrequire 'opal/nodes/closure'\n\nmodule Opal\n  # Compile a string of ruby code into javascript.\n  #\n  # @example\n  #\n  #     Opal.compile \"ruby_code\"\n  #     # => \"string of javascript code\"\n  #\n  # @see Opal::Compiler.new for compiler options\n  #\n  # @param source [String] ruby source\n  # @param options [Hash] compiler options\n  # @return [String] javascript code\n  #\n  def self.compile(source, options = {})\n    Compiler.new(source, options).compile\n  end\n\n  # {Opal::Compiler} is the main class used to compile ruby to javascript code.\n  # This class uses {Opal::Parser} to gather the sexp syntax tree for the ruby\n  # code, and then uses {Opal::Node} to step through the sexp to generate valid\n  # javascript.\n  #\n  # @example\n  #   Opal::Compiler.new(\"ruby code\").compile\n  #   # => \"javascript code\"\n  #\n  # @example Accessing result\n  #   compiler = Opal::Compiler.new(\"ruby_code\")\n  #   compiler.compile\n  #   compiler.result # => \"javascript code\"\n  #\n  # @example Source Maps\n  #   compiler = Opal::Compiler.new(\"\")\n  #   compiler.compile\n  #   compiler.source_map # => #<SourceMap:>\n  #\n  class Compiler\n    include Nodes::Closure::CompilerSupport\n\n    # Generated code gets indented with two spaces on each scope\n    INDENT = '  '\n\n    # All compare method nodes - used to optimize performance of\n    # math comparisons\n    COMPARE = %w[< > <= >=].freeze\n\n    def self.module_name(path)\n      path = File.join(File.dirname(path), File.basename(path).split('.').first)\n      Pathname(path).cleanpath.to_s\n    end\n\n    # Defines a compiler option.\n    # @option as: [Symbol] uses a different method name, e.g. with a question mark for booleans\n    # @option default: [Object] the default value for the option\n    # @option magic_comment: [Bool] allows magic-comments to override the option value\n    def self.compiler_option(name, config = {})\n      method_name = config.fetch(:as, name)\n      define_method(method_name) { option_value(name, config) }\n    end\n\n    # Fetches and memoizes the value for an option.\n    def option_value(name, config)\n      return @option_values[name] if @option_values.key? name\n\n      default_value = config[:default]\n      valid_values  = config[:valid_values]\n      magic_comment = config[:magic_comment]\n\n      value = @options.fetch(name, default_value)\n\n      if magic_comment && @magic_comments.key?(name)\n        value = @magic_comments.fetch(name)\n      end\n\n      if valid_values && !valid_values.include?(value)\n        raise(\n          ArgumentError,\n          \"invalid value \#{value.inspect} for option \#{name.inspect} \" \\\n          \"(valid values: \#{valid_values.inspect})\"\n        )\n      end\n\n      @option_values[name] = value\n    end\n\n    # @!method file\n    #\n    # The filename to use for compiling this code. Used for __FILE__ directives\n    # as well as finding relative require()\n    #\n    # @return [String]\n    compiler_option :file, default: '(file)'\n\n    # @!method method_missing?\n    #\n    # adds method stubs for all used methods in file\n    #\n    # @return [Boolean]\n    compiler_option :method_missing, default: true, as: :method_missing?\n\n    # @!method arity_check?\n    #\n    # adds an arity check to every method definition\n    #\n    # @return [Boolean]\n    compiler_option :arity_check, default: false, as: :arity_check?\n\n    # @deprecated\n    # @!method freezing?\n    #\n    # stubs out #freeze and #frozen?\n    #\n    # @return [Boolean]\n    compiler_option :freezing, default: true, as: :freezing?\n\n    # @!method irb?\n    #\n    # compile top level local vars with support for irb style vars\n    compiler_option :irb, default: false, as: :irb?\n\n    # @!method dynamic_require_severity\n    #\n    # how to handle dynamic requires (:error, :warning, :ignore)\n    compiler_option :dynamic_require_severity, default: :ignore, valid_values: %i[error warning ignore]\n\n    # @!method requirable?\n    #\n    # Prepare the code for future requires\n    compiler_option :requirable, default: false, as: :requirable?\n\n    # @!method load?\n    #\n    # Instantly load a requirable module\n    compiler_option :load, default: false, as: :load?\n\n    # @!method esm?\n    #\n    # Encourage ESM semantics, eg. exporting run result\n    compiler_option :esm, default: false, as: :esm?\n\n    # @!method no_export?\n    #\n    # Don't export this compile, even if ESM mode is enabled. We use\n    # this internally in CLI, so that even if ESM output is desired,\n    # we would only have one default export.\n    compiler_option :no_export, default: false, as: :no_export?\n\n    # @!method inline_operators?\n    #\n    # are operators compiled inline\n    compiler_option :inline_operators, default: true, as: :inline_operators?\n\n    compiler_option :eval, default: false, as: :eval?\n\n    # @!method enable_source_location?\n    #\n    # Adds source_location for every method definition\n    compiler_option :enable_source_location, default: false, as: :enable_source_location?\n\n    # @!method enable_file_source_embed?\n    #\n    # Embeds source code along compiled files\n    compiler_option :enable_file_source_embed, default: false, as: :enable_file_source_embed?\n\n    # @!method use_strict?\n    #\n    # Enables JavaScript's strict mode (i.e., adds 'use strict'; statement)\n    compiler_option :use_strict, default: false, as: :use_strict?, magic_comment: true\n\n    # @!method parse_comments?\n    #\n    # Adds comments for every method definition\n    compiler_option :parse_comments, default: false, as: :parse_comments?\n\n    compiler_option :scope_variables, default: []\n\n    # @!method async_await\n    #\n    # Enable async/await support and optionally enable auto-await.\n    #\n    # Use either true, false, an Array of Symbols, a String containing names\n    # to auto-await separated by a comma or a Regexp.\n    #\n    # Auto-await awaits provided methods by default as if .__await__ was added to\n    # them automatically.\n    #\n    # By default, the support is disabled (set to false).\n    #\n    # If the config value is not set to false, any calls to #__await__ will be\n    # translated to ES8 await keyword which makes the scope return a Promise\n    # and a containing scope will be async (instead of a value, it will return\n    # a Promise).\n    #\n    # If the config value is an array, or a String separated by a comma,\n    # auto-await is also enabled.\n    #\n    # A member of this collection can contain a wildcard character * in which\n    # case all methods containing a given substring will be awaited.\n    #\n    # It can be used as a magic comment, examples:\n    # ```\n    # # await: true\n    # # await: *await*\n    # # await: *await*, sleep, gets\n    compiler_option :await, default: false, as: :async_await, magic_comment: true\n\n    # @return [String] The compiled ruby code\n    attr_reader :result\n\n    # @return [Array] all [Opal::Fragment] used to produce result\n    attr_reader :fragments\n\n    # Current scope\n    attr_accessor :scope\n\n    # Top scope\n    attr_accessor :top_scope\n\n    # Current case_stmt\n    attr_reader :case_stmt\n\n    # Any content in __END__ special construct\n    attr_reader :eof_content\n\n    # Comments from the source code\n    attr_reader :comments\n\n    # Method calls made in this file\n    attr_reader :method_calls\n\n    # Magic comment flags extracted from the leading comments\n    attr_reader :magic_comments\n\n    # Access the source code currently processed\n    attr_reader :source\n\n    # Set if some rewritter caused a dynamic cache result, meaning it's not\n    # fit to be cached\n    attr_accessor :dynamic_cache_result\n\n    def initialize(source, options = {})\n      @source = source\n      @indent = ''\n      @unique = 0\n      @options = options\n      @comments = Hash.new([])\n      @case_stmt = nil\n      @method_calls = Set.new\n      @option_values = {}\n      @magic_comments = {}\n      @dynamic_cache_result = false\n    end\n\n    # Compile some ruby code to a string.\n    #\n    # @return [String] javascript code\n    def compile\n      parse\n\n      @fragments = re_raise_with_location { process(@sexp).flatten }\n      @fragments << fragment(\"\\n\", nil, s(:newline)) unless @fragments.last.code.end_with?(\"\\n\")\n\n      @result = @fragments.map(&:code).join('')\n    end\n\n    def parse\n      @buffer = ::Opal::Parser::SourceBuffer.new(file, 1)\n      @buffer.source = @source\n\n      @parser = Opal::Parser.default_parser\n\n      sexp, comments, tokens = re_raise_with_location { @parser.tokenize(@buffer) }\n\n      kind = case\n             when requirable?\n               :require\n             when eval?\n               :eval\n             else\n               :main\n             end\n\n      @sexp = sexp.tap { |i| i.meta[:kind] = kind }\n\n      first_node = sexp.children.first if sexp.children.first.location\n\n      @comments = ::Parser::Source::Comment.associate_locations(first_node, comments)\n      @magic_comments = MagicComments.parse(first_node, comments)\n      @eof_content = EofContent.new(tokens, @source).eof\n    end\n\n    # Returns a source map that can be used in the browser to map back to\n    # original ruby code.\n    #\n    # @param source_file [String] optional source_file to reference ruby source\n    # @return [Opal::SourceMap]\n    def source_map\n      # We only use @source_map if compiler is cached.\n      @source_map || ::Opal::SourceMap::File.new(@fragments, file, @source, @result)\n    end\n\n    # Any helpers required by this file. Used by {Opal::Nodes::Top} to reference\n    # runtime helpers that are needed. These are used to minify resulting\n    # javascript by keeping a reference to helpers