source\n          source = fix_quotes(source)\n          source = find_contents(source)\n          source = find_code(source)\n          source = wrap_compiled(source)\n          source = require_erb(source)\n          source\n        end\n      end\n\n      def compile\n        Opal.compile prepared_source\n      end\n\n      def fix_quotes(result)\n        result.gsub '\"', '\\\\\"'\n      end\n\n      def require_erb(result)\n        'require \"erb\";' + result\n      end\n\n      def find_contents(result)\n        result.gsub(/<%=([\\s\\S]+?)%>/) do\n          inner = Regexp.last_match(1).gsub(/\\\\'/, \"'\").gsub(/\\\\\"/, '\"')\n\n          if inner =~ BLOCK_EXPR\n            \"\\\")\\noutput_buffer.append= \#{inner}\\noutput_buffer.append(\\\"\"\n          else\n            \"\\\")\\noutput_buffer.append=(\#{inner})\\noutput_buffer.append(\\\"\"\n          end\n        end\n      end\n\n      def find_code(result)\n        result.gsub(/<%([\\s\\S]+?)%>/) do\n          inner = Regexp.last_match(1).gsub(/\\\\\"/, '\"')\n          \"\\\")\\n\#{inner}\\noutput_buffer.append(\\\"\"\n        end\n      end\n\n      def wrap_compiled(result)\n        path = @file_name.sub(/\\.opalerb\#{REGEXP_END}/, '')\n        \"Template.new('\#{path}') do |output_buffer|\\noutput_buffer.append(\\\"\#{result}\\\")\\noutput_buffer.join\\nend\\n\"\n      end\n    end\n  end\nend\n"], :names=>["<top (required)>", "self", "require", "<module:Opal>", "<module:ERB>", "compile", "source", "file_name", "Compiler", "new", "<class:Compiler>", "freeze", "initialize", "@source", "@file_name", "@result", "prepared_source", "@prepared_source", "$ret_or_1", "fix_quotes", "find_contents", "find_code", "wrap_compiled", "require_erb", "Opal", "result", "gsub", "+", "block in find_contents", "block (2 levels) in find_contents", "inner", "Regexp", "last_match", "1", "=~", "BLOCK_EXPR", "block in find_code", "block (2 levels) in find_code", "path", "sub", "REGEXP_END"], :mappings=>"AAAAA,2BAAAA,gBAAAA