kBG,MAAlBH;AAAAA,UAAAA;;;UACEgB,OAAOxB,cAAUyB,KAAAA,CAAK,SAACjB,YAAD,EAAYkB,gBAAZ,CAAA,CAAf,EAAyClB,EAA/BiB;UACjBjB,OAACA,gBAAD,GAAA,CAAiBgB,IAAjB,CAAA,GAAsBhB,gDAAtB,GAAA,CAAsEG,MAAtE,CAAA,GAA6EH;QAF/EA,CAAAA;MAlDFZ,GAAAA,WAAAA,EAAAA,IAAAA;IAzBFN,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAJAH;"}}, {:offset=>{:line=>38178, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./opal-parser.rb"], :sourcesContent=>["# parser uses String#unpack\nrequire 'corelib/string/unpack'\n\nrequire 'opal/compiler'\nrequire 'opal/erb'\nrequire 'opal/version'\n\nmodule Kernel\n  def eval(str, binding = nil, file = nil, line = nil)\n    str = ::Opal.coerce_to!(str, String, :to_str)\n    default_eval_options = { file: file || '(eval)', eval: true }\n    compiling_options = __OPAL_COMPILER_CONFIG__.merge(default_eval_options)\n    code = `Opal.compile(str, compiling_options)`\n    if binding\n      binding.js_eval(code)\n    else\n      %x{\n        return (function(self) {\n          return eval(\#{code});\n        })(self)\n      }\n    end\n  end\n\n  def require_remote(url)\n    %x{\n      var r = new XMLHttpRequest();\n      r.open(\"GET\", url, false);\n      r.send('');\n    }\n    eval `r.responseText`\n  end\nend\n\n%x{\n  Opal.compile = function(str, options) {\n    try {\n      str = \#{::Opal.coerce_to!(`str`, String, :to_str)}\n      if (options) options = Opal.hash(options);\n      return Opal.Opal.$compile(str, options);\n    }\n    catch (e) {\n      if (e.$$class === Opal.Opal.SyntaxError) {\n        var err = Opal.SyntaxError.$new(e.message);\n        err.$set_backtrace(e.$backtrace());\n        throw(err);\n      }\n      else { throw e; }\n    }\n  };\n\n  Opal['eval'] = function(str, options) {\n    return eval(Opal.compile(str, options));\n  };\n\n  function run_ruby_scripts() {\n    var tag, tags = document.getElementsByTagName('script');\n\n    for (var i = 0, len = tags.length; i < len; i++) {\n      tag = tags[i];\n      if (tag.type === \"text/ruby\") {\n        if (tag.src)       Opal.Kernel.$require_remote(tag.src);\n        if (tag.innerHTML) Opal.Kernel.$eval(tag.innerHTML);\n      }\n    }\n  }\n\n  if (typeof(document) !== 'undefined') {\n    if (window.addEventListener) {\n      window.addEventListener('DOMContentLoaded', run_ruby_scripts, false);\n    }\n    else {\n      window.attachEvent('onload', run_ruby_scripts);\n    }\n  }\n}\n"], :names=>["<main>", "self", "require", "<module:Kernel>", "eval", "str", "binding", "file", "line", "Opal", "coerce_to!", "String", "default_eval_options", "$ret_or_1", "compiling_options", "__OPAL_COMPILER_CONFIG__", "merge", "code", "js_eval", "require_remote", "url"], :mappings=>"AAAAA,2BAAAA;EAAAA;;;EACAC,IAAAC,SAAAA,CAAQF,uBAARE;EAEAD,IAAAC,SAAAA,CAAQF,eAARE;EACAD,IAAAC,SAAAA,CAAQF,UAARE;EACAD,IAAAC,SAAAA,CAAQF,cAARE;EAEAC;EAAAA;;IAAAA;;;;AACEC,IAAAA,oBAAAA,wBAASC,GAAD,EAAMC,OAAN,EAAqBC,IAArB,EAAiCC,IAAzCJ;AAAAA,MAAAA;;;MAAc,+BAAU;MAAK,yBAAO;MAAK,yBAAO;MAC9CC,MAAMI,KAAMC,eAAAA,CAAYL,GAAlB,EAAuBM,YAAvB,EAA+B,QAAzBD;MACZE,uBAAuB,0BAAA,QAAQ,CAAA,QAAAC,CAAAA,YAAAN,IAAAM,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAQT,QAAR,CAAA,CAAR,EAAA,QAAgC,IAAhC;MACvBU,oBAAoBC,iCAAwBC,OAAAA,CAAOJ,oBAAPI;MAC5CC,OAAQb;MACR,IAAA,QAAGE,OAAH,CAAA;QACEF,OAAAE,OAAOY,SAAAA,CAASD,IAATC;MADT;;AAIJd;AACAA,sBAAwBa,IAAKb;AAC7BA;AACAA;MAPI;IALFA,CAAAA,IAAAA;IAgBAD,OAAAgB,8BAAAA,0BAAmBC,GAAnBD,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,MAAAA;;;;AAEFA;AACAA;AACAA;AACAA;MACIA,OAAAf,MAAMe,cAANf,2DAAAA,oBAAAA,OAAAA,sDAAAA,gBANFe;QAAAA;QAAAA;MAAAA;IAAAA,CAAAA;EAjBFhB,GAAAA,WAAAA;;AA4BAH;AACAA;AACAA,YAAcS,KAAMC,eAAAA,CAAaV,GAAnB,EAAyBW,YAAzB,EAAiC,QAA3BD;AACpBV;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AA1EAA;"}}]}